function extractStripeMetadataValue_(obj, key) {
  if (!obj || typeof obj !== 'object') return '';
  const meta = obj.metadata && typeof obj.metadata === 'object' ? obj.metadata : {};
  return trimString_(meta[key]);
}

function validateCurrentStripeCheckoutWebhookOrder_(eventObj, orderInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const token = trimString_(
    extractStripeMetadataValue_(eventObj, 'token') ||
    row.token
  );
  if (!token) return { ok: true, current: true, rowInfo: null };
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const rowInfo = findRowByToken_(infra.exportSheet, token);
  if (!rowInfo) return { ok: true, current: true, rowInfo: null };
  const exportRow = rowInfo.rowObjNormalized || {};
  const activeOrderId = trimString_(exportRow.activeorderid);
  const latestCheckoutAttemptId = trimString_(exportRow.latestcheckoutattemptid);
  const orderId = trimString_(row.orderid);
  const orderCheckoutAttemptId = trimString_(row.checkoutattemptid);
  const eventCheckoutAttemptId = trimString_(extractStripeMetadataValue_(eventObj, 'checkoutAttemptId'));
  const effectiveCheckoutAttemptId = orderCheckoutAttemptId || eventCheckoutAttemptId;
  const eventObjectType = trimString_(eventObj && eventObj.object).toLowerCase();
  const eventId = trimString_(eventObj && eventObj.id);
  const eventIsCheckoutSession = eventObjectType === 'checkout.session' || eventId.indexOf('cs_') === 0;
  const orderStripeSessionId = trimString_(row.stripesessionid);
  const eventStripeSessionId = eventIsCheckoutSession ? eventId : '';
  const hasCurrentCheckoutPointers = !!activeOrderId || !!latestCheckoutAttemptId;
  const current = hasCurrentCheckoutPointers
    && (!activeOrderId || (orderId && activeOrderId === orderId))
    && (!latestCheckoutAttemptId || (effectiveCheckoutAttemptId && latestCheckoutAttemptId === effectiveCheckoutAttemptId))
    && (!eventCheckoutAttemptId || !latestCheckoutAttemptId || eventCheckoutAttemptId === latestCheckoutAttemptId)
    && (!eventStripeSessionId || !orderStripeSessionId || eventStripeSessionId === orderStripeSessionId);
  if (current) {
    return { ok: true, current: true, rowInfo: rowInfo };
  }
  const result = {
    ok: true,
    ignored: true,
    code: 'superseded_checkout_attempt',
    eventType: trimString_(opts.eventType),
    token: token,
    orderId: orderId,
    checkoutAttemptId: effectiveCheckoutAttemptId,
    activeOrderId: activeOrderId,
    latestCheckoutAttemptId: latestCheckoutAttemptId
  };
  console.log('[RT-STRIPE-WEBHOOK-SUPERSEDED] ' + JSON.stringify(result));
  return Object.assign({ current: false, rowInfo: rowInfo }, result);
}

function buildStripeLatestEventOrderUpdates_(eventPayload, dataObject) {
  const event = (eventPayload && typeof eventPayload === 'object') ? eventPayload : {};
  const obj = (dataObject && typeof dataObject === 'object') ? dataObject : {};
  const created = Number(event.created || 0);
  const updates = {
    stripeLatestEventId: trimString_(event.id),
    stripeLatestEventType: trimString_(event.type),
    stripeLatestEventAt: created > 0 ? new Date(created * 1000).toISOString() : nowIso_()
  };
  const chargeId = stripeIdFromObject_(obj.latest_charge || obj.latestCharge || obj.charge) ||
    (trimString_(obj.object).toLowerCase() === 'charge' ? trimString_(obj.id) : '');
  if (chargeId) updates.stripeLatestChargeId = chargeId;
  return updates;
}

function getPortalAccountInfoForOrder_(orderInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const orderRow = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const token = trimString_(orderRow.token);
  const rowInfo = token ? findRowByToken_(infra.exportSheet, token) : null;
  if (rowInfo) {
    return createPortalAccountIfMissing_(Object.assign({}, deriveOrgContextFromRow_(rowInfo.rowObjNormalized), {
      cfg: cfg,
      ss: ss,
      infra: infra,
      createIfMissing: true
    }));
  }
  const accountId = trimString_(orderRow.accountid || orderRow.currentaccountid);
  return accountId ? getPortalAccountByAccountId_(accountId, { cfg: cfg, ss: ss, infra: infra }) : null;
}

function extractFailureFromStripeObject_(stripeObj) {
  const obj = (stripeObj && typeof stripeObj === 'object') ? stripeObj : {};
  const failure = (obj.last_payment_error && typeof obj.last_payment_error === 'object')
    ? obj.last_payment_error
    : obj;
  return {
    code: trimString_(failure.code || failure.failure_code || obj.failure_code),
    message: trimString_(failure.message || failure.failure_message || obj.failure_message)
  };
}

function hasStripeMicrodepositNextAction_(stripeObj) {
  const obj = (stripeObj && typeof stripeObj === 'object') ? stripeObj : {};
  const nextAction = (obj.next_action && typeof obj.next_action === 'object')
    ? obj.next_action
    : ((obj.nextAction && typeof obj.nextAction === 'object') ? obj.nextAction : {});
  const type = trimString_(nextAction.type || nextAction.next_action_type).toLowerCase();
  return type === 'verify_with_microdeposits' ||
    !!(nextAction.verify_with_microdeposits && typeof nextAction.verify_with_microdeposits === 'object') ||
    !!(nextAction.verifyWithMicrodeposits && typeof nextAction.verifyWithMicrodeposits === 'object');
}

function deriveAchVerificationStatusFromStripeIntent_(stripeObj, fallback) {
  const obj = (stripeObj && typeof stripeObj === 'object') ? stripeObj : {};
  const status = trimString_(obj.status).toLowerCase();
  const failure = extractFailureFromStripeObject_(obj);
  const failureSignal = [
    failure.code,
    failure.message
  ].join(' ').toLowerCase();
  if (hasStripeMicrodepositNextAction_(obj)) return 'microdeposit_pending';
  if (failureSignal.indexOf('microdeposit') >= 0) {
    if (/(timeout|exceeded|failed|mismatch|invalid)/i.test(failureSignal)) return 'verification_failed';
    return 'microdeposit_pending';
  }
  if (status === 'requires_action') return 'microdeposit_pending';
  if (status === 'requires_payment_method' && failureSignal) return 'verification_failed';
  if (status === 'processing') return 'processing';
  if (status === 'succeeded') return 'succeeded';
  return trimString_(fallback);
}

function mapAchPaymentMethodStatusFromVerification_(verificationStatus, fallbackStatus) {
  const fallback = trimString_(fallbackStatus);
  const raw = trimString_(verificationStatus).toLowerCase();
  if (/(fail|failed|failure|blocked|invalid|expired|timeout|exceeded|requires_payment_method)/i.test(raw)) return 'failed';
  if (/(pending|processing|microdeposit|requires_action|unverified)/i.test(raw)) return 'pending';
  return fallback || 'active';
}

function normalizeAchSummaryVerificationStatus_(intentStatus, bankStatus) {
  const intent = trimString_(intentStatus);
  const bank = trimString_(bankStatus);
  const intentRaw = intent.toLowerCase();
  if (/(microdeposit|requires_action|verification_failed|requires_payment_method|fail|failed|timeout|exceeded|invalid|blocked)/i.test(intentRaw)) {
    return intent;
  }
  return bank || intent;
}

function resolveAchPaymentMethodSummaryFromPaymentIntent_(paymentIntentObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const pi = (paymentIntentObj && typeof paymentIntentObj === 'object') ? paymentIntentObj : {};
  let paymentMethod = pi.payment_method && typeof pi.payment_method === 'object' ? pi.payment_method : null;
  const paymentMethodId = stripeIdFromObject_(pi.payment_method);
  if (!paymentMethod && paymentMethodId) {
    const methodResult = retrieveStripePaymentMethod_(paymentMethodId, opts);
    if (methodResult.ok) paymentMethod = methodResult.body;
  }
  const latestChargeId = stripeIdFromObject_(pi.latest_charge);
  let mandateId = '';
  if (pi.mandate) mandateId = stripeIdFromObject_(pi.mandate);
  if (!mandateId && pi.payment_method_options && pi.payment_method_options.us_bank_account) {
    mandateId = stripeIdFromObject_(pi.payment_method_options.us_bank_account.mandate);
  }
  const verificationStatus = deriveAchVerificationStatusFromStripeIntent_(pi, opts.verificationStatus);
  return paymentMethod ? extractAchPaymentMethodSummaryFromStripe_(paymentMethod, {
    source: trimString_(opts.source) || 'checkout_payment',
    mandateId: mandateId,
    verificationStatus: verificationStatus,
    status: mapAchPaymentMethodStatusFromVerification_(verificationStatus, 'active')
  }) : null;
}

function getStripePaymentMethodTypes_(stripeObj) {
  const obj = (stripeObj && typeof stripeObj === 'object') ? stripeObj : {};
  return Array.isArray(obj.payment_method_types)
    ? obj.payment_method_types.map(function(item) { return trimString_(item).toLowerCase(); }).filter(Boolean)
    : [];
}

function hasOnlyStripeUsBankPaymentMethodType_(stripeObj) {
  const methodTypes = getStripePaymentMethodTypes_(stripeObj);
  return methodTypes.length === 1 && methodTypes[0] === 'us_bank_account';
}

function hasStripeUsBankOptions_(stripeObj) {
  const obj = (stripeObj && typeof stripeObj === 'object') ? stripeObj : {};
  const options = obj.payment_method_options && typeof obj.payment_method_options === 'object'
    ? obj.payment_method_options
    : {};
  return !!(options.us_bank_account && typeof options.us_bank_account === 'object');
}

function hasStripeUsBankPaymentMethodEvidence_(paymentMethodObj) {
  const method = (paymentMethodObj && typeof paymentMethodObj === 'object') ? paymentMethodObj : {};
  return trimString_(method.type).toLowerCase() === 'us_bank_account' ||
    !!(method.us_bank_account && typeof method.us_bank_account === 'object');
}

function hasStripeUsBankChargeEvidence_(chargeObj) {
  const charge = (chargeObj && typeof chargeObj === 'object') ? chargeObj : {};
  const details = charge.payment_method_details && typeof charge.payment_method_details === 'object'
    ? charge.payment_method_details
    : {};
  return trimString_(details.type).toLowerCase() === 'us_bank_account' ||
    !!(details.us_bank_account && typeof details.us_bank_account === 'object');
}

function hasStripeUsBankPaymentIntentEvidence_(paymentIntentObj) {
  const pi = (paymentIntentObj && typeof paymentIntentObj === 'object') ? paymentIntentObj : {};
  if (hasOnlyStripeUsBankPaymentMethodType_(pi) || hasStripeUsBankOptions_(pi)) return true;
  if (hasStripeUsBankPaymentMethodEvidence_(pi.payment_method)) return true;
  if (hasStripeUsBankChargeEvidence_(pi.latest_charge)) return true;
  const charges = pi.charges && Array.isArray(pi.charges.data) ? pi.charges.data : [];
  return charges.some(function(charge) {
    return hasStripeUsBankChargeEvidence_(charge);
  });
}

function hasStripeUsBankCheckoutSessionEvidence_(sessionObj) {
  const session = (sessionObj && typeof sessionObj === 'object') ? sessionObj : {};
  if (hasOnlyStripeUsBankPaymentMethodType_(session) || hasStripeUsBankOptions_(session)) return true;
  return hasStripeUsBankPaymentIntentEvidence_(session.payment_intent);
}

function hasDashboardAchSetupMetadata_(stripeObj) {
  const source = trimString_(extractStripeMetadataValue_(stripeObj, 'source')).toLowerCase();
  const path = trimString_(extractStripeMetadataValue_(stripeObj, 'path')).toLowerCase();
  return source === 'dashboard_bank_setup' || path === 'dashboard_bank_setup';
}

function buildAchStripeEventEvidence_(options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const orderInfo = opts.orderInfo || null;
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const achSummary = opts.achSummary || opts.summary || null;
  const setupSummary = opts.setupSummary || null;
  const session = (opts.session || opts.checkoutSession || null);
  const paymentIntent = (opts.paymentIntent || null);
  const charge = (opts.charge || null);
  const paymentMethod = (opts.paymentMethod || null);
  const setupIntent = (opts.setupIntent || null);
  const reasons = [];
  if (trimString_(row.paymentmethodselected).toLowerCase() === PAYMENT_METHODS.ach) reasons.push('order_payment_method_ach');
  if (achSummary) reasons.push('ach_payment_method_summary');
  if (setupSummary) reasons.push('ach_setup_summary');
  if (hasStripeUsBankCheckoutSessionEvidence_(session)) reasons.push('checkout_session_us_bank_account');
  if (hasStripeUsBankPaymentIntentEvidence_(paymentIntent)) reasons.push('payment_intent_us_bank_account');
  if (hasStripeUsBankChargeEvidence_(charge)) reasons.push('charge_us_bank_account');
  if (hasStripeUsBankPaymentMethodEvidence_(paymentMethod)) reasons.push('payment_method_us_bank_account');
  if (hasStripeUsBankPaymentMethodEvidence_(setupIntent && setupIntent.payment_method)) reasons.push('setup_intent_payment_method_us_bank_account');
  if (hasDashboardAchSetupMetadata_(session) || hasDashboardAchSetupMetadata_(setupIntent)) reasons.push('dashboard_bank_setup_metadata');
  const isAchPayment = reasons.some(function(reason) {
    return [
      'order_payment_method_ach',
      'ach_payment_method_summary',
      'checkout_session_us_bank_account',
      'payment_intent_us_bank_account',
      'charge_us_bank_account',
      'payment_method_us_bank_account'
    ].indexOf(reason) >= 0;
  });
  const isAchSetup = reasons.some(function(reason) {
    return [
      'ach_setup_summary',
      'ach_payment_method_summary',
      'checkout_session_us_bank_account',
      'payment_method_us_bank_account',
      'setup_intent_payment_method_us_bank_account',
      'dashboard_bank_setup_metadata'
    ].indexOf(reason) >= 0;
  });
  return {
    ok: true,
    eventType: trimString_(opts.eventType),
    isAchPayment: isAchPayment,
    isAchSetup: isAchSetup,
    isAch: isAchPayment || isAchSetup,
    forbidAchPaymentWrites: !isAchPayment,
    forbidAchSetupWrites: !isAchSetup,
    forbidAchWrites: !(isAchPayment || isAchSetup),
    achSummary: achSummary || setupSummary || null,
    reasons: reasons
  };
}

function isAchPaymentIntentForOrder_(paymentIntentObj, orderInfo, achSummary) {
  return buildAchStripeEventEvidence_({
    eventType: 'payment_intent',
    orderInfo: orderInfo,
    paymentIntent: paymentIntentObj,
    achSummary: achSummary
  }).isAchPayment;
}

function isAchCheckoutSessionForOrder_(sessionObj, orderInfo, achSummary) {
  return buildAchStripeEventEvidence_({
    eventType: 'checkout.session',
    orderInfo: orderInfo,
    session: sessionObj,
    achSummary: achSummary
  }).isAchPayment;
}

function isAchChargeForOrder_(chargeObj, orderInfo) {
  return buildAchStripeEventEvidence_({
    eventType: 'charge',
    orderInfo: orderInfo,
    charge: chargeObj
  }).isAchPayment;
}

function buildAchOrderPaymentSource_(orderInfoOrCtx, stripeObj) {
  const source = (orderInfoOrCtx && typeof orderInfoOrCtx === 'object') ? orderInfoOrCtx : {};
  const row = source.rowObjNormalized || {};
  const payload = source.payload && typeof source.payload === 'object' ? source.payload : {};
  const draft = source.orderDraft && typeof source.orderDraft === 'object'
    ? source.orderDraft
    : safeJsonParse_(row.orderdraftjson || row.orderDraftJson, {}) || {};
  const value = trimString_(
    extractStripeMetadataValue_(stripeObj || {}, 'paymentOrigin') ||
    extractStripeMetadataValue_(stripeObj || {}, 'checkoutOrigin') ||
    row.achpaymentsource ||
    row.achPaymentSource ||
    draft.paymentOrigin ||
    draft.checkoutOrigin ||
    payload.paymentOrigin ||
    payload.checkoutOrigin
  );
  const normalized = normalizeAchPaymentSource_(value);
  return normalized === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link
    ? ACH_PAYMENT_METHOD_SOURCES.ap_payment_link
    : ACH_PAYMENT_METHOD_SOURCES.order_checkout;
}

function buildAchOrderOnlyPaymentUpdates_(orderInfoOrCtx, stripeObj) {
  const source = (orderInfoOrCtx && typeof orderInfoOrCtx === 'object') ? orderInfoOrCtx : {};
  const row = source.rowObjNormalized || {};
  const customerId = stripeIdFromObject_(
    (stripeObj && typeof stripeObj === 'object' ? stripeObj.customer : '') ||
    source.stripeCustomerId ||
    row.stripeachcustomerid ||
    row.stripeAchCustomerId
  );
  return {
    achPaymentSource: buildAchOrderPaymentSource_(orderInfoOrCtx, stripeObj),
    achPaymentVisibilityScope: ACH_PAYMENT_VISIBILITY_SCOPES.order_only,
    stripeAchCustomerId: customerId
  };
}

function resolveAchPaymentMethodSummaryFromCheckoutSession_(sessionObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const session = (sessionObj && typeof sessionObj === 'object') ? sessionObj : {};
  let pi = session.payment_intent && typeof session.payment_intent === 'object' ? session.payment_intent : null;
  const paymentIntentId = stripeIdFromObject_(session.payment_intent);
  if (!pi && paymentIntentId) {
    const piResult = retrieveStripePaymentIntent_(paymentIntentId, opts);
    if (piResult.ok) pi = piResult.body;
  }
  return pi ? resolveAchPaymentMethodSummaryFromPaymentIntent_(pi, opts) : null;
}

function isDashboardAchSetupIntent_(setupIntentObj) {
  return hasDashboardAchSetupMetadata_(setupIntentObj);
}

function resolveAchPaymentMethodSummaryFromSetupIntent_(setupIntentObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const setupIntent = (setupIntentObj && typeof setupIntentObj === 'object') ? setupIntentObj : {};
  let paymentMethod = setupIntent.payment_method && typeof setupIntent.payment_method === 'object'
    ? setupIntent.payment_method
    : null;
  const paymentMethodId = stripeIdFromObject_(setupIntent.payment_method);
  if (!paymentMethod && paymentMethodId) {
    const methodResult = retrieveStripePaymentMethod_(paymentMethodId, opts);
    if (methodResult.ok) paymentMethod = methodResult.body;
  }
  const verificationStatus = deriveAchVerificationStatusFromStripeIntent_(setupIntent, opts.verificationStatus);
  return paymentMethod ? extractAchPaymentMethodSummaryFromStripe_(paymentMethod, {
    source: 'dashboard_setup',
    stripeCustomerId: trimString_(opts.stripeCustomerId) || stripeIdFromObject_(setupIntent.customer),
    verificationStatus: verificationStatus,
    status: mapAchPaymentMethodStatusFromVerification_(verificationStatus, 'active'),
    setupIntentId: trimString_(opts.setupIntentId) || trimString_(setupIntent.id),
    setupSessionId: trimString_(opts.setupSessionId),
    setupStatus: trimString_(setupIntent.status)
  }) : null;
}

function updateExportPointersForWebhookOrder_(cfg, ss, infra, orderInfo, orderSummary) {
  const token = trimString_(orderInfo && orderInfo.rowObjNormalized && orderInfo.rowObjNormalized.token);
  if (!token) return null;
  const rowInfo = findRowByToken_(infra.exportSheet, token);
  if (!rowInfo) return null;
  const accountInfo = getPortalAccountInfoForOrder_(orderInfo, { cfg: cfg, ss: ss, infra: infra });
  return writeCurrentOrderPointersToExportLog_({
    cfg: cfg,
    ss: ss,
    infra: infra,
    rowInfo: rowInfo,
    orderSummary: orderSummary,
    accountSummary: accountInfo && accountInfo.summary ? accountInfo.summary : getAccountStatus({ token: token }).accountSummary
  });
}

function buildAchPendingProductionPolicyUpdates_(accountSummary, orderInfo, now) {
  /* Legacy account/order ACH pending-production approval fields are now inert.
     ACH pending must remain payment-confirmation pending until Stripe reports a
     paid/success signal, or Team Mode explicitly initiates production. */
  return {
    orderState: ORDER_STATES.awaiting_payment_confirmation,
    productionAuthorizationState: PRODUCTION_AUTHORIZATION_STATES.not_authorized,
    authorizedToProduceAt: '',
    achPendingProductionApprovedAtOrder: ''
  };
}

function getTerminalAchPendingMutationReason_(orderInfo) {
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const paymentMethodSelected = trimString_(row.paymentmethodselected).toLowerCase();
  if (paymentMethodSelected && paymentMethodSelected !== PAYMENT_METHODS.ach) return '';
  const paymentState = trimString_(row.paymentstate).toLowerCase();
  const orderState = trimString_(row.orderstate).toLowerCase();
  const failureCode = trimString_(row.achfailurecode).toLowerCase();
  const latestEventType = trimString_(row.stripelatesteventtype).toLowerCase();
  const draft = safeJsonParse_(row.orderdraftjson, {}) || {};
  const teamMeta = readTeamWorkflowMetaFromDraft_(draft);
  if (trimString_(row.paidat) || paymentState === PAYMENT_STATES.paid) return 'paid';
  if (paymentState === PAYMENT_STATES.failed) return 'failed';
  if (latestEventType === 'charge.dispute.created' || failureCode.indexOf('dispute') >= 0) return 'disputed';
  if (teamMeta.workflowMode === TEAM_WORKFLOW_MODES.team_hold) return 'team_hold';
  if (orderState === ORDER_STATES.in_production || orderState === ORDER_STATES.closed) return orderState;
  return '';
}

function shouldMarkAchPaymentMethodUnusableForFailure_(failure, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  if (opts.force === true) return true;
  const source = (failure && typeof failure === 'object') ? failure : {};
  const signal = [
    source.code,
    source.message,
    opts.reason,
    opts.verificationStatus
  ].join(' ').toLowerCase();
  if (!signal) return false;
  return /(microdeposit.*(failed|timeout|exceeded)|verification.*(failed|timeout|exceeded)|mandate|authorization|debit.*not.*authorized|account.*closed|no_account|invalid.*account|bank.*account.*unusable|payment_method.*unusable|dispute|late.*return)/i.test(signal);
}

function markOrderAchPaymentMethodUnusableIfNeeded_(accountInfo, orderInfo, achSummary, failure, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = normalizeAchPaymentMethodSummary_(achSummary);
  const paymentMethodId = trimString_(
    (summary && summary.paymentMethodId) ||
    row.achpaymentmethodid ||
    row.achPaymentMethodId
  );
  if (!paymentMethodId || !accountInfo || !accountInfo.rowInfo) return accountInfo;
  const verificationStatus = trimString_(
    (summary && summary.verificationStatus) ||
    row.achverificationstatus ||
    row.achVerificationStatus
  );
  if (!shouldMarkAchPaymentMethodUnusableForFailure_(failure, Object.assign({}, opts, {
    verificationStatus: verificationStatus
  }))) {
    return accountInfo;
  }
  return markAchPaymentMethodUnusable_(accountInfo, paymentMethodId, opts.markReason || 'blocked', opts);
}

function buildAchSuccessProductionStateUpdates_(orderInfo) {
  const orderRow = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const currentOrderState = trimString_(orderRow.orderstate);
  const earlierStates = {};
  [
    '',
    ORDER_STATES.draft,
    ORDER_STATES.payment_in_progress,
    ORDER_STATES.awaiting_manual_payment,
    ORDER_STATES.awaiting_po_submission,
    ORDER_STATES.awaiting_payment_confirmation,
    PORTAL_LIFECYCLE_STATES.checkout_started_unpaid,
    PORTAL_LIFECYCLE_STAGES.checkout_started
  ].forEach(function(state) {
    earlierStates[trimString_(state)] = true;
  });
  const currentProductionAuthorizationState = trimString_(orderRow.productionauthorizationstate).toLowerCase();
  const nextProductionAuthorizationState = currentProductionAuthorizationState &&
    currentProductionAuthorizationState !== PRODUCTION_AUTHORIZATION_STATES.not_authorized
    ? currentProductionAuthorizationState
    : PRODUCTION_AUTHORIZATION_STATES.authorized;
  return {
    orderState: Object.prototype.hasOwnProperty.call(earlierStates, currentOrderState)
      ? ORDER_STATES.ready_for_production
      : currentOrderState,
    productionAuthorizationState: nextProductionAuthorizationState
  };
}

function hasPortalOrderRecordedPaidState_(orderInfo) {
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  return !!trimString_(row.paidat) || trimString_(row.paymentstate).toLowerCase() === PAYMENT_STATES.paid;
}

function handleCheckoutSessionCompleted_(sessionObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  if (trimString_(sessionObj && sessionObj.mode).toLowerCase() === 'setup' ||
      extractStripeMetadataValue_(sessionObj, 'source') === 'dashboard_bank_setup') {
    return handleCheckoutSetupSessionCompleted_(sessionObj, opts);
  }
  const token = extractStripeMetadataValue_(sessionObj, 'token');
  const checkoutAttemptId = extractStripeMetadataValue_(sessionObj, 'checkoutAttemptId');
  const paymentMethodSelected = extractStripeMetadataValue_(sessionObj, 'paymentMethodSelected') || PAYMENT_METHODS.card;
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const orderInfo = getPortalOrderByCheckoutAttemptId_(checkoutAttemptId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) ||
    getPortalOrderByStripeSessionId_(trimString_(sessionObj && sessionObj.id), { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet });
  if (!orderInfo) return { ok: false, error: 'Order not found for checkout session.' };
  const currentGuard = validateCurrentStripeCheckoutWebhookOrder_(sessionObj, orderInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    eventType: 'checkout.session.completed'
  });
  if (currentGuard.current === false) return currentGuard;
  const now = nowIso_();
  const achSummary = resolveAchPaymentMethodSummaryFromCheckoutSession_(sessionObj, { cfg: cfg, source: 'checkout_payment' });
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: 'checkout.session.completed',
    orderInfo: orderInfo,
    session: sessionObj,
    achSummary: achSummary
  });
  const isAch = achEvidence.isAchPayment === true;
  if (isAch) {
    const terminalReason = getTerminalAchPendingMutationReason_(orderInfo);
    if (terminalReason) {
      return {
        ok: true,
        ignored: true,
        type: 'checkout.session.completed',
        reason: 'terminal_ach_order_preserved',
        terminalReason: terminalReason
      };
    }
  }
  const effectivePaymentMethodSelected = isAch
    ? PAYMENT_METHODS.ach
    : (paymentMethodSelected === PAYMENT_METHODS.ach ? PAYMENT_METHODS.card : paymentMethodSelected);
  const delayed = isAch || trimString_(sessionObj && sessionObj.payment_status).toLowerCase() !== 'paid';
  const currentDraft = safeJsonParse_(orderInfo.rowObjNormalized.orderdraftjson, {}) || {};
  const nextDraft = applyStripeCheckoutChargeSummaryToOrderDraft_(
    mergeOrderDraftShippingDetails_(currentDraft, sessionObj),
    buildStripeCheckoutActualAmountSummary_(sessionObj, currentDraft)
  );
  let accountInfo = getPortalAccountInfoForOrder_(orderInfo, { cfg: cfg, ss: ss, infra: infra });
  if (isAch && achSummary && accountInfo) {
    accountInfo = upsertAchPaymentMethodOnPortalAccount_(accountInfo, achSummary, {
      cfg: cfg,
      ss: ss,
      infra: infra
    });
  }
  const achPolicy = isAch
    ? buildAchPendingProductionPolicyUpdates_(accountInfo && accountInfo.summary ? accountInfo.summary : {}, orderInfo, now)
    : {};
  const eventUpdates = buildStripeLatestEventOrderUpdates_(opts.eventPayload, sessionObj);
  const sessionUpdates = {
    cfg: cfg,
    ss: ss,
    infra: infra,
    orderRowInfo: orderInfo,
    orderDraft: nextDraft,
    stripeSessionId: trimString_(sessionObj && sessionObj.id),
    stripePaymentIntentId: stripeIdFromObject_(sessionObj && sessionObj.payment_intent),
    amountCardFee: nextDraft.amountCardFee,
    amountChargedTax: nextDraft.amountChargedTax,
    amountChargedTotal: nextDraft.amountChargedTotal,
    stripeAmountSubtotalCents: nextDraft.stripeAmountSubtotalCents,
    stripeAmountTotalCents: nextDraft.stripeAmountTotalCents,
    portalLockState: PORTAL_LOCK_STATES.locked,
    paymentMethodSelected: effectivePaymentMethodSelected,
    paymentState: delayed ? PAYMENT_STATES.pending : PAYMENT_STATES.paid,
    orderState: isAch ? achPolicy.orderState : (delayed ? ORDER_STATES.awaiting_payment_confirmation : ORDER_STATES.ready_for_production),
    productionAuthorizationState: isAch ? achPolicy.productionAuthorizationState : (delayed ? PRODUCTION_AUTHORIZATION_STATES.not_authorized : PRODUCTION_AUTHORIZATION_STATES.authorized),
    lockedAt: trimString_(orderInfo.rowObjNormalized.lockedat) || now,
    paidAt: delayed ? '' : now,
    authorizedToProduceAt: isAch ? achPolicy.authorizedToProduceAt : (delayed ? '' : now)
  };
  if (isAch) {
    Object.assign(sessionUpdates, {
      achPaymentMethodId: achSummary ? achSummary.paymentMethodId : trimString_(orderInfo.rowObjNormalized.achpaymentmethodid),
      achBankName: achSummary ? achSummary.bankName : trimString_(orderInfo.rowObjNormalized.achbankname),
      achLast4: achSummary ? achSummary.last4 : trimString_(orderInfo.rowObjNormalized.achlast4),
      achMandateId: achSummary ? achSummary.mandateId : trimString_(orderInfo.rowObjNormalized.achmandateid),
      achFinancialConnectionsAccountId: achSummary ? achSummary.financialConnectionsAccountId : trimString_(orderInfo.rowObjNormalized.achfinancialconnectionsaccountid),
      achVerificationStatus: achSummary && achSummary.verificationStatus ? achSummary.verificationStatus : 'pending',
      achVerificationFlow: 'stripe_hosted_checkout',
      achPaymentSource: buildAchOrderPaymentSource_(orderInfo, sessionObj),
      achPaymentVisibilityScope: ACH_PAYMENT_VISIBILITY_SCOPES.order_only,
      stripeAchCustomerId: stripeIdFromObject_(sessionObj && sessionObj.customer),
      achFailureCode: '',
      achFailureMessage: '',
      achPendingProductionApprovedAtOrder: achPolicy.achPendingProductionApprovedAtOrder
    });
  }
  const updatedOrder = updatePortalOrderState_(Object.assign(sessionUpdates, eventUpdates));
  const orderSummary = buildPortalOrderSummary_(updatedOrder.rowObjNormalized);
  const rowInfo = findRowByToken_(infra.exportSheet, token || trimString_(orderInfo.rowObjNormalized.token));
  if (rowInfo) {
    const accountSummary = accountInfo && accountInfo.summary ? accountInfo.summary : getAccountStatus({ token: trimString_(rowInfo.rowObjNormalized.token) }).accountSummary;
    writeCurrentOrderPointersToExportLog_({
      cfg: cfg,
      ss: ss,
      infra: infra,
      rowInfo: rowInfo,
      orderSummary: orderSummary,
      accountSummary: accountSummary
    });
    setPortalClientLockForRow_(infra.exportSheet, rowInfo, true, {
      token: trimString_(rowInfo.rowObjNormalized.token)
    });
    if (!delayed) {
      finalizePortalAfterPayment({
        token: trimString_(rowInfo.rowObjNormalized.token),
        portalState: safeJsonParse_(rowInfo.rowObjNormalized.portalstatejson, {}) || { printJobs: {} },
        submittedAt: now,
        systemMessage: 'Order placed successfully on ' + now + '.'
      });
    }
  }
  if (isAch && delayed) {
    queueOrderAchLifecycleEmailsSafely_(
      updatedOrder,
      sessionObj,
      PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_invoice_email,
      AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_submitted,
      {
        cfg: cfg,
        ss: ss,
        infra: infra,
        accountInfo: accountInfo,
        eventType: 'checkout.session.completed'
      }
    );
  } else if (!isAch && !delayed && effectivePaymentMethodSelected === PAYMENT_METHODS.card) {
    queuePaymentLifecycleClientAndTeamEmailsSafely_(
      updatedOrder,
      sessionObj,
      PAYMENT_LIFECYCLE_EMAIL_MILESTONES.card_paid,
      {
        cfg: cfg,
        ss: ss,
        infra: infra,
        accountInfo: accountInfo,
        eventType: 'checkout.session.completed'
      }
    );
  }
  return { ok: true, delayed: delayed, orderSummary: orderSummary };
}

function handleCheckoutSetupSessionCompleted_(sessionObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  let session = (sessionObj && typeof sessionObj === 'object') ? sessionObj : {};
  if (!session.setup_intent || typeof session.setup_intent !== 'object') {
    const sessionResult = retrieveStripeCheckoutSession_(trimString_(session.id), { cfg: cfg });
    if (sessionResult.ok && sessionResult.body) session = sessionResult.body;
  }
  let setupIntent = session.setup_intent && typeof session.setup_intent === 'object' ? session.setup_intent : null;
  const setupIntentId = stripeIdFromObject_(session.setup_intent);
  if (!setupIntent && setupIntentId) {
    const setupResult = retrieveStripeSetupIntent_(setupIntentId, { cfg: cfg });
    if (setupResult.ok) setupIntent = setupResult.body;
  }
  const setupCustomerId = stripeIdFromObject_(session.customer || (setupIntent && setupIntent.customer));
  const achSummary = setupIntent ? resolveAchPaymentMethodSummaryFromSetupIntent_(setupIntent, {
    cfg: cfg,
    setupIntentId: setupIntentId,
    setupSessionId: trimString_(session.id),
    stripeCustomerId: setupCustomerId
  }) : null;
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: 'checkout.session.completed',
    session: session,
    setupIntent: setupIntent,
    achSummary: achSummary
  });
  if (achEvidence.isAchSetup !== true) {
    return {
      ok: true,
      ignored: true,
      type: 'checkout.session.completed',
      reason: 'non_ach_setup_session'
    };
  }
  const accountId = extractStripeMetadataValue_(session, 'accountId') ||
    extractStripeMetadataValue_(setupIntent || {}, 'accountId') ||
    trimString_(session.client_reference_id);
  const customerId = setupCustomerId;
  let accountInfo = accountId ? getPortalAccountByAccountId_(accountId, { cfg: cfg, ss: ss, infra: infra }) : null;
  if (!accountInfo && customerId) {
    accountInfo = getPortalAccountByStripeCustomerId_(customerId, { cfg: cfg, ss: ss, infra: infra });
  }
  if (!accountInfo || !accountInfo.rowInfo) {
    return { ok: false, error: 'Portal account not found for ACH setup session.' };
  }
  if (customerId) {
    accountInfo = updatePortalAccountStripeCustomerIdIfBlank_(accountInfo, customerId, {
      cfg: cfg,
      ss: ss,
      infra: infra
    });
  }
  if (achSummary) {
    accountInfo = upsertDashboardSavedAchPaymentMethodOnPortalAccount_(accountInfo, Object.assign({}, achSummary, {
      stripeCustomerId: customerId,
      setupIntentId: setupIntentId,
      setupSessionId: trimString_(session.id),
      setupStatus: trimString_(setupIntent && setupIntent.status) || 'completed'
    }), {
      cfg: cfg,
      ss: ss,
      infra: infra
    });
  }
  setRowValuesByHeaderMap_(infra.accountsSheet, accountInfo.rowInfo.row, accountInfo.rowInfo.colMap, {
    achSetupSessionId: trimString_(session.id),
    achSetupIntentId: setupIntentId,
    achSetupStatus: trimString_(setupIntent && setupIntent.status) || 'completed',
    achSetupLastUpdatedAt: nowIso_(),
    updatedAt: nowIso_()
  });
  return {
    ok: true,
    setupStatus: trimString_(setupIntent && setupIntent.status) || 'completed',
    accountSummary: buildPortalAccountSummary_(buildRowInfoFromSheet_(infra.accountsSheet, accountInfo.rowInfo.row).rowObjNormalized, cfg)
  };
}

function handleCheckoutAsyncPaymentSucceeded_(sessionObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const token = extractStripeMetadataValue_(sessionObj, 'token');
  const checkoutAttemptId = extractStripeMetadataValue_(sessionObj, 'checkoutAttemptId');
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const orderInfo = getPortalOrderByCheckoutAttemptId_(checkoutAttemptId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) ||
    getPortalOrderByStripeSessionId_(trimString_(sessionObj && sessionObj.id), { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet });
  if (!orderInfo) return { ok: false, error: 'Order not found for async success.' };
  const currentGuard = validateCurrentStripeCheckoutWebhookOrder_(sessionObj, orderInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    eventType: 'checkout.session.async_payment_succeeded'
  });
  if (currentGuard.current === false) return currentGuard;
  const now = nowIso_();
  const alreadyPaid = hasPortalOrderRecordedPaidState_(orderInfo);
  const currentDraft = safeJsonParse_(orderInfo.rowObjNormalized.orderdraftjson, {}) || {};
  const nextDraft = applyStripeCheckoutChargeSummaryToOrderDraft_(
    mergeOrderDraftShippingDetails_(currentDraft, sessionObj),
    buildStripeCheckoutActualAmountSummary_(sessionObj, currentDraft)
  );
  const achSummary = resolveAchPaymentMethodSummaryFromCheckoutSession_(sessionObj, { cfg: cfg, source: 'checkout_payment' });
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: 'checkout.session.async_payment_succeeded',
    orderInfo: orderInfo,
    session: sessionObj,
    achSummary: achSummary
  });
  if (achEvidence.isAchPayment !== true) {
    return {
      ok: true,
      ignored: true,
      type: 'checkout.session.async_payment_succeeded',
      reason: 'non_ach_async_payment_succeeded'
    };
  }
  let accountInfo = getPortalAccountInfoForOrder_(orderInfo, { cfg: cfg, ss: ss, infra: infra });
  if (achSummary && accountInfo) {
    accountInfo = upsertAchPaymentMethodOnPortalAccount_(accountInfo, achSummary, {
      cfg: cfg,
      ss: ss,
      infra: infra
    });
  }
  const successProductionState = buildAchSuccessProductionStateUpdates_(orderInfo);
  const eventUpdates = buildStripeLatestEventOrderUpdates_(opts.eventPayload, sessionObj);
  const updatedOrder = updatePortalOrderState_(Object.assign({
    cfg: cfg,
    ss: ss,
    infra: infra,
    orderRowInfo: orderInfo,
    orderDraft: nextDraft,
    stripeSessionId: trimString_(sessionObj && sessionObj.id),
    stripePaymentIntentId: stripeIdFromObject_(sessionObj && sessionObj.payment_intent),
    amountCardFee: nextDraft.amountCardFee,
    amountChargedTax: nextDraft.amountChargedTax,
    amountChargedTotal: nextDraft.amountChargedTotal,
    stripeAmountSubtotalCents: nextDraft.stripeAmountSubtotalCents,
    stripeAmountTotalCents: nextDraft.stripeAmountTotalCents,
    portalLockState: PORTAL_LOCK_STATES.locked,
    paymentState: PAYMENT_STATES.paid,
    orderState: successProductionState.orderState,
    productionAuthorizationState: successProductionState.productionAuthorizationState,
    lockedAt: trimString_(orderInfo.rowObjNormalized.lockedat) || now,
    paidAt: trimString_(orderInfo.rowObjNormalized.paidat) || now,
    authorizedToProduceAt: trimString_(orderInfo.rowObjNormalized.authorizedtoproduceat) || now,
    achPaymentMethodId: achSummary ? achSummary.paymentMethodId : trimString_(orderInfo.rowObjNormalized.achpaymentmethodid),
    achBankName: achSummary ? achSummary.bankName : trimString_(orderInfo.rowObjNormalized.achbankname),
    achLast4: achSummary ? achSummary.last4 : trimString_(orderInfo.rowObjNormalized.achlast4),
    achMandateId: achSummary ? achSummary.mandateId : trimString_(orderInfo.rowObjNormalized.achmandateid),
    achFinancialConnectionsAccountId: achSummary ? achSummary.financialConnectionsAccountId : trimString_(orderInfo.rowObjNormalized.achfinancialconnectionsaccountid),
    achVerificationStatus: achSummary ? (achSummary.verificationStatus || 'succeeded') : trimString_(orderInfo.rowObjNormalized.achverificationstatus),
    achPaymentSource: buildAchOrderPaymentSource_(orderInfo, sessionObj),
    achPaymentVisibilityScope: ACH_PAYMENT_VISIBILITY_SCOPES.order_only,
    stripeAchCustomerId: stripeIdFromObject_(sessionObj && sessionObj.customer),
    achFailureCode: '',
    achFailureMessage: ''
  }, eventUpdates));
  const rowInfo = findRowByToken_(infra.exportSheet, token || trimString_(orderInfo.rowObjNormalized.token));
  if (rowInfo) {
    writeCurrentOrderPointersToExportLog_({
      cfg: cfg,
      ss: ss,
      infra: infra,
      rowInfo: rowInfo,
      orderSummary: buildPortalOrderSummary_(updatedOrder.rowObjNormalized),
      accountSummary: accountInfo && accountInfo.summary ? accountInfo.summary : getAccountStatus({ token: trimString_(rowInfo.rowObjNormalized.token) }).accountSummary
    });
    if (!alreadyPaid) {
      finalizePortalAfterPayment({
        token: trimString_(rowInfo.rowObjNormalized.token),
        portalState: safeJsonParse_(rowInfo.rowObjNormalized.portalstatejson, {}) || { printJobs: {} },
        submittedAt: now,
        systemMessage: 'ACH payment cleared on ' + now + '. Order authorized for production.'
      });
    }
  }
  queueOrderAchLifecycleEmailsSafely_(
    updatedOrder,
    sessionObj,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_receipt_email,
    AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_confirmed,
    {
      cfg: cfg,
      ss: ss,
      infra: infra,
      accountInfo: accountInfo,
      eventType: 'checkout.session.async_payment_succeeded'
    }
  );
  return { ok: true };
}

function handleCheckoutAsyncPaymentFailed_(sessionObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const checkoutAttemptId = extractStripeMetadataValue_(sessionObj, 'checkoutAttemptId');
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const orderInfo = getPortalOrderByCheckoutAttemptId_(checkoutAttemptId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) ||
    getPortalOrderByStripeSessionId_(trimString_(sessionObj && sessionObj.id), { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet });
  if (!orderInfo) return { ok: false, error: 'Order not found for async failure.' };
  const currentGuard = validateCurrentStripeCheckoutWebhookOrder_(sessionObj, orderInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    eventType: 'checkout.session.async_payment_failed'
  });
  if (currentGuard.current === false) return currentGuard;
  const achSummary = resolveAchPaymentMethodSummaryFromCheckoutSession_(sessionObj, { cfg: cfg, source: 'checkout_payment' });
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: 'checkout.session.async_payment_failed',
    orderInfo: orderInfo,
    session: sessionObj,
    achSummary: achSummary
  });
  if (achEvidence.isAchPayment !== true) {
    return {
      ok: true,
      ignored: true,
      type: 'checkout.session.async_payment_failed',
      reason: 'non_ach_async_payment_failed'
    };
  }
  const existingOrderState = trimString_(orderInfo.rowObjNormalized.orderstate).toLowerCase();
  const existingAuthorized = existingOrderState === ORDER_STATES.in_production ||
    existingOrderState === ORDER_STATES.closed;
  const failure = extractFailureFromStripeObject_(sessionObj);
  let accountInfo = getPortalAccountInfoForOrder_(orderInfo, { cfg: cfg, ss: ss, infra: infra });
  accountInfo = markOrderAchPaymentMethodUnusableIfNeeded_(accountInfo, orderInfo, achSummary, failure, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    reason: 'checkout.session.async_payment_failed'
  });
  const currentDraft = safeJsonParse_(orderInfo.rowObjNormalized.orderdraftjson, {}) || {};
  const nextDraft = existingAuthorized ? writeTeamWorkflowMetaIntoDraft_(currentDraft, {
    workflowMode: TEAM_WORKFLOW_MODES.team_hold
  }) : currentDraft;
  const eventUpdates = buildStripeLatestEventOrderUpdates_(opts.eventPayload, sessionObj);
  const updatedOrder = updatePortalOrderState_(Object.assign({
    cfg: cfg,
    ss: ss,
    infra: infra,
    orderRowInfo: orderInfo,
    orderDraft: nextDraft,
    paymentState: PAYMENT_STATES.failed,
    orderState: existingAuthorized ? trimString_(orderInfo.rowObjNormalized.orderstate) || ORDER_STATES.ready_for_production : ORDER_STATES.awaiting_payment_confirmation,
    productionAuthorizationState: existingAuthorized ? PRODUCTION_AUTHORIZATION_STATES.authorized : PRODUCTION_AUTHORIZATION_STATES.not_authorized,
    achPaymentSource: buildAchOrderPaymentSource_(orderInfo, sessionObj),
    achPaymentVisibilityScope: ACH_PAYMENT_VISIBILITY_SCOPES.order_only,
    stripeAchCustomerId: stripeIdFromObject_(sessionObj && sessionObj.customer),
    achFailureCode: failure.code,
    achFailureMessage: failure.message || 'Stripe async payment failed.',
    notes: existingAuthorized
      ? 'Stripe async payment failed after ACH-pending production approval. Team review required.'
      : 'Stripe async payment failed.'
  }, eventUpdates));
  const token = trimString_(orderInfo.rowObjNormalized.token);
  const rowInfo = findRowByToken_(infra.exportSheet, token);
  if (rowInfo) {
    writeCurrentOrderPointersToExportLog_({
      cfg: cfg,
      ss: ss,
      infra: infra,
      rowInfo: rowInfo,
      orderSummary: buildPortalOrderSummary_(updatedOrder.rowObjNormalized),
      accountSummary: getAccountStatus({ token: token }).accountSummary
    });
  }
  queueOrderAchLifecycleEmailsSafely_(
    updatedOrder,
    sessionObj,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_action_email,
    AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_failed,
    {
      cfg: cfg,
      ss: ss,
      infra: infra,
      accountInfo: accountInfo,
      eventType: 'checkout.session.async_payment_failed'
    }
  );
  return { ok: true };
}

function handlePaymentIntentFailed_(paymentIntentObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const paymentIntentId = trimString_(paymentIntentObj && paymentIntentObj.id);
  if (!paymentIntentId) return { ok: false, error: 'Missing payment intent id.' };
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const orderInfo = getPortalOrderByStripePaymentIntentId_(paymentIntentId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) ||
    getPortalOrderByOrderId_(extractStripeMetadataValue_(paymentIntentObj, 'orderId'), { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet });
  if (!orderInfo) return { ok: false, error: 'Order not found for payment intent.' };
  const currentGuard = validateCurrentStripeCheckoutWebhookOrder_(paymentIntentObj, orderInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    eventType: 'payment_intent.payment_failed'
  });
  if (currentGuard.current === false) return currentGuard;
  const achSummary = resolveAchPaymentMethodSummaryFromPaymentIntent_(paymentIntentObj, { cfg: cfg, source: 'checkout_payment' });
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: 'payment_intent.payment_failed',
    orderInfo: orderInfo,
    paymentIntent: paymentIntentObj,
    achSummary: achSummary
  });
  const isAch = achEvidence.isAchPayment === true;
  const existingOrderState = trimString_(orderInfo.rowObjNormalized.orderstate).toLowerCase();
  const existingAuthorized = existingOrderState === ORDER_STATES.in_production ||
    existingOrderState === ORDER_STATES.closed;
  const failure = extractFailureFromStripeObject_(paymentIntentObj);
  if (isAch) {
    const accountInfo = getPortalAccountInfoForOrder_(orderInfo, { cfg: cfg, ss: ss, infra: infra });
    markOrderAchPaymentMethodUnusableIfNeeded_(accountInfo, orderInfo, achSummary, failure, {
      cfg: cfg,
      ss: ss,
      infra: infra,
      reason: 'payment_intent.payment_failed'
    });
  }
  const currentDraft = safeJsonParse_(orderInfo.rowObjNormalized.orderdraftjson, {}) || {};
  const shouldTeamHold = isAch && existingAuthorized;
  const nextDraft = shouldTeamHold ? writeTeamWorkflowMetaIntoDraft_(currentDraft, {
    workflowMode: TEAM_WORKFLOW_MODES.team_hold
  }) : currentDraft;
  const eventUpdates = buildStripeLatestEventOrderUpdates_(opts.eventPayload, paymentIntentObj);
  const failureUpdates = {
    cfg: cfg,
    ss: ss,
    infra: infra,
    orderRowInfo: orderInfo,
    orderDraft: nextDraft,
    paymentState: PAYMENT_STATES.failed,
    orderState: existingAuthorized ? trimString_(orderInfo.rowObjNormalized.orderstate) || ORDER_STATES.ready_for_production : ORDER_STATES.awaiting_payment_confirmation,
    productionAuthorizationState: existingAuthorized ? PRODUCTION_AUTHORIZATION_STATES.authorized : PRODUCTION_AUTHORIZATION_STATES.not_authorized,
    notes: shouldTeamHold
      ? 'Stripe payment intent failed after ACH-pending production approval. Team review required.'
      : 'Stripe payment intent failed.'
  };
  if (isAch) {
    failureUpdates.achFailureCode = failure.code;
    failureUpdates.achFailureMessage = failure.message || 'Stripe payment intent failed.';
    Object.assign(failureUpdates, buildAchOrderOnlyPaymentUpdates_(orderInfo, paymentIntentObj));
  }
  const updatedOrder = updatePortalOrderState_(Object.assign(failureUpdates, eventUpdates));
  const token = trimString_(orderInfo.rowObjNormalized.token);
  const rowInfo = findRowByToken_(infra.exportSheet, token);
  if (rowInfo) {
    writeCurrentOrderPointersToExportLog_({
      cfg: cfg,
      ss: ss,
      infra: infra,
      rowInfo: rowInfo,
      orderSummary: buildPortalOrderSummary_(updatedOrder.rowObjNormalized),
      accountSummary: getAccountStatus({ token: token }).accountSummary
    });
  }
  if (isAch) {
    queueOrderAchLifecycleEmailsSafely_(
      updatedOrder,
      paymentIntentObj,
      PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_action_email,
      AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_failed,
      {
        cfg: cfg,
        ss: ss,
        infra: infra,
        eventType: 'payment_intent.payment_failed'
      }
    );
  } else {
    const updatedSummary = buildPortalOrderSummary_(updatedOrder.rowObjNormalized);
    if (trimString_(updatedSummary.paymentMethodSelected).toLowerCase() === PAYMENT_METHODS.card) {
      queuePaymentLifecycleClientAndTeamEmailsSafely_(
        updatedOrder,
        paymentIntentObj,
        PAYMENT_LIFECYCLE_EMAIL_MILESTONES.card_failed,
        {
          cfg: cfg,
          ss: ss,
          infra: infra,
          eventType: 'payment_intent.payment_failed'
        }
      );
    }
  }
  return { ok: true };
}

function handlePaymentIntentProcessing_(paymentIntentObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const paymentIntentId = trimString_(paymentIntentObj && paymentIntentObj.id);
  if (!paymentIntentId) return { ok: false, error: 'Missing payment intent id.' };
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const orderInfo = getPortalOrderByStripePaymentIntentId_(paymentIntentId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) ||
    getPortalOrderByOrderId_(extractStripeMetadataValue_(paymentIntentObj, 'orderId'), { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet });
  if (!orderInfo) return { ok: false, error: 'Order not found for payment intent processing.' };
  const currentGuard = validateCurrentStripeCheckoutWebhookOrder_(paymentIntentObj, orderInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    eventType: 'payment_intent.processing'
  });
  if (currentGuard.current === false) return currentGuard;
  const achSummary = resolveAchPaymentMethodSummaryFromPaymentIntent_(paymentIntentObj, { cfg: cfg, source: 'checkout_payment' });
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: 'payment_intent.processing',
    orderInfo: orderInfo,
    paymentIntent: paymentIntentObj,
    achSummary: achSummary
  });
  const isAch = achEvidence.isAchPayment === true;
  if (!isAch) {
    return {
      ok: true,
      ignored: true,
      type: 'payment_intent.processing',
      reason: 'non_ach_payment_intent'
    };
  }
  const terminalReason = getTerminalAchPendingMutationReason_(orderInfo);
  if (terminalReason) {
    return {
      ok: true,
      ignored: true,
      type: 'payment_intent.processing',
      reason: 'terminal_ach_order_preserved',
      terminalReason: terminalReason
    };
  }
  let accountInfo = getPortalAccountInfoForOrder_(orderInfo, { cfg: cfg, ss: ss, infra: infra });
  if (achSummary && accountInfo) {
    accountInfo = upsertAchPaymentMethodOnPortalAccount_(accountInfo, achSummary, { cfg: cfg, ss: ss, infra: infra });
  }
  const policy = buildAchPendingProductionPolicyUpdates_(accountInfo && accountInfo.summary ? accountInfo.summary : {}, orderInfo, nowIso_());
  const eventUpdates = buildStripeLatestEventOrderUpdates_(opts.eventPayload, paymentIntentObj);
  const updatedOrder = updatePortalOrderState_(Object.assign({
    cfg: cfg,
    ss: ss,
    infra: infra,
    orderRowInfo: orderInfo,
    stripePaymentIntentId: paymentIntentId,
    paymentMethodSelected: PAYMENT_METHODS.ach,
    paymentState: PAYMENT_STATES.pending,
    orderState: policy.orderState,
    productionAuthorizationState: policy.productionAuthorizationState,
    portalLockState: PORTAL_LOCK_STATES.locked,
    lockedAt: trimString_(orderInfo.rowObjNormalized.lockedat) || nowIso_(),
    authorizedToProduceAt: policy.authorizedToProduceAt,
    achPaymentMethodId: achSummary ? achSummary.paymentMethodId : trimString_(orderInfo.rowObjNormalized.achpaymentmethodid),
    achBankName: achSummary ? achSummary.bankName : trimString_(orderInfo.rowObjNormalized.achbankname),
    achLast4: achSummary ? achSummary.last4 : trimString_(orderInfo.rowObjNormalized.achlast4),
    achMandateId: achSummary ? achSummary.mandateId : trimString_(orderInfo.rowObjNormalized.achmandateid),
    achFinancialConnectionsAccountId: achSummary ? achSummary.financialConnectionsAccountId : trimString_(orderInfo.rowObjNormalized.achfinancialconnectionsaccountid),
    achVerificationStatus: achSummary && achSummary.verificationStatus ? achSummary.verificationStatus : 'processing',
    achVerificationFlow: 'stripe_hosted_checkout',
    achPaymentSource: buildAchOrderPaymentSource_(orderInfo, paymentIntentObj),
    achPaymentVisibilityScope: ACH_PAYMENT_VISIBILITY_SCOPES.order_only,
    stripeAchCustomerId: stripeIdFromObject_(paymentIntentObj && paymentIntentObj.customer),
    achPendingProductionApprovedAtOrder: policy.achPendingProductionApprovedAtOrder
  }, eventUpdates));
  updateExportPointersForWebhookOrder_(cfg, ss, infra, orderInfo, buildPortalOrderSummary_(updatedOrder.rowObjNormalized));
  queueOrderAchLifecycleEmailsSafely_(
    updatedOrder,
    paymentIntentObj,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_invoice_email,
    AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_submitted,
    {
      cfg: cfg,
      ss: ss,
      infra: infra,
      accountInfo: accountInfo,
      eventType: 'payment_intent.processing'
    }
  );
  return { ok: true };
}

function handlePaymentIntentSucceeded_(paymentIntentObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const paymentIntentId = trimString_(paymentIntentObj && paymentIntentObj.id);
  if (!paymentIntentId) return { ok: false, error: 'Missing payment intent id.' };
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const orderInfo = getPortalOrderByStripePaymentIntentId_(paymentIntentId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) ||
    getPortalOrderByOrderId_(extractStripeMetadataValue_(paymentIntentObj, 'orderId'), { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet });
  if (!orderInfo) return { ok: false, error: 'Order not found for payment intent success.' };
  const currentGuard = validateCurrentStripeCheckoutWebhookOrder_(paymentIntentObj, orderInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    eventType: 'payment_intent.succeeded'
  });
  if (currentGuard.current === false) return currentGuard;
  const achSummary = resolveAchPaymentMethodSummaryFromPaymentIntent_(paymentIntentObj, { cfg: cfg, source: 'checkout_payment' });
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: 'payment_intent.succeeded',
    orderInfo: orderInfo,
    paymentIntent: paymentIntentObj,
    achSummary: achSummary
  });
  const isAch = achEvidence.isAchPayment === true;
  if (!isAch) {
    return {
      ok: true,
      ignored: true,
      type: 'payment_intent.succeeded',
      reason: 'non_ach_payment_intent'
    };
  }
  let accountInfo = getPortalAccountInfoForOrder_(orderInfo, { cfg: cfg, ss: ss, infra: infra });
  if (achSummary && accountInfo) {
    accountInfo = upsertAchPaymentMethodOnPortalAccount_(accountInfo, achSummary, { cfg: cfg, ss: ss, infra: infra });
  }
  const now = nowIso_();
  const alreadyPaid = hasPortalOrderRecordedPaidState_(orderInfo);
  const successProductionState = buildAchSuccessProductionStateUpdates_(orderInfo);
  const eventUpdates = buildStripeLatestEventOrderUpdates_(opts.eventPayload, paymentIntentObj);
  const updatedOrder = updatePortalOrderState_(Object.assign({
    cfg: cfg,
    ss: ss,
    infra: infra,
    orderRowInfo: orderInfo,
    stripePaymentIntentId: paymentIntentId,
    paymentState: PAYMENT_STATES.paid,
    orderState: successProductionState.orderState,
    productionAuthorizationState: successProductionState.productionAuthorizationState,
    portalLockState: PORTAL_LOCK_STATES.locked,
    lockedAt: trimString_(orderInfo.rowObjNormalized.lockedat) || now,
    paidAt: trimString_(orderInfo.rowObjNormalized.paidat) || now,
    authorizedToProduceAt: trimString_(orderInfo.rowObjNormalized.authorizedtoproduceat) || now,
    achPaymentMethodId: achSummary ? achSummary.paymentMethodId : trimString_(orderInfo.rowObjNormalized.achpaymentmethodid),
    achBankName: achSummary ? achSummary.bankName : trimString_(orderInfo.rowObjNormalized.achbankname),
    achLast4: achSummary ? achSummary.last4 : trimString_(orderInfo.rowObjNormalized.achlast4),
    achMandateId: achSummary ? achSummary.mandateId : trimString_(orderInfo.rowObjNormalized.achmandateid),
    achFinancialConnectionsAccountId: achSummary ? achSummary.financialConnectionsAccountId : trimString_(orderInfo.rowObjNormalized.achfinancialconnectionsaccountid),
    achVerificationStatus: achSummary && achSummary.verificationStatus ? achSummary.verificationStatus : 'succeeded',
    achPaymentSource: buildAchOrderPaymentSource_(orderInfo, paymentIntentObj),
    achPaymentVisibilityScope: ACH_PAYMENT_VISIBILITY_SCOPES.order_only,
    stripeAchCustomerId: stripeIdFromObject_(paymentIntentObj && paymentIntentObj.customer),
    achFailureCode: '',
    achFailureMessage: ''
  }, eventUpdates));
  const updatedSummary = buildPortalOrderSummary_(updatedOrder.rowObjNormalized);
  updateExportPointersForWebhookOrder_(cfg, ss, infra, orderInfo, updatedSummary);
  const token = trimString_(orderInfo.rowObjNormalized.token);
  const rowInfo = token ? findRowByToken_(infra.exportSheet, token) : null;
  if (rowInfo && !alreadyPaid) {
    finalizePortalAfterPayment({
      token: token,
      portalState: safeJsonParse_(rowInfo.rowObjNormalized.portalstatejson, {}) || { printJobs: {} },
      submittedAt: now,
      systemMessage: 'ACH payment cleared on ' + now + '. Order authorized for production.'
    });
  }
  queueOrderAchLifecycleEmailsSafely_(
    updatedOrder,
    paymentIntentObj,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_receipt_email,
    AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_confirmed,
    {
      cfg: cfg,
      ss: ss,
      infra: infra,
      accountInfo: accountInfo,
      eventType: 'payment_intent.succeeded'
    }
  );
  return { ok: true };
}

function handleChargeUpdated_(chargeObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const charge = (chargeObj && typeof chargeObj === 'object') ? chargeObj : {};
  const chargeId = trimString_(charge.id);
  const paymentIntentId = stripeIdFromObject_(charge.payment_intent);
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const orderInfo = getPortalOrderByStripeLatestChargeId_(chargeId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) ||
    getPortalOrderByStripePaymentIntentId_(paymentIntentId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet });
  if (!orderInfo) return { ok: true, ignored: true, type: 'charge.updated' };
  const bank = charge.payment_method_details && charge.payment_method_details.us_bank_account
    ? charge.payment_method_details.us_bank_account
    : {};
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: trimString_(opts.eventPayload && opts.eventPayload.type) || 'charge.updated',
    orderInfo: orderInfo,
    charge: charge
  });
  const eventUpdates = buildStripeLatestEventOrderUpdates_(opts.eventPayload, charge);
  const chargeUpdates = {
    cfg: cfg,
    ss: ss,
    infra: infra,
    orderRowInfo: orderInfo,
    stripeLatestChargeId: chargeId
  };
  if (achEvidence.isAchPayment === true) {
    Object.assign(chargeUpdates, {
      achBankName: trimString_(bank.bank_name) || trimString_(orderInfo.rowObjNormalized.achbankname),
      achLast4: trimString_(bank.last4) || trimString_(orderInfo.rowObjNormalized.achlast4),
      achExpectedDebitDate: trimString_(bank.expected_debit_date || charge.expected_debit_date || orderInfo.rowObjNormalized.achexpecteddebitdate)
    });
  }
  const updatedOrder = updatePortalOrderState_(Object.assign(chargeUpdates, eventUpdates));
  updateExportPointersForWebhookOrder_(cfg, ss, infra, orderInfo, buildPortalOrderSummary_(updatedOrder.rowObjNormalized));
  return { ok: true };
}

function handleChargeFailed_(chargeObj, options) {
  const charge = (chargeObj && typeof chargeObj === 'object') ? chargeObj : {};
  const paymentIntentId = stripeIdFromObject_(charge.payment_intent);
  if (paymentIntentId) {
    const piResult = retrieveStripePaymentIntent_(paymentIntentId, { cfg: getConfig_() });
    if (piResult.ok) return handlePaymentIntentFailed_(piResult.body, options);
  }
  return handlePaymentIntentFailed_(Object.assign({}, charge, {
    id: paymentIntentId,
    last_payment_error: {
      code: charge.failure_code,
      message: charge.failure_message
    }
  }), options);
}

function handleChargeDisputeCreated_(disputeObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const dispute = (disputeObj && typeof disputeObj === 'object') ? disputeObj : {};
  const chargeId = stripeIdFromObject_(dispute.charge);
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const orderInfo = getPortalOrderByStripeLatestChargeId_(chargeId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet });
  if (!orderInfo) return { ok: true, ignored: true, type: 'charge.dispute.created' };
  const currentGuard = validateCurrentStripeCheckoutWebhookOrder_(dispute, orderInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    eventType: 'charge.dispute.created'
  });
  if (currentGuard.current === false) return currentGuard;
  let chargeObj = dispute.charge && typeof dispute.charge === 'object' ? dispute.charge : null;
  if (!chargeObj && chargeId) {
    const chargeResult = retrieveStripeCharge_(chargeId, { cfg: cfg });
    if (chargeResult.ok && chargeResult.body) chargeObj = chargeResult.body;
  }
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: 'charge.dispute.created',
    orderInfo: orderInfo,
    charge: chargeObj
  });
  if (achEvidence.isAchPayment !== true) {
    return {
      ok: true,
      ignored: true,
      type: 'charge.dispute.created',
      reason: 'non_ach_dispute'
    };
  }
  const accountInfo = getPortalAccountInfoForOrder_(orderInfo, { cfg: cfg, ss: ss, infra: infra });
  markOrderAchPaymentMethodUnusableIfNeeded_(accountInfo, orderInfo, null, {
    code: trimString_(dispute.reason) || 'dispute_created',
    message: 'Stripe ACH dispute or late return opened.'
  }, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    force: true,
    reason: 'charge.dispute.created'
  });
  const currentDraft = safeJsonParse_(orderInfo.rowObjNormalized.orderdraftjson, {}) || {};
  const eventUpdates = buildStripeLatestEventOrderUpdates_(opts.eventPayload, dispute);
  const updatedOrder = updatePortalOrderState_(Object.assign({
    cfg: cfg,
    ss: ss,
    infra: infra,
    orderRowInfo: orderInfo,
    orderDraft: writeTeamWorkflowMetaIntoDraft_(currentDraft, { workflowMode: TEAM_WORKFLOW_MODES.team_hold }),
    paymentState: PAYMENT_STATES.failed,
    achFailureCode: trimString_(dispute.reason) || 'dispute_created',
    achFailureMessage: 'ACH payment dispute or late return opened in Stripe.',
    notes: 'Stripe ACH dispute created. Team review required.'
  }, eventUpdates));
  updateExportPointersForWebhookOrder_(cfg, ss, infra, orderInfo, buildPortalOrderSummary_(updatedOrder.rowObjNormalized));
  queueOrderAchLifecycleEmailsSafely_(
    updatedOrder,
    chargeObj || dispute,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_action_email,
    AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_failed,
    {
      cfg: cfg,
      ss: ss,
      infra: infra,
      accountInfo: accountInfo,
      eventType: 'charge.dispute.created'
    }
  );
  return { ok: true };
}

function handlePaymentMethodAutomaticallyUpdated_(paymentMethodObj) {
  const method = (paymentMethodObj && typeof paymentMethodObj === 'object') ? paymentMethodObj : {};
  const customerId = stripeIdFromObject_(method.customer);
  if (!customerId) return { ok: true, ignored: true, type: 'payment_method.automatically_updated' };
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const accountInfo = getPortalAccountByStripeCustomerId_(customerId, { cfg: cfg, ss: ss, infra: infra });
  if (!accountInfo) return { ok: true, ignored: true, type: 'payment_method.automatically_updated' };
  const summary = extractAchPaymentMethodSummaryFromStripe_(method, {
    source: 'stripe_auto_update',
    status: 'active'
  });
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: 'payment_method.automatically_updated',
    paymentMethod: method,
    achSummary: summary
  });
  if (achEvidence.isAchSetup === true || achEvidence.isAchPayment === true) {
    upsertAchPaymentMethodOnPortalAccount_(accountInfo, summary, { cfg: cfg, ss: ss, infra: infra });
  }
  return { ok: true };
}

function handleSetupIntentSucceeded_(setupIntentObj) {
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const accountId = extractStripeMetadataValue_(setupIntentObj, 'accountId');
  const customerId = stripeIdFromObject_(setupIntentObj && setupIntentObj.customer);
  let accountInfo = accountId ? getPortalAccountByAccountId_(accountId, { cfg: cfg, ss: ss, infra: infra }) : null;
  if (!accountInfo && customerId) accountInfo = getPortalAccountByStripeCustomerId_(customerId, { cfg: cfg, ss: ss, infra: infra });
  if (!accountInfo) return { ok: false, error: 'Portal account not found for setup intent.' };
  const summary = resolveAchPaymentMethodSummaryFromSetupIntent_(setupIntentObj, {
    cfg: cfg,
    setupIntentId: trimString_(setupIntentObj && setupIntentObj.id),
    stripeCustomerId: customerId
  });
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: 'setup_intent.succeeded',
    setupIntent: setupIntentObj,
    achSummary: summary
  });
  if (achEvidence.isAchSetup !== true) {
    return {
      ok: true,
      ignored: true,
      type: 'setup_intent.succeeded',
      reason: 'non_ach_setup_intent'
    };
  }
  if (customerId) {
    accountInfo = updatePortalAccountStripeCustomerIdIfBlank_(accountInfo, customerId, {
      cfg: cfg,
      ss: ss,
      infra: infra
    });
  }
  if (summary) {
    accountInfo = upsertDashboardSavedAchPaymentMethodOnPortalAccount_(accountInfo, Object.assign({}, summary, {
      stripeCustomerId: customerId
    }), { cfg: cfg, ss: ss, infra: infra });
  }
  setRowValuesByHeaderMap_(infra.accountsSheet, accountInfo.rowInfo.row, accountInfo.rowInfo.colMap, {
    achSetupIntentId: trimString_(setupIntentObj && setupIntentObj.id),
    achSetupStatus: 'succeeded',
    achSetupLastUpdatedAt: nowIso_(),
    updatedAt: nowIso_()
  });
  return {
    ok: true,
    accountSummary: buildPortalAccountSummary_(buildRowInfoFromSheet_(infra.accountsSheet, accountInfo.rowInfo.row).rowObjNormalized, cfg)
  };
}

function handleSetupIntentFailed_(setupIntentObj) {
  const cfg = getConfig_();
  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const accountId = extractStripeMetadataValue_(setupIntentObj, 'accountId');
  const customerId = stripeIdFromObject_(setupIntentObj && setupIntentObj.customer);
  let accountInfo = accountId ? getPortalAccountByAccountId_(accountId, { cfg: cfg, ss: ss, infra: infra }) : null;
  if (!accountInfo && customerId) accountInfo = getPortalAccountByStripeCustomerId_(customerId, { cfg: cfg, ss: ss, infra: infra });
  if (!accountInfo) return { ok: true, ignored: true, type: 'setup_intent.setup_failed' };
  const summary = resolveAchPaymentMethodSummaryFromSetupIntent_(setupIntentObj, {
    cfg: cfg,
    stripeCustomerId: customerId
  });
  const achEvidence = buildAchStripeEventEvidence_({
    eventType: 'setup_intent.setup_failed',
    setupIntent: setupIntentObj,
    achSummary: summary
  });
  if (achEvidence.isAchSetup !== true) {
    return {
      ok: true,
      ignored: true,
      type: 'setup_intent.setup_failed',
      reason: 'non_ach_setup_intent'
    };
  }
  const failedRowUpdate = markMatchingDashboardSavedAchSetupMethodFailed_(accountInfo, setupIntentObj, {
    cfg: cfg,
    ss: ss,
    infra: infra
  });
  if (failedRowUpdate && failedRowUpdate.matched === true && failedRowUpdate.accountInfo) {
    accountInfo = failedRowUpdate.accountInfo;
  }
  setRowValuesByHeaderMap_(infra.accountsSheet, accountInfo.rowInfo.row, accountInfo.rowInfo.colMap, {
    achSetupIntentId: trimString_(setupIntentObj && setupIntentObj.id),
    achSetupStatus: 'failed',
    achSetupLastUpdatedAt: nowIso_(),
    updatedAt: nowIso_()
  });
  return {
    ok: true,
    matchedSavedBankRow: failedRowUpdate && failedRowUpdate.matched === true,
    ambiguousSavedBankRow: failedRowUpdate && failedRowUpdate.ambiguous === true,
    accountSummary: buildPortalAccountSummary_(buildRowInfoFromSheet_(infra.accountsSheet, accountInfo.rowInfo.row).rowObjNormalized, cfg)
  };
}

/* ---------------- Stripe Event Processing + Portal Finalization ---------------- */

function processStripeEventPayload_(eventPayload, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const eventObj = (eventPayload && typeof eventPayload === 'object') ? eventPayload : {};
  const type = trimString_(eventObj.type);
  const dataObject = eventObj.data && eventObj.data.object ? eventObj.data.object : null;
  if (!type || !dataObject) {
    return { ok: false, error: 'Invalid Stripe event payload.' };
  }

  // TODO: This processor is intentionally transport-agnostic so a future
  // verified Cloud Run forwarder can POST trusted event JSON into Apps Script.
  switch (type) {
    case 'checkout.session.completed':
      return handleCheckoutSessionCompleted_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    case 'checkout.session.async_payment_succeeded':
      return handleCheckoutAsyncPaymentSucceeded_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    case 'checkout.session.async_payment_failed':
      return handleCheckoutAsyncPaymentFailed_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    case 'payment_intent.processing':
      return handlePaymentIntentProcessing_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    case 'payment_intent.succeeded':
      return handlePaymentIntentSucceeded_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    case 'payment_intent.payment_failed':
      return handlePaymentIntentFailed_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    case 'charge.updated':
    case 'charge.succeeded':
      return handleChargeUpdated_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    case 'charge.failed':
      return handleChargeFailed_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    case 'charge.dispute.created':
      return handleChargeDisputeCreated_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    case 'payment_method.automatically_updated':
      return handlePaymentMethodAutomaticallyUpdated_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    case 'setup_intent.succeeded':
      return handleSetupIntentSucceeded_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    case 'setup_intent.setup_failed':
      return handleSetupIntentFailed_(dataObject, Object.assign({}, opts, { eventPayload: eventObj }));
    default:
      return { ok: true, ignored: true, type: type };
  }
}

function resolveWebhookRoute_(e, payload) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  const bodyRoute = trimString_(p.route);
  const queryRoute = trimString_(e && e.parameter && e.parameter.route);
  return trimString_(bodyRoute || queryRoute).toLowerCase();
}

function looksLikeStripeEventPayload_(value) {
  const obj = (value && typeof value === 'object') ? value : null;
  if (!obj) return false;
  if (!trimString_(obj.type)) return false;
  return !!(obj.data && obj.data.object && typeof obj.data.object === 'object');
}

function extractForwardedStripeEventPayload_(payload) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  if (looksLikeStripeEventPayload_(p.stripeEvent)) return p.stripeEvent;
  if (looksLikeStripeEventPayload_(p.event)) return p.event;
  if (looksLikeStripeEventPayload_(p)) return p;
  return null;
}

function summarizeForwardedStripeEvent_(eventPayload) {
  const eventObj = (eventPayload && typeof eventPayload === 'object') ? eventPayload : {};
  const dataObject = eventObj.data && eventObj.data.object && typeof eventObj.data.object === 'object'
    ? eventObj.data.object
    : {};
  const paymentIntentId = stripeIdFromObject_(dataObject.payment_intent || dataObject.paymentIntent) ||
    (trimString_(dataObject.object).toLowerCase() === 'payment_intent' ? trimString_(dataObject.id) : '');
  const setupIntentId = stripeIdFromObject_(dataObject.setup_intent || dataObject.setupIntent) ||
    (trimString_(dataObject.object).toLowerCase() === 'setup_intent' ? trimString_(dataObject.id) : '');
  const checkoutSessionId = (trimString_(dataObject.object).toLowerCase() === 'checkout.session' ? trimString_(dataObject.id) : '') ||
    stripeIdFromObject_(dataObject.checkout_session || dataObject.checkoutSession);
  const chargeId = stripeIdFromObject_(dataObject.charge || dataObject.latest_charge || dataObject.latestCharge) ||
    (trimString_(dataObject.object).toLowerCase() === 'charge' ? trimString_(dataObject.id) : '');
  return {
    eventId: trimString_(eventObj.id),
    eventType: trimString_(eventObj.type),
    objectId: trimString_(dataObject.id),
    paymentIntentId: paymentIntentId,
    setupIntentId: setupIntentId,
    checkoutSessionId: checkoutSessionId,
    chargeId: chargeId,
    orderId: trimString_(
      extractStripeMetadataValue_(dataObject, 'orderId') ||
      dataObject.orderId
    ),
    token: trimString_(
      extractStripeMetadataValue_(dataObject, 'token') ||
      dataObject.token ||
      dataObject.client_reference_id ||
      dataObject.clientReferenceId
    ),
    checkoutAttemptId: trimString_(
      extractStripeMetadataValue_(dataObject, 'checkoutAttemptId') ||
      dataObject.checkoutAttemptId
    ),
    accountId: trimString_(
      extractStripeMetadataValue_(dataObject, 'accountId') ||
      dataObject.accountId ||
      dataObject.client_reference_id ||
      dataObject.clientReferenceId
    )
  };
}

function logStripeWebhookIngress_(details) {
  try {
    const meta = (details && typeof details === 'object') ? details : {};
    console.log('[RT-STRIPE-WEBHOOK] ' + JSON.stringify(meta));
  } catch (_) {}
}

function redactStripeObjectForStorage_(value, depth, parentKey) {
  const level = Math.max(0, parseInt(String(depth || 0), 10) || 0);
  if (level > 8) return '[redacted_depth_limit]';
  if (value == null) return value;
  const keyName = trimString_(parentKey).toLowerCase();
  if (/(^|_)(url|uri)$|url$|uri$|redirect|return_url|success_url|cancel_url/i.test(keyName)) {
    return '[redacted_url]';
  }
  if (/(routing|account_number|accountnumber|bank_account_token|client_secret|secret|verification_code|microdeposit|address|phone|postal|zip|line1|line2|city|state|country)/i.test(keyName)) {
    return '[redacted]';
  }
  if (keyName === 'financial_connections_account' && value && typeof value === 'object') {
    return '[redacted_financial_connections_account]';
  }
  if ((keyName === 'billing_details' || keyName === 'customer_details') && value && typeof value === 'object') {
    return {
      name: trimString_(value.name),
      email: normalizeEmail_(value.email),
      address: value.address ? '[redacted]' : '',
      phone: value.phone ? '[redacted]' : ''
    };
  }
  if (keyName === 'us_bank_account' && value && typeof value === 'object') {
    return {
      bank_name: trimString_(value.bank_name || value.bankName),
      last4: trimString_(value.last4),
      account_holder_type: trimString_(value.account_holder_type || value.accountHolderType),
      account_type: trimString_(value.account_type || value.accountType),
      status: trimString_(value.status),
      financial_connections_account: stripeIdFromObject_(value.financial_connections_account || value.financialConnectionsAccount)
    };
  }
  if (Array.isArray(value)) {
    return value.slice(0, 30).map(function(item) {
      return redactStripeObjectForStorage_(item, level + 1, keyName);
    });
  }
  if (typeof value === 'object') {
    const out = {};
    Object.keys(value).slice(0, 120).forEach(function(key) {
      out[key] = redactStripeObjectForStorage_(value[key], level + 1, key);
    });
    return out;
  }
  if (typeof value === 'string' && value.length > 1000) return value.slice(0, 1000) + '...';
  return value;
}

function buildRedactedStripeEventJson_(eventPayload) {
  try {
    const redacted = redactStripeObjectForStorage_(eventPayload, 0, '');
    const text = JSON.stringify(redacted);
    return text.length > 45000 ? text.slice(0, 45000) + '...[truncated]' : text;
  } catch (err) {
    return JSON.stringify({ redactionError: String((err && err.message) || err) });
  }
}

function findPortalStripeEventInfo_(stripeEventsSheet, stripeEventId) {
  const eventId = trimString_(stripeEventId);
  if (!stripeEventsSheet || !eventId) return null;
  const lastCol = stripeEventsSheet.getLastColumn();
  const lastRow = stripeEventsSheet.getLastRow();
  if (lastCol < 1 || lastRow < 2) return null;
  const header = stripeEventsSheet.getRange(1, 1, 1, lastCol).getValues()[0];
  const colMap = buildColumnMap_(header);
  const idCol = colMap.stripeeventid;
  if (!idCol) return null;
  const matches = stripeEventsSheet.getRange(2, idCol, lastRow - 1, 1)
    .createTextFinder(eventId)
    .matchEntireCell(true)
    .findAll() || [];
  if (!matches.length) return null;
  return buildRowInfoFromSheet_(stripeEventsSheet, matches[0].getRow(), header);
}

function beginPortalStripeEventAudit_(eventPayload, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const sheet = infra.stripeEventsSheet;
  const summary = summarizeForwardedStripeEvent_(eventPayload);
  const eventId = trimString_(summary.eventId);
  if (!eventId) {
    return { ok: true, auditable: false, summary: summary };
  }
  const existing = findPortalStripeEventInfo_(sheet, eventId);
  if (existing) {
    const status = trimString_(existing.rowObjNormalized.processingstatus).toLowerCase();
    if (status === PORTAL_STRIPE_EVENT_STATUSES.processed) {
      return {
        ok: true,
        auditable: true,
        duplicateProcessed: true,
        rowInfo: existing,
        summary: summary
      };
    }
    setRowValuesByHeaderMap_(sheet, existing.row, existing.colMap, {
      processingStatus: PORTAL_STRIPE_EVENT_STATUSES.processing,
      errorMessage: ''
    });
    return {
      ok: true,
      auditable: true,
      rowInfo: buildRowInfoFromSheet_(sheet, existing.row),
      summary: summary
    };
  }
  const header = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  const colMap = buildColumnMap_(header);
  const rowVals = new Array(sheet.getLastColumn()).fill('');
  const now = nowIso_();
  const byHeader = {
    stripeEventId: summary.eventId,
    eventType: summary.eventType,
    objectId: summary.objectId,
    paymentIntentId: summary.paymentIntentId,
    setupIntentId: summary.setupIntentId,
    checkoutSessionId: summary.checkoutSessionId,
    chargeId: summary.chargeId,
    orderId: summary.orderId,
    checkoutAttemptId: summary.checkoutAttemptId,
    token: summary.token,
    accountId: summary.accountId,
    receivedAt: now,
    processingStatus: PORTAL_STRIPE_EVENT_STATUSES.processing,
    rawEventJsonRedacted: buildRedactedStripeEventJson_(eventPayload)
  };
  Object.keys(byHeader).forEach(function(headerName) {
    const col = colMap[normalizeHeaderKey_(headerName)];
    if (col) rowVals[col - 1] = byHeader[headerName];
  });
  const row = sheet.getLastRow() + 1;
  sheet.getRange(row, 1, 1, rowVals.length).setValues([rowVals]);
  return {
    ok: true,
    auditable: true,
    rowInfo: buildRowInfoFromSheet_(sheet, row, header, rowVals),
    summary: summary
  };
}

function completePortalStripeEventAudit_(eventAudit, status, errorMessage, options) {
  const audit = (eventAudit && typeof eventAudit === 'object') ? eventAudit : {};
  if (!audit.auditable || !audit.rowInfo) return;
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  setRowValuesByHeaderMap_(infra.stripeEventsSheet, audit.rowInfo.row, audit.rowInfo.colMap, {
    processedAt: nowIso_(),
    processingStatus: trimString_(status) || PORTAL_STRIPE_EVENT_STATUSES.processed,
    errorMessage: trimString_(errorMessage)
  });
}

function processForwardedStripeWebhookPayload_(payload, options) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = getConfig_();
  const providedSecret = trimString_(
    p.sharedSecret ||
    p.forwardSharedSecret ||
    p.webhookForwardSharedSecret
  );
  const authPassed = !!cfg.stripeWebhookForwardSharedSecret && providedSecret === cfg.stripeWebhookForwardSharedSecret;
  const eventPayload = extractForwardedStripeEventPayload_(p);
  const summary = summarizeForwardedStripeEvent_(eventPayload || p.stripeEvent || p.event || {});

  logStripeWebhookIngress_({
    route: trimString_(opts.route).toLowerCase(),
    authPassed: authPassed,
    eventId: summary.eventId,
    eventType: summary.eventType,
    token: summary.token,
    checkoutAttemptId: summary.checkoutAttemptId
  });

  if (!authPassed) {
    return {
      ok: false,
      webhookProcessed: false,
      error: 'Unauthorized webhook forwarder payload.',
      eventType: summary.eventType || ''
    };
  }
  if (!eventPayload) {
    return {
      ok: false,
      webhookProcessed: false,
      error: 'Missing forwarded Stripe event payload.',
      eventType: summary.eventType || ''
    };
  }

  const ss = SpreadsheetApp.openById(cfg.sheetId);
  const infra = ensurePortalInfrastructure_(ss, cfg);
  const lock = LockService.getScriptLock();
  let lockAcquired = false;
  let eventAudit = null;
  let result;
  try {
    lockAcquired = lock.tryLock(30000);
    if (!lockAcquired) {
      return {
        ok: false,
        webhookProcessed: false,
        error: 'Stripe webhook processing lock unavailable.',
        eventId: summary.eventId || '',
        eventType: summary.eventType || '',
        token: summary.token || '',
        checkoutAttemptId: summary.checkoutAttemptId || ''
      };
    }
    eventAudit = beginPortalStripeEventAudit_(eventPayload, {
      cfg: cfg,
      ss: ss,
      infra: infra
    });
    if (eventAudit && eventAudit.duplicateProcessed === true) {
      logStripeWebhookIngress_({
        route: trimString_(opts.route).toLowerCase(),
        authPassed: authPassed,
        eventId: summary.eventId,
        eventType: summary.eventType,
        duplicateProcessed: true
      });
      return {
        ok: true,
        webhookProcessed: true,
        duplicate: true,
        eventType: summary.eventType || ''
      };
    }
    result = processStripeEventPayload_(eventPayload, {
      cfg: cfg,
      ss: ss,
      infra: infra,
      eventAudit: eventAudit
    });
    completePortalStripeEventAudit_(
      eventAudit,
      result && result.ok === false ? PORTAL_STRIPE_EVENT_STATUSES.failed : PORTAL_STRIPE_EVENT_STATUSES.processed,
      result && result.ok === false ? trimString_(result.error || result.code) : '',
      {
        cfg: cfg,
        ss: ss,
        infra: infra
      });
  } catch (err) {
    completePortalStripeEventAudit_(eventAudit, PORTAL_STRIPE_EVENT_STATUSES.failed, String((err && err.message) || err), {
      cfg: cfg,
      ss: ss,
      infra: infra
    });
    throw err;
  } finally {
    if (lockAcquired) {
      try {
        lock.releaseLock();
      } catch (_) {}
    }
  }

  logStripeWebhookIngress_({
    route: trimString_(opts.route).toLowerCase(),
    authPassed: authPassed,
    eventId: summary.eventId,
    eventType: summary.eventType,
    token: summary.token,
    checkoutAttemptId: summary.checkoutAttemptId,
    result: {
      ok: !!(result && result.ok === true),
      ignored: !!(result && result.ignored === true),
      error: trimString_(result && result.error)
    }
  });

  if (!result || result.ok !== true) {
    return {
      ok: false,
      webhookProcessed: false,
      error: String((result && result.error) || 'Stripe webhook processing failed.'),
      eventId: summary.eventId || '',
      eventType: summary.eventType || '',
      token: summary.token || '',
      checkoutAttemptId: summary.checkoutAttemptId || ''
    };
  }

  return {
    ok: true,
    webhookProcessed: true,
    ignored: !!result.ignored,
    eventId: summary.eventId || '',
    eventType: summary.eventType || '',
    token: summary.token || '',
    checkoutAttemptId: summary.checkoutAttemptId || ''
  };
}

function verifyTeamModePassword(payload) {
  try {
    const p = (payload && typeof payload === 'object') ? payload : {};
    const token = String(p.token || '').trim();
    const password = String(p.password || '');
    if (!token || !password) {
      return { ok: false, error: 'Password is required.' };
    }

    const cfg = getConfig_();
    if (password !== String(cfg.teamModePassword || '')) {
      return { ok: false, error: 'Incorrect password.' };
    }

    const ss = SpreadsheetApp.openById(cfg.sheetId);
    const exportSheet = ensurePortalInfrastructure_(ss, cfg).exportSheet;
    if (!exportSheet) {
      return { ok: false, error: 'Auth configuration is incomplete.' };
    }

    const rowInfo = findRowByToken_(exportSheet, token);
    if (!rowInfo) {
      return { ok: false, error: 'Link not found.' };
    }

    return {
      ok: true,
      senderName: getVisibleTeamAuthorName_(rowInfo.rowObjNormalized),
      teamAuthKey: buildTeamModeAuthKey_(token, cfg)
    };
  } catch (err) {
    return { ok: false, error: String((err && err.message) || err) };
  }
}

function buildTeamModeAuthKey_(token, cfg, options) {
  const id = trimString_(token);
  if (!id) return '';
  const config = cfg || getConfig_();
  const opts = (options && typeof options === 'object') ? options : {};
  const issuedAt = Math.max(0, parseInt(String(opts.issuedAt || Date.now()), 10) || Date.now());
  const payload = id + '|' + String(issuedAt);
  const secret = String(config.teamModePassword || '');
  const signature = Utilities.base64EncodeWebSafe(
    Utilities.computeHmacSha256Signature(payload, secret)
  ).replace(/=+$/g, '');
  return String(issuedAt) + '.' + signature;
}

function validateTeamModeAuthKey_(token, authKey, cfg) {
  const id = trimString_(token);
  const key = trimString_(authKey);
  if (!id || !key) return false;
  const parts = key.split('.');
  if (parts.length !== 2) return false;
  const issuedAt = Math.max(0, parseInt(String(parts[0] || 0), 10) || 0);
  const signature = trimString_(parts[1]);
  if (!issuedAt || !signature) return false;
  if ((Date.now() - issuedAt) > TEAM_MODE_AUTH_TTL_MS) return false;
  return buildTeamModeAuthKey_(id, cfg, { issuedAt: issuedAt }) === key;
}

function buildTeamModeEmailAccessSignature_(payloadB64, cfg) {
  const config = cfg || getConfig_();
  const secret = String(config.teamModeEmailAccessSecret || '').trim();
  if (!payloadB64 || !secret) return '';
  return Utilities.base64EncodeWebSafe(
    Utilities.computeHmacSha256Signature(String(payloadB64), secret)
  ).replace(/=+$/g, '');
}

function constantTimeStringEquals_(left, right) {
  const a = String(left || '');
  const b = String(right || '');
  let diff = a.length ^ b.length;
  const max = Math.max(a.length, b.length);
  for (let i = 0; i < max; i++) {
    diff |= (a.charCodeAt(i) || 0) ^ (b.charCodeAt(i) || 0);
  }
  return diff === 0;
}

function buildTeamModeEmailAccessToken_(token, options, cfg) {
  const id = trimString_(token);
  if (!id) return '';
  const opts = (options && typeof options === 'object') ? options : {};
  const issuedAt = Math.max(0, parseInt(String(opts.issuedAt || Date.now()), 10) || Date.now());
  const expiresAt = Math.max(issuedAt, parseInt(String(opts.expiresAt || (issuedAt + TEAM_MODE_EMAIL_ACCESS_TTL_MS)), 10) || (issuedAt + TEAM_MODE_EMAIL_ACCESS_TTL_MS));
  const payload = {
    v: 1,
    t: id,
    m: 'team',
    a: normalizeLifecycleEmailTeamAction_(opts.teamAction),
    r: trimString_(opts.teamReview).toLowerCase(),
    iat: issuedAt,
    exp: expiresAt
  };
  const payloadB64 = Utilities.base64EncodeWebSafe(
    Utilities.newBlob(JSON.stringify(payload), 'application/json').getBytes()
  ).replace(/=+$/g, '');
  const signature = buildTeamModeEmailAccessSignature_(payloadB64, cfg);
  return signature ? (payloadB64 + '.' + signature) : '';
}

function decodeTeamModeEmailAccessPayload_(payloadB64) {
  const clean = trimString_(payloadB64);
  if (!clean) return null;
  try {
    const bytes = Utilities.base64DecodeWebSafe(clean);
    const json = Utilities.newBlob(bytes, 'application/json').getDataAsString();
    const payload = safeJsonParse_(json, null);
    return (payload && typeof payload === 'object') ? payload : null;
  } catch (_) {
    return null;
  }
}

function validateTeamModeEmailAccessToken_(teamAccess, options, cfg) {
  const access = trimString_(teamAccess);
  const opts = (options && typeof options === 'object') ? options : {};
  const token = trimString_(opts.token);
  if (!access || !token) return false;
  const parts = access.split('.');
  if (parts.length !== 2) return false;
  const payloadB64 = trimString_(parts[0]);
  const signature = trimString_(parts[1]);
  if (!payloadB64 || !signature) return false;
  const expected = buildTeamModeEmailAccessSignature_(payloadB64, cfg);
  if (!expected || !constantTimeStringEquals_(signature, expected)) return false;
  const payload = decodeTeamModeEmailAccessPayload_(payloadB64);
  if (!payload) return false;
  const now = Date.now();
  const issuedAt = Math.max(0, parseInt(String(payload.iat || 0), 10) || 0);
  const expiresAt = Math.max(0, parseInt(String(payload.exp || 0), 10) || 0);
  if (payload.v !== 1 || payload.m !== 'team') return false;
  if (trimString_(payload.t) !== token) return false;
  if (!issuedAt || !expiresAt || expiresAt < now || issuedAt > now + (5 * 60 * 1000)) return false;
  if ((expiresAt - issuedAt) > TEAM_MODE_EMAIL_ACCESS_TTL_MS) return false;
  const expectedAction = normalizeLifecycleEmailTeamAction_(opts.teamAction);
  const expectedReview = trimString_(opts.teamReview).toLowerCase();
  if (normalizeLifecycleEmailTeamAction_(payload.a) !== expectedAction) return false;
  if (trimString_(payload.r).toLowerCase() !== expectedReview) return false;
  return true;
}

function verifyTeamModeEmailAccess(payload) {
  try {
    const p = (payload && typeof payload === 'object') ? payload : {};
    const token = trimString_(p.token);
    const teamAccess = trimString_(p.teamAccess);
    const teamAction = normalizeLifecycleEmailTeamAction_(p.teamAction);
    const teamReview = trimString_(p.teamReview).toLowerCase();
    const genericError = 'This Team Mode email link has expired or is invalid. Enter the team password to continue.';
    if (!token || !teamAccess) {
      return { ok: false, error: genericError };
    }

    const cfg = getConfig_();
    if (!validateTeamModeEmailAccessToken_(teamAccess, {
      token: token,
      teamAction: teamAction,
      teamReview: teamReview
    }, cfg)) {
      return { ok: false, error: genericError };
    }

    const ss = SpreadsheetApp.openById(cfg.sheetId);
    const exportSheet = ensurePortalInfrastructure_(ss, cfg).exportSheet;
    if (!exportSheet) {
      return { ok: false, error: 'Auth configuration is incomplete.' };
    }

    const rowInfo = findRowByToken_(exportSheet, token);
    if (!rowInfo) {
      return { ok: false, error: genericError };
    }

    return {
      ok: true,
      senderName: getVisibleTeamAuthorName_(rowInfo.rowObjNormalized),
      teamAuthKey: buildTeamModeAuthKey_(token, cfg)
    };
  } catch (err) {
    return { ok: false, error: String((err && err.message) || err) };
  }
}

function assertTeamModeAuthorized_(ctx, payload) {
  const token = trimString_(
    payload && payload.token ||
    ctx && ctx.exportRowInfo && ctx.exportRowInfo.rowObjNormalized && ctx.exportRowInfo.rowObjNormalized.token
  );
  if (!token) {
    throw new Error('Team review link is missing.');
  }
  const authKey = trimString_(payload && payload.teamAuthKey);
  if (!validateTeamModeAuthKey_(token, authKey, ctx && ctx.cfg)) {
    throw new Error('Team authorization expired. Re-enter the team password and try again.');
  }
  return true;
}

function normalizeResetReturnToken_(value) {
  const clean = trimString_(value);
  return /^[a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12}$/i.test(clean)
    ? clean.toLowerCase()
    : '';
}

function buildPasswordResetReturnBridgeValue_(token) {
  const cleanToken = normalizeResetReturnToken_(token);
  return cleanToken ? (PASSWORD_RESET_RETURN_BRIDGE_PREFIX + cleanToken) : '';
}

function normalizeResetReturnBridgeToken_(value) {
  const clean = trimString_(value).toLowerCase();
  if (!clean || clean.indexOf(PASSWORD_RESET_RETURN_BRIDGE_PREFIX) !== 0) return '';
  return normalizeResetReturnToken_(clean.slice(PASSWORD_RESET_RETURN_BRIDGE_PREFIX.length));
}

function generateResetReturnToken_() {
  return normalizeResetReturnToken_(Utilities.getUuid());
}

function buildResetReturnCacheKey_(token) {
  const clean = normalizeResetReturnToken_(token);
  return clean ? (AUTH_RESET_RETURN_CACHE_PREFIX + clean) : '';
}

function cacheResetReturnToken_(token, email, expiresAtMs) {
  const cleanToken = normalizeResetReturnToken_(token);
  const cleanEmail = normalizeEmail_(email);
  const expiry = Number(expiresAtMs || 0);
  if (!cleanToken || !cleanEmail || !expiry) return false;
  const ttlSeconds = Math.min(
    Math.floor(AUTH_POLICY.RESET_CODE_TTL_MS / 1000),
    Math.floor((expiry - Date.now()) / 1000)
  );
  if (!ttlSeconds || ttlSeconds <= 0) return false;
  const key = buildResetReturnCacheKey_(cleanToken);
  if (!key) return false;
  CacheService.getScriptCache().put(key, JSON.stringify({
    email: cleanEmail,
    expiresAt: new Date(expiry).toISOString()
  }), ttlSeconds);
  return true;
}

function resolveResetReturnToken_(token) {
  const cleanToken = normalizeResetReturnToken_(token);
  const key = buildResetReturnCacheKey_(cleanToken);
  if (!key) return { ok: false, error: 'reset_link_expired' };
  const cache = CacheService.getScriptCache();
  const raw = trimString_(cache.get(key));
  if (!raw) return { ok: false, error: 'reset_link_expired' };
  let parsed = null;
  try {
    parsed = JSON.parse(raw);
  } catch (_) {
    parsed = null;
  }
  const email = normalizeEmail_(parsed && parsed.email);
  const expiresAtMs = parseIsoDateMs_(parsed && parsed.expiresAt);
  if (!email || !expiresAtMs || expiresAtMs <= Date.now()) {
    try {
      cache.remove(key);
    } catch (_) {}
    return { ok: false, error: 'reset_link_expired' };
  }
  return {
    ok: true,
    email: email,
    expiresAt: new Date(expiresAtMs).toISOString()
  };
}

function buildPasswordResetReturnUrl_(token) {
  const cleanToken = normalizeResetReturnToken_(token);
  if (!cleanToken) return '';
  return appendQueryParamsToUrl_(buildExternalPortalBaseUrl_(), {
    accountDocAction: buildPasswordResetReturnBridgeValue_(cleanToken)
  });
}

function buildPasswordResetEmailContent_(code, resetUrl) {
  const cleanCode = trimString_(code);
  const cleanUrl = trimString_(resetUrl);
  const theme = getPortalNativeEmailTheme_();
  const cta = buildLifecycleEmailCtaBlock_(
    'Return to the portal to reset your password',
    cleanUrl
  );
  const centeredCtaHtml = cta.html
    ? ('<div style="text-align:center;">' + cta.html + '</div>')
    : '';
  const fallback = 'If the button does not work, open the portal and choose Forgot password, then enter this code.';
  const body = [
    'Use this code to reset your Red Threads portal password.',
    '',
    'Reset code: ' + cleanCode,
    '',
    'This code expires in 15 minutes.',
    '',
    cleanUrl ? cta.text : '',
    '',
    fallback,
    '',
    'If you did not request this, you can ignore this email.',
    '',
    buildStandardNoReplyFooterCopy_()
  ].filter(function(line, idx, arr) {
    if (line) return true;
    return idx > 0 && idx < arr.length - 1;
  }).join('\n');
  const bodyHtml = [
    '<div style="' + buildPortalNativeEmailStyle_({
      'font-family': theme.fontFamily,
      'font-size': '15px',
      'line-height': '1.7',
      color: theme.textMuted
    }) + '">',
    '<p style="margin:0 0 16px;color:' + theme.text + ';">Use this code to reset your Red Threads portal password.</p>',
    '<div style="' + buildPortalNativeEmailStyle_({
      margin: '0 0 18px',
      padding: '18px 20px',
      'border-radius': '14px',
      border: '1px solid ' + theme.panelBorder,
      background: theme.panelBg,
      color: theme.text,
      'font-size': '32px',
      'line-height': '1',
      'font-weight': '900',
      'letter-spacing': '.28em',
      'text-align': 'center'
    }) + '">' + escapeHtml_(cleanCode) + '</div>',
    '<p style="margin:0 0 16px;color:' + theme.textMuted + ';">This code expires in 15 minutes.</p>',
    centeredCtaHtml,
    '<p style="margin:0 0 14px;color:' + theme.textSoft + ';">' + escapeHtml_(fallback) + '</p>',
    '<p style="margin:0 0 18px;color:' + theme.textSoft + ';">If you did not request this, you can ignore this email.</p>',
    buildLifecycleEmailFooter_().html,
    '</div>'
  ].filter(Boolean).join('\n');
  return {
    subject: 'Reset your Red Threads portal password',
    body: body,
    htmlBody: buildPortalNativeEmailShellHtml_({
      heading: 'Reset your Red Threads portal password',
      badgeLabel: 'Password reset',
      bodyHtml: bodyHtml,
      maxWidth: '640px'
    })
  };
}

function authResolveResetReturnToken(payload) {
  try {
    const p = (payload && typeof payload === 'object') ? payload : {};
    const resolved = resolveResetReturnToken_(p.resetToken || p.token);
    if (!resolved || resolved.ok !== true) {
      return { ok: false, error: 'This reset link expired. Enter your email to request a new code.' };
    }
    return {
      ok: true,
      email: resolved.email,
      expiresAt: resolved.expiresAt
    };
  } catch (_) {
    return { ok: false, error: 'This reset link expired. Enter your email to request a new code.' };
  }
}

function authSendResetCode(payload) {
  try {
    const p = (payload && typeof payload === 'object') ? payload : {};
    const email = normalizeEmail_(p.email);
    if (!email) return { ok: false, error: 'Email is required.' };

    const cfg = getConfig_();
    const ss = SpreadsheetApp.openById(cfg.sheetId);
    const infra = ensurePortalInfrastructure_(ss, cfg);
    const exportSheet = infra.exportSheet;
    const usersSheet = infra.usersSheet;
    if (!exportSheet || !usersSheet) return { ok: false, error: 'Auth configuration is incomplete.' };

    let user = findUserByEmail_(usersSheet, email);
    if (!user) {
      const allowed = emailExistsInExportLog_(exportSheet, email);
      if (!allowed) return { ok: false, error: 'No account found for that email.' };
      user = createUser_(usersSheet, email, '');
    }

    const now = Date.now();
    const existingExpires = parseIsoDateMs_(user.rowObjNormalized[AUTH_COLUMNS.USERS.resetCodeExpiresAt]);
    if (existingExpires > now) {
      const sentAt = existingExpires - AUTH_POLICY.RESET_CODE_TTL_MS;
      if ((now - sentAt) < AUTH_POLICY.RESET_RESEND_THROTTLE_MS) {
        return { ok: false, error: 'Please wait 30 seconds before requesting another code.' };
      }
    }

    const code = generateResetCode_();
    const expiresAtMs = now + AUTH_POLICY.RESET_CODE_TTL_MS;
    const expiresAt = new Date(expiresAtMs).toISOString();
    updateUserResetCode_(usersSheet, user, code, expiresAt);

    let resetReturnUrl = '';
    try {
      const resetReturnToken = generateResetReturnToken_();
      if (cacheResetReturnToken_(resetReturnToken, email, expiresAtMs)) {
        resetReturnUrl = buildPasswordResetReturnUrl_(resetReturnToken);
      }
    } catch (_) {
      resetReturnUrl = '';
    }
    const emailContent = buildPasswordResetEmailContent_(code, resetReturnUrl);
    sendNotificationEmail_({
      to: email,
      subject: emailContent.subject,
      body: emailContent.body,
      htmlBody: emailContent.htmlBody
    });

    return { ok: true };
  } catch (err) {
    return { ok: false, error: String((err && err.message) || err) };
  }
}

function authResetPassword(payload) {
  try {
    const p = (payload && typeof payload === 'object') ? payload : {};
    const email = normalizeEmail_(p.email);
    const code = String(p.code || '').trim();
    const newPassword = String(p.newPassword || '');
    const resetToken = normalizeResetReturnToken_(p.resetToken || p.token);

    if (!email || !code || !newPassword) {
      return { ok: false, error: 'Email, code, and new password are required.' };
    }
    if (resetToken) {
      const resolved = resolveResetReturnToken_(resetToken);
      const resolvedEmail = normalizeEmail_(resolved && resolved.email);
      if (!resolved || resolved.ok !== true || resolvedEmail !== email) {
        return { ok: false, error: 'This reset link expired. Enter your email to request a new code.' };
      }
    }

    const cfg = getConfig_();
    const ss = SpreadsheetApp.openById(cfg.sheetId);
    const usersSheet = ensurePortalInfrastructure_(ss, cfg).usersSheet;
    if (!usersSheet) return { ok: false, error: 'Auth configuration is incomplete.' };

    const user = findUserByEmail_(usersSheet, email);
    if (!user) return { ok: false, error: 'Invalid reset code.' };

    const storedCode = String(user.rowObjNormalized[AUTH_COLUMNS.USERS.resetCode] || '').trim();
    const expiresAtMs = parseIsoDateMs_(user.rowObjNormalized[AUTH_COLUMNS.USERS.resetCodeExpiresAt]);
    const now = Date.now();

    if (!storedCode || storedCode !== code) {
      return { ok: false, error: 'Invalid reset code.' };
    }
    if (!expiresAtMs || expiresAtMs <= now) {
      return { ok: false, error: 'Reset code expired. Request a new code.' };
    }

    const nextHash = hashPasswordV2_(newPassword);
    const updates = {};
    updates[AUTH_COLUMNS.USERS.passwordHash] = nextHash;
    updates[AUTH_COLUMNS.USERS.resetCode] = '';
    updates[AUTH_COLUMNS.USERS.resetCodeExpiresAt] = '';
    updateUserColumns_(usersSheet, user, updates);

    return { ok: true };
  } catch (err) {
    return { ok: false, error: String((err && err.message) || err) };
  }
}

/* ---------------- Portal VM Assembly ---------------- */

function buildAuthShellVm_() {
  const cfg = getConfig_();
  return {
    token: '',
    mode: 'client',
    status: '',
    readOnly: false,
    row: {},
    snapshot: {
      meta: {
        contractVersion: '2.0.0'
      },
      printJobs: []
    },
    portalState: {},
    chatLog: [],
    featureFlags: buildPortalFeatureFlags_(cfg),
    postUrl: getWebAppUrl_(),
    diagnostics: {
      shell: 'auth'
    },
    authShell: true
  };
}

function buildPortalVmForRow_(rowInfo, token, mode, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  let effectiveRowInfo = (rowInfo && typeof rowInfo === 'object') ? rowInfo : null;
  let row = effectiveRowInfo && effectiveRowInfo.rowObjNormalized ? effectiveRowInfo.rowObjNormalized : null;
  if (!row) return { ok: false, error: 'Link not found.' };

  const rawStatus = String(row.status || '').trim();
  if (rawStatus.toLowerCase() === 'replaced') {
    return { ok: false, error: 'This estimate link has been replaced.' };
  }

  const snapshotRaw = String(
    Object.prototype.hasOwnProperty.call(opts, 'snapshotRaw')
      ? opts.snapshotRaw
      : row.snapshotjson || ''
  ).trim();
  if (!snapshotRaw) return { ok: false, error: 'Snapshot data is missing.' };

  const snapshot = (opts.snapshot && typeof opts.snapshot === 'object')
    ? opts.snapshot
    : safeJsonParse_(snapshotRaw, null);
  if (!snapshot || typeof snapshot !== 'object') {
    return { ok: false, error: 'Snapshot data is malformed.' };
  }
  const artworkOverrides = applyArtworkOverridesRuntimeLayerToSnapshot_(
    snapshot,
    row.artworkoverridesjson
  );

  const rawPrintJobs = Array.isArray(snapshot.printJobs)
    ? snapshot.printJobs
    : ((snapshot.printJobs && typeof snapshot.printJobs === 'object')
      ? Object.keys(snapshot.printJobs).map(key => snapshot.printJobs[key])
      : []);
  const printJobIds = rawPrintJobs
    .map((job, idx) => {
      if (!job || typeof job !== 'object') return '';
      return String(job.printJobId || ('PJ' + (idx + 1))).trim();
    })
    .filter(Boolean);

  const contractVersion = String(
    row.contractversion ||
    (snapshot.meta && snapshot.meta.contractVersion) ||
    ''
  ).trim();
  if (majorVersion_(contractVersion) !== 2) {
    return { ok: false, error: 'Unsupported contract version.' };
  }

  const portalState = safeJsonParse_(row.portalstatejson, null);
  const chatLog = normalizeChatLog_(safeJsonParse_(row.chatlogjson, []));
  const readOnly = isLockedPortalRow_(row, portalState);
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const readOnlyAccount = opts.readOnlyAccount === true;
  const accountIdentity = deriveOrgContextFromRow_(row);
  const accountInfo = readOnlyAccount
    ? getPortalAccountByOrgOrEmail_(Object.assign({}, accountIdentity, {
      cfg: cfg,
      ss: ss,
      infra: infra,
      readOnly: true
    }))
    : createPortalAccountIfMissing_(Object.assign({}, accountIdentity, {
    cfg: cfg,
    ss: ss,
    infra: infra
  }));
  const accountSummary = accountInfo ? accountInfo.summary : buildEphemeralAccountSummary_(accountIdentity, cfg);
  if (!readOnlyAccount) {
    effectiveRowInfo = maybeBackfillExportRowOrgContextFromAccount_(infra.exportSheet, effectiveRowInfo, accountSummary) || effectiveRowInfo;
  }
  row = effectiveRowInfo && effectiveRowInfo.rowObjNormalized ? effectiveRowInfo.rowObjNormalized : row;
  const latestOrderInfo = getCurrentPortalOrderForRow_(effectiveRowInfo, {
    cfg: cfg,
    ss: ss,
    ordersSheet: infra.ordersSheet,
    token: token
  });
  const latestOrderSummary = latestOrderInfo ? buildPortalOrderSummary_(latestOrderInfo.rowObjNormalized) : null;
  const currentStateSummary = buildCurrentOrderStateSummaryFromRow_(row, accountSummary, latestOrderSummary);
  const workflowContext = buildTeamWorkflowContext_({
    row: row,
    latestOrderSummary: latestOrderSummary,
    currentStateSummary: currentStateSummary,
    accountSummary: accountSummary
  });
  const decoratedLatestOrderSummary = latestOrderSummary
    ? attachTeamWorkflowMetaToOrderSummary_(latestOrderSummary, workflowContext)
    : null;
  const decoratedCurrentStateSummary = attachTeamWorkflowMetaToCurrentStateSummary_(currentStateSummary, workflowContext);
  const displayStatus = derivePortalDisplayOrderStatus_(
    Object.assign({}, row, decoratedCurrentStateSummary, decoratedLatestOrderSummary),
    rawStatus
  );
  let projectStatusSeed = null;
  try {
    const projectProjectionContext = buildDashboardProjectProjectionContext_(effectiveRowInfo, {
      rowInfo: effectiveRowInfo,
      runtimeMeta: {
        row: row,
        snapshot: snapshot,
        printJobs: normalizePrintJobsForOrder_(snapshot && snapshot.printJobs)
      },
      cfg: cfg,
      ss: ss,
      infra: infra,
      accountSummary: accountSummary,
      latestOrderInfo: latestOrderInfo,
      latestOrderSummary: latestOrderSummary
    });
    projectStatusSeed = buildDashboardProjectStatusMetaFromProjectionContext_(projectProjectionContext);
  } catch (err) {
    console.log('[RT-PROJECT-HEADER-STATUS] ' + String((err && err.message) || err));
  }

  return {
    ok: true,
    vm: {
      token: token,
      mode: normalizeMode_(mode || 'client'),
      status: displayStatus,
      readOnly: readOnly,
      row: row,
      snapshot: snapshot,
      artworkOverrides: artworkOverrides,
      portalState: portalState,
      chatLog: chatLog,
      accountSummary: accountSummary,
      latestOrderSummary: decoratedLatestOrderSummary,
      currentStateSummary: decoratedCurrentStateSummary,
      projectStatusSeed: projectStatusSeed,
      featureFlags: buildPortalFeatureFlags_(cfg),
      postUrl: getWebAppUrl_(),
      diagnostics: {
        token: token,
        status: displayStatus,
        contractVersion: contractVersion,
        snapshotId: String(row.snapshotid || '').trim(),
        exportedAt: String(row.exportedat || '').trim(),
        printJobsCount: printJobIds.length,
        printJobIds: printJobIds,
        snapshotSnippet: snapshotRaw.slice(0, 500)
      }
    }
  };
}

function persistPortalStateForRow_(sheet, rowInfo, portalState, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const colMap = rowInfo.colMap || {};
  const row = rowInfo.row;

  const portalStateCol = colMap.portalstatejson;
  const statusCol = colMap.status;
  const submittedAtCol = colMap.submittedat;
  const submittedStateCol = colMap.submittedstatejson;
  const chatCol = colMap.chatlogjson || EXPORT_LOG_COLUMNS.chatLogJson;

  if (!portalStateCol || !statusCol) {
    return { ok: false, error: 'Required columns missing (portalStateJson/status).' };
  }
  if (opts.writeSubmittedState === true && !submittedStateCol) {
    return { ok: false, error: 'Required column missing (submittedStateJson).' };
  }
  if (opts.submittedAt && !submittedAtCol) {
    return { ok: false, error: 'Required column missing (submittedAt).' };
  }

  const nowIso = String(opts.submittedAt || new Date().toISOString());
  const stateToStore = JSON.parse(JSON.stringify(portalState));
  stateToStore.version = String(stateToStore.version || '1');
  stateToStore.savedAt = nowIso;
  stateToStore.isReadOnly = opts.locked === true;
  const derivedStatus = derivePortalDisplayOrderStatus_(Object.assign({}, rowInfo.rowObjNormalized || {}, {
    portalLockState: opts.locked === true ? PORTAL_LOCK_STATES.locked : PORTAL_LOCK_STATES.editable,
    currentOrderState: opts.currentOrderState,
    currentPaymentState: opts.currentPaymentState,
    currentProductionAuthorizationState: opts.currentProductionAuthorizationState,
    currentPaymentMethod: opts.currentPaymentMethod,
    paidAt: opts.paidAt,
    authorizedToProduceAt: opts.authorizedToProduceAt,
    status: opts.status || (rowInfo.rowObjNormalized && rowInfo.rowObjNormalized.status)
  }), opts.status);
  if (Array.isArray(opts.chatLog)) {
    writeChatLogIntoPortalState_(stateToStore, normalizeChatLog_(opts.chatLog));
  }

  sheet.getRange(row, portalStateCol).setValue(JSON.stringify(stateToStore));
  sheet.getRange(row, statusCol).setValue(derivedStatus);
  if (Array.isArray(opts.chatLog) && chatCol) {
    sheet.getRange(row, chatCol).setValue(JSON.stringify(normalizeChatLog_(opts.chatLog)));
  }
  if (opts.submittedAt && submittedAtCol) {
    sheet.getRange(row, submittedAtCol).setValue(nowIso);
  } else if (opts.clearSubmittedAt === true && submittedAtCol) {
    sheet.getRange(row, submittedAtCol).setValue('');
  }
  if (opts.writeSubmittedState === true && submittedStateCol) {
    const existingSubmittedState = rowInfo.rowObjNormalized
      ? rowInfo.rowObjNormalized.submittedstatejson
      : '';
    if (!hasNonBlankJsonSignal_(existingSubmittedState)) {
      const submittedState = JSON.parse(JSON.stringify(stateToStore));
      sheet.getRange(row, submittedStateCol).setValue(JSON.stringify(submittedState));
    }
  }
  SpreadsheetApp.flush();
  try {
    invalidateDashboardProjectsCacheForRow_(buildRowInfoFromSheet_(sheet, row));
  } catch (_) {}

  return {
    ok: true,
    token: String(opts.token || ''),
    status: derivedStatus,
    savedAt: nowIso,
    submittedAt: opts.submittedAt ? nowIso : ''
  };
}

function normalizeMode_(value) {
  const s = String(value || '').trim().toLowerCase();
  return (s === 'team') ? 'team' : 'client';
}

/* ---------------- Workbook Infrastructure + Shared Helpers ---------------- */

function ensureTeamModeEmailAccessSecret_(props) {
  const store = props || PropertiesService.getScriptProperties();
  let secret = String(store.getProperty(CONFIG_KEYS.TEAM_MODE_EMAIL_ACCESS_SECRET) || '').trim();
  if (secret) return secret;
  secret = [
    Utilities.getUuid(),
    Utilities.getUuid(),
    String(Date.now())
  ].join(':');
  try {
    store.setProperty(CONFIG_KEYS.TEAM_MODE_EMAIL_ACCESS_SECRET, secret);
  } catch (_) {
    // Fall back to the in-memory value for this execution; the next execution
    // will retry persistence before any email-link verification succeeds.
  }
  return secret;
}

function getConfig_() {
  const props = PropertiesService.getScriptProperties();
  const driveFolderDefaults = {};
  driveFolderDefaults[CONFIG_KEYS.INVOICE_DRIVE_FOLDER_ID] = DEFAULT_INVOICE_DRIVE_FOLDER_ID;
  driveFolderDefaults[CONFIG_KEYS.TERMS_DRIVE_FOLDER_ID] = DEFAULT_TERMS_DRIVE_FOLDER_ID;
  driveFolderDefaults[CONFIG_KEYS.TAX_EXEMPT_DRIVE_FOLDER_ID] = DEFAULT_TAX_EXEMPT_DRIVE_FOLDER_ID;

  // Keep script property aligned to the required bound sheet.
  if (props.getProperty(CONFIG_KEYS.SHEET_ID) !== REQUIRED_SHEET_ID) {
    try {
      props.setProperty(CONFIG_KEYS.SHEET_ID, REQUIRED_SHEET_ID);
    } catch (_) {
      // Continue using REQUIRED_SHEET_ID even if property write is unavailable.
    }
  }

  Object.keys(driveFolderDefaults).forEach(key => {
    if (props.getProperty(key) !== driveFolderDefaults[key]) {
      try {
        props.setProperty(key, driveFolderDefaults[key]);
      } catch (_) {
        // Continue using the checked-in folder IDs even if property write is unavailable.
      }
    }
  });

  const sheetId = REQUIRED_SHEET_ID;
  const exportLogSheetName = props.getProperty(CONFIG_KEYS.EXPORT_LOG_SHEET) || 'EXPORT_LOG';
  const portalOrdersSheetName = props.getProperty(CONFIG_KEYS.PORTAL_ORDERS_SHEET) || DEFAULT_PORTAL_ORDERS_SHEET;
  const portalAccountsSheetName = props.getProperty(CONFIG_KEYS.PORTAL_ACCOUNTS_SHEET) || DEFAULT_PORTAL_ACCOUNTS_SHEET;
  const teamModePassword = String(props.getProperty(CONFIG_KEYS.TEAM_MODE_PASSWORD) || DEFAULT_TEAM_MODE_PASSWORD).trim();
  const teamModeEmailAccessSecret = ensureTeamModeEmailAccessSecret_(props);
  const stripePublishableKey = String(props.getProperty(CONFIG_KEYS.STRIPE_PUBLISHABLE_KEY) || '').trim();
  const stripeSecretKey = String(props.getProperty(CONFIG_KEYS.STRIPE_SECRET_KEY) || '').trim();
  const stripeWebhookSecret = String(props.getProperty(CONFIG_KEYS.STRIPE_WEBHOOK_SECRET) || '').trim();
  const stripeWebhookForwardSharedSecret = String(props.getProperty(CONFIG_KEYS.STRIPE_WEBHOOK_FORWARD_SHARED_SECRET) || '').trim();
  const stripeAchEnabled = parseConfigBoolean_(
    props.getProperty(CONFIG_KEYS.STRIPE_ACH_ENABLED),
    DEFAULT_STRIPE_ACH_ENABLED
  );
  const stripeAchVerificationMethod = normalizeStripeAchVerificationMethod_(
    props.getProperty(CONFIG_KEYS.STRIPE_ACH_VERIFICATION_METHOD) || DEFAULT_STRIPE_ACH_VERIFICATION_METHOD
  );
  const stripeAchFinancialConnectionsPermissions = parseStripeAchFinancialConnectionsPermissions_(
    props.getProperty(CONFIG_KEYS.STRIPE_ACH_FINANCIAL_CONNECTIONS_PERMISSIONS)
  );
  const stripeAchSaveForFuture = parseConfigBoolean_(
    props.getProperty(CONFIG_KEYS.STRIPE_ACH_SAVE_FOR_FUTURE),
    DEFAULT_STRIPE_ACH_SAVE_FOR_FUTURE
  );
  const stripeAchRequireCustomer = parseConfigBoolean_(
    props.getProperty(CONFIG_KEYS.STRIPE_ACH_REQUIRE_CUSTOMER),
    DEFAULT_STRIPE_ACH_REQUIRE_CUSTOMER
  );
  const stripeAchDefaultPendingProductionApproved = parseConfigBoolean_(
    props.getProperty(CONFIG_KEYS.STRIPE_ACH_DEFAULT_PENDING_PRODUCTION_APPROVED),
    DEFAULT_STRIPE_ACH_DEFAULT_PENDING_PRODUCTION_APPROVED
  );
  const emailReviewTriggerSecret = String(props.getProperty(CONFIG_KEYS.EMAIL_REVIEW_TRIGGER_SECRET) || '').trim();
  const termsDocumentUrl = String(props.getProperty(CONFIG_KEYS.TERMS_DOCUMENT_URL) || DEFAULT_TERMS_DOCUMENT_URL).trim();
  const creditTermsFormFileId = String(props.getProperty(CONFIG_KEYS.CREDIT_TERMS_FORM_FILE_ID) || DEFAULT_CREDIT_TERMS_FORM_FILE_ID).trim();
  const taxExemptFormFileId = String(props.getProperty(CONFIG_KEYS.TAX_EXEMPT_FORM_FILE_ID) || DEFAULT_TAX_EXEMPT_FORM_FILE_ID).trim();
  const invoiceDriveFolderId = DEFAULT_INVOICE_DRIVE_FOLDER_ID;
  const termsDriveFolderId = DEFAULT_TERMS_DRIVE_FOLDER_ID;
  const taxExemptDriveFolderId = DEFAULT_TAX_EXEMPT_DRIVE_FOLDER_ID;
  const stripePriceCurrency = String(props.getProperty(CONFIG_KEYS.STRIPE_PRICE_CURRENCY) || DEFAULT_STRIPE_PRICE_CURRENCY).trim().toUpperCase() || DEFAULT_STRIPE_PRICE_CURRENCY;
  const stripeMode = String(props.getProperty(CONFIG_KEYS.STRIPE_MODE) || DEFAULT_STRIPE_MODE).trim().toLowerCase() || DEFAULT_STRIPE_MODE;
  const stripeReturnUrl = String(props.getProperty(CONFIG_KEYS.STRIPE_RETURN_URL) || props.getProperty(CONFIG_KEYS.SUCCESS_REDIRECT_URL) || '').trim();
  const successRedirectUrl = String(props.getProperty(CONFIG_KEYS.SUCCESS_REDIRECT_URL) || '').trim();

  return {
    sheetId: sheetId,
    exportLogSheetName: exportLogSheetName,
    portalOrdersSheetName: portalOrdersSheetName,
    portalAccountsSheetName: portalAccountsSheetName,
    teamModePassword: teamModePassword,
    teamModeEmailAccessSecret: teamModeEmailAccessSecret,
    stripePublishableKey: stripePublishableKey,
    stripeSecretKey: stripeSecretKey,
    stripeWebhookSecret: stripeWebhookSecret,
    stripeWebhookForwardSharedSecret: stripeWebhookForwardSharedSecret,
    stripeAchEnabled: stripeAchEnabled,
    stripeAchVerificationMethod: stripeAchVerificationMethod,
    stripeAchFinancialConnectionsPermissions: stripeAchFinancialConnectionsPermissions,
    stripeAchSaveForFuture: stripeAchSaveForFuture,
    stripeAchRequireCustomer: stripeAchRequireCustomer,
    stripeAchDefaultPendingProductionApproved: stripeAchDefaultPendingProductionApproved,
    emailReviewTriggerSecret: emailReviewTriggerSecret,
    termsDocumentUrl: termsDocumentUrl,
    creditTermsFormFileId: creditTermsFormFileId,
    taxExemptFormFileId: taxExemptFormFileId,
    invoiceDriveFolderId: invoiceDriveFolderId,
    termsDriveFolderId: termsDriveFolderId,
    taxExemptDriveFolderId: taxExemptDriveFolderId,
    stripePriceCurrency: stripePriceCurrency,
    stripeMode: stripeMode,
    stripeReturnUrl: stripeReturnUrl,
    successRedirectUrl: successRedirectUrl
  };
}

function parseConfigBoolean_(value, defaultValue) {
  if (value === true || value === false) return value;
  const raw = String(value == null ? '' : value).trim().toLowerCase();
  if (!raw) return defaultValue === true;
  if (raw === 'true' || raw === 'yes' || raw === 'y' || raw === '1' || raw === 'enabled' || raw === 'on') return true;
  if (raw === 'false' || raw === 'no' || raw === 'n' || raw === '0' || raw === 'disabled' || raw === 'off') return false;
  return defaultValue === true;
}

function normalizeStripeAchVerificationMethod_(value) {
  const raw = trimString_(value).toLowerCase();
  if (raw === 'instant' || raw === 'microdeposits' || raw === 'automatic') return raw;
  return DEFAULT_STRIPE_ACH_VERIFICATION_METHOD;
}

function parseStripeAchFinancialConnectionsPermissions_(value) {
  const raw = String(value == null ? '' : value).trim();
  const items = raw
    ? raw.split(/[\s,;|]+/).map(function(item) { return trimString_(item).toLowerCase(); }).filter(Boolean)
    : DEFAULT_STRIPE_ACH_FINANCIAL_CONNECTIONS_PERMISSIONS.slice();
  const allowed = {
    payment_method: true
  };
  const normalized = uniqueTrimmedStrings_(items).filter(function(item) {
    return allowed[item] === true;
  });
  return normalized.length ? normalized : DEFAULT_STRIPE_ACH_FINANCIAL_CONNECTIONS_PERMISSIONS.slice();
}

function buildPortalFeatureFlags_(cfg) {
  const config = cfg || getConfig_();
  return {
    achPaymentEnabled: config.stripeAchEnabled === true,
    achVerificationMethod: trimString_(config.stripeAchVerificationMethod) || DEFAULT_STRIPE_ACH_VERIFICATION_METHOD,
    achFinancialConnectionsPermissions: Array.isArray(config.stripeAchFinancialConnectionsPermissions)
      ? config.stripeAchFinancialConnectionsPermissions.slice()
      : DEFAULT_STRIPE_ACH_FINANCIAL_CONNECTIONS_PERMISSIONS.slice()
  };
}

function boolFromCell_(value) {
  if (value === true || value === false) return value;
  const raw = String(value == null ? '' : value).trim().toLowerCase();
  if (!raw) return false;
  return raw === 'true' || raw === 'yes' || raw === 'y' || raw === '1' || raw === 'approved';
}

function trimString_(value) {
  return String(value == null ? '' : value).trim();
}

function toFiniteNumber_(value, fallback) {
  const num = Number(value);
  return Number.isFinite(num) ? num : Number(fallback || 0);
}

function roundMoney_(value) {
  return Math.round(toFiniteNumber_(value, 0) * 100) / 100;
}

function nowIso_() {
  return new Date().toISOString();
}

function newPortalId_(prefix) {
  const safePrefix = String(prefix || 'id').trim() || 'id';
  return safePrefix + '_' + Utilities.getUuid().replace(/-/g, '');
}

function safeSheetName_(value, fallback) {
  const raw = trimString_(value);
  return raw || String(fallback || '').trim();
}

function ensureSheetHeaders_(sheet, requiredHeaders) {
  const required = Array.isArray(requiredHeaders) ? requiredHeaders : [];
  if (!sheet) throw new Error('Sheet is required.');

  const hasAnyColumns = sheet.getMaxColumns() > 0 || sheet.getLastColumn() > 0;
  const existingHeader = hasAnyColumns && sheet.getLastRow() >= 1
    ? sheet.getRange(1, 1, 1, Math.max(1, sheet.getLastColumn())).getValues()[0]
    : [];

  const existingNormalized = new Set(
    existingHeader
      .map(normalizeHeaderKey_)
      .filter(Boolean)
  );

  const missing = required.filter(header => !existingNormalized.has(normalizeHeaderKey_(header)));
  if (!existingHeader.length) {
    const width = Math.max(1, required.length);
    if (sheet.getMaxColumns() < width) {
      sheet.insertColumnsAfter(sheet.getMaxColumns(), width - sheet.getMaxColumns());
    }
    sheet.getRange(1, 1, 1, width).setValues([required.slice(0, width)]);
  } else if (missing.length) {
    const startCol = sheet.getLastColumn() + 1;
    sheet.insertColumnsAfter(sheet.getLastColumn(), missing.length);
    sheet.getRange(1, startCol, 1, missing.length).setValues([missing]);
  }

  const header = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  return buildColumnMap_(header);
}

function ensureNamedSheetWithHeaders_(ss, name, headers) {
  const sheetName = safeSheetName_(name, '');
  if (!sheetName) throw new Error('Sheet name is required.');
  let sheet = ss.getSheetByName(sheetName);
  if (!sheet) sheet = ss.insertSheet(sheetName);
  ensureSheetHeaders_(sheet, headers);
  return sheet;
}

// Keep the live workbook contract frozen here: EXPORT_LOG, USERS,
// USER_SESSIONS, PORTAL_ORDERS, and PORTAL_ACCOUNTS.
function ensurePortalInfrastructure_(ss, cfg) {
  const exportSheet = ss.getSheetByName(cfg.exportLogSheetName);
  if (!exportSheet) {
    throw new Error('EXPORT_LOG sheet not found.');
  }
  ensureSheetHeaders_(exportSheet, EXPORT_LOG_POINTER_HEADERS);

  const usersSheet = ensureNamedSheetWithHeaders_(ss, AUTH_SHEETS.USERS, USER_HEADERS);
  const sessionsSheet = ensureNamedSheetWithHeaders_(ss, AUTH_SHEETS.USER_SESSIONS, USER_SESSION_HEADERS);
  const ordersSheet = ensureNamedSheetWithHeaders_(ss, cfg.portalOrdersSheetName, PORTAL_ORDER_HEADERS);
  const accountsSheet = ensureNamedSheetWithHeaders_(ss, cfg.portalAccountsSheetName, PORTAL_ACCOUNT_HEADERS);
  const stripeEventsSheet = ensureNamedSheetWithHeaders_(ss, PORTAL_STRIPE_EVENTS_SHEET_NAME, PORTAL_STRIPE_EVENTS_HEADERS);

  return {
    exportSheet: exportSheet,
    usersSheet: usersSheet,
    sessionsSheet: sessionsSheet,
    ordersSheet: ordersSheet,
    accountsSheet: accountsSheet,
    stripeEventsSheet: stripeEventsSheet
  };
}

function buildRowInfoFromSheet_(sheet, row, header, rowVals) {
  const safeHeader = Array.isArray(header) ? header : sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  const safeRowVals = Array.isArray(rowVals) ? rowVals : sheet.getRange(row, 1, 1, sheet.getLastColumn()).getValues()[0];
  const rowObj = {};
  const rowObjNormalized = {};
  safeHeader.forEach((h, idx) => {
    const rawKey = String(h || '').trim();
    rowObj[rawKey] = safeRowVals[idx];
    rowObjNormalized[normalizeHeaderKey_(rawKey)] = safeRowVals[idx];
  });
  return {
    row: row,
    rowObj: rowObj,
    rowObjNormalized: rowObjNormalized,
    colMap: buildColumnMap_(safeHeader)
  };
}

function listSheetRowInfos_(sheet) {
  const lastRow = sheet.getLastRow();
  const lastCol = sheet.getLastColumn();
  if (lastRow < 2 || lastCol < 1) return [];
  const header = sheet.getRange(1, 1, 1, lastCol).getValues()[0];
  const rows = sheet.getRange(2, 1, lastRow - 1, lastCol).getValues();
  return rows.map((rowVals, idx) => buildRowInfoFromSheet_(sheet, idx + 2, header, rowVals));
}

function setRowValuesByHeaderMap_(sheet, row, colMap, updates) {
  Object.keys(updates || {}).forEach((headerKey) => {
    const col = colMap[normalizeHeaderKey_(headerKey)] || colMap[headerKey];
    if (!col) return;
    sheet.getRange(row, col).setValue(updates[headerKey]);
  });
}

function getUserContextBySessionId_(ss, sessionId) {
  const id = trimString_(sessionId);
  if (!id) return { ok: false, error: 'Missing session.' };
  const sessionsSheet = ensureNamedSheetWithHeaders_(ss, AUTH_SHEETS.USER_SESSIONS, USER_SESSION_HEADERS);
  const session = validateSession_(sessionsSheet, id);
  if (!session.ok) return session;
  const usersSheet = ensureNamedSheetWithHeaders_(ss, AUTH_SHEETS.USERS, USER_HEADERS);
  const user = findUserByEmail_(usersSheet, session.email);
  return {
    ok: true,
    email: session.email,
    session: session,
    user: user
  };
}

function deriveOrgContextFromRow_(row) {
  const normalizedRow = (row && typeof row === 'object') ? row : {};
  return {
    orgId: trimString_(
      normalizedRow.orgid ||
      normalizedRow.companyid ||
      normalizedRow.accountorgid
    ),
    orgName: trimString_(
      normalizedRow.orgname ||
      normalizedRow.company ||
      normalizedRow.companyname
    ),
    personEmail: normalizeEmail_(
      normalizedRow.personemail ||
      normalizedRow.primaryemail
    ),
    personName: trimString_(
      normalizedRow.personname ||
      normalizedRow.clientname ||
      normalizedRow.primarycontactname
    )
  };
}

function buildAccountIdentityFromInputs_(opts) {
  const options = (opts && typeof opts === 'object') ? opts : {};
  return {
    orgId: trimString_(options.orgId),
    orgName: trimString_(options.orgName),
    personEmail: normalizeEmail_(options.personEmail || options.primaryEmail || options.email),
    personName: trimString_(options.personName || options.primaryContactName || options.displayName),
    billingContactEmail: normalizeEmail_(options.billingContactEmail || options.personEmail || options.primaryEmail || options.email),
    billingContactName: trimString_(options.billingContactName || options.personName || options.primaryContactName || options.displayName)
  };
}

function mergeAccountIdentity_(baseIdentity, overrideIdentity) {
  const base = buildAccountIdentityFromInputs_(baseIdentity);
  const override = buildAccountIdentityFromInputs_(overrideIdentity);
  return {
    orgId: override.orgId || base.orgId,
    orgName: override.orgName || base.orgName,
    personEmail: override.personEmail || base.personEmail,
    personName: override.personName || base.personName,
    billingContactEmail: override.billingContactEmail || base.billingContactEmail || override.personEmail || base.personEmail,
    billingContactName: override.billingContactName || base.billingContactName || override.personName || base.personName
  };
}

function normalizeAccountDocumentType_(value) {
  const raw = trimString_(value).toLowerCase();
  if (raw === 'terms' || raw === 'credit_terms' || raw === 'creditterms') return ACCOUNT_DOCUMENT_TYPES.credit_terms;
  if (raw === 'tax' || raw === 'tax_exempt' || raw === 'taxexempt' || raw === 'michigan_tax_exempt') return ACCOUNT_DOCUMENT_TYPES.tax_exempt;
  return '';
}

function getAccountDocumentWorkflowKey_(documentType) {
  const type = normalizeAccountDocumentType_(documentType);
  if (type === ACCOUNT_DOCUMENT_TYPES.credit_terms) return 'creditTerms';
  if (type === ACCOUNT_DOCUMENT_TYPES.tax_exempt) return 'taxExempt';
  return '';
}

function normalizeAccountDocumentStatus_(value) {
  const raw = trimString_(value).toLowerCase();
  if (!raw) return 'not_started';
  if (raw === 'pending_submission') return 'submitted';
  if (raw === 'submitted' || raw === 'under_review' || raw === 'approved' || raw === 'rejected' || raw === 'denied' || raw === 'not_started') {
    return raw;
  }
  return raw;
}

function buildDriveFileViewUrl_(fileId) {
  const id = trimString_(fileId);
  return id ? ('https://drive.google.com/file/d/' + encodeURIComponent(id) + '/view') : '';
}

function buildDriveFilePreviewUrl_(fileId) {
  const id = trimString_(fileId);
  return id ? ('https://drive.google.com/file/d/' + encodeURIComponent(id) + '/preview') : '';
}

function buildDriveFileDownloadUrl_(fileId) {
  const id = trimString_(fileId);
  return id ? ('https://drive.google.com/uc?export=download&id=' + encodeURIComponent(id)) : '';
}

function extractDriveFileIdFromUrl_(value) {
  const text = trimString_(value);
  if (!text) return '';
  let match = text.match(/\/file\/d\/([a-zA-Z0-9_-]+)/i);
  if (match && match[1]) return trimString_(match[1]);
  match = text.match(/[?&]id=([a-zA-Z0-9_-]+)/i);
  if (match && match[1]) return trimString_(match[1]);
  match = text.match(/\/d\/([a-zA-Z0-9_-]+)/i);
  if (match && match[1]) return trimString_(match[1]);
  return '';
}

function buildApprovedTaxViewerArtifactFromSummary_(summary) {
  const data = (summary && typeof summary === 'object') ? summary : {};
  const storedUrl = trimString_(data.taxExemptCertificateUrl);
  const fileId = extractDriveFileIdFromUrl_(storedUrl);
  if (!storedUrl && !fileId) return null;
  const sourceFile = fileId ? getDriveFileByIdSafe_(fileId) : null;
  const fileName = sourceFile
    ? sanitizeUploadedDocumentName_(sourceFile.getName(), 'Michigan-Tax-Exemption-Certificate')
    : 'Michigan-Tax-Exemption-Certificate';
  const mimeType = trimString_(sourceFile ? sourceFile.getMimeType() : '') || MimeType.PDF;
  const isImage = /^image\//i.test(mimeType);
  const inlineAsset = fileId
    ? buildDriveBinaryDataPayload_(fileId, fileName, mimeType)
    : null;
  return {
    fileId: fileId,
    fileName: fileName,
    mimeType: mimeType,
    fileUrl: storedUrl || buildDriveFileViewUrl_(fileId),
    previewUrl: fileId ? buildDriveFilePreviewUrl_(fileId) : storedUrl,
    imageUrl: (isImage && fileId) ? buildDriveFilePublicViewAssetUrl_(fileId) : '',
    imageCandidates: (isImage && fileId) ? buildDriveFilePublicImageCandidates_(fileId) : [],
    base64Data: inlineAsset ? trimString_(inlineAsset.base64Data) : '',
    submittedAt: trimString_(data.taxExemptSubmittedAt),
    submittedByName: trimString_(data.primaryContactName),
    submittedByEmail: normalizeEmail_(data.primaryEmail)
  };
}

function buildApprovedCreditTermsViewerArtifactFromSummary_(summary) {
  const data = (summary && typeof summary === 'object') ? summary : {};
  const storedUrl = trimString_(data.signedTermsFileUrl);
  const fileId = extractDriveFileIdFromUrl_(storedUrl);
  if (!storedUrl && !fileId) return null;
  const sourceFile = fileId ? getDriveFileByIdSafe_(fileId) : null;
  const fileName = sourceFile
    ? sanitizeUploadedDocumentName_(sourceFile.getName(), 'Red-Threads-Credit-Terms')
    : 'Red-Threads-Credit-Terms';
  const mimeType = trimString_(sourceFile ? sourceFile.getMimeType() : '') || MimeType.PDF;
  const isImage = /^image\//i.test(mimeType);
  const inlineAsset = fileId
    ? buildDriveBinaryDataPayload_(fileId, fileName, mimeType)
    : null;
  return {
    fileId: fileId,
    fileName: fileName,
    mimeType: mimeType,
    fileUrl: storedUrl || buildDriveFileViewUrl_(fileId),
    previewUrl: fileId ? buildDriveFilePreviewUrl_(fileId) : storedUrl,
    imageUrl: (isImage && fileId) ? buildDriveFilePublicViewAssetUrl_(fileId) : '',
    imageCandidates: (isImage && fileId) ? buildDriveFilePublicImageCandidates_(fileId) : [],
    base64Data: inlineAsset ? trimString_(inlineAsset.base64Data) : '',
    submittedAt: trimString_(data.signedTermsSubmittedAt),
    submittedByName: trimString_(data.primaryContactName),
    submittedByEmail: normalizeEmail_(data.primaryEmail)
  };
}

function getApprovedPaymentTermsOptions_() {
  return APPROVED_PAYMENT_TERMS_OPTIONS.map(function(option) {
    return {
      code: trimString_(option.code),
      label: trimString_(option.label),
      days: Math.max(0, parseInt(String(option.days || 0), 10) || 0)
    };
  });
}

function getApprovedPaymentTermsOptionByCode_(value) {
  const code = trimString_(value).toLowerCase();
  if (!code) return null;
  const options = getApprovedPaymentTermsOptions_();
  for (var i = 0; i < options.length; i += 1) {
    if (trimString_(options[i].code).toLowerCase() === code) {
      return options[i];
    }
  }
  return null;
}

function buildApprovedPaymentTermsSelection_(payload) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  const option = getApprovedPaymentTermsOptionByCode_(
    p.paymentTermsCode || p.approvedPaymentTermsCode || p.termsCode || p.code
  );
  if (!option) {
    throw new Error('Select an approved payment term before approving credit terms.');
  }
  return {
    code: option.code,
    label: option.label,
    days: option.days,
    notes: trimString_(p.paymentTermsNotes || p.approvedPaymentTermsNotes || p.notes)
  };
}

function buildApprovedPaymentTermsSummaryFromRow_(row) {
  const source = (row && typeof row === 'object') ? row : {};
  return {
    code: trimString_(source.approvedpaymenttermscode || source.approvedPaymentTermsCode),
    label: trimString_(source.approvedpaymenttermslabel || source.approvedPaymentTermsLabel),
    days: Math.max(0, parseInt(String(source.approvedpaymenttermsdays || source.approvedPaymentTermsDays || 0), 10) || 0),
    notes: trimString_(source.approvedpaymenttermsnotes || source.approvedPaymentTermsNotes),
    setAt: trimString_(source.approvedpaymenttermssetat || source.approvedPaymentTermsSetAt),
    setByName: trimString_(source.approvedpaymenttermssetbyname || source.approvedPaymentTermsSetByName),
    setByEmail: normalizeEmail_(source.approvedpaymenttermssetbyemail || source.approvedPaymentTermsSetByEmail)
  };
}

function normalizeAchPaymentSource_(value) {
  const raw = trimString_(value).toLowerCase();
  if (!raw) return ACH_PAYMENT_METHOD_SOURCES.order_checkout;
  if (raw === 'ap' || raw === 'ap_payment' || raw === 'ap_payment_link' || raw === 'accounts_payable') {
    return ACH_PAYMENT_METHOD_SOURCES.ap_payment_link;
  }
  if (raw === 'dashboard' || raw === 'dashboard_setup' || raw === 'dashboard_bank_setup') {
    return ACH_PAYMENT_METHOD_SOURCES.dashboard_setup;
  }
  if (raw === 'stripe_auto_update') return ACH_PAYMENT_METHOD_SOURCES.stripe_auto_update;
  if (raw === 'checkout_payment') return ACH_PAYMENT_METHOD_SOURCES.checkout_payment;
  if (raw === 'order_checkout' || raw === 'order_payment') return ACH_PAYMENT_METHOD_SOURCES.order_checkout;
  return raw;
}

function normalizeAchCheckoutIntent_(value) {
  const raw = trimString_(value).toLowerCase();
  if (raw === ACH_CHECKOUT_INTENTS.saved_bank ||
      raw === ACH_CHECKOUT_INTENTS.new_bank ||
      raw === ACH_CHECKOUT_INTENTS.unspecified) {
    return raw;
  }
  if (raw === 'saved' || raw === 'saved_payment_method' || raw === 'default_bank') {
    return ACH_CHECKOUT_INTENTS.saved_bank;
  }
  if (raw === 'new' || raw === 'connect_bank' || raw === 'new_payment_method') {
    return ACH_CHECKOUT_INTENTS.new_bank;
  }
  return ACH_CHECKOUT_INTENTS.unspecified;
}

function normalizeAchVisibilityScope_(value) {
  const raw = trimString_(value).toLowerCase();
  if (!raw) return '';
  if (raw === ACH_PAYMENT_VISIBILITY_SCOPES.dashboard_saved ||
      raw === ACH_PAYMENT_VISIBILITY_SCOPES.order_only ||
      raw === ACH_PAYMENT_VISIBILITY_SCOPES.hidden_from_dashboard ||
      raw === ACH_PAYMENT_VISIBILITY_SCOPES.blocked ||
      raw === ACH_PAYMENT_VISIBILITY_SCOPES.removed) {
    return raw;
  }
  if (raw === 'dashboard' || raw === 'saved' || raw === 'account_saved') return ACH_PAYMENT_VISIBILITY_SCOPES.dashboard_saved;
  if (raw === 'order' || raw === 'ap') return ACH_PAYMENT_VISIBILITY_SCOPES.order_only;
  return raw;
}

function inferAchVisibilityScope_(source, status, existingScope) {
  const scope = normalizeAchVisibilityScope_(existingScope);
  if (scope) return scope;
  const normalizedSource = normalizeAchPaymentSource_(source);
  const normalizedStatus = normalizeAchPaymentMethodStatus_(status);
  if (normalizedStatus === 'removed') return ACH_PAYMENT_VISIBILITY_SCOPES.removed;
  if (normalizedSource === ACH_PAYMENT_METHOD_SOURCES.dashboard_setup) return ACH_PAYMENT_VISIBILITY_SCOPES.dashboard_saved;
  if (normalizedSource === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link ||
      normalizedSource === ACH_PAYMENT_METHOD_SOURCES.order_checkout ||
      normalizedSource === ACH_PAYMENT_METHOD_SOURCES.checkout_payment) {
    return ACH_PAYMENT_VISIBILITY_SCOPES.order_only;
  }
  return ACH_PAYMENT_VISIBILITY_SCOPES.hidden_from_dashboard;
}

function normalizeAchPaymentMethodStatus_(value) {
  const raw = trimString_(value).toLowerCase();
  if (!raw) return 'pending';
  if (raw === 'active' || raw === 'pending' || raw === 'failed' || raw === 'blocked' || raw === 'removed') return raw;
  return raw;
}

function normalizeAchPaymentMethodSummary_(value) {
  const source = (value && typeof value === 'object') ? value : {};
  const paymentMethodId = trimString_(source.paymentMethodId || source.paymentmethodid || source.id);
  if (!paymentMethodId) return null;
  const status = normalizeAchPaymentMethodStatus_(source.status);
  const methodSource = normalizeAchPaymentSource_(source.source);
  return {
    paymentMethodId: paymentMethodId,
    stripeCustomerId: trimString_(source.stripeCustomerId || source.stripecustomerid),
    bankName: trimString_(source.bankName || source.bankname),
    last4: trimString_(source.last4).slice(-4),
    accountHolderType: trimString_(source.accountHolderType || source.accountholdertype),
    accountType: trimString_(source.accountType || source.accounttype),
    financialConnectionsAccountId: trimString_(source.financialConnectionsAccountId || source.financialconnectionsaccountid),
    mandateId: trimString_(source.mandateId || source.mandateid),
    verificationStatus: trimString_(source.verificationStatus || source.verificationstatus),
    status: status,
    isDefault: source.isDefault === true || boolFromCell_(source.isdefault),
    createdAt: trimString_(source.createdAt || source.createdat),
    updatedAt: trimString_(source.updatedAt || source.updatedat),
    source: methodSource,
    visibilityScope: inferAchVisibilityScope_(methodSource, status, source.visibilityScope || source.visibilityscope),
    linkedOrderId: trimString_(source.linkedOrderId || source.linkedorderid),
    linkedCheckoutAttemptId: trimString_(source.linkedCheckoutAttemptId || source.linkedcheckoutattemptid),
    linkedBy: trimString_(source.linkedBy || source.linkedby),
    setupIntentId: trimString_(source.setupIntentId || source.setupintentid),
    setupSessionId: trimString_(source.setupSessionId || source.setupsessionid),
    paymentIntentId: trimString_(source.paymentIntentId || source.paymentintentid),
    setupStatus: trimString_(source.setupStatus || source.setupstatus)
  };
}

function normalizeAchPaymentMethodsJson_(value) {
  const parsed = Array.isArray(value) ? value : safeJsonParse_(value, []);
  if (!Array.isArray(parsed)) return [];
  const seen = {};
  return parsed.map(normalizeAchPaymentMethodSummary_).filter(function(item) {
    if (!item || seen[item.paymentMethodId]) return false;
    seen[item.paymentMethodId] = true;
    return true;
  });
}

function stripeIdFromObject_(value) {
  if (typeof value === 'string') return trimString_(value);
  if (value && typeof value === 'object') return trimString_(value.id);
  return '';
}

function stripeApiRequest_(path, params, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const method = trimString_(opts.method || 'get').toLowerCase();
  const cleanPath = '/' + trimString_(path).replace(/^\/+/, '');
  if (!trimString_(cfg.stripeSecretKey)) {
    return {
      ok: false,
      configured: false,
      statusCode: 0,
      code: 'stripe_config_missing',
      error: 'Stripe secret key is not configured.'
    };
  }
  const requestParams = (params && typeof params === 'object') ? params : {};
  let url = 'https://api.stripe.com' + cleanPath;
  const request = {
    method: method,
    headers: {
      Authorization: 'Bearer ' + cfg.stripeSecretKey,
      'Stripe-Version': trimString_(opts.stripeVersion || DEFAULT_STRIPE_CHECKOUT_SESSION_API_VERSION)
    },
    muteHttpExceptions: true
  };
  if (method === 'get' || method === 'delete') {
    url = appendQueryParamsToUrl_(url, requestParams);
  } else {
    request.payload = requestParams;
  }

  let response;
  try {
    response = UrlFetchApp.fetch(url, request);
  } catch (err) {
    return {
      ok: false,
      configured: true,
      statusCode: 0,
      code: 'stripe_request_failed',
      error: String((err && err.message) || err)
    };
  }
  const statusCode = Number(response.getResponseCode() || 0);
  const bodyText = String(response.getContentText() || '');
  const body = safeJsonParse_(bodyText, null);
  const headers = response.getAllHeaders ? (response.getAllHeaders() || {}) : {};
  const responseStripeVersion = getHttpHeaderValue_(headers, 'Stripe-Version');
  if (statusCode < 200 || statusCode >= 300 || !body || typeof body !== 'object') {
    return {
      ok: false,
      configured: true,
      statusCode: statusCode,
      code: trimString_(body && body.error && body.error.code) || 'stripe_api_error',
      error: trimString_(body && body.error && body.error.message) || 'Stripe API request failed.',
      stripeVersion: trimString_(opts.stripeVersion || DEFAULT_STRIPE_CHECKOUT_SESSION_API_VERSION),
      responseStripeVersion: responseStripeVersion
    };
  }
  return {
    ok: true,
    configured: true,
    statusCode: statusCode,
    body: body,
    stripeVersion: trimString_(opts.stripeVersion || DEFAULT_STRIPE_CHECKOUT_SESSION_API_VERSION),
    responseStripeVersion: responseStripeVersion
  };
}

function retrieveStripeCustomer_(stripeCustomerId, options) {
  const customerId = trimString_(stripeCustomerId);
  if (!customerId) return { ok: false, error: 'Missing Stripe Customer ID.' };
  return stripeApiRequest_('/v1/customers/' + encodeURIComponent(customerId), {}, Object.assign({}, options || {}, {
    method: 'get'
  }));
}

function buildStripeCustomerSafeProfile_(accountSummary) {
  const account = (accountSummary && typeof accountSummary === 'object') ? accountSummary : {};
  return {
    email: normalizeEmail_(account.primaryEmail || account.billingContactEmail),
    name: trimString_(account.primaryContactName || account.orgName)
  };
}

function refreshStripeCustomerSafeProfile_(stripeCustomerId, accountSummary, options) {
  const customerId = trimString_(stripeCustomerId);
  if (!customerId) return { ok: false, code: 'stripe_customer_required', error: 'Missing Stripe Customer ID.' };
  const opts = (options && typeof options === 'object') ? options : {};
  const current = (opts.customer && typeof opts.customer === 'object') ? opts.customer : {};
  const profile = buildStripeCustomerSafeProfile_(accountSummary);
  const collectSetupEmailInCheckout = opts.collectSetupEmailInCheckout === true;
  const params = {};
  if (collectSetupEmailInCheckout) {
    if (normalizeEmail_(current.email)) params.email = '';
  } else if (profile.email && normalizeEmail_(current.email) !== profile.email) {
    params.email = profile.email;
  }
  if (profile.name && trimString_(current.name) !== profile.name) params.name = profile.name;
  if (!Object.keys(params).length) {
    return {
      ok: true,
      customerId: customerId,
      customer: current,
      refreshed: false
    };
  }
  const result = stripeApiRequest_('/v1/customers/' + encodeURIComponent(customerId), params, Object.assign({}, opts, {
    method: 'post'
  }));
  if (!result.ok) return result;
  return Object.assign({}, result, {
    customerId: customerId,
    customer: result.body,
    refreshed: true
  });
}

function retrieveStripeCheckoutSession_(stripeSessionId, options) {
  const sessionId = trimString_(stripeSessionId);
  if (!sessionId) return { ok: false, error: 'Missing Stripe Checkout Session ID.' };
  return stripeApiRequest_('/v1/checkout/sessions/' + encodeURIComponent(sessionId), {
    'expand[0]': 'payment_intent',
    'expand[1]': 'payment_intent.payment_method',
    'expand[2]': 'setup_intent',
    'expand[3]': 'setup_intent.payment_method'
  }, Object.assign({}, options || {}, { method: 'get' }));
}

function retrieveStripePaymentIntent_(paymentIntentId, options) {
  const id = trimString_(paymentIntentId);
  if (!id) return { ok: false, error: 'Missing Stripe PaymentIntent ID.' };
  return stripeApiRequest_('/v1/payment_intents/' + encodeURIComponent(id), {
    'expand[0]': 'payment_method',
    'expand[1]': 'latest_charge'
  }, Object.assign({}, options || {}, { method: 'get' }));
}

function retrieveStripeSetupIntent_(setupIntentId, options) {
  const id = trimString_(setupIntentId);
  if (!id) return { ok: false, error: 'Missing Stripe SetupIntent ID.' };
  return stripeApiRequest_('/v1/setup_intents/' + encodeURIComponent(id), {
    'expand[0]': 'payment_method'
  }, Object.assign({}, options || {}, { method: 'get' }));
}

function retrieveStripePaymentMethod_(paymentMethodId, options) {
  const id = trimString_(paymentMethodId);
  if (!id) return { ok: false, error: 'Missing Stripe PaymentMethod ID.' };
  return stripeApiRequest_('/v1/payment_methods/' + encodeURIComponent(id), {}, Object.assign({}, options || {}, {
    method: 'get'
  }));
}

function updateStripePaymentMethodDashboardRedisplay_(paymentMethodId, accountSummary, options) {
  const id = trimString_(paymentMethodId);
  if (!id || id.indexOf('pm_') !== 0) {
    return {
      ok: false,
      skipped: true,
      code: 'missing_payment_method',
      error: 'Missing Stripe PaymentMethod ID.'
    };
  }
  const account = (accountSummary && typeof accountSummary === 'object') ? accountSummary : {};
  const name = trimString_(account.billingContactName || account.primaryContactName || account.orgName);
  const email = normalizeEmail_(account.billingContactEmail || account.primaryEmail);
  const params = {
    allow_redisplay: 'always'
  };
  if (name) params['billing_details[name]'] = name;
  if (email) params['billing_details[email]'] = email;
  return stripeApiRequest_('/v1/payment_methods/' + encodeURIComponent(id), params, Object.assign({}, options || {}, {
    method: 'post'
  }));
}

function maybeHardenPreferredAchPaymentMethodForCheckout_(ctx, timing) {
  const context = (ctx && typeof ctx === 'object') ? ctx : {};
  const preferredId = trimString_(context.preferredAchPaymentMethodId);
  if (!preferredId) return;
  const paymentOrigin = normalizeAchPaymentSource_(context.paymentOrigin || (context.payload && (context.payload.paymentOrigin || context.payload.checkoutOrigin)));
  if (paymentOrigin === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link) return;
  const preferredMethod = context.preferredAchPaymentMethod || null;
  if (!preferredMethod ||
      !isDashboardSavedAchPaymentMethod_(preferredMethod) ||
      !isAchPaymentMethodUsableForCheckout_(preferredMethod)) {
    return;
  }
  const accountSummary = context.accountInfo && context.accountInfo.summary ? context.accountInfo.summary : {};
  markCheckoutTiming_(timing, 'ach_preferred_payment_method_update_start');
  const result = updateStripePaymentMethodDashboardRedisplay_(preferredId, accountSummary, { cfg: context.cfg });
  markCheckoutTiming_(timing, 'ach_preferred_payment_method_update_end', {
    ok: !!(result && result.ok === true),
    statusCode: Number(result && result.statusCode || 0) || 0
  });
  if (!result || result.ok !== true) {
    console.log('[RT-STRIPE-ACH-PM-REDISPLAY] ' + JSON.stringify({
      ok: false,
      code: trimString_(result && result.code) || 'stripe_payment_method_update_failed',
      statusCode: Number(result && result.statusCode || 0) || 0
    }));
  }
}

function retrieveStripeCharge_(chargeId, options) {
  const id = trimString_(chargeId);
  if (!id) return { ok: false, error: 'Missing Stripe Charge ID.' };
  return stripeApiRequest_('/v1/charges/' + encodeURIComponent(id), {}, Object.assign({}, options || {}, {
    method: 'get'
  }));
}

function createStripeCustomer_(accountSummary, options) {
  const account = (accountSummary && typeof accountSummary === 'object') ? accountSummary : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const profile = buildStripeCustomerSafeProfile_(account);
  const email = opts.collectSetupEmailInCheckout === true ? '' : profile.email;
  const name = profile.name;
  const params = {
    'metadata[source]': 'red_threads_portal'
  };
  if (email) params.email = email;
  if (name) params.name = name;
  if (trimString_(account.accountId)) params['metadata[accountId]'] = trimString_(account.accountId);
  if (trimString_(account.orgId)) params['metadata[orgId]'] = trimString_(account.orgId);
  if (trimString_(account.orgName)) params['metadata[orgName]'] = trimString_(account.orgName);

  const result = stripeApiRequest_('/v1/customers', params, Object.assign({}, opts, {
    method: 'post'
  }));
  if (!result.ok) return result;
  const customerId = trimString_(result.body && result.body.id);
  if (!customerId || customerId.indexOf('cus_') !== 0) {
    return { ok: false, statusCode: result.statusCode, error: 'Stripe Customer creation did not return a Customer ID.' };
  }
  return Object.assign({}, result, {
    customerId: customerId,
    customer: result.body
  });
}

function updatePortalAccountStripeCustomerId_(accountInfo, stripeCustomerId, options) {
  const info = (accountInfo && typeof accountInfo === 'object') ? accountInfo : {};
  const rowInfo = info.rowInfo || null;
  const customerId = trimString_(stripeCustomerId);
  if (!rowInfo || !rowInfo.row || !rowInfo.colMap) {
    return Object.assign({}, info, {
      summary: Object.assign({}, info.summary || {}, { stripeCustomerId: customerId })
    });
  }
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  setRowValuesByHeaderMap_(opts.accountsSheet || infra.accountsSheet, rowInfo.row, rowInfo.colMap, {
    stripeCustomerId: customerId,
    updatedAt: nowIso_()
  });
  const refreshed = buildRowInfoFromSheet_(opts.accountsSheet || infra.accountsSheet, rowInfo.row);
  return {
    rowInfo: refreshed,
    summary: buildPortalAccountSummary_(refreshed.rowObjNormalized, cfg)
  };
}

function updatePortalAccountStripeCustomerIdIfBlank_(accountInfo, stripeCustomerId, options) {
  const info = (accountInfo && typeof accountInfo === 'object') ? accountInfo : {};
  const customerId = trimString_(stripeCustomerId);
  if (!customerId) return info;
  const account = info.summary || {};
  if (trimString_(account.stripeCustomerId)) return info;
  return updatePortalAccountStripeCustomerId_(info, customerId, options);
}

function ensureStripeCustomerForPortalAccount_(ctxOrAccountSummary, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const source = (ctxOrAccountSummary && typeof ctxOrAccountSummary === 'object') ? ctxOrAccountSummary : {};
  let accountInfo = opts.accountInfo || source.accountInfo || null;
  if (!accountInfo && source.rowInfo) {
    accountInfo = {
      rowInfo: source.rowInfo,
      summary: buildPortalAccountSummary_(source.rowInfo.rowObjNormalized || {}, opts.cfg || getConfig_())
    };
  }
  if (!accountInfo && (source.accountId || source.primaryEmail || source.orgId || source.orgName)) {
    accountInfo = {
      rowInfo: null,
      summary: source
    };
  }
  const accountSummary = accountInfo && accountInfo.summary ? accountInfo.summary : {};
  let customerId = trimString_(accountSummary.stripeCustomerId);
  if (customerId) {
    const retrieved = retrieveStripeCustomer_(customerId, opts);
    if (retrieved.ok === true && !(retrieved.body && retrieved.body.deleted === true)) {
      const refreshed = refreshStripeCustomerSafeProfile_(customerId, accountSummary, Object.assign({}, opts, {
        customer: retrieved.body
      }));
      if (!refreshed || refreshed.ok !== true) {
        return Object.assign({}, refreshed || {}, {
          customerId: customerId,
          accountInfo: accountInfo,
          code: trimString_(refreshed && refreshed.code) || 'stripe_customer_profile_refresh_failed',
          error: trimString_(refreshed && refreshed.error) || 'Unable to refresh Stripe Customer profile for ACH setup.'
        });
      }
      return {
        ok: true,
        customerId: customerId,
        customer: refreshed.customer || retrieved.body,
        accountInfo: accountInfo
      };
    }
    if (Number(retrieved.statusCode || 0) !== 404) {
      return Object.assign({}, retrieved, {
        customerId: customerId,
        accountInfo: accountInfo
      });
    }
  }
  if (!accountInfo || !accountInfo.rowInfo) {
    return {
      ok: false,
      code: 'portal_account_required_for_stripe_customer',
      error: 'A persisted portal account is required before starting ACH checkout.'
    };
  }
  const created = createStripeCustomer_(accountSummary, opts);
  if (!created.ok) return Object.assign({}, created, { accountInfo: accountInfo });
  accountInfo = updatePortalAccountStripeCustomerId_(accountInfo, created.customerId, opts);
  return {
    ok: true,
    customerId: created.customerId,
    customer: created.customer,
    accountInfo: accountInfo
  };
}

function extractAchPaymentMethodSummaryFromStripe_(paymentMethodObj, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const method = (paymentMethodObj && typeof paymentMethodObj === 'object') ? paymentMethodObj : {};
  const bank = method.us_bank_account && typeof method.us_bank_account === 'object' ? method.us_bank_account : {};
  const methodType = trimString_(method.type).toLowerCase();
  const hasBankPayload = !!(method.us_bank_account && typeof method.us_bank_account === 'object');
  if (!hasBankPayload && methodType !== 'us_bank_account') return null;
  const paymentMethodId = trimString_(opts.paymentMethodId || method.id);
  if (!paymentMethodId) return null;
  const bankVerificationStatus = trimString_(
    bank.status ||
    method.status ||
    (method.allow_redisplay === 'limited' ? 'verified' : '')
  );
  const verificationStatus = normalizeAchSummaryVerificationStatus_(opts.verificationStatus, bankVerificationStatus);
  return normalizeAchPaymentMethodSummary_({
    paymentMethodId: paymentMethodId,
    stripeCustomerId: trimString_(opts.stripeCustomerId) || stripeIdFromObject_(method.customer),
    bankName: bank.bank_name || bank.bankName || opts.bankName,
    last4: bank.last4 || opts.last4,
    accountHolderType: bank.account_holder_type || bank.accountHolderType || opts.accountHolderType,
    accountType: bank.account_type || bank.accountType || opts.accountType,
    financialConnectionsAccountId: stripeIdFromObject_(bank.financial_connections_account || bank.financialConnectionsAccount || opts.financialConnectionsAccountId),
    mandateId: opts.mandateId || stripeIdFromObject_(method.mandate),
    verificationStatus: verificationStatus,
    status: mapAchPaymentMethodStatusFromVerification_(verificationStatus, opts.status),
    isDefault: opts.isDefault === true,
    createdAt: opts.createdAt || (method.created ? new Date(Number(method.created) * 1000).toISOString() : nowIso_()),
    updatedAt: opts.updatedAt || nowIso_(),
    source: opts.source || ACH_PAYMENT_METHOD_SOURCES.unknown,
    visibilityScope: opts.visibilityScope,
    linkedOrderId: opts.linkedOrderId,
    linkedCheckoutAttemptId: opts.linkedCheckoutAttemptId,
    linkedBy: opts.linkedBy,
    setupIntentId: opts.setupIntentId,
    setupSessionId: opts.setupSessionId,
    paymentIntentId: opts.paymentIntentId,
    setupStatus: opts.setupStatus
  });
}

function getDefaultAchPaymentMethodForAccount_(accountSummary) {
  const account = (accountSummary && typeof accountSummary === 'object') ? accountSummary : {};
  const defaultId = trimString_(account.defaultAchPaymentMethodId);
  const methods = normalizeAchPaymentMethodsJson_(account.achPaymentMethods || account.achPaymentMethodsJson);
  return methods.find(function(item) {
    return isAchPaymentMethodUsableForDefault_(item) && (item.isDefault === true || (defaultId && item.paymentMethodId === defaultId));
  }) || null;
}

function isDashboardSavedAchPaymentMethod_(achMethod) {
  const method = normalizeAchPaymentMethodSummary_(achMethod);
  if (!method) return false;
  const scope = normalizeAchVisibilityScope_(method.visibilityScope);
  const source = normalizeAchPaymentSource_(method.source);
  const status = trimString_(method.status).toLowerCase();
  if (status === 'removed' || scope === ACH_PAYMENT_VISIBILITY_SCOPES.removed) return false;
  return scope === ACH_PAYMENT_VISIBILITY_SCOPES.dashboard_saved ||
    (source === ACH_PAYMENT_METHOD_SOURCES.dashboard_setup &&
      scope !== ACH_PAYMENT_VISIBILITY_SCOPES.order_only &&
      scope !== ACH_PAYMENT_VISIBILITY_SCOPES.hidden_from_dashboard);
}

function isAchMethodVisibleInDashboard_(achMethod) {
  return isDashboardSavedAchPaymentMethod_(achMethod);
}

function isAchPaymentMethodUsableForDefault_(achMethod) {
  const method = normalizeAchPaymentMethodSummary_(achMethod);
  if (!method) return false;
  if (!isDashboardSavedAchPaymentMethod_(method)) return false;
  const status = trimString_(method.status).toLowerCase();
  const verificationStatus = trimString_(method.verificationStatus).toLowerCase();
  if (/(blocked|removed|fail|failed|invalid|expired|timeout|exceeded|requires_payment_method)/i.test(status + ' ' + verificationStatus)) {
    return false;
  }
  if (/(pending|processing|microdeposit|requires_action|unverified)/i.test(status + ' ' + verificationStatus)) {
    return false;
  }
  return status === 'active' || status === 'verified' || status === 'succeeded' ||
    verificationStatus === 'active' || verificationStatus === 'verified' || verificationStatus === 'succeeded';
}

function isAchPaymentMethodUsableForCheckout_(achMethod) {
  return isAchPaymentMethodUsableForDefault_(achMethod);
}

function validatePreferredAchPaymentMethodForCheckout_(ctx) {
  const context = (ctx && typeof ctx === 'object') ? ctx : {};
  const payload = (context.payload && typeof context.payload === 'object') ? context.payload : {};
  const preferredId = trimString_(payload.preferredAchPaymentMethodId);
  const requestedIntent = normalizeAchCheckoutIntent_(payload.achCheckoutIntent);
  if (!preferredId) {
    return {
      ok: true,
      preferredAchPaymentMethodId: '',
      achCheckoutIntent: requestedIntent === ACH_CHECKOUT_INTENTS.saved_bank
        ? ACH_CHECKOUT_INTENTS.unspecified
        : requestedIntent,
      preferredAchPaymentMethod: null
    };
  }
  const account = context.accountInfo && context.accountInfo.summary ? context.accountInfo.summary : {};
  const methods = normalizeAchPaymentMethodsJson_(account.achPaymentMethods || account.achPaymentMethodsJson);
  const method = methods.find(function(item) {
    return trimString_(item && item.paymentMethodId) === preferredId;
  }) || null;
  if (!method || !isDashboardSavedAchPaymentMethod_(method) || !isAchPaymentMethodUsableForCheckout_(method)) {
    return {
      ok: false,
      code: 'preferred_ach_payment_method_invalid',
      error: 'The selected saved ACH bank is no longer available. Choose another bank or continue through Stripe Checkout.'
    };
  }
  return {
    ok: true,
    preferredAchPaymentMethodId: preferredId,
    achCheckoutIntent: ACH_CHECKOUT_INTENTS.saved_bank,
    preferredAchPaymentMethod: method
  };
}

function applyAchCheckoutPreferenceToContext_(ctx, preference) {
  const context = (ctx && typeof ctx === 'object') ? ctx : {};
  const pref = (preference && typeof preference === 'object') ? preference : {};
  context.preferredAchPaymentMethodId = trimString_(pref.preferredAchPaymentMethodId);
  context.achCheckoutIntent = normalizeAchCheckoutIntent_(pref.achCheckoutIntent);
  context.preferredAchPaymentMethod = pref.preferredAchPaymentMethod || null;
  context.orderDraft = Object.assign({}, context.orderDraft || {}, {
    preferredAchPaymentMethodId: context.preferredAchPaymentMethodId,
    achCheckoutIntent: context.achCheckoutIntent
  });
  return context;
}

function writeAchPaymentMethodsForPortalAccount_(accountInfo, methods, options) {
  const info = (accountInfo && typeof accountInfo === 'object') ? accountInfo : {};
  const rowInfo = info.rowInfo || null;
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const accountsSheet = opts.accountsSheet || infra.accountsSheet;
  if (!rowInfo || !rowInfo.row || !rowInfo.colMap) return info;
  const normalized = (Array.isArray(methods) ? methods : []).map(normalizeAchPaymentMethodSummary_).filter(Boolean);
  const defaultMethod = normalized.find(function(item) {
    return item.isDefault === true && isAchPaymentMethodUsableForDefault_(item);
  }) || normalized.find(function(item) {
    return isAchPaymentMethodUsableForDefault_(item);
  }) || null;
  if (defaultMethod) defaultMethod.isDefault = true;
  const finalMethods = normalized.map(function(item) {
    if (!defaultMethod) return Object.assign({}, item, { isDefault: false });
    return Object.assign({}, item, { isDefault: item.paymentMethodId === defaultMethod.paymentMethodId });
  });
  setRowValuesByHeaderMap_(accountsSheet, rowInfo.row, rowInfo.colMap, {
    achPaymentMethodsJson: JSON.stringify(finalMethods),
    defaultAchPaymentMethodId: defaultMethod ? trimString_(defaultMethod.paymentMethodId) : '',
    defaultAchBankName: defaultMethod ? trimString_(defaultMethod.bankName) : '',
    defaultAchLast4: defaultMethod ? trimString_(defaultMethod.last4) : '',
    defaultAchVerificationStatus: defaultMethod ? trimString_(defaultMethod.verificationStatus) : '',
    defaultAchMandateId: defaultMethod ? trimString_(defaultMethod.mandateId) : '',
    defaultAchFinancialConnectionsAccountId: defaultMethod ? trimString_(defaultMethod.financialConnectionsAccountId) : '',
    updatedAt: nowIso_()
  });
  const refreshed = buildRowInfoFromSheet_(accountsSheet, rowInfo.row);
  return {
    rowInfo: refreshed,
    summary: buildPortalAccountSummary_(refreshed.rowObjNormalized, cfg)
  };
}

function updateExistingDashboardSavedAchMethodOnly_(accountInfo, achSummary, options) {
  const info = (accountInfo && typeof accountInfo === 'object') ? accountInfo : {};
  const rowInfo = info.rowInfo || null;
  const incoming = normalizeAchPaymentMethodSummary_(achSummary);
  if (!rowInfo || !incoming) return info;
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const account = buildPortalAccountSummary_(rowInfo.rowObjNormalized || {}, cfg);
  let changed = false;
  const methods = normalizeAchPaymentMethodsJson_(account.achPaymentMethods).map(function(item) {
    if (item.paymentMethodId !== incoming.paymentMethodId || !isDashboardSavedAchPaymentMethod_(item)) return item;
    changed = true;
    return normalizeAchPaymentMethodSummary_(Object.assign({}, item, incoming, {
      visibilityScope: ACH_PAYMENT_VISIBILITY_SCOPES.dashboard_saved,
      source: trimString_(item.source) || ACH_PAYMENT_METHOD_SOURCES.dashboard_setup,
      isDefault: item.isDefault === true,
      updatedAt: nowIso_()
    }));
  }).filter(Boolean);
  return changed ? writeAchPaymentMethodsForPortalAccount_(info, methods, opts) : info;
}

function upsertDashboardSavedAchPaymentMethodOnPortalAccount_(accountInfo, achSummary, options) {
  const summary = normalizeAchPaymentMethodSummary_(Object.assign({}, achSummary || {}, {
    source: ACH_PAYMENT_METHOD_SOURCES.dashboard_setup,
    visibilityScope: ACH_PAYMENT_VISIBILITY_SCOPES.dashboard_saved
  }));
  return upsertAchPaymentMethodOnPortalAccount_(accountInfo, summary, options);
}

function upsertAchPaymentMethodOnPortalAccount_(accountInfo, achSummary, options) {
  const info = (accountInfo && typeof accountInfo === 'object') ? accountInfo : {};
  const rowInfo = info.rowInfo || null;
  const summary = normalizeAchPaymentMethodSummary_(achSummary);
  if (!summary) return info;
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const accountsSheet = opts.accountsSheet || infra.accountsSheet;
  if (!rowInfo || !rowInfo.row || !rowInfo.colMap) return info;
  if (!isAchMethodVisibleInDashboard_(summary)) {
    return updateExistingDashboardSavedAchMethodOnly_(info, summary, opts);
  }

  const currentAccount = buildPortalAccountSummary_(rowInfo.rowObjNormalized || {}, cfg);
  const current = normalizeAchPaymentMethodsJson_(currentAccount.achPaymentMethods);
  const now = nowIso_();
  const incoming = Object.assign({}, summary, {
    updatedAt: now,
    createdAt: trimString_(summary.createdAt) || now,
    source: ACH_PAYMENT_METHOD_SOURCES.dashboard_setup,
    visibilityScope: ACH_PAYMENT_VISIBILITY_SCOPES.dashboard_saved
  });
  const existingIdx = current.findIndex(function(item) {
    return item.paymentMethodId === incoming.paymentMethodId;
  });
  if (existingIdx >= 0) {
    current[existingIdx] = normalizeAchPaymentMethodSummary_(Object.assign({}, current[existingIdx], incoming));
  } else {
    current.push(incoming);
  }
  const hasExistingDefault = current.some(function(item) {
    return item.paymentMethodId !== incoming.paymentMethodId && item.isDefault === true && isAchPaymentMethodUsableForDefault_(item);
  });
  const incomingDefaultEligible = isAchPaymentMethodUsableForDefault_(incoming);
  const shouldDefault = incomingDefaultEligible && (
    incoming.isDefault === true ||
    !trimString_(currentAccount.defaultAchPaymentMethodId) ||
    !hasExistingDefault
  );
  const normalized = current.map(function(item) {
    const retainExistingDefault = item.isDefault === true && isAchPaymentMethodUsableForDefault_(item);
    return normalizeAchPaymentMethodSummary_(Object.assign({}, item, {
      isDefault: shouldDefault ? item.paymentMethodId === incoming.paymentMethodId : retainExistingDefault
    }));
  }).filter(Boolean);
  const defaultMethod = normalized.find(function(item) {
    return item.isDefault === true && isAchPaymentMethodUsableForDefault_(item);
  }) || null;
  return writeAchPaymentMethodsForPortalAccount_(info, normalized, Object.assign({}, opts, {
    accountsSheet: accountsSheet
  }));
}

function setDefaultAchPaymentMethodForAccount_(accountInfo, paymentMethodId, options) {
  const info = (accountInfo && typeof accountInfo === 'object') ? accountInfo : {};
  const rowInfo = info.rowInfo || null;
  const targetId = trimString_(paymentMethodId);
  if (!rowInfo || !targetId) return info;
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const account = buildPortalAccountSummary_(rowInfo.rowObjNormalized || {}, cfg);
  const methods = normalizeAchPaymentMethodsJson_(account.achPaymentMethods).map(function(item) {
    return normalizeAchPaymentMethodSummary_(Object.assign({}, item, {
      isDefault: item.paymentMethodId === targetId,
      updatedAt: item.paymentMethodId === targetId ? nowIso_() : item.updatedAt
    }));
  }).filter(Boolean);
  const defaultMethod = methods.find(function(item) {
    return item.paymentMethodId === targetId && isAchPaymentMethodUsableForDefault_(item);
  }) || null;
  if (!defaultMethod) return info;
  setRowValuesByHeaderMap_(opts.accountsSheet || infra.accountsSheet, rowInfo.row, rowInfo.colMap, {
    achPaymentMethodsJson: JSON.stringify(methods),
    defaultAchPaymentMethodId: defaultMethod.paymentMethodId,
    defaultAchBankName: defaultMethod.bankName,
    defaultAchLast4: defaultMethod.last4,
    defaultAchVerificationStatus: defaultMethod.verificationStatus,
    defaultAchMandateId: defaultMethod.mandateId,
    defaultAchFinancialConnectionsAccountId: defaultMethod.financialConnectionsAccountId,
    updatedAt: nowIso_()
  });
  const refreshed = buildRowInfoFromSheet_(opts.accountsSheet || infra.accountsSheet, rowInfo.row);
  return {
    rowInfo: refreshed,
    summary: buildPortalAccountSummary_(refreshed.rowObjNormalized, cfg)
  };
}

function hideAchPaymentMethodFromDashboardForAccount_(accountInfo, paymentMethodId, options) {
  const info = (accountInfo && typeof accountInfo === 'object') ? accountInfo : {};
  const rowInfo = info.rowInfo || null;
  const targetId = trimString_(paymentMethodId);
  if (!rowInfo || !targetId) return info;
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const account = buildPortalAccountSummary_(rowInfo.rowObjNormalized || {}, cfg);
  let changed = false;
  const methods = normalizeAchPaymentMethodsJson_(account.achPaymentMethods).map(function(item) {
    if (item.paymentMethodId !== targetId || !isDashboardSavedAchPaymentMethod_(item)) return item;
    changed = true;
    return normalizeAchPaymentMethodSummary_(Object.assign({}, item, {
      visibilityScope: ACH_PAYMENT_VISIBILITY_SCOPES.hidden_from_dashboard,
      isDefault: false,
      updatedAt: nowIso_()
    }));
  }).filter(Boolean);
  if (!changed) return info;
  return writeAchPaymentMethodsForPortalAccount_(info, methods, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    accountsSheet: opts.accountsSheet || infra.accountsSheet
  });
}

function markAchPaymentMethodUnusable_(accountInfo, paymentMethodId, reason, options) {
  const info = (accountInfo && typeof accountInfo === 'object') ? accountInfo : {};
  const rowInfo = info.rowInfo || null;
  const targetId = trimString_(paymentMethodId);
  if (!rowInfo || !targetId) return info;
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const account = buildPortalAccountSummary_(rowInfo.rowObjNormalized || {}, cfg);
  const blockedStatus = trimString_(reason).toLowerCase() === 'removed' ? 'removed' : 'blocked';
  const methods = normalizeAchPaymentMethodsJson_(account.achPaymentMethods).map(function(item) {
    if (item.paymentMethodId !== targetId) return item;
    return normalizeAchPaymentMethodSummary_(Object.assign({}, item, {
      status: blockedStatus,
      isDefault: false,
      updatedAt: nowIso_()
    }));
  }).filter(Boolean);
  const nextDefault = methods.find(function(item) {
    return isAchPaymentMethodUsableForDefault_(item);
  }) || null;
  if (nextDefault) nextDefault.isDefault = true;
  setRowValuesByHeaderMap_(opts.accountsSheet || infra.accountsSheet, rowInfo.row, rowInfo.colMap, {
    achPaymentMethodsJson: JSON.stringify(methods),
    defaultAchPaymentMethodId: nextDefault ? nextDefault.paymentMethodId : '',
    defaultAchBankName: nextDefault ? nextDefault.bankName : '',
    defaultAchLast4: nextDefault ? nextDefault.last4 : '',
    defaultAchVerificationStatus: nextDefault ? nextDefault.verificationStatus : '',
    defaultAchMandateId: nextDefault ? nextDefault.mandateId : '',
    defaultAchFinancialConnectionsAccountId: nextDefault ? nextDefault.financialConnectionsAccountId : '',
    updatedAt: nowIso_()
  });
  const refreshed = buildRowInfoFromSheet_(opts.accountsSheet || infra.accountsSheet, rowInfo.row);
  return {
    rowInfo: refreshed,
    summary: buildPortalAccountSummary_(refreshed.rowObjNormalized, cfg)
  };
}

function markMatchingDashboardSavedAchSetupMethodFailed_(accountInfo, setupIntentObj, options) {
  const info = (accountInfo && typeof accountInfo === 'object') ? accountInfo : {};
  const rowInfo = info.rowInfo || null;
  if (!rowInfo || !rowInfo.row || !rowInfo.colMap) {
    return { matched: false, ambiguous: false, accountInfo: info };
  }
  const intent = (setupIntentObj && typeof setupIntentObj === 'object') ? setupIntentObj : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const account = info.summary || buildPortalAccountSummary_(rowInfo.rowObjNormalized || {}, cfg);
  const customerId = stripeIdFromObject_(intent.customer);
  const accountCustomerId = trimString_(account.stripeCustomerId);
  const setupIntentId = trimString_(intent.id);
  const paymentMethodId = stripeIdFromObject_(intent.payment_method);
  const accountSetupIntentId = trimString_(account.achSetupIntentId);
  const setupSessionId = setupIntentId && setupIntentId === accountSetupIntentId
    ? trimString_(account.achSetupSessionId)
    : '';
  const methods = normalizeAchPaymentMethodsJson_(account.achPaymentMethods);
  const hasCompatibleCustomer = !customerId || (accountCustomerId && customerId === accountCustomerId) || methods.some(function(item) {
    return trimString_(item.stripeCustomerId) === customerId;
  });
  if (!hasCompatibleCustomer) {
    return { matched: false, ambiguous: false, accountInfo: info };
  }
  const matches = methods.filter(function(item) {
    if (!item || !isDashboardSavedAchPaymentMethod_(item)) return false;
    if (setupIntentId && trimString_(item.setupIntentId) === setupIntentId) return true;
    if (setupSessionId && trimString_(item.setupSessionId) === setupSessionId) return true;
    return !!(paymentMethodId && trimString_(item.paymentMethodId) === paymentMethodId);
  });
  if (matches.length !== 1) {
    return {
      matched: false,
      ambiguous: matches.length > 1,
      accountInfo: info
    };
  }

  const targetPaymentMethodId = trimString_(matches[0].paymentMethodId) || paymentMethodId;
  const targetSetupIntentId = trimString_(matches[0].setupIntentId) || setupIntentId;
  const targetSetupSessionId = trimString_(matches[0].setupSessionId) || setupSessionId;
  const now = nowIso_();
  const failedMethods = methods.map(function(item) {
    const itemPaymentMethodId = trimString_(item.paymentMethodId);
    const itemSetupIntentId = trimString_(item.setupIntentId);
    const itemSetupSessionId = trimString_(item.setupSessionId);
    const isTarget =
      (targetPaymentMethodId && itemPaymentMethodId === targetPaymentMethodId) ||
      (targetSetupIntentId && itemSetupIntentId === targetSetupIntentId) ||
      (targetSetupSessionId && itemSetupSessionId === targetSetupSessionId);
    if (!isTarget) return item;
    return normalizeAchPaymentMethodSummary_(Object.assign({}, item, {
      status: 'failed',
      verificationStatus: 'failed',
      setupStatus: 'failed',
      setupIntentId: trimString_(item.setupIntentId) || setupIntentId,
      setupSessionId: trimString_(item.setupSessionId) || setupSessionId,
      stripeCustomerId: trimString_(item.stripeCustomerId) || customerId,
      isDefault: false,
      updatedAt: now
    }));
  }).filter(Boolean);
  const updated = writeAchPaymentMethodsForPortalAccount_(info, failedMethods, opts);
  return {
    matched: true,
    ambiguous: false,
    paymentMethodId: targetPaymentMethodId,
    accountInfo: updated || info
  };
}

function getDriveFileByIdSafe_(fileId) {
  const id = trimString_(fileId);
  if (!id) return null;
  try {
    return DriveApp.getFileById(id);
  } catch (_) {
    return null;
  }
}

function cloneJsonValue_(value, fallback) {
  try {
    return JSON.parse(JSON.stringify(value));
  } catch (_) {
    return fallback;
  }
}

function parsePortalAccountNotes_(rawValue) {
  const raw = trimString_(rawValue);
  if (!raw) return {};
  const parsed = safeJsonParse_(raw, null);
  if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) return parsed;
  return { legacyText: raw };
}

function buildPortalAccountNotesText_(notesObj) {
  const notes = (notesObj && typeof notesObj === 'object' && !Array.isArray(notesObj)) ? notesObj : {};
  return JSON.stringify(notes);
}

function getPortalAccountDocumentNotes_(accountRow, documentType) {
  const type = normalizeAccountDocumentType_(documentType);
  if (!type) return {};
  const row = (accountRow && typeof accountRow === 'object') ? accountRow : {};
  const notes = parsePortalAccountNotes_(row.notes);
  const workflows = (notes.documentWorkflow && typeof notes.documentWorkflow === 'object' && !Array.isArray(notes.documentWorkflow))
    ? notes.documentWorkflow
    : {};
  const entry = workflows[type];
  return (entry && typeof entry === 'object' && !Array.isArray(entry)) ? entry : {};
}

function updatePortalAccountDocumentNotes_(accountRow, documentType, mutateFn) {
  const row = (accountRow && typeof accountRow === 'object') ? accountRow : {};
  const type = normalizeAccountDocumentType_(documentType);
  const notes = parsePortalAccountNotes_(row.notes);
  if (!notes.documentWorkflow || typeof notes.documentWorkflow !== 'object' || Array.isArray(notes.documentWorkflow)) {
    notes.documentWorkflow = {};
  }
  const current = notes.documentWorkflow[type] && typeof notes.documentWorkflow[type] === 'object' && !Array.isArray(notes.documentWorkflow[type])
    ? cloneJsonValue_(notes.documentWorkflow[type], {})
    : {};
  const next = typeof mutateFn === 'function' ? mutateFn(current, notes) : current;
  notes.documentWorkflow[type] = (next && typeof next === 'object' && !Array.isArray(next)) ? next : {};
  return buildPortalAccountNotesText_(notes);
}

function normalizeEmailRecipients_(value) {
  const rawItems = Array.isArray(value)
    ? value
    : String(value || '').split(/[\n,;]+/);
  const seen = {};
  const recipients = [];
  rawItems.forEach((item) => {
    const email = normalizeEmail_(item);
    if (!email || seen[email]) return;
    seen[email] = true;
    recipients.push(email);
  });
  return recipients;
}

function getAccountDocumentDefinition_(documentType, cfg) {
  const type = normalizeAccountDocumentType_(documentType);
  const config = cfg || getConfig_();
  if (type === ACCOUNT_DOCUMENT_TYPES.credit_terms) {
    const sourceFileId = trimString_(config.creditTermsFormFileId);
    return {
      type: type,
      workflowKey: 'creditTerms',
      teamReviewQueryValue: 'credit_terms',
      label: 'Red Threads Credit Terms',
      shortLabel: 'Credit Terms',
      sourceFileId: sourceFileId,
      sourceDocumentUrl: buildDriveFileViewUrl_(sourceFileId) || trimString_(config.termsDocumentUrl),
      sourceDocumentDownloadUrl: buildDriveFileDownloadUrl_(sourceFileId),
      uploadFolderId: trimString_(config.termsDriveFolderId),
      statusField: 'termsStatus',
      approvedField: 'termsApproved',
      approvedAtField: 'termsApprovedAt',
      approvedByNameField: 'termsApprovedByName',
      approvedByEmailField: 'termsApprovedByEmail',
      artifactUrlField: 'signedTermsFileUrl',
      submittedAtField: 'signedTermsSubmittedAt',
      sourceUrlField: 'termsDocumentUrl',
      paymentTermsCodeField: 'approvedPaymentTermsCode',
      paymentTermsLabelField: 'approvedPaymentTermsLabel',
      paymentTermsDaysField: 'approvedPaymentTermsDays',
      paymentTermsNotesField: 'approvedPaymentTermsNotes',
      paymentTermsSetAtField: 'approvedPaymentTermsSetAt',
      paymentTermsSetByNameField: 'approvedPaymentTermsSetByName',
      paymentTermsSetByEmailField: 'approvedPaymentTermsSetByEmail',
      supportsGuidedForm: false,
      uploadLabel: 'Upload signed terms document',
      blankEmailSubject: 'Credit terms application — Red Threads',
      teamReviewSubject: 'Review credit terms application'
    };
  }
  if (type === ACCOUNT_DOCUMENT_TYPES.tax_exempt) {
    const sourceFileId = trimString_(config.taxExemptFormFileId);
    return {
      type: type,
      workflowKey: 'taxExempt',
      teamReviewQueryValue: 'tax_exempt',
      label: 'Michigan Sales Tax Exemption',
      shortLabel: 'Tax Exemption',
      sourceFileId: sourceFileId,
      sourceDocumentUrl: buildDriveFileViewUrl_(sourceFileId),
      sourceDocumentDownloadUrl: buildDriveFileDownloadUrl_(sourceFileId),
      uploadFolderId: trimString_(config.taxExemptDriveFolderId),
      statusField: 'taxExemptStatus',
      approvedField: 'taxExemptApproved',
      approvedAtField: 'taxExemptApprovedAt',
      approvedByNameField: 'taxExemptApprovedByName',
      approvedByEmailField: 'taxExemptApprovedByEmail',
      artifactUrlField: 'taxExemptCertificateUrl',
      submittedAtField: 'taxExemptSubmittedAt',
      certificateNumberField: 'taxExemptCertificateNumber',
      expiresAtField: 'taxExemptExpiresAt',
      supportsGuidedForm: true,
      uploadLabel: 'Upload completed exemption document',
      blankEmailSubject: 'Sales tax exemption form — Red Threads',
      teamReviewSubject: 'Review sales tax exemption form'
    };
  }
  return null;
}

function getRequiredAccountDocumentDefinition_(documentType, cfg) {
  const definition = getAccountDocumentDefinition_(documentType, cfg);
  if (!definition) {
    throw new Error('Unsupported document type.');
  }
  return definition;
}

function getAccountDocumentWorkflowFromSummary_(summary, documentType, cfg) {
  const definition = getAccountDocumentDefinition_(documentType, cfg);
  if (!definition || !definition.workflowKey) return null;
  const source = (summary && typeof summary === 'object') ? summary : {};
  const workflows = (source.documentWorkflows && typeof source.documentWorkflows === 'object')
    ? source.documentWorkflows
    : {};
  return workflows[definition.workflowKey] || null;
}

function findMostRecentExportRowForAccountDocument_(ctx) {
  const source = (ctx && typeof ctx === 'object') ? ctx : {};
  if (source.exportRowInfo && source.exportRowInfo.rowObjNormalized) return source.exportRowInfo;
  const exportSheet = source.infra && source.infra.exportSheet;
  if (!exportSheet) return null;
  const accountSummary = source.accountInfo && source.accountInfo.summary ? source.accountInfo.summary : {};
  const identity = source.identity && typeof source.identity === 'object' ? source.identity : {};
  const orgId = trimString_(accountSummary.orgId || identity.orgId);
  const orgName = trimString_(accountSummary.orgName || identity.orgName).toLowerCase();
  const emails = normalizeEmailRecipients_([
    accountSummary.primaryEmail,
    accountSummary.billingContactEmail,
    identity.personEmail
  ]);
  const matches = listSheetRowInfos_(exportSheet).filter(function(info) {
    const row = (info && info.rowObjNormalized && typeof info.rowObjNormalized === 'object') ? info.rowObjNormalized : {};
    const token = trimString_(row.token);
    if (!token) return false;
    if (orgId && trimString_(row.orgid) === orgId) return true;
    if (orgName && trimString_(row.orgname).toLowerCase() === orgName) return true;
    const rowEmail = normalizeEmail_(row.personemail || row.primaryemail);
    return !!(rowEmail && emails.indexOf(rowEmail) >= 0);
  });
  if (!matches.length) return null;
  matches.sort(function(a, b) {
    const rowA = (a && a.rowObjNormalized) ? a.rowObjNormalized : {};
    const rowB = (b && b.rowObjNormalized) ? b.rowObjNormalized : {};
    const dateA = Date.parse(trimString_(rowA.exportedat || rowA.createdat || ''));
    const dateB = Date.parse(trimString_(rowB.exportedat || rowB.createdat || ''));
    if (!isNaN(dateA) && !isNaN(dateB) && dateA !== dateB) return dateB - dateA;
    return Number((b && b.row) || 0) - Number((a && a.row) || 0);
  });
  return matches[0] || null;
}

function resolveAccountDocumentPortalToken_(ctx) {
  const directToken = trimString_(ctx && ctx.exportRowInfo && ctx.exportRowInfo.rowObjNormalized && ctx.exportRowInfo.rowObjNormalized.token);
  if (directToken) return directToken;
  const fallbackRow = findMostRecentExportRowForAccountDocument_(ctx);
  return trimString_(fallbackRow && fallbackRow.rowObjNormalized && fallbackRow.rowObjNormalized.token);
}

function buildAccountDocumentTeamReviewUrl_(documentType, token, cfg) {
  const id = trimString_(token);
  if (!id) return '';
  const definition = getAccountDocumentDefinition_(documentType, cfg);
  const reviewQueryValue = trimString_(definition && definition.teamReviewQueryValue);
  return buildLifecycleEmailTeamUrl_(id, {
    teamReview: reviewQueryValue,
    cfg: cfg
  });
}

function sanitizeAccountDocumentClientMeta_(meta) {
  const source = (meta && typeof meta === 'object') ? meta : {};
  const lastSubmission = (source.lastSubmission && typeof source.lastSubmission === 'object')
    ? source.lastSubmission
    : {};
  const lastDecision = (source.lastDecision && typeof source.lastDecision === 'object')
    ? source.lastDecision
    : {};
  const submissions = Array.isArray(source.submissions) ? source.submissions : [];
  return {
    submissionCount: submissions.length,
    lastSubmission: {
      submittedAt: trimString_(lastSubmission.submittedAt),
      submittedByName: trimString_(lastSubmission.submittedByName),
      submittedByEmail: normalizeEmail_(lastSubmission.submittedByEmail),
      submissionSource: trimString_(lastSubmission.submissionSource),
      artifactUrl: trimString_(lastSubmission.artifactUrl),
      artifactName: trimString_(lastSubmission.artifactName),
      artifactFiles: normalizeAccountDocumentArtifactFiles_(lastSubmission.artifactFiles),
      certificateNumber: trimString_(lastSubmission.certificateNumber),
      guidedFormData: lastSubmission.guidedFormData && typeof lastSubmission.guidedFormData === 'object'
        ? cloneJsonValue_(lastSubmission.guidedFormData, {})
        : null
    },
    lastDecision: {
      decidedAt: trimString_(lastDecision.decidedAt),
      decision: trimString_(lastDecision.decision),
      decidedByName: trimString_(lastDecision.decidedByName),
      decidedByEmail: normalizeEmail_(lastDecision.decidedByEmail),
      reason: trimString_(lastDecision.reason)
    },
    lastBlankEmail: source.lastBlankEmail && typeof source.lastBlankEmail === 'object'
      ? {
          sentAt: trimString_(source.lastBlankEmail.sentAt),
          sentByName: trimString_(source.lastBlankEmail.sentByName),
          sentByEmail: normalizeEmail_(source.lastBlankEmail.sentByEmail),
          recipients: normalizeEmailRecipients_(source.lastBlankEmail.recipients)
        }
      : null
  };
}

function buildAccountDocumentWorkflowSummary_(accountRow, documentType, cfg) {
  const row = (accountRow && typeof accountRow === 'object') ? accountRow : {};
  const definition = getAccountDocumentDefinition_(documentType, cfg);
  if (!definition) return null;
  const notesMeta = getPortalAccountDocumentNotes_(row, definition.type);
  const status = normalizeAccountDocumentStatus_(row[normalizeHeaderKey_(definition.statusField)] || row[definition.statusField]);
  const approved = boolFromCell_(row[normalizeHeaderKey_(definition.approvedField)] || row[definition.approvedField])
    || status === 'approved';
  const uploadedDocumentUrl = trimString_(row[normalizeHeaderKey_(definition.artifactUrlField)] || row[definition.artifactUrlField])
    || trimString_(notesMeta.lastSubmission && notesMeta.lastSubmission.artifactUrl);
  const submittedAt = trimString_(row[normalizeHeaderKey_(definition.submittedAtField)] || row[definition.submittedAtField])
    || trimString_(notesMeta.lastSubmission && notesMeta.lastSubmission.submittedAt);
  const certificateNumber = definition.certificateNumberField
    ? trimString_(row[normalizeHeaderKey_(definition.certificateNumberField)] || row[definition.certificateNumberField])
    : '';
  const expiresAt = definition.expiresAtField
    ? trimString_(row[normalizeHeaderKey_(definition.expiresAtField)] || row[definition.expiresAtField])
    : '';
  const approvedPaymentTerms = definition.paymentTermsCodeField
    ? buildApprovedPaymentTermsSummaryFromRow_(row)
    : {
        code: '',
        label: '',
        days: 0,
        notes: '',
        setAt: '',
        setByName: '',
        setByEmail: ''
      };
  return {
    type: definition.type,
    label: definition.label,
    shortLabel: definition.shortLabel,
    status: status,
    approved: approved,
    active: definition.type === ACCOUNT_DOCUMENT_TYPES.tax_exempt ? isTaxExemptActive_(row) : approved,
    submittedAt: submittedAt,
    uploadedDocumentUrl: uploadedDocumentUrl,
    certificateNumber: certificateNumber,
    expiresAt: expiresAt,
    sourceDocumentUrl: definition.sourceDocumentUrl,
    sourceDocumentDownloadUrl: definition.sourceDocumentDownloadUrl,
    supportsGuidedForm: definition.supportsGuidedForm === true,
    approvedPaymentTermsCode: approvedPaymentTerms.code,
    approvedPaymentTermsLabel: approvedPaymentTerms.label,
    approvedPaymentTermsDays: approvedPaymentTerms.days,
    approvedPaymentTermsNotes: approvedPaymentTerms.notes,
    approvedPaymentTermsSetAt: approvedPaymentTerms.setAt,
    approvedPaymentTermsSetByName: approvedPaymentTerms.setByName,
    approvedPaymentTermsSetByEmail: approvedPaymentTerms.setByEmail,
    clientMeta: sanitizeAccountDocumentClientMeta_(notesMeta)
  };
}

function buildPortalAccountSummary_(accountRow, cfg) {
  const row = (accountRow && typeof accountRow === 'object') ? accountRow : {};
  const termsApproved = isTermsApproved_(row);
  const taxExemptApproved = isTaxExemptApproved_(row);
  const taxExemptActive = isTaxExemptActive_(row);
  const approvedPaymentTerms = buildApprovedPaymentTermsSummaryFromRow_(row);
  const creditTermsWorkflow = buildAccountDocumentWorkflowSummary_(row, ACCOUNT_DOCUMENT_TYPES.credit_terms, cfg);
  const taxExemptWorkflow = buildAccountDocumentWorkflowSummary_(row, ACCOUNT_DOCUMENT_TYPES.tax_exempt, cfg);
  const summary = {
    accountId: trimString_(row.accountid || row.accountId),
    accountAccessToken: trimString_(row.accountaccesstoken || row.accountAccessToken),
    orgId: trimString_(row.orgid || row.orgId),
    orgName: trimString_(row.orgname || row.orgName),
    primaryEmail: normalizeEmail_(row.primaryemail || row.primaryEmail),
    primaryContactName: trimString_(row.primarycontactname || row.primaryContactName),
    termsStatus: normalizeAccountDocumentStatus_(row.termsstatus || row.termsStatus),
    termsApproved: termsApproved,
    termsApprovedAt: trimString_(row.termsapprovedat || row.termsApprovedAt),
    signedTermsFileUrl: trimString_(row.signedtermsfileurl || row.signedTermsFileUrl),
    signedTermsSubmittedAt: trimString_(row.signedtermssubmittedat || row.signedTermsSubmittedAt),
    approvedPaymentTermsCode: approvedPaymentTerms.code,
    approvedPaymentTermsLabel: approvedPaymentTerms.label,
    approvedPaymentTermsDays: approvedPaymentTerms.days,
    approvedPaymentTermsNotes: approvedPaymentTerms.notes,
    approvedPaymentTermsSetAt: approvedPaymentTerms.setAt,
    approvedPaymentTermsSetByName: approvedPaymentTerms.setByName,
    approvedPaymentTermsSetByEmail: approvedPaymentTerms.setByEmail,
    taxExemptStatus: normalizeAccountDocumentStatus_(row.taxexemptstatus || row.taxExemptStatus),
    taxExemptApproved: taxExemptApproved,
    taxExemptExpiresAt: trimString_(row.taxexemptexpiresat || row.taxExemptExpiresAt),
    taxExemptActive: taxExemptActive,
    taxExemptCertificateUrl: trimString_(row.taxexemptcertificateurl || row.taxExemptCertificateUrl),
    taxExemptCertificateNumber: trimString_(row.taxexemptcertificatenumber || row.taxExemptCertificateNumber),
    taxExemptSubmittedAt: trimString_(row.taxexemptsubmittedat || row.taxExemptSubmittedAt),
    poAvailable: termsApproved,
    termsDocumentUrl: trimString_(row.termsdocumenturl || row.termsDocumentUrl) || String(cfg.termsDocumentUrl || '').trim(),
    termsDocumentDownloadUrl: creditTermsWorkflow ? creditTermsWorkflow.sourceDocumentDownloadUrl : '',
    taxExemptDocumentUrl: taxExemptWorkflow ? taxExemptWorkflow.sourceDocumentUrl : '',
    taxExemptDocumentDownloadUrl: taxExemptWorkflow ? taxExemptWorkflow.sourceDocumentDownloadUrl : '',
    billingContactEmail: normalizeEmail_(row.billingcontactemail || row.billingContactEmail),
    billingContactName: trimString_(row.billingcontactname || row.billingContactName),
    stripeCustomerId: trimString_(row.stripecustomerid || row.stripeCustomerId),
    achPaymentMethods: normalizeAchPaymentMethodsJson_(row.achpaymentmethodsjson || row.achPaymentMethodsJson),
    defaultAchPaymentMethodId: trimString_(row.defaultachpaymentmethodid || row.defaultAchPaymentMethodId),
    defaultAchBankName: trimString_(row.defaultachbankname || row.defaultAchBankName),
    defaultAchLast4: trimString_(row.defaultachlast4 || row.defaultAchLast4),
    defaultAchVerificationStatus: trimString_(row.defaultachverificationstatus || row.defaultAchVerificationStatus),
    defaultAchMandateId: trimString_(row.defaultachmandateid || row.defaultAchMandateId),
    defaultAchFinancialConnectionsAccountId: trimString_(row.defaultachfinancialconnectionsaccountid || row.defaultAchFinancialConnectionsAccountId),
    achSetupIntentId: trimString_(row.achsetupintentid || row.achSetupIntentId),
    achSetupSessionId: trimString_(row.achsetupsessionid || row.achSetupSessionId),
    achSetupStatus: trimString_(row.achsetupstatus || row.achSetupStatus),
    achSetupLastUpdatedAt: trimString_(row.achsetuplastupdatedat || row.achSetupLastUpdatedAt),
    achPendingProductionApproved: boolFromCell_(row.achpendingproductionapproved || row.achPendingProductionApproved),
    achPendingProductionApprovedAt: trimString_(row.achpendingproductionapprovedat || row.achPendingProductionApprovedAt),
    achPendingProductionApprovedBy: trimString_(row.achpendingproductionapprovedby || row.achPendingProductionApprovedBy),
    achPendingProductionApprovalNotes: trimString_(row.achpendingproductionapprovalnotes || row.achPendingProductionApprovalNotes),
    createdAt: trimString_(row.createdat || row.createdAt),
    updatedAt: trimString_(row.updatedat || row.updatedAt),
    documentWorkflows: {
      creditTerms: creditTermsWorkflow,
      taxExempt: taxExemptWorkflow
    }
  };
  return summary;
}

function isTermsApproved_(account) {
  const row = (account && typeof account === 'object') ? account : {};
  return boolFromCell_(row.termsapproved || row.termsApproved) ||
    normalizeAccountDocumentStatus_(row.termsstatus || row.termsStatus) === 'approved';
}

function isTaxExemptApproved_(account) {
  const row = (account && typeof account === 'object') ? account : {};
  return boolFromCell_(row.taxexemptapproved || row.taxExemptApproved) ||
    normalizeAccountDocumentStatus_(row.taxexemptstatus || row.taxExemptStatus) === 'approved';
}

function isTaxExemptActive_(account) {
  if (!isTaxExemptApproved_(account)) return false;
  const row = (account && typeof account === 'object') ? account : {};
  const expiresAt = trimString_(row.taxexemptexpiresat || row.taxExemptExpiresAt);
  if (!expiresAt) return true;
  const expiresMs = parseIsoDateMs_(expiresAt);
  if (!expiresMs) return true;
  return expiresMs >= Date.now();
}

function hasValidPortalAccountIdentityForCreate_(identity) {
  const source = (identity && typeof identity === 'object') ? identity : {};
  return !!(
    trimString_(source.orgId) &&
    normalizeEmail_(source.personEmail)
  );
}

function maybeBackfillPortalAccountIdentity_(accountInfo, identity, opts) {
  const info = (accountInfo && typeof accountInfo === 'object') ? accountInfo : null;
  const rowInfo = info && info.rowInfo ? info.rowInfo : null;
  const source = buildAccountIdentityFromInputs_(identity);
  const options = (opts && typeof opts === 'object') ? opts : {};
  if (!rowInfo || !rowInfo.colMap || !rowInfo.rowObjNormalized) return info;

  const updates = {};
  const current = rowInfo.rowObjNormalized;

  if (!trimString_(current.orgid) && source.orgId) updates.orgId = source.orgId;
  if (!trimString_(current.orgname) && source.orgName) updates.orgName = source.orgName;
  if (!normalizeEmail_(current.primaryemail) && source.personEmail) updates.primaryEmail = source.personEmail;
  if (!trimString_(current.primarycontactname) && source.personName) updates.primaryContactName = source.personName;
  if (!normalizeEmail_(current.billingcontactemail) && source.billingContactEmail) updates.billingContactEmail = source.billingContactEmail;
  if (!trimString_(current.billingcontactname) && source.billingContactName) updates.billingContactName = source.billingContactName;

  if (!Object.keys(updates).length) return info;

  updates.updatedAt = nowIso_();
  setRowValuesByHeaderMap_(options.accountsSheet || rowInfo.sheet || (options.infra && options.infra.accountsSheet), rowInfo.row, rowInfo.colMap, updates);
  const refreshed = buildRowInfoFromSheet_(
    options.accountsSheet || (options.infra && options.infra.accountsSheet),
    rowInfo.row,
    options.header || null
  );
  return {
    rowInfo: refreshed,
    summary: buildPortalAccountSummary_(refreshed.rowObjNormalized, options.cfg || getConfig_())
  };
}

function maybeBackfillExportRowOrgContextFromAccount_(exportSheet, rowInfo, accountSummary) {
  const sheet = exportSheet || null;
  const info = (rowInfo && typeof rowInfo === 'object') ? rowInfo : null;
  const summary = (accountSummary && typeof accountSummary === 'object') ? accountSummary : {};
  if (!sheet || !info || !info.colMap || !info.rowObjNormalized) return info;

  const current = info.rowObjNormalized;
  const updates = {};
  const resolvedOrgId = trimString_(summary.orgId);
  const resolvedOrgName = trimString_(summary.orgName);

  if (!trimString_(current.orgid) && resolvedOrgId) updates.orgId = resolvedOrgId;
  if (!trimString_(current.orgname) && resolvedOrgName) updates.orgName = resolvedOrgName;

  if (!Object.keys(updates).length) return info;

  setRowValuesByHeaderMap_(sheet, info.row, info.colMap, updates);
  return buildRowInfoFromSheet_(sheet, info.row);
}

function getPortalAccountByOrgOrEmail_(opts) {
  const options = (opts && typeof opts === 'object') ? opts : {};
  const cfg = options.cfg || getConfig_();
  const ss = options.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = options.infra || ensurePortalInfrastructure_(ss, cfg);
  const accountsSheet = infra.accountsSheet;
  const identity = buildAccountIdentityFromInputs_(options);
  const orgId = identity.orgId;
  const orgName = trimString_(identity.orgName).toLowerCase();
  const email = identity.personEmail;
  const rows = listSheetRowInfos_(accountsSheet);

  let match = null;
  if (orgId) {
    match = rows.find(info => trimString_(info.rowObjNormalized.orgid) === orgId) || null;
  }
  if (!match && orgName) {
    match = rows.find(info => trimString_(info.rowObjNormalized.orgname).toLowerCase() === orgName) || null;
  }
  if (!match && email) {
    match = rows.find(info => normalizeEmail_(info.rowObjNormalized.primaryemail) === email) || null;
  }
  if (!match && email) {
    match = rows.find(info => normalizeEmail_(info.rowObjNormalized.billingcontactemail) === email) || null;
  }

  if (!match) return null;
  if (options.readOnly === true) {
    return {
      rowInfo: match,
      summary: buildPortalAccountSummary_(match.rowObjNormalized, cfg)
    };
  }
  return maybeBackfillPortalAccountIdentity_({
    rowInfo: match,
    summary: buildPortalAccountSummary_(match.rowObjNormalized, cfg)
  }, identity, {
    cfg: cfg,
    infra: infra,
    accountsSheet: accountsSheet
  });
}

function createPortalAccountIfMissing_(opts) {
  const options = (opts && typeof opts === 'object') ? opts : {};
  const cfg = options.cfg || getConfig_();
  const ss = options.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = options.infra || ensurePortalInfrastructure_(ss, cfg);
  const existing = getPortalAccountByOrgOrEmail_(Object.assign({}, options, {
    cfg: cfg,
    ss: ss,
    infra: infra
  }));
  if (existing) return existing;
  if (options.createIfMissing === false) return null;

  const accountsSheet = infra.accountsSheet;
  const header = accountsSheet.getRange(1, 1, 1, accountsSheet.getLastColumn()).getValues()[0];
  const colMap = buildColumnMap_(header);
  const identity = buildAccountIdentityFromInputs_(options);
  if (!hasValidPortalAccountIdentityForCreate_(identity)) return null;
  const creditTermsDefinition = getAccountDocumentDefinition_(ACCOUNT_DOCUMENT_TYPES.credit_terms, cfg);
  const now = nowIso_();
  const rowVals = new Array(accountsSheet.getLastColumn()).fill('');

  rowVals[colMap.accountid - 1] = newPortalId_('acct');
  if (colMap.accountaccesstoken) rowVals[colMap.accountaccesstoken - 1] = newPortalAccountAccessToken_({ cfg: cfg, ss: ss, infra: infra });
  rowVals[colMap.orgid - 1] = identity.orgId;
  rowVals[colMap.orgname - 1] = identity.orgName;
  rowVals[colMap.primaryemail - 1] = identity.personEmail;
  rowVals[colMap.primarycontactname - 1] = identity.personName;
  rowVals[colMap.termsstatus - 1] = 'not_started';
  rowVals[colMap.termsapproved - 1] = false;
  rowVals[colMap.termsdocumenturl - 1] = creditTermsDefinition ? creditTermsDefinition.sourceDocumentUrl : cfg.termsDocumentUrl;
  rowVals[colMap.approvedpaymenttermsdays - 1] = 0;
  rowVals[colMap.taxexemptstatus - 1] = 'not_started';
  rowVals[colMap.taxexemptapproved - 1] = false;
  rowVals[colMap.billingcontactemail - 1] = identity.billingContactEmail || identity.personEmail;
  rowVals[colMap.billingcontactname - 1] = identity.billingContactName || identity.personName;
  if (colMap.achpaymentmethodsjson) rowVals[colMap.achpaymentmethodsjson - 1] = '[]';
  if (colMap.achpendingproductionapproved) {
    rowVals[colMap.achpendingproductionapproved - 1] = cfg.stripeAchDefaultPendingProductionApproved === true;
  }
  rowVals[colMap.createdat - 1] = now;
  rowVals[colMap.updatedat - 1] = now;

  const row = accountsSheet.getLastRow() + 1;
  accountsSheet.getRange(row, 1, 1, rowVals.length).setValues([rowVals]);
  const createdInfo = buildRowInfoFromSheet_(accountsSheet, row, header, rowVals);
  return {
    rowInfo: createdInfo,
    summary: buildPortalAccountSummary_(createdInfo.rowObjNormalized, cfg)
  };
}

function getWebAppUrl_() {
  return ScriptApp.getService().getUrl();
}

function buildPortalDirectUrl_(token) {
  const baseUrl = String(getWebAppUrl_() || '').trim();
  const tokenValue = String(token || '').trim();
  if (!baseUrl || !tokenValue) return '';
  return baseUrl + (baseUrl.indexOf('?') >= 0 ? '&' : '?') + 't=' + encodeURIComponent(tokenValue);
}

function buildExternalPortalUrl_(token) {
  const tokenValue = String(token || '').trim();
  if (!tokenValue) return '';
  return 'https://www.redthreads.com/portal?t=' + encodeURIComponent(tokenValue);
}

function buildExternalPortalBaseUrl_() {
  return 'https://www.redthreads.com/portal';
}

function isPublicRedThreadsPortalUrl_(value) {
  const clean = trimString_(value);
  if (!clean) return false;
  function isAllowedPublicPortalParts_(protocol, hostValue, pathValue) {
    const protocolText = trimString_(protocol).toLowerCase();
    const host = trimString_(hostValue).toLowerCase();
    const path = trimString_(pathValue).replace(/\/+$/, '').toLowerCase();
    return protocolText === 'https:' &&
      (host === 'www.redthreads.com' || host === 'redthreads.com') &&
      (path === '/portal' || path === '');
  }
  try {
    const parsed = new URL(clean);
    return isAllowedPublicPortalParts_(parsed.protocol, parsed.hostname, parsed.pathname);
  } catch (_) {
    const match = clean.match(/^(https:)?\/\/([^/?#]+)([^?#]*)?(?:[?#]|$)/i);
    if (!match) return false;
    return isAllowedPublicPortalParts_(match[1] || '', match[2] || '', match[3] || '');
  }
}

function normalizePublicPortalReturnUrl_(value) {
  const clean = trimString_(value);
  if (!isPublicRedThreadsPortalUrl_(clean)) return '';
  return clean;
}

function normalizePublicPortalBaseUrl_(value) {
  const clean = normalizePublicPortalReturnUrl_(value);
  if (!clean) return '';
  try {
    const parsed = new URL(clean);
    parsed.search = '';
    parsed.hash = '';
    return parsed.toString();
  } catch (_) {
    return 'https://www.redthreads.com/portal';
  }
}

function buildExternalPortalDashboardUrl_(accountSummary, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const account = (accountSummary && typeof accountSummary === 'object') ? accountSummary : {};
  const base = normalizePublicPortalBaseUrl_(opts.returnUrl) ||
    normalizePublicPortalBaseUrl_(cfg.stripeReturnUrl) ||
    'https://www.redthreads.com/portal';
  const params = { dashboard: '1' };
  const accessToken = trimString_(account.accountAccessToken);
  const accountId = trimString_(account.accountId);
  if (accessToken) {
    params.accountAccessToken = accessToken;
  } else if (accountId) {
    params.accountId = accountId;
  }
  return appendQueryParamsToUrl_(base, params);
}

function buildTeamSnapshotPortalUrl_(token) {
  const tokenValue = trimString_(token);
  if (!tokenValue) return '';
  return buildLifecycleEmailTeamUrl_(tokenValue);
}

function normalizeLifecycleEmailTeamAction_(value) {
  const clean = trimString_(value).toLowerCase();
  const map = {
    review_payment_issue: 'review_payment_issue',
    manual_payment: 'manual_payment',
    mark_manual_payment_received: 'manual_payment',
    po_payment: 'po_payment',
    mark_po_payment_received: 'po_payment',
    initiate_production: 'initiate_production',
    optional_initiate_production: 'optional_initiate_production',
    move_through_production: 'move_through_production',
    mark_jobs_completed: 'mark_jobs_completed',
    mark_production_complete: 'mark_jobs_completed',
    monitor_payment: 'monitor_payment'
  };
  return map[clean] || '';
}

function buildLifecycleEmailTeamUrl_(token, options) {
  const tokenValue = trimString_(token);
  if (!tokenValue) return '';
  const opts = (options && typeof options === 'object') ? options : {};
  const params = { mode: 'team' };
  const action = normalizeLifecycleEmailTeamAction_(opts.teamAction);
  if (action) params.teamAction = action;
  const teamReview = trimString_(opts.teamReview).toLowerCase();
  if (teamReview) params.teamReview = teamReview;
  const teamAccess = buildTeamModeEmailAccessToken_(tokenValue, {
    teamAction: action,
    teamReview: teamReview
  }, opts.cfg);
  if (teamAccess) params.teamAccess = teamAccess;
  return appendQueryParamsToUrl_(buildExternalPortalUrl_(tokenValue), params);
}

function buildLifecycleEmailTeamActionUrl_(token, teamAction) {
  const action = normalizeLifecycleEmailTeamAction_(teamAction);
  return buildLifecycleEmailTeamUrl_(token, action ? { teamAction: action } : {});
}

function buildLifecycleEmailTeamReviewUrl_(token, reviewType) {
  const reviewValue = trimString_(reviewType);
  return buildLifecycleEmailTeamUrl_(token, {
    teamReview: reviewValue
  });
}

function buildDashboardCreditTermsResubmitUrl_(token) {
  return buildDashboardAccountDocumentResubmitUrl_(token, ACCOUNT_DOCUMENT_TYPES.credit_terms);
}

function buildDashboardAccountDocumentResubmitUrl_(token, documentType) {
  const tokenValue = trimString_(token);
  const type = normalizeAccountDocumentType_(documentType);
  if (!tokenValue || !type) return '';
  return appendQueryParamsToUrl_(buildExternalPortalUrl_(tokenValue), {
    dashboard: '1',
    accountDoc: type,
    accountDocAction: 'resubmit'
  });
}

function buildPortalSummaryUrl_(token, extraParams) {
  const extra = (extraParams && typeof extraParams === 'object') ? extraParams : {};
  return appendQueryParamsToUrl_(buildExternalPortalUrl_(token), Object.assign({
    summary: '1'
  }, extra));
}

function buildLifecycleEmailInvoiceUrl_(token, extraParams) {
  return buildPortalSummaryUrl_(token, extraParams);
}

function buildLifecycleEmailApStatusUrl_(token) {
  return buildLifecycleEmailInvoiceUrl_(token, {
    paymentOrigin: 'ap'
  });
}

function buildPurchaseOrderResumePortalUrl_(token, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  return buildPortalSummaryUrl_(token, {
    resumePo: '1',
    poStage: trimString_(opts.stage) || 'submit'
  });
}

function buildLockedOrderPaymentPortalUrl_(token, paymentMethodSelected) {
  const method = trimString_(paymentMethodSelected).toLowerCase();
  if (method !== PAYMENT_METHODS.card && method !== PAYMENT_METHODS.ach) return '';
  return buildPortalSummaryUrl_(token, {
    payNow: method
  });
}

function buildAchApPaymentPortalUrl_(token) {
  return buildPortalSummaryUrl_(token, {
    payNow: PAYMENT_METHODS.ach,
    paymentOrigin: 'ap'
  });
}

function appendQueryParamsToUrl_(baseUrl, params) {
  const base = trimString_(baseUrl);
  const entries = (params && typeof params === 'object') ? params : {};
  if (!base) return '';
  try {
    const url = new URL(base);
    Object.keys(entries).forEach((key) => {
      const value = entries[key];
      if (value == null) return;
      const text = String(value).trim();
      if (!text) return;
      url.searchParams.set(String(key), text);
    });
    return url.toString();
  } catch (_) {
    const pairs = [];
    Object.keys(entries).forEach((key) => {
      const value = entries[key];
      if (value == null) return;
      const text = String(value).trim();
      if (!text) return;
      pairs.push(encodeURIComponent(String(key)) + '=' + encodeURIComponent(text));
    });
    if (!pairs.length) return base;
    return base + (base.indexOf('?') >= 0 ? '&' : '?') + pairs.join('&');
  }
}

function buildStripeReturnBaseUrl_(token, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = getConfig_();
  const overrideUrl = normalizePublicPortalReturnUrl_(opts.returnUrl);
  const configReturnUrl = normalizePublicPortalReturnUrl_(cfg.stripeReturnUrl);
  const base = trimString_(overrideUrl || buildExternalPortalUrl_(token) || configReturnUrl || buildPortalDirectUrl_(token));
  if (!base) return '';
  const tokenValue = trimString_(token);
  if (!tokenValue) return base;
  if (/[?&](?:t|token)=/i.test(base)) return base;
  return appendQueryParamsToUrl_(base, { t: tokenValue });
}

function buildStripeCheckoutReturnUrl_(token, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const baseUrl = buildStripeReturnBaseUrl_(token, opts);
  return appendQueryParamsToUrl_(baseUrl, opts.queryParams || {})
    .replace(/%7BCHECKOUT_SESSION_ID%7D/gi, '{CHECKOUT_SESSION_ID}');
}

function normalizePriceMapForOrder_(raw) {
  const out = {};
  if (!raw || typeof raw !== 'object') return out;
  Object.keys(raw).forEach((tierKey) => {
    const tierObj = raw[tierKey];
    if (!tierObj || typeof tierObj !== 'object') return;
    const tierNum = Number(tierKey);
    if (!Number.isFinite(tierNum)) return;
    const row = {};
    Object.keys(tierObj).forEach((size) => {
      const value = Number(tierObj[size]);
      if (Number.isFinite(value)) row[String(size)] = value;
    });
    out[String(tierNum)] = row;
  });
  return out;
}

function normalizeTierListForOrder_(jobTiers, skus) {
  const set = {};
  (Array.isArray(jobTiers) ? jobTiers : []).forEach((tier) => {
    const n = Number(tier);
    if (Number.isFinite(n) && n > 0) set[String(n)] = n;
  });
  (Array.isArray(skus) ? skus : []).forEach((sku) => {
    Object.keys((sku && sku.printedUnitPriceByTierBySize) || {}).forEach((tierKey) => {
      const n = Number(tierKey);
      if (Number.isFinite(n) && n > 0) set[String(n)] = n;
    });
  });
  const tiers = Object.keys(set).map((key) => set[key]).sort((a, b) => a - b);
  if (!tiers.length) tiers.push(1);
  return tiers;
}

function normalizeSkusForOrder_(rawSkus, jobId) {
  const out = [];
  const list = Array.isArray(rawSkus) ? rawSkus : [];
  for (let i = 0; i < list.length; i += 1) {
    const raw = list[i];
    if (!raw || typeof raw !== 'object') continue;
    out.push({
      skuId: trimString_(raw.skuId) || (jobId + '-SKU' + (i + 1)),
      skuKey: trimString_(raw.skuKey),
      uiName: trimString_(raw.uiName) || 'Unnamed SKU',
      vendorProductUrl: trimString_(raw.vendorProductUrl),
      imageUrl: trimString_(raw.imageUrl),
      sizesAllowed: (Array.isArray(raw.sizesAllowed) ? raw.sizesAllowed : []).map(trimString_).filter(Boolean),
      colorways: (Array.isArray(raw.colorways) ? raw.colorways : []).map(trimString_).filter(Boolean),
      printedUnitPriceByTierBySize: normalizePriceMapForOrder_(raw.printedUnitPriceByTierBySize),
      upchargeBySize: (raw.upchargeBySize && typeof raw.upchargeBySize === 'object') ? raw.upchargeBySize : {}
    });
  }
  return out;
}

/* ---------------- Order Draft Normalization + Pricing Helpers ---------------- */

function normalizePrintJobsForOrder_(rawPrintJobs) {
  const rawList = Array.isArray(rawPrintJobs)
    ? rawPrintJobs
    : ((rawPrintJobs && typeof rawPrintJobs === 'object')
      ? Object.keys(rawPrintJobs).sort().map((key) => rawPrintJobs[key])
      : []);
  return rawList
    .map((rawJob, idx) => {
      if (!rawJob || typeof rawJob !== 'object') return null;
      const printJobId = trimString_(rawJob.printJobId) || ('PJ' + (idx + 1));
      const skus = normalizeSkusForOrder_(rawJob.skus, printJobId);
      return {
        printJobId: printJobId,
        printJobName: trimString_(rawJob.printJobName) || ('Project ' + (idx + 1)),
        printJobNotes: trimString_(rawJob.printJobNotes),
        deliveryEstimate: trimString_(rawJob.deliveryEstimate),
        turnaroundTime: trimString_(rawJob.turnaroundTime),
        decorations: Array.isArray(rawJob.decorations) ? rawJob.decorations : [],
        addOns: Array.isArray(rawJob.addOns) ? rawJob.addOns.map((item, addOnIdx) => Object.assign({ __idx: addOnIdx }, item || {})) : [],
        skus: skus,
        mockups: (rawJob.mockups && typeof rawJob.mockups === 'object') ? rawJob.mockups : {},
        artworkOverridesBySlot: (rawJob.artworkOverridesBySlot && typeof rawJob.artworkOverridesBySlot === 'object')
          ? rawJob.artworkOverridesBySlot
          : {},
        priceTiers: normalizeTierListForOrder_(rawJob.priceTiers, skus)
      };
    })
    .filter(Boolean);
}

function normalizePortalStateForOrder_(rawState, printJobs) {
  const parsed = safeJsonParse_(rawState, {});
  const source = (parsed && typeof parsed === 'object') ? parsed : {};
  const out = {
    printJobs: {},
    documentReferences: source.documentReferences && typeof source.documentReferences === 'object' && !Array.isArray(source.documentReferences)
      ? JSON.parse(JSON.stringify(source.documentReferences))
      : {}
  };
  function normalizeRemovedAddOnIndexes_(value) {
    const seen = {};
    return (Array.isArray(value) ? value : [])
      .map(function(item) {
        return Number(String(item).trim());
      })
      .filter(function(idx) {
        if (!Number.isFinite(idx) || idx < 0 || seen[String(idx)]) return false;
        seen[String(idx)] = true;
        return true;
      })
      .sort(function(a, b) { return a - b; });
  }
  (Array.isArray(printJobs) ? printJobs : []).forEach((job) => {
    const srcJob = source.printJobs && source.printJobs[job.printJobId] ? source.printJobs[job.printJobId] : {};
    const jobState = {
      hidden: Boolean(srcJob && srcJob.hidden === true),
      removedAddOnIndexes: normalizeRemovedAddOnIndexes_(srcJob && srcJob.removedAddOnIndexes),
      skus: {}
    };
    (Array.isArray(job.skus) ? job.skus : []).forEach((sku) => {
      const srcSku = srcJob && srcJob.skus && srcJob.skus[sku.skuId] ? srcJob.skus[sku.skuId] : {};
      const skuState = {
        hidden: Boolean(srcSku && srcSku.hidden === true),
        colorways: {}
      };
      const colors = {};
      (Array.isArray(sku.colorways) ? sku.colorways : []).forEach((color) => {
        const name = trimString_(color);
        if (name) colors[name.toLowerCase()] = name;
      });
      Object.keys((srcSku && srcSku.colorways) || {}).forEach((color) => {
        const name = trimString_(color);
        if (name) colors[name.toLowerCase()] = name;
      });
      Object.keys(colors).forEach((key) => {
        const colorName = colors[key];
        const srcColor = srcSku && srcSku.colorways && srcSku.colorways[colorName] ? srcSku.colorways[colorName] : {};
        const qtyBySize = {};
        (Array.isArray(sku.sizesAllowed) ? sku.sizesAllowed : []).forEach((size) => {
          qtyBySize[String(size)] = Math.max(0, parseInt(String(srcColor && srcColor.qtyBySize ? srcColor.qtyBySize[size] : 0), 10) || 0);
        });
        skuState.colorways[colorName] = {
          hidden: Boolean(srcColor && srcColor.hidden === true),
          qtyBySize: qtyBySize
        };
      });
      jobState.skus[sku.skuId] = skuState;
    });
    out.printJobs[job.printJobId] = jobState;
  });
  const purchaseOrderDraft = normalizePurchaseOrderDraftState_(source.purchaseOrderDraft);
  if (purchaseOrderDraft) {
    out.purchaseOrderDraft = purchaseOrderDraft;
  }
  return out;
}

function shouldExcludeAddOnFromOrder_(addOn, removedIndexSet) {
  const item = (addOn && typeof addOn === 'object') ? addOn : {};
  const idx = parseInt(String(item.__idx), 10);
  if (removedIndexSet && Number.isFinite(idx) && removedIndexSet.has(idx)) return true;

  const truthyFalse = ['false', '0', 'no', 'off'];
  const hiddenFlags = [
    item.hidden,
    item.cancelled,
    item.canceled
  ];
  for (var i = 0; i < hiddenFlags.length; i += 1) {
    var raw = hiddenFlags[i];
    if (raw === true) return true;
    if (truthyFalse.indexOf(String(raw).trim().toLowerCase()) >= 0) continue;
    if (String(raw).trim().toLowerCase() === 'true') return true;
  }

  const inactiveFields = ['active', 'isActive', 'enabled', 'selected', 'included'];
  for (var j = 0; j < inactiveFields.length; j += 1) {
    var key = inactiveFields[j];
    if (!Object.prototype.hasOwnProperty.call(item, key)) continue;
    var value = item[key];
    if (value === false) return true;
    var normalized = String(value).trim().toLowerCase();
    if (truthyFalse.indexOf(normalized) >= 0) return true;
  }
  return false;
}

function getVisibleAddOnsForOrder_(job, portalState) {
  const jobState = portalState && portalState.printJobs ? portalState.printJobs[job.printJobId] : null;
  const removed = new Set(Array.isArray(jobState && jobState.removedAddOnIndexes) ? jobState.removedAddOnIndexes : []);
  return (Array.isArray(job && job.addOns) ? job.addOns : [])
    .filter(isPortalDisplayAddOn_)
    .filter(function(addOn) {
      return !shouldExcludeAddOnFromOrder_(addOn, removed);
    });
}

function getVisibleJobsForOrder_(printJobs, portalState) {
  return (Array.isArray(printJobs) ? printJobs : []).filter((job) => {
    const state = portalState && portalState.printJobs ? portalState.printJobs[job.printJobId] : null;
    return !(state && state.hidden === true);
  });
}

function getPrintJobDisplayNumberForOrder_(printJobs, printJobId) {
  const cleanId = trimString_(printJobId);
  const list = Array.isArray(printJobs) ? printJobs : [];
  for (let i = 0; i < list.length; i += 1) {
    if (trimString_(list[i] && list[i].printJobId) === cleanId) return i + 1;
  }
  return 0;
}

function getVisibleSkusForOrder_(job, portalState) {
  const jobState = portalState && portalState.printJobs ? portalState.printJobs[job.printJobId] : null;
  return (Array.isArray(job && job.skus) ? job.skus : []).filter((sku) => {
    const skuState = jobState && jobState.skus ? jobState.skus[sku.skuId] : null;
    return !(skuState && skuState.hidden === true);
  });
}

function getVisibleColorsForOrder_(jobId, sku, portalState) {
  const jobState = portalState && portalState.printJobs ? portalState.printJobs[jobId] : null;
  const skuState = jobState && jobState.skus ? jobState.skus[sku.skuId] : null;
  const colors = {};
  (Array.isArray(sku && sku.colorways) ? sku.colorways : []).forEach((color) => {
    const name = trimString_(color);
    if (name) colors[name.toLowerCase()] = name;
  });
  Object.keys((skuState && skuState.colorways) || {}).forEach((color) => {
    const name = trimString_(color);
    if (name) colors[name.toLowerCase()] = name;
  });
  return Object.keys(colors)
    .map((key) => colors[key])
    .filter((colorName) => {
      const colorState = skuState && skuState.colorways ? skuState.colorways[colorName] : null;
      return !(colorState && colorState.hidden === true);
    });
}

function getQtyBySizeForOrder_(jobId, sku, colorName, portalState) {
  const jobState = portalState && portalState.printJobs ? portalState.printJobs[jobId] : null;
  const skuState = jobState && jobState.skus ? jobState.skus[sku.skuId] : null;
  const colorState = skuState && skuState.colorways ? skuState.colorways[colorName] : null;
  const qtyBySize = {};
  (Array.isArray(sku.sizesAllowed) ? sku.sizesAllowed : []).forEach((size) => {
    qtyBySize[String(size)] = Math.max(0, parseInt(String(colorState && colorState.qtyBySize ? colorState.qtyBySize[size] : 0), 10) || 0);
  });
  return qtyBySize;
}

function getEnteredUnitsForOrderJob_(job, portalState) {
  if (!job || !job.printJobId) return 0;
  return getVisibleSkusForOrder_(job, portalState).reduce(function(jobTotal, sku) {
    return jobTotal + getVisibleColorsForOrder_(job.printJobId, sku, portalState).reduce(function(skuTotal, colorName) {
      const qtyBySize = getQtyBySizeForOrder_(job.printJobId, sku, colorName, portalState);
      return skuTotal + Object.keys(qtyBySize).reduce(function(colorTotal, size) {
        return colorTotal + Math.max(0, parseInt(String(qtyBySize[size] || 0), 10) || 0);
      }, 0);
    }, 0);
  }, 0);
}

function getMinimumUnitsForOrderJob_(job, portalState) {
  if (!job) return 0;
  const tiers = normalizeTierListForOrder_(job.priceTiers, getVisibleSkusForOrder_(job, portalState))
    .map(function(tier) { return Number(tier); })
    .filter(function(tier) { return Number.isFinite(tier) && tier > 0 && tier < 2000; })
    .sort(function(a, b) { return a - b; });
  return tiers.length ? tiers[0] : 0;
}

function buildOrderJobSelectionStateForOrder_(job, portalState, printJobs) {
  return {
    job: job,
    printJobId: trimString_(job && job.printJobId),
    printJobNumber: getPrintJobDisplayNumberForOrder_(printJobs, job && job.printJobId),
    enteredUnits: getEnteredUnitsForOrderJob_(job, portalState),
    minimumUnits: getMinimumUnitsForOrderJob_(job, portalState)
  };
}

function getOrderJobSelectionStatesForOrder_(printJobs, portalState) {
  return getVisibleJobsForOrder_(printJobs, portalState).map(function(job) {
    return buildOrderJobSelectionStateForOrder_(job, portalState, printJobs);
  });
}

function getIncludedOrderJobSelectionStates_(printJobs, portalState) {
  return getOrderJobSelectionStatesForOrder_(printJobs, portalState).filter(function(item) {
    return item.enteredUnits > 0;
  });
}

function buildOrderActionRuleState_(ctx) {
  const context = (ctx && typeof ctx === 'object') ? ctx : {};
  const row = (context.row && typeof context.row === 'object') ? context.row : {};
  const snapshot = context.snapshot || {};
  const printJobs = normalizePrintJobsForOrder_(snapshot && snapshot.printJobs);
  const portalState = normalizePortalStateForOrder_(context.portalState || {}, printJobs);
  return {
    row: row,
    snapshot: snapshot,
    printJobs: printJobs,
    portalState: portalState,
    includedJobSelectionStates: getIncludedOrderJobSelectionStates_(printJobs, portalState)
  };
}

function pickActiveTierForOrder_(tiers, totalQty) {
  const list = (Array.isArray(tiers) ? tiers : [])
    .map((tier) => Number(tier))
    .filter((tier) => Number.isFinite(tier) && tier > 0)
    .sort((a, b) => a - b);
  if (!list.length) return 1;
  const qty = Math.max(0, parseInt(String(totalQty || 0), 10) || 0);
  let chosen = list[0];
  list.forEach((tier) => {
    if (qty >= tier) chosen = tier;
  });
  return chosen;
}

function unitPriceForOrder_(sku, tier, size) {
  const map = (sku && sku.printedUnitPriceByTierBySize) || {};
  const keys = Object.keys(map)
    .map((key) => Number(key))
    .filter((num) => Number.isFinite(num))
    .sort((a, b) => a - b);
  if (!keys.length) return null;
  const wanted = Number.isFinite(Number(tier)) ? Number(tier) : keys[0];
  let chosen = keys[0];
  keys.forEach((key) => {
    if (wanted >= key) chosen = key;
  });
  const row = map[String(chosen)] || {};
  const value = Number(row[String(size)]);
  return Number.isFinite(value) ? value : null;
}

function isPortalDisplayAddOn_(addOn) {
  const raw = addOn ? addOn.portal_display : false;
  return raw === true || String(raw).toLowerCase() === 'true';
}

function isRushAddOn_(addOn) {
  const feeType = trimString_(addOn && addOn.fee_type).toLowerCase();
  const feeKey = trimString_(addOn && addOn.fee_key).toUpperCase();
  return feeType === 'percent' || feeKey.indexOf('RUSH') === 0;
}

function isShippingAddOn_(addOn) {
  const label = trimString_(
    (addOn && addOn.invoice_label) ||
    (addOn && addOn.fee_name) ||
    (addOn && addOn.name) ||
    (addOn && addOn.fee_key)
  ).toLowerCase();
  return /ship|freight|delivery/.test(label);
}

function normalizeFulfillmentMethod_(value) {
  const normalized = trimString_(value).toLowerCase();
  return normalized === FULFILLMENT_METHODS.shipping || normalized === FULFILLMENT_METHODS.pickup
    ? normalized
    : '';
}

function computeFulfillmentContextForOrderDraft_(portalState, orderTotal) {
  const fulfillmentMethod = normalizeFulfillmentMethod_(portalState && portalState.fulfillmentMethod);
  const totalCents = Math.max(0, Math.round(roundMoney_(orderTotal) * 100));
  if (fulfillmentMethod === FULFILLMENT_METHODS.shipping) {
    const qualifiesForFreeShipping = totalCents > STRIPE_FULFILLMENT_FREE_SHIPPING_THRESHOLD_CENTS;
    return {
      fulfillmentMethod: FULFILLMENT_METHODS.shipping,
      shippingChargeCents: qualifiesForFreeShipping ? 0 : STRIPE_FULFILLMENT_FLAT_RATE_SHIPPING_CENTS,
      shippingModeLabel: STRIPE_FULFILLMENT_SHIPPING_SERVICE_LABEL,
      qualifiesForFreeShipping: qualifiesForFreeShipping
    };
  }
  if (fulfillmentMethod === FULFILLMENT_METHODS.pickup) {
    return {
      fulfillmentMethod: FULFILLMENT_METHODS.pickup,
      shippingChargeCents: 0,
      shippingModeLabel: 'Local Pickup',
      qualifiesForFreeShipping: false
    };
  }
  return {
    fulfillmentMethod: '',
    shippingChargeCents: 0,
    shippingModeLabel: '',
    qualifiesForFreeShipping: false
  };
}

function extractStripeShippingDetails_(sessionObj) {
  const shippingDetails = (sessionObj && sessionObj.shipping_details && typeof sessionObj.shipping_details === 'object')
    ? sessionObj.shipping_details
    : null;
  const shippingCost = (sessionObj && sessionObj.shipping_cost && typeof sessionObj.shipping_cost === 'object')
    ? sessionObj.shipping_cost
    : null;
  if (!shippingDetails && !shippingCost) return null;
  const result = {};
  if (shippingDetails) {
    const address = shippingDetails.address && typeof shippingDetails.address === 'object'
      ? shippingDetails.address
      : null;
    result.name = trimString_(shippingDetails.name);
    result.phone = trimString_(shippingDetails.phone);
    if (address) {
      result.address = {
        line1: trimString_(address.line1),
        line2: trimString_(address.line2),
        city: trimString_(address.city),
        state: trimString_(address.state),
        postal_code: trimString_(address.postal_code),
        country: trimString_(address.country)
      };
    }
  }
  if (shippingCost) {
    result.shippingRate = trimString_(shippingCost.shipping_rate);
    result.shippingAmountTotalCents = Math.max(0, parseInt(String(shippingCost.amount_total || 0), 10) || 0);
  }
  return result;
}

function normalizeOrderDraftShippingDetailsInput_(rawDetails, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const raw = (rawDetails && typeof rawDetails === 'object') ? rawDetails : {};
  const rawAddress = (raw.address && typeof raw.address === 'object') ? raw.address : {};
  const details = {
    name: trimString_(raw.name),
    phone: trimString_(raw.phone),
    company: trimString_(raw.company),
    address: {
      line1: trimString_(rawAddress.line1 || raw.line1),
      line2: trimString_(rawAddress.line2 || raw.line2),
      city: trimString_(rawAddress.city || raw.city),
      state: trimString_(rawAddress.state || raw.state),
      postal_code: trimString_(rawAddress.postal_code || raw.postal_code || raw.zip),
      country: 'United States'
    }
  };
  const hasAnyValue = Boolean(
    details.name
    || details.phone
    || details.company
    || details.address.line1
    || details.address.line2
    || details.address.city
    || details.address.state
    || details.address.postal_code
  );
  if (!hasAnyValue && opts.preserveEmpty !== true) return null;
  return details;
}

function validateRequiredOrderDraftShippingDetails_(shippingDetails) {
  const details = normalizeOrderDraftShippingDetailsInput_(shippingDetails);
  if (!details || !details.name) return 'Enter the shipping full name before continuing.';
  if (!details.phone) return 'Enter the shipping phone number before continuing.';
  if (!details.address.line1) return 'Enter shipping address line 1 before continuing.';
  if (!details.address.city) return 'Enter the shipping city before continuing.';
  if (!details.address.state) return 'Select the shipping state before continuing.';
  if (!details.address.postal_code) return 'Enter the shipping ZIP code before continuing.';
  return '';
}

function normalizePurchaseOrderDraftStatus_(value) {
  const normalized = trimString_(value).toLowerCase();
  return normalized === PURCHASE_ORDER_DRAFT_STATUSES.email_sent
    ? PURCHASE_ORDER_DRAFT_STATUSES.email_sent
    : (normalized === PURCHASE_ORDER_DRAFT_STATUSES.draft_ready ? PURCHASE_ORDER_DRAFT_STATUSES.draft_ready : '');
}

function normalizePurchaseOrderDraftResumeStage_(value) {
  return trimString_(value).toLowerCase() === 'review' ? 'review' : 'submit';
}

function buildPurchaseOrderDraftFingerprint_(orderDraft) {
  const draft = (orderDraft && typeof orderDraft === 'object') ? orderDraft : {};
  const fingerprintSource = {
    token: trimString_(draft.token),
    snapshotId: trimString_(draft.snapshotId),
    fulfillmentMethod: normalizeFulfillmentMethod_(draft.fulfillmentMethod),
    shippingChargeCents: Math.max(0, parseInt(String(draft.shippingChargeCents || 0), 10) || 0),
    shippingModeLabel: trimString_(draft.shippingModeLabel),
    shippingDetails: normalizeOrderDraftShippingDetailsInput_(draft.shippingDetails, { preserveEmpty: true }),
    amountGrandTotal: roundMoney_(draft.amountGrandTotal),
    selectedJobs: buildPortalOrderSelectedJobsSummary_(draft.selectedJobs)
  };
  const digest = Utilities.computeDigest(
    Utilities.DigestAlgorithm.SHA_256,
    JSON.stringify(fingerprintSource)
  );
  return Utilities.base64EncodeWebSafe(digest).replace(/=+$/g, '');
}

function normalizePurchaseOrderDraftState_(rawDraft) {
  const parsed = safeJsonParse_(rawDraft, {});
  const source = (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) ? parsed : {};
  const hasMeaningfulValue = Boolean(
    source.status != null
    || source.invoiceNumber != null
    || source.invoicePdfUrl != null
    || source.invoiceFileName != null
    || source.documentReference != null
    || source.invoiceSentToEmail != null
    || source.invoiceSentAt != null
    || source.lastPreparedAt != null
    || source.draftFingerprint != null
    || source.fulfillmentMethod != null
    || source.resumeStage != null
    || source.shippingDetails != null
    || source.emailJobId != null
    || source.emailJobStatus != null
    || source.emailJobUpdatedAt != null
    || source.emailJobError != null
  );
  if (!hasMeaningfulValue) return null;
  const invoiceSentToEmail = normalizeEmailRecipients_(source.invoiceSentToEmail).join(', ');
  const status = normalizePurchaseOrderDraftStatus_(source.status)
    || (invoiceSentToEmail || trimString_(source.invoiceSentAt)
      ? PURCHASE_ORDER_DRAFT_STATUSES.email_sent
      : PURCHASE_ORDER_DRAFT_STATUSES.draft_ready);
  return {
    status: status,
    invoiceNumber: trimString_(source.invoiceNumber),
    invoicePdfUrl: trimString_(source.invoicePdfUrl),
    invoiceFileName: trimString_(source.invoiceFileName),
    documentReference: source.documentReference && typeof source.documentReference === 'object'
      ? buildPortalDocumentReference_(source.documentReference)
      : null,
    invoiceSentToEmail: invoiceSentToEmail,
    invoiceSentAt: trimString_(source.invoiceSentAt),
    lastPreparedAt: trimString_(source.lastPreparedAt),
    draftFingerprint: trimString_(source.draftFingerprint),
    fulfillmentMethod: normalizeFulfillmentMethod_(source.fulfillmentMethod),
    shippingDetails: normalizeOrderDraftShippingDetailsInput_(source.shippingDetails, { preserveEmpty: true }),
    resumeStage: normalizePurchaseOrderDraftResumeStage_(source.resumeStage),
    emailJobId: trimString_(source.emailJobId),
    emailJobStatus: trimString_(source.emailJobStatus),
    emailJobUpdatedAt: trimString_(source.emailJobUpdatedAt),
    emailJobError: trimString_(source.emailJobError)
  };
}

function readPurchaseOrderDraftFromPortalState_(portalState) {
  return normalizePurchaseOrderDraftState_(
    portalState && typeof portalState === 'object'
      ? portalState.purchaseOrderDraft
      : null
  );
}

function writePurchaseOrderDraftIntoPortalState_(portalState, draftState) {
  const nextState = JSON.parse(JSON.stringify(
    (portalState && typeof portalState === 'object' && !Array.isArray(portalState))
      ? portalState
      : { printJobs: {} }
  ));
  const normalizedDraft = normalizePurchaseOrderDraftState_(draftState);
  if (normalizedDraft) {
    nextState.purchaseOrderDraft = normalizedDraft;
  } else {
    delete nextState.purchaseOrderDraft;
  }
  return nextState;
}

function clearPurchaseOrderDraftFromPortalState_(portalState) {
  return writePurchaseOrderDraftIntoPortalState_(portalState, null);
}

function buildPurchaseOrderDraftStateFromInvoice_(ctx, invoiceInfo, options) {
  const safeInvoice = (invoiceInfo && typeof invoiceInfo === 'object') ? invoiceInfo : {};
  const opts = (options && typeof options === 'object') ? options : {};
  return normalizePurchaseOrderDraftState_({
    status: opts.status,
    invoiceNumber: trimString_(safeInvoice.invoiceNumber),
    invoicePdfUrl: trimString_(safeInvoice.invoicePdfUrl),
    invoiceFileName: trimString_(safeInvoice.fileName),
    documentReference: safeInvoice.documentReference && typeof safeInvoice.documentReference === 'object'
      ? safeInvoice.documentReference
      : null,
    invoiceSentToEmail: opts.invoiceSentToEmail,
    invoiceSentAt: trimString_(opts.invoiceSentAt),
    lastPreparedAt: trimString_(opts.lastPreparedAt) || nowIso_(),
    draftFingerprint: trimString_(opts.draftFingerprint) || buildPurchaseOrderDraftFingerprint_(ctx && ctx.orderDraft),
    fulfillmentMethod: normalizeFulfillmentMethod_(ctx && ctx.orderDraft && ctx.orderDraft.fulfillmentMethod),
    shippingDetails: ctx && ctx.orderDraft ? ctx.orderDraft.shippingDetails : null,
    resumeStage: opts.resumeStage
  });
}

function mergeOrderDraftShippingDetails_(orderDraft, sessionObj) {
  const draft = (orderDraft && typeof orderDraft === 'object')
    ? JSON.parse(JSON.stringify(orderDraft))
    : {};
  const shippingDetails = extractStripeShippingDetails_(sessionObj);
  if (!shippingDetails) return draft;
  draft.shippingDetails = shippingDetails;
  draft.shippingDetailsCaptured = true;
  return draft;
}

function computeRushAddOnAmount_(addOn, orderBasis) {
  const pct = Math.max(0, toFiniteNumber_(addOn && addOn.percent_rate, 0));
  const minAmount = Math.max(0, toFiniteNumber_(addOn && addOn.min_amount, 0));
  return roundMoney_(Math.max(minAmount, orderBasis * pct));
}

function normalizeSummaryOptionsForOrderDraft_(summaryOptions) {
  const source = (summaryOptions && typeof summaryOptions === 'object') ? summaryOptions : {};
  const hiddenZeroQtyJobIds = Array.isArray(source.hiddenZeroQtyJobIds)
    ? Array.from(new Set(source.hiddenZeroQtyJobIds
        .map(function(id) { return trimString_(id); })
        .filter(Boolean)))
    : [];
  return {
    creditCardFeeEnabled: source.creditCardFeeEnabled === true,
    salesTaxEnabled: source.salesTaxEnabled !== false,
    hiddenZeroQtyJobIds: hiddenZeroQtyJobIds
  };
}

function resolveOrderDraftTaxDecision_(accountSummary, summaryOptions) {
  const normalizedSummaryOptions = normalizeSummaryOptionsForOrderDraft_(summaryOptions);
  const taxExemptionActive = !!(accountSummary && accountSummary.taxExemptActive === true);
  const taxExemptApplied = taxExemptionActive && normalizedSummaryOptions.salesTaxEnabled === false;
  const taxShouldApply = !taxExemptApplied;
  return {
    taxShouldApply: taxShouldApply,
    taxExemptApplied: taxExemptApplied,
    taxStatusApplied: taxExemptApplied ? 'tax_exempt_active' : 'standard'
  };
}

function shouldApplySalesTaxToOrderDraft_(accountSummary, summaryOptions) {
  return resolveOrderDraftTaxDecision_(accountSummary, summaryOptions).taxShouldApply;
}

function deriveTaxAmountForOrderDraft_(totalsBeforeTax, accountSummary, summaryOptions, taxDecision) {
  const decision = (taxDecision && typeof taxDecision === 'object')
    ? taxDecision
    : resolveOrderDraftTaxDecision_(accountSummary, summaryOptions);
  if (decision.taxShouldApply !== true) return 0;
  const taxableBasis = Math.max(0, roundMoney_(toFiniteNumber_(totalsBeforeTax, 0)));
  return roundMoney_(taxableBasis * 0.06);
}

function buildOrderDraftFromSnapshotAndPortalState_(opts) {
  const options = (opts && typeof opts === 'object') ? opts : {};
  const rowInfo = options.rowInfo || null;
  const row = rowInfo && rowInfo.rowObjNormalized ? rowInfo.rowObjNormalized : ((options.row && typeof options.row === 'object') ? options.row : {});
  const snapshot = options.snapshot || safeJsonParse_(row.snapshotjson, {});
  const printJobs = normalizePrintJobsForOrder_(snapshot && snapshot.printJobs);
  const portalStateSource = safeJsonParse_(options.portalState || row.portalstatejson || {}, {});
  const portalState = normalizePortalStateForOrder_(portalStateSource, printJobs);
  const summaryOptions = normalizeSummaryOptionsForOrderDraft_(portalStateSource && portalStateSource.summaryOptions);
  portalState.fulfillmentMethod = normalizeFulfillmentMethod_(portalStateSource && portalStateSource.fulfillmentMethod);
  portalState.shippingChargeCents = Math.max(0, parseInt(String(portalStateSource && portalStateSource.shippingChargeCents || 0), 10) || 0);
  portalState.shippingModeLabel = trimString_(portalStateSource && portalStateSource.shippingModeLabel);
  portalState.shippingDetails = normalizeOrderDraftShippingDetailsInput_(portalStateSource && portalStateSource.shippingDetails);
  const accountSummary = options.accountSummary || null;
  const dealNumber = trimString_(row.dealnumber || (snapshot && snapshot.meta && snapshot.meta.dealNumber));
  const includedJobSelectionStates = getIncludedOrderJobSelectionStates_(printJobs, portalState);
  const taxDecision = resolveOrderDraftTaxDecision_(accountSummary, summaryOptions);
  const selectedJobs = [];
  const canceledJobs = [];

  let amountSubtotal = 0;
  let amountShipping = 0;
  let amountRush = 0;
  let totalUnits = 0;

  printJobs.forEach((job) => {
    const jobState = portalState && portalState.printJobs ? portalState.printJobs[job.printJobId] : null;
    if (jobState && jobState.hidden === true) {
      canceledJobs.push({
        printJobId: job.printJobId,
        printJobName: job.printJobName
      });
    }
  });

  includedJobSelectionStates.forEach((selectionState) => {
    const job = selectionState.job;
    const printJobNumber = selectionState.printJobNumber || getPrintJobDisplayNumberForOrder_(printJobs, job && job.printJobId) || 1;
    const visibleSkus = getVisibleSkusForOrder_(job, portalState);
    let jobQty = 0;
    let jobSubtotal = 0;
    const skuSummaries = [];
    const skuWorking = [];

    visibleSkus.forEach((sku) => {
      let skuUnits = 0;
      const colorSummaries = [];
      getVisibleColorsForOrder_(job.printJobId, sku, portalState).forEach((colorName) => {
        const qtyBySize = getQtyBySizeForOrder_(job.printJobId, sku, colorName, portalState);
        const rowUnits = Object.keys(qtyBySize).reduce((sum, size) => sum + Math.max(0, parseInt(String(qtyBySize[size] || 0), 10) || 0), 0);
        if (rowUnits <= 0) return;
        skuUnits += rowUnits;
        colorSummaries.push({
          colorway: colorName,
          qtyBySize: qtyBySize,
          units: rowUnits
        });
      });
      if (!skuUnits) return;
      jobQty += skuUnits;
      skuWorking.push({
        sku: sku,
        units: skuUnits,
        colors: colorSummaries
      });
    });

    const activeTier = pickActiveTierForOrder_(job.priceTiers, jobQty);
    skuWorking.forEach((entry) => {
      let skuTotal = 0;
      const priceBucketMap = {};
      const priceBuckets = [];
      entry.colors.forEach((colorSummary) => {
        Object.keys(colorSummary.qtyBySize).forEach((size) => {
          const qty = Math.max(0, parseInt(String(colorSummary.qtyBySize[size] || 0), 10) || 0);
          if (!qty) return;
          const unitPrice = unitPriceForOrder_(entry.sku, activeTier, size);
          if (unitPrice == null) return;
          const lineTotal = qty * unitPrice;
          const unitPriceRounded = roundMoney_(unitPrice);
          const unitPriceCents = Math.max(0, Math.round(unitPriceRounded * 100));
          const lineTotalCents = unitPriceCents * qty;
          skuTotal += lineTotal;
          const colorKey = trimString_(colorSummary.colorway).toLowerCase();
          const unitPriceKey = unitPriceRounded.toFixed(2);
          const bucketKey = colorKey + '|' + unitPriceKey;
          let bucket = priceBucketMap[bucketKey];
          if (!bucket) {
            bucket = {
              colorway: trimString_(colorSummary.colorway),
              unitPrice: unitPriceRounded,
              unitPriceCents: unitPriceCents,
              units: 0,
              total: 0,
              totalCents: 0,
              qtyBySize: {}
            };
            priceBucketMap[bucketKey] = bucket;
            priceBuckets.push(bucket);
          }
          bucket.units += qty;
          bucket.total += lineTotal;
          bucket.totalCents += lineTotalCents;
          bucket.qtyBySize[String(size)] = (bucket.qtyBySize[String(size)] || 0) + qty;
        });
      });
      jobSubtotal += skuTotal;
      skuSummaries.push({
        skuId: entry.sku.skuId,
        skuKey: entry.sku.skuKey,
        uiName: entry.sku.uiName,
        vendorProductUrl: entry.sku.vendorProductUrl,
        imageUrl: entry.sku.imageUrl,
        units: entry.units,
        total: roundMoney_(skuTotal),
        colors: entry.colors,
        priceBuckets: priceBuckets.map((bucket) => ({
          colorway: bucket.colorway,
          unitPrice: roundMoney_(bucket.unitPrice),
          unitPriceCents: Math.max(0, parseInt(String(bucket.unitPriceCents || 0), 10) || 0),
          units: bucket.units,
          total: roundMoney_(bucket.totalCents / 100),
          totalCents: Math.max(0, parseInt(String(bucket.totalCents || 0), 10) || 0),
          qtyBySize: bucket.qtyBySize
        }))
      });
    });

    amountSubtotal += jobSubtotal;

    const visibleAddOns = getVisibleAddOnsForOrder_(job, portalState);
    let staticPositive = 0;
    visibleAddOns.forEach((addOn) => {
      if (isRushAddOn_(addOn)) return;
      staticPositive += Math.max(0, toFiniteNumber_(addOn.amount, 0));
    });
    const rushBasis = Math.max(0, jobSubtotal + staticPositive);

    const addOnSummaries = [];
    visibleAddOns.forEach((addOn) => {
      const amount = isRushAddOn_(addOn)
        ? computeRushAddOnAmount_(addOn, rushBasis)
        : roundMoney_(toFiniteNumber_(addOn.amount, 0));
      if (!amount) return;
      if (isRushAddOn_(addOn)) amountRush += amount;
      else amountShipping += amount;
      addOnSummaries.push({
        label: trimString_(
          addOn.invoice_label ||
          addOn.fee_name ||
          addOn.name ||
          addOn.fee_key
        ),
        amount: amount,
        type: isRushAddOn_(addOn) ? 'rush' : (isShippingAddOn_(addOn) ? 'shipping' : 'fee')
      });
    });

    totalUnits += jobQty;
    selectedJobs.push({
      printJobId: job.printJobId,
      printJobNumber: printJobNumber,
      printJobName: job.printJobName,
      deliveryEstimate: job.deliveryEstimate,
      turnaroundTime: job.turnaroundTime,
      decorations: Array.isArray(job.decorations) ? job.decorations : [],
      units: jobQty,
      skus: skuSummaries,
      addOns: addOnSummaries,
      mockups: {
        previewMockupFileId: trimString_(job.mockups && job.mockups.previewMockupFileId),
        artMockupFileId: trimString_(job.mockups && job.mockups.artMockupFileId),
        garmentMockupFileId: trimString_(job.mockups && job.mockups.garmentMockupFileId),
        previewUrl: trimString_(job.mockups && job.mockups.previewUrl)
      }
    });
  });

  amountSubtotal = roundMoney_(amountSubtotal);
  amountShipping = roundMoney_(amountShipping);
  amountRush = roundMoney_(amountRush);
  const amountTax = roundMoney_(deriveTaxAmountForOrderDraft_(amountSubtotal + amountShipping + amountRush, accountSummary, summaryOptions, taxDecision));
  const amountGrandTotal = roundMoney_(amountSubtotal + amountShipping + amountRush + amountTax);
  const fulfillment = computeFulfillmentContextForOrderDraft_(portalState, amountGrandTotal);
  const orgContext = deriveOrgContextFromRow_(row);
  const accountIdentity = buildAccountIdentityFromPortalAccountSummary_(accountSummary);
  const currency = trimString_(options.currency || (snapshot && snapshot.meta && snapshot.meta.currency) || getConfig_().stripePriceCurrency || DEFAULT_STRIPE_PRICE_CURRENCY).toUpperCase();

  return {
    token: trimString_(options.token || row.token),
    snapshotId: trimString_(row.snapshotid || (snapshot && snapshot.meta && snapshot.meta.snapshotId)),
    dealNumber: trimString_(row.dealnumber || (snapshot && snapshot.meta && snapshot.meta.dealNumber)),
    projectName: deriveProjectNameForNotification_(row, snapshot, {}),
    personEmail: normalizeEmail_(orgContext.personEmail),
    personName: trimString_(accountIdentity.personName || orgContext.personName),
    billingContactName: trimString_(accountIdentity.billingContactName || orgContext.personName),
    orgId: trimString_(options.orgId || (accountSummary && accountSummary.orgId) || orgContext.orgId),
    orgName: trimString_(options.orgName || (accountSummary && accountSummary.orgName) || orgContext.orgName),
    accountId: trimString_(accountSummary && accountSummary.accountId),
    selectedJobs: selectedJobs,
    canceledJobs: canceledJobs,
    totalUnits: totalUnits,
    amountSubtotal: amountSubtotal,
    amountShipping: amountShipping,
    amountRush: amountRush,
    taxShouldApply: taxDecision.taxShouldApply,
    amountTax: amountTax,
    amountGrandTotal: amountGrandTotal,
    fulfillmentMethod: fulfillment.fulfillmentMethod,
    shippingChargeCents: fulfillment.shippingChargeCents,
    shippingCharge: roundMoney_(fulfillment.shippingChargeCents / 100),
    shippingModeLabel: fulfillment.shippingModeLabel,
    qualifiesForFreeShipping: fulfillment.qualifiesForFreeShipping,
    shippingDetails: normalizeOrderDraftShippingDetailsInput_(portalState.shippingDetails),
    shippingDetailsCaptured: !!normalizeOrderDraftShippingDetailsInput_(portalState.shippingDetails),
    currency: currency || DEFAULT_STRIPE_PRICE_CURRENCY,
    taxStatusApplied: taxDecision.taxStatusApplied,
    taxExemptApplied: taxDecision.taxExemptApplied,
    portalLockState: trimString_(row.portallockstate) || PORTAL_LOCK_STATES.editable,
    paymentState: trimString_(row.currentpaymentstate) || PAYMENT_STATES.not_started,
    paymentMethodSelected: trimString_(row.currentpaymentmethod),
    productionAuthorizationState: trimString_(row.currentproductionauthorizationstate) || PRODUCTION_AUTHORIZATION_STATES.not_authorized,
    orderState: trimString_(row.currentorderstate) || ORDER_STATES.draft,
    createdAt: nowIso_(),
    generatedAt: nowIso_()
  };
}

function getOrderSheet_(ss, cfg) {
  return ensureNamedSheetWithHeaders_(ss, cfg.portalOrdersSheetName, PORTAL_ORDER_HEADERS);
}

function getPortalEmailQueueSheet_(ss) {
  return ensureNamedSheetWithHeaders_(ss, PORTAL_EMAIL_QUEUE_SHEET_NAME, PORTAL_EMAIL_QUEUE_HEADERS);
}

function getPortalAccountSheet_(ss, cfg) {
  return ensureNamedSheetWithHeaders_(ss, cfg.portalAccountsSheetName, PORTAL_ACCOUNT_HEADERS);
}

function normalizeTeamWorkflowMode_(value) {
  const mode = trimString_(value).toLowerCase();
  if (mode === TEAM_WORKFLOW_MODES.team_hold) return TEAM_WORKFLOW_MODES.team_hold;
  if (mode === TEAM_WORKFLOW_MODES.checkout_reset) return TEAM_WORKFLOW_MODES.checkout_reset;
  return TEAM_WORKFLOW_MODES.none;
}

function normalizeTeamJobCompletionMap_(value) {
  const source = (value && typeof value === 'object' && !Array.isArray(value)) ? value : {};
  const out = {};
  Object.keys(source).forEach(function(jobId) {
    const cleanJobId = trimString_(jobId);
    if (!cleanJobId) return;
    const entry = source[jobId];
    if (!entry || typeof entry !== 'object') return;
    const completionDate = trimString_(entry.completionDate || entry.completedOn || entry.date);
    if (!completionDate) return;
    out[cleanJobId] = {
      completionDate: completionDate,
      actorName: trimString_(entry.actorName || entry.completedBy || entry.authorName),
      recordedAt: trimString_(entry.recordedAt || entry.completedAt || entry.ts)
    };
  });
  return out;
}

function readTeamWorkflowMetaFromDraft_(draft) {
  const safeDraft = (draft && typeof draft === 'object') ? draft : {};
  const raw = (safeDraft.teamModeMeta && typeof safeDraft.teamModeMeta === 'object' && !Array.isArray(safeDraft.teamModeMeta))
    ? safeDraft.teamModeMeta
    : {};
  return {
    workflowMode: normalizeTeamWorkflowMode_(raw.workflowMode),
    completedJobsByJobId: normalizeTeamJobCompletionMap_(raw.completedJobsByJobId),
    productionInitiatedAt: trimString_(raw.productionInitiatedAt),
    productionInitiatedBy: trimString_(raw.productionInitiatedBy)
  };
}

function writeTeamWorkflowMetaIntoDraft_(draft, meta) {
  const safeDraft = Object.assign({}, (draft && typeof draft === 'object') ? draft : {});
  const current = readTeamWorkflowMetaFromDraft_(safeDraft);
  const nextMeta = (meta && typeof meta === 'object') ? meta : {};
  const workflowMode = Object.prototype.hasOwnProperty.call(nextMeta, 'workflowMode')
    ? normalizeTeamWorkflowMode_(nextMeta.workflowMode)
    : current.workflowMode;
  const completedJobsByJobId = Object.prototype.hasOwnProperty.call(nextMeta, 'completedJobsByJobId')
    ? normalizeTeamJobCompletionMap_(nextMeta.completedJobsByJobId)
    : current.completedJobsByJobId;
  const productionInitiatedAt = Object.prototype.hasOwnProperty.call(nextMeta, 'productionInitiatedAt')
    ? trimString_(nextMeta.productionInitiatedAt)
    : current.productionInitiatedAt;
  const productionInitiatedBy = Object.prototype.hasOwnProperty.call(nextMeta, 'productionInitiatedBy')
    ? trimString_(nextMeta.productionInitiatedBy)
    : current.productionInitiatedBy;
  safeDraft.teamModeMeta = {
    workflowMode: workflowMode,
    completedJobsByJobId: completedJobsByJobId,
    productionInitiatedAt: productionInitiatedAt,
    productionInitiatedBy: productionInitiatedBy
  };
  return safeDraft;
}

function buildPortalOrderSelectedJobsSummary_(selectedJobs) {
  return (Array.isArray(selectedJobs) ? selectedJobs : []).map(function(job) {
    const item = (job && typeof job === 'object') ? job : {};
    return {
      printJobId: trimString_(item.printJobId),
      printJobNumber: trimString_(item.printJobNumber),
      printJobName: trimString_(item.printJobName),
      turnaroundTime: trimString_(item.turnaroundTime),
      deliveryEstimate: trimString_(item.deliveryEstimate),
      units: Math.max(0, parseInt(String(item.units || 0), 10) || 0)
    };
  }).filter(function(job) {
    return !!job.printJobId;
  });
}

function buildPortalOrderLockedDraftSummary_(orderDraft) {
  const draft = (orderDraft && typeof orderDraft === 'object') ? orderDraft : {};
  const selectedJobs = (Array.isArray(draft.selectedJobs) ? draft.selectedJobs : []).map(function(job) {
    const item = (job && typeof job === 'object') ? job : {};
    const skus = (Array.isArray(item.skus) ? item.skus : []).map(function(sku) {
      const skuItem = (sku && typeof sku === 'object') ? sku : {};
      return {
        skuId: trimString_(skuItem.skuId),
        skuKey: trimString_(skuItem.skuKey),
        uiName: trimString_(skuItem.uiName),
        vendorProductUrl: trimString_(skuItem.vendorProductUrl),
        imageUrl: trimString_(skuItem.imageUrl),
        units: Math.max(0, parseInt(String(skuItem.units || 0), 10) || 0),
        total: roundMoney_(skuItem.total || 0),
        priceBuckets: (Array.isArray(skuItem.priceBuckets) ? skuItem.priceBuckets : []).map(function(bucket) {
          const priceBucket = (bucket && typeof bucket === 'object') ? bucket : {};
          return {
            colorway: trimString_(priceBucket.colorway),
            unitPrice: roundMoney_(priceBucket.unitPrice || 0),
            unitPriceCents: Math.max(0, parseInt(String(priceBucket.unitPriceCents || 0), 10) || 0),
            units: Math.max(0, parseInt(String(priceBucket.units || 0), 10) || 0),
            total: roundMoney_(priceBucket.total || 0),
            totalCents: Math.max(0, parseInt(String(priceBucket.totalCents || 0), 10) || 0),
            qtyBySize: Object.keys((priceBucket.qtyBySize && typeof priceBucket.qtyBySize === 'object') ? priceBucket.qtyBySize : {}).reduce(function(map, size) {
              const cleanSize = trimString_(size);
              const qty = Math.max(0, parseInt(String(priceBucket.qtyBySize[size] || 0), 10) || 0);
              if (cleanSize && qty > 0) map[cleanSize] = qty;
              return map;
            }, {})
          };
        }).filter(function(bucket) {
          return bucket.units > 0;
        })
      };
    }).filter(function(sku) {
      return !!sku.skuId && sku.units > 0;
    });
    const addOns = (Array.isArray(item.addOns) ? item.addOns : []).map(function(addOn) {
      const addOnItem = (addOn && typeof addOn === 'object') ? addOn : {};
      return {
        label: trimString_(addOnItem.label),
        amount: roundMoney_(addOnItem.amount || 0),
        type: trimString_(addOnItem.type)
      };
    }).filter(function(addOn) {
      return !!addOn.label && Number(addOn.amount) !== 0;
    });
    return {
      printJobId: trimString_(item.printJobId),
      printJobNumber: trimString_(item.printJobNumber),
      printJobName: trimString_(item.printJobName),
      turnaroundTime: trimString_(item.turnaroundTime),
      deliveryEstimate: trimString_(item.deliveryEstimate),
      decorations: Array.isArray(item.decorations) ? item.decorations : [],
      units: Math.max(0, parseInt(String(item.units || 0), 10) || 0),
      skus: skus,
      addOns: addOns,
      mockups: {
        previewUrl: trimString_(item.mockups && item.mockups.previewUrl)
      }
    };
  }).filter(function(job) {
    return !!job.printJobId && job.units > 0;
  });
  return {
    selectedJobs: selectedJobs,
    canceledJobs: (Array.isArray(draft.canceledJobs) ? draft.canceledJobs : []).map(function(job) {
      const item = (job && typeof job === 'object') ? job : {};
      return {
        printJobId: trimString_(item.printJobId),
        printJobName: trimString_(item.printJobName)
      };
    }).filter(function(job) {
      return !!job.printJobId;
    }),
    totalUnits: Math.max(0, parseInt(String(draft.totalUnits || 0), 10) || 0),
    amountSubtotal: roundMoney_(draft.amountSubtotal || 0),
    amountShipping: roundMoney_(draft.amountShipping || 0),
    amountRush: roundMoney_(draft.amountRush || 0),
    amountTax: roundMoney_(draft.amountTax || 0),
    amountGrandTotal: roundMoney_(draft.amountGrandTotal || 0),
    fulfillmentMethod: normalizeFulfillmentMethod_(draft.fulfillmentMethod),
    shippingChargeCents: Math.max(0, parseInt(String(draft.shippingChargeCents || 0), 10) || 0),
    shippingModeLabel: trimString_(draft.shippingModeLabel),
    shippingDetailsCaptured: draft.shippingDetailsCaptured === true,
    shippingDetails: normalizeOrderDraftShippingDetailsInput_(draft.shippingDetails),
    generatedAt: trimString_(draft.generatedAt || draft.createdAt)
  };
}

/* ---------------- Canonical Lifecycle Source Chain ---------------- */
/* Canonical lifecycle source — do not bypass for new lifecycle decisions.
   Command chain:
   1. buildPortalOrderSummary_()
   2. buildCurrentOrderStateSummaryFromRow_()
   3. derivePortalLifecycle_()
   4. buildPortalLifecycleHydratedContext_() */
function buildPortalOrderSummary_(row) {
  const order = (row && typeof row === 'object') ? row : {};
  const draft = safeJsonParse_(order.orderdraftjson || order.orderDraftJson, {}) || {};
  const teamMeta = readTeamWorkflowMetaFromDraft_(draft);
  const summary = {
    orderId: trimString_(order.orderid || order.orderId),
    checkoutAttemptId: trimString_(order.checkoutattemptid || order.checkoutAttemptId),
    orderRevision: Math.max(1, parseInt(String(order.orderrevision || order.orderRevision || 1), 10) || 1),
    portalLockState: trimString_(order.portallockstate || order.portalLockState) || PORTAL_LOCK_STATES.editable,
    orderState: trimString_(order.orderstate || order.orderState) || ORDER_STATES.draft,
    paymentMethodSelected: trimString_(order.paymentmethodselected || order.paymentMethodSelected),
    paymentState: trimString_(order.paymentstate || order.paymentState) || PAYMENT_STATES.not_started,
    productionAuthorizationState: trimString_(order.productionauthorizationstate || order.productionAuthorizationState) || PRODUCTION_AUTHORIZATION_STATES.not_authorized,
    invoiceNumber: trimString_(order.invoicenumber || order.invoiceNumber),
    invoiceDocumentReference: draft.documentReference && typeof draft.documentReference === 'object'
      ? buildPortalDocumentReference_(draft.documentReference)
      : null,
    invoicePdfUrl: trimString_(order.invoicepdfurl || order.invoicePdfUrl),
    invoiceSentToEmail: trimString_(order.invoicesenttoemail || order.invoiceSentToEmail),
    poNumber: trimString_(order.ponumber || order.poNumber),
    poDocumentUrl: trimString_(order.podocumenturl || order.poDocumentUrl),
    poSubmittedBy: trimString_(order.posubmittedby || order.poSubmittedBy),
    poSubmittedAt: trimString_(order.posubmittedat || order.poSubmittedAt),
    approvedPaymentTermsDays: Math.max(0, parseInt(String(order.approvedpaymenttermsdays || order.approvedPaymentTermsDays || 0), 10) || 0),
    approvedPaymentTermsLabel: trimString_(order.approvedpaymenttermslabel || order.approvedPaymentTermsLabel),
    amountGrandTotal: roundMoney_(order.amountgrandtotal || order.amountGrandTotal || 0),
    amountTax: roundMoney_(order.amounttax || order.amountTax || 0),
    amountCardFee: roundMoney_(order.amountcardfee || order.amountCardFee || draft.amountCardFee || 0),
    amountChargedTax: roundMoney_(order.amountchargedtax || order.amountChargedTax || draft.amountChargedTax || 0),
    amountChargedTotal: roundMoney_(order.amountchargedtotal || order.amountChargedTotal || draft.amountChargedTotal || 0),
    stripeAmountSubtotalCents: Math.max(0, parseInt(String(order.stripeamountsubtotalcents || order.stripeAmountSubtotalCents || draft.stripeAmountSubtotalCents || 0), 10) || 0),
    stripeAmountTotalCents: Math.max(0, parseInt(String(order.stripeamounttotalcents || order.stripeAmountTotalCents || draft.stripeAmountTotalCents || 0), 10) || 0),
    currency: trimString_(order.currency || DEFAULT_STRIPE_PRICE_CURRENCY) || DEFAULT_STRIPE_PRICE_CURRENCY,
    fulfillmentMethod: normalizeFulfillmentMethod_(draft.fulfillmentMethod),
    shippingChargeCents: Math.max(0, parseInt(String(draft.shippingChargeCents || 0), 10) || 0),
    shippingModeLabel: trimString_(draft.shippingModeLabel),
    shippingDetailsCaptured: draft.shippingDetailsCaptured === true,
    shippingDetails: normalizeOrderDraftShippingDetailsInput_(draft.shippingDetails),
    paidAt: trimString_(order.paidat || order.paidAt),
    paymentReceivedManuallyAt: trimString_(order.paymentreceivedmanuallyat || order.paymentReceivedManuallyAt),
    authorizedToProduceAt: trimString_(order.authorizedtoproduceat || order.authorizedToProduceAt),
    lockedAt: trimString_(order.lockedat || order.lockedAt),
    createdAt: trimString_(order.createdat || order.createdAt),
    stripeSessionId: trimString_(order.stripesessionid || order.stripeSessionId),
    stripePaymentIntentId: trimString_(order.stripepaymentintentid || order.stripePaymentIntentId),
    achPaymentMethodId: trimString_(order.achpaymentmethodid || order.achPaymentMethodId),
    achBankName: trimString_(order.achbankname || order.achBankName),
    achLast4: trimString_(order.achlast4 || order.achLast4),
    achMandateId: trimString_(order.achmandateid || order.achMandateId),
    achFinancialConnectionsAccountId: trimString_(order.achfinancialconnectionsaccountid || order.achFinancialConnectionsAccountId),
    achVerificationStatus: trimString_(order.achverificationstatus || order.achVerificationStatus),
    achVerificationFlow: trimString_(order.achverificationflow || order.achVerificationFlow),
    achPaymentSource: trimString_(order.achpaymentsource || order.achPaymentSource),
    achPaymentVisibilityScope: trimString_(order.achpaymentvisibilityscope || order.achPaymentVisibilityScope),
    stripeAchCustomerId: trimString_(order.stripeachcustomerid || order.stripeAchCustomerId),
    achExpectedDebitDate: trimString_(order.achexpecteddebitdate || order.achExpectedDebitDate),
    achFailureCode: trimString_(order.achfailurecode || order.achFailureCode),
    achFailureMessage: trimString_(order.achfailuremessage || order.achFailureMessage),
    achPendingProductionApprovedAtOrder: trimString_(order.achpendingproductionapprovedatorder || order.achPendingProductionApprovedAtOrder),
    stripeLatestChargeId: trimString_(order.stripelatestchargeid || order.stripeLatestChargeId),
    stripeLatestEventId: trimString_(order.stripelatesteventid || order.stripeLatestEventId),
    stripeLatestEventType: trimString_(order.stripelatesteventtype || order.stripeLatestEventType),
    stripeLatestEventAt: trimString_(order.stripelatesteventat || order.stripeLatestEventAt),
    lastUpdatedAt: trimString_(order.lastupdatedat || order.lastUpdatedAt),
    teamWorkflowMode: teamMeta.workflowMode,
    teamJobCompletionByJobId: teamMeta.completedJobsByJobId,
    selectedJobs: buildPortalOrderSelectedJobsSummary_(draft.selectedJobs),
    lockedOrderDraft: buildPortalOrderLockedDraftSummary_(draft)
  };
  summary.displayStatus = derivePortalDisplayOrderStatus_(summary, order.status);
  return summary;
}

function getLatestPortalOrderByToken_(token, options) {
  const cleanToken = trimString_(token);
  if (!cleanToken) return null;
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const ordersSheet = opts.ordersSheet || getOrderSheet_(ss, cfg);
  const rows = findOrderRowsByToken_(ordersSheet, cleanToken);
  if (!rows.length) return null;
  rows.sort(comparePortalOrderInfosDesc_);
  return rows[0];
}

function comparePortalOrderInfosDesc_(a, b) {
  const rowA = a && a.rowObjNormalized ? a.rowObjNormalized : {};
  const rowB = b && b.rowObjNormalized ? b.rowObjNormalized : {};
  const tsA = parseIsoDateMs_(rowA.lastupdatedat || rowA.createdat);
  const tsB = parseIsoDateMs_(rowB.lastupdatedat || rowB.createdat);
  if (tsA !== tsB) return tsB - tsA;
  const revA = Math.max(1, parseInt(String(rowA.orderrevision || 1), 10) || 1);
  const revB = Math.max(1, parseInt(String(rowB.orderrevision || 1), 10) || 1);
  if (revA !== revB) return revB - revA;
  return 0;
}

function buildLatestPortalOrderInfoMapByToken_(tokens, options) {
  const cleanTokens = uniqueTrimmedStrings_(tokens);
  if (!cleanTokens.length) return {};
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const ordersSheet = opts.ordersSheet || getOrderSheet_(ss, cfg);
  if (cleanTokens.length <= 8) {
    return cleanTokens.reduce(function(map, token) {
      const info = getLatestPortalOrderByToken_(token, {
        cfg: cfg,
        ss: ss,
        ordersSheet: ordersSheet
      });
      if (info) map[token] = info;
      return map;
    }, {});
  }
  const tokenSet = cleanTokens.reduce(function(map, token) {
    map[token] = true;
    return map;
  }, {});
  const latestByToken = {};
  listSheetRowInfos_(ordersSheet).forEach(function(info) {
    const token = trimString_(info && info.rowObjNormalized && info.rowObjNormalized.token);
    if (!token || !tokenSet[token]) return;
    const current = latestByToken[token] || null;
    if (!current || comparePortalOrderInfosDesc_(info, current) < 0) {
      latestByToken[token] = info;
    }
  });
  return latestByToken;
}

function listPortalOrdersByToken_(token, options) {
  const cleanToken = trimString_(token);
  if (!cleanToken) return [];
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const ordersSheet = opts.ordersSheet || getOrderSheet_(ss, cfg);
  return findOrderRowsByToken_(ordersSheet, cleanToken)
    .sort((a, b) => {
      const tsA = parseIsoDateMs_(a.rowObjNormalized.lastupdatedat || a.rowObjNormalized.createdat);
      const tsB = parseIsoDateMs_(b.rowObjNormalized.lastupdatedat || b.rowObjNormalized.createdat);
      if (tsA !== tsB) return tsB - tsA;
      const revA = Math.max(1, parseInt(String(a.rowObjNormalized.orderrevision || 1), 10) || 1);
      const revB = Math.max(1, parseInt(String(b.rowObjNormalized.orderrevision || 1), 10) || 1);
      if (revA !== revB) return revB - revA;
      return 0;
    });
}

function findOrderRowsByToken_(ordersSheet, token) {
  const cleanToken = trimString_(token);
  if (!ordersSheet || !cleanToken) return [];
  const lastCol = ordersSheet.getLastColumn();
  const lastRow = ordersSheet.getLastRow();
  if (lastCol < 1 || lastRow < 2) return [];
  const header = ordersSheet.getRange(1, 1, 1, lastCol).getValues()[0];
  const colMap = buildColumnMap_(header);
  const tokenCol = colMap.token;
  if (!tokenCol) return [];
  const tokenRange = ordersSheet.getRange(2, tokenCol, lastRow - 1, 1);
  const matches = tokenRange.createTextFinder(cleanToken).matchEntireCell(true).findAll() || [];
  if (!matches.length) return [];
  return matches.map(function(cell) {
    const rowNumber = cell.getRow();
    const rowVals = ordersSheet.getRange(rowNumber, 1, 1, lastCol).getValues()[0];
    return buildRowInfoFromSheet_(ordersSheet, rowNumber, header, rowVals);
  });
}

function findReusablePurchaseOrderOrderByToken_(token, options) {
  const rows = listPortalOrdersByToken_(token, options);
  if (!rows.length) return null;
  const priority = {};
  priority[ORDER_STATES.awaiting_po_submission] = 3;
  priority[ORDER_STATES.ready_for_production] = 2;
  priority[ORDER_STATES.awaiting_payment_confirmation] = 1;
  const poRows = rows.filter(function(info) {
    return trimString_(info.rowObjNormalized.paymentmethodselected) === PAYMENT_METHODS.purchase_order;
  });
  if (!poRows.length) return null;
  poRows.sort(function(a, b) {
    const stateA = trimString_(a.rowObjNormalized.orderstate);
    const stateB = trimString_(b.rowObjNormalized.orderstate);
    const scoreA = priority[stateA] || 0;
    const scoreB = priority[stateB] || 0;
    if (scoreA !== scoreB) return scoreB - scoreA;
    const revA = Math.max(1, parseInt(String(a.rowObjNormalized.orderrevision || 1), 10) || 1);
    const revB = Math.max(1, parseInt(String(b.rowObjNormalized.orderrevision || 1), 10) || 1);
    if (revA !== revB) return revB - revA;
    const tsA = parseIsoDateMs_(a.rowObjNormalized.lastupdatedat || a.rowObjNormalized.createdat);
    const tsB = parseIsoDateMs_(b.rowObjNormalized.lastupdatedat || b.rowObjNormalized.createdat);
    return tsB - tsA;
  });
  return poRows[0];
}

