function writeCurrentOrderPointersToExportLog_(opts) {
  const options = (opts && typeof opts === 'object') ? opts : {};
  const cfg = options.cfg || getConfig_();
  const ss = options.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = options.infra || ensurePortalInfrastructure_(ss, cfg);
  const exportSheet = infra.exportSheet;
  const rowInfo = options.rowInfo || findRowByToken_(exportSheet, trimString_(options.token));
  if (!rowInfo) throw new Error('Token not found.');
  const orderSummary = options.orderSummary || {};
  const accountSummary = options.accountSummary || {};
  const updates = {
    activeOrderId: trimString_(orderSummary.orderId || options.activeOrderId),
    latestCheckoutAttemptId: trimString_(orderSummary.checkoutAttemptId || options.latestCheckoutAttemptId),
    currentAccountId: trimString_(accountSummary.accountId || options.currentAccountId),
    portalLockState: trimString_(orderSummary.portalLockState || options.portalLockState),
    currentOrderState: trimString_(orderSummary.orderState || options.currentOrderState),
    currentPaymentState: trimString_(orderSummary.paymentState || options.currentPaymentState),
    currentProductionAuthorizationState: trimString_(orderSummary.productionAuthorizationState || options.currentProductionAuthorizationState),
    currentPaymentMethod: trimString_(orderSummary.paymentMethodSelected || options.currentPaymentMethod),
    teamWorkflowMode: normalizeTeamWorkflowMode_(orderSummary.teamWorkflowMode || options.teamWorkflowMode),
    teamJobCompletionJson: JSON.stringify(normalizeTeamJobCompletionMap_(orderSummary.teamJobCompletionByJobId || options.teamJobCompletionByJobId)),
    termsApproved: Boolean(accountSummary.termsApproved === true || options.termsApproved === true),
    taxExemptApproved: Boolean(accountSummary.taxExemptApproved === true || options.taxExemptApproved === true),
    latestInvoiceNumber: trimString_(orderSummary.invoiceNumber || options.latestInvoiceNumber),
    lastOrderUpdatedAt: trimString_(orderSummary.lastUpdatedAt || options.lastOrderUpdatedAt || nowIso_())
  };
  updates.status = derivePortalDisplayOrderStatus_(Object.assign({}, rowInfo.rowObjNormalized || {}, updates, {
    paymentState: trimString_(orderSummary.paymentState || options.currentPaymentState),
    productionAuthorizationState: trimString_(orderSummary.productionAuthorizationState || options.currentProductionAuthorizationState),
    paidAt: trimString_(orderSummary.paidAt || options.paidAt),
    authorizedToProduceAt: trimString_(orderSummary.authorizedToProduceAt || options.authorizedToProduceAt),
    status: options.status || (rowInfo.rowObjNormalized && rowInfo.rowObjNormalized.status)
  }), options.status);
  setRowValuesByHeaderMap_(exportSheet, rowInfo.row, rowInfo.colMap, updates);
  SpreadsheetApp.flush();
  const refreshedRowInfo = buildRowInfoFromSheet_(exportSheet, rowInfo.row);
  invalidateDashboardProjectsCacheForRow_(refreshedRowInfo);
  return refreshedRowInfo;
}

function invalidateDashboardProjectsCacheForEmail_(email) {
  const normalizedEmail = normalizeEmail_(email);
  bumpDashboardProjectsCacheEpoch_();
  if (!normalizedEmail) return;
  try {
    const cache = CacheService.getScriptCache();
    cache.remove(buildProjectsCacheKey_(normalizedEmail, 'summary'));
    cache.remove(buildProjectsCacheKey_(normalizedEmail, 'full'));
  } catch (_) {}
}

function invalidateDashboardProjectsCacheForRow_(rowInfo) {
  const normalizedRow = rowInfo && rowInfo.rowObjNormalized && typeof rowInfo.rowObjNormalized === 'object'
    ? rowInfo.rowObjNormalized
    : ((rowInfo && typeof rowInfo === 'object') ? rowInfo : {});
  invalidateDashboardProjectsCacheForEmail_(normalizedRow.personemail || normalizedRow.personEmail);
}

function buildCurrentOrderStateSummaryFromRow_(row, accountSummary, latestOrderSummary) {
  /* Canonical lifecycle source — export-row pointer summary only.
     Raw export-row fields remain compatibility inputs here; do not use them
     directly for new lifecycle decisions outside the canonical chain. */
  const normalizedRow = (row && typeof row === 'object') ? row : {};
  const latest = latestOrderSummary || {};
  const account = accountSummary || {};
  const portalState = safeJsonParse_(normalizedRow.portalstatejson, {}) || {};
  const purchaseOrderDraft = readPurchaseOrderDraftFromPortalState_(portalState);
  const currentPortalLockState = trimString_(normalizedRow.portallockstate).toLowerCase();
  const currentOrderState = trimString_(normalizedRow.currentorderstate).toLowerCase();
  const currentPaymentState = trimString_(normalizedRow.currentpaymentstate).toLowerCase();
  const currentProductionState = trimString_(normalizedRow.currentproductionauthorizationstate).toLowerCase();
  const hasCurrentLifecyclePointers = Boolean(
    trimString_(normalizedRow.activeorderid)
    || trimString_(normalizedRow.latestcheckoutattemptid)
    || currentPortalLockState === PORTAL_LOCK_STATES.locked
    || (currentOrderState && currentOrderState !== ORDER_STATES.draft)
    || (currentPaymentState && currentPaymentState !== PAYMENT_STATES.not_started)
    || (currentProductionState && currentProductionState !== PRODUCTION_AUTHORIZATION_STATES.not_authorized)
    || trimString_(normalizedRow.currentpaymentmethod)
    || trimString_(normalizedRow.paidat)
    || trimString_(normalizedRow.posubmittedat)
    || trimString_(normalizedRow.authorizedtoproduceat)
    || !!purchaseOrderDraft
  );
  const hasLatestOrderSummary = !!trimString_(latest.orderId);
  const pointerSource = (hasCurrentLifecyclePointers || !hasLatestOrderSummary) ? normalizedRow : latest;
  const summary = {
    activeOrderId: trimString_(pointerSource.activeorderid || pointerSource.orderId),
    latestCheckoutAttemptId: trimString_(pointerSource.latestcheckoutattemptid || pointerSource.checkoutAttemptId),
    currentAccountId: trimString_(pointerSource.currentaccountid || account.accountId),
    portalLockState: trimString_(pointerSource.portallockstate || pointerSource.portalLockState || PORTAL_LOCK_STATES.editable),
    currentOrderState: trimString_(pointerSource.currentorderstate || pointerSource.orderState || ORDER_STATES.draft),
    currentPaymentState: trimString_(pointerSource.currentpaymentstate || pointerSource.paymentState || PAYMENT_STATES.not_started),
    currentProductionAuthorizationState: trimString_(pointerSource.currentproductionauthorizationstate || pointerSource.productionAuthorizationState || PRODUCTION_AUTHORIZATION_STATES.not_authorized),
    currentPaymentMethod: trimString_(pointerSource.currentpaymentmethod || pointerSource.paymentMethodSelected),
    teamWorkflowMode: normalizeTeamWorkflowMode_(pointerSource.teamworkflowmode || pointerSource.teamWorkflowMode),
    teamJobCompletionByJobId: normalizeTeamJobCompletionMap_(
      trimString_(normalizedRow.teamjobcompletionjson)
        ? safeJsonParse_(normalizedRow.teamjobcompletionjson, {})
        : (latest.teamJobCompletionByJobId || {})
    ),
    termsApproved: boolFromCell_(normalizedRow.termsapproved || account.termsApproved),
    taxExemptApproved: boolFromCell_(normalizedRow.taxexemptapproved || account.taxExemptApproved),
    latestInvoiceNumber: trimString_(pointerSource.latestinvoicenumber || pointerSource.invoiceNumber),
    lastOrderUpdatedAt: trimString_(pointerSource.lastorderupdatedat || pointerSource.lastUpdatedAt),
    purchaseOrderDraft: purchaseOrderDraft
  };
  summary.displayStatus = derivePortalDisplayOrderStatus_(summary, normalizedRow.status || latest.displayStatus || latest.status);
  return summary;
}

function deriveAchLifecycleState_(context) {
  const ctx = (context && typeof context === 'object') ? context : {};
  const latest = (ctx.latest && typeof ctx.latest === 'object') ? ctx.latest : {};
  const paymentState = trimString_(ctx.paymentState || latest.paymentState).toLowerCase();
  const orderState = trimString_(ctx.orderState || latest.orderState).toLowerCase();
  const achPaymentSource = normalizeAchPaymentSource_(ctx.achPaymentSource || latest.achPaymentSource);
  const stripeSessionId = trimString_(ctx.stripeSessionId || latest.stripeSessionId);
  const checkoutAttemptId = trimString_(ctx.checkoutAttemptId || latest.checkoutAttemptId);
  const verificationStatus = trimString_(latest.achVerificationStatus).toLowerCase();
  const failureCode = trimString_(latest.achFailureCode).toLowerCase();
  const eventType = trimString_(latest.stripeLatestEventType).toLowerCase();
  const isApPaymentLink = achPaymentSource === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link;
  const hasCheckoutSignal = !!stripeSessionId || !!checkoutAttemptId;
  if (paymentState === PAYMENT_STATES.paid) return ACH_DETAIL_STATES.paid;
  if (eventType === 'charge.dispute.created' || failureCode.indexOf('dispute') >= 0) return ACH_DETAIL_STATES.disputed;
  if (paymentState === PAYMENT_STATES.failed) {
    if (failureCode.indexOf('mandate') >= 0 || failureCode.indexOf('authorization') >= 0) {
      return ACH_DETAIL_STATES.blocked_or_mandate_invalid;
    }
    return ACH_DETAIL_STATES.failed;
  }
  if (verificationStatus.indexOf('microdeposit') >= 0 || verificationStatus === 'requires_action') {
    return ACH_DETAIL_STATES.microdeposit_pending;
  }
  if (verificationStatus.indexOf('pending') >= 0 || verificationStatus === 'unverified') {
    return ACH_DETAIL_STATES.bank_verification_pending;
  }
  if (paymentState === PAYMENT_STATES.checkout_created || orderState === ORDER_STATES.payment_in_progress) {
    return ACH_DETAIL_STATES.checkout_started;
  }
  if (isApPaymentLink && paymentState === PAYMENT_STATES.not_started && !hasCheckoutSignal) {
    return ACH_DETAIL_STATES.not_started;
  }
  if (paymentState === PAYMENT_STATES.pending || orderState === ORDER_STATES.awaiting_payment_confirmation) {
    return ACH_DETAIL_STATES.processing;
  }
  return ACH_DETAIL_STATES.not_started;
}

function isPortalProductionStartTriggerActive_(context) {
  const ctx = (context && typeof context === 'object') ? context : {};
  const orderState = trimString_(ctx.orderState).toLowerCase();
  return ctx.isPaymentReceived === true
    || ctx.isPoSubmitted === true
    || orderState === ORDER_STATES.in_production
    || ctx.hasAnyCompletionSignal === true;
}

function derivePortalLifecycle_(context) {
  /* Canonical lifecycle source — do not bypass. New lifecycle states, booleans,
     and next-action semantics should be derived here first. */
  const options = context;
  const opts = (options && typeof options === 'object') ? options : {};
  const row = (opts.row && typeof opts.row === 'object') ? opts.row : {};
  const latest = (opts.latestOrderSummary && typeof opts.latestOrderSummary === 'object') ? opts.latestOrderSummary : {};
  const current = (opts.currentStateSummary && typeof opts.currentStateSummary === 'object') ? opts.currentStateSummary : {};
  const account = (opts.accountSummary && typeof opts.accountSummary === 'object') ? opts.accountSummary : {};
  const paymentMethodSelected = trimString_(
    current.currentPaymentMethod ||
    latest.paymentMethodSelected ||
    row.currentpaymentmethod ||
    row.paymentmethodselected
  ).toLowerCase();
  const portalLockState = trimString_(
    current.portalLockState ||
    latest.portalLockState ||
    row.currentportallockstate ||
    row.portallockstate
  ).toLowerCase();
  const orderState = trimString_(
    current.currentOrderState ||
    latest.orderState ||
    row.currentorderstate ||
    row.orderstate
  ).toLowerCase();
  const paymentState = trimString_(
    current.currentPaymentState ||
    latest.paymentState ||
    row.currentpaymentstate ||
    row.paymentstate
  ).toLowerCase();
  const productionAuthorizationState = trimString_(
    current.currentProductionAuthorizationState ||
    latest.productionAuthorizationState ||
    row.currentproductionauthorizationstate ||
    row.productionauthorizationstate
  ).toLowerCase();
  const teamWorkflowMode = normalizeTeamWorkflowMode_(
    current.teamWorkflowMode ||
    latest.teamWorkflowMode ||
    row.teamworkflowmode
  );
  const activeOrderId = trimString_(
    current.activeOrderId ||
    latest.orderId ||
    row.activeorderid
  );
  const latestCheckoutAttemptId = trimString_(
    current.latestCheckoutAttemptId ||
    latest.checkoutAttemptId ||
    row.latestcheckoutattemptid
  );
  const stripeSessionId = trimString_(
    latest.stripeSessionId ||
    row.stripesessionid
  );
  const stripePaymentIntentId = trimString_(
    latest.stripePaymentIntentId ||
    row.stripepaymentintentid
  );
  const achPaymentSource = normalizeAchPaymentSource_(
    latest.achPaymentSource ||
    row.achpaymentsource ||
    current.achPaymentSource
  );
  const purchaseOrderDraft = normalizePurchaseOrderDraftState_(
    current.purchaseOrderDraft
    || readPurchaseOrderDraftFromPortalState_(safeJsonParse_(row.portalstatejson, {}))
  );
  const invoiceNumber = trimString_(current.latestInvoiceNumber || latest.invoiceNumber || row.latestinvoicenumber);
  const lockedAt = trimString_(latest.lockedAt || row.lockedat);
  const createdAt = trimString_(latest.createdAt);
  const paidAt = trimString_(latest.paidAt || row.paidat);
  const paymentReceivedManuallyAt = trimString_(latest.paymentReceivedManuallyAt || row.paymentreceivedmanuallyat);
  const authorizedToProduceAt = trimString_(latest.authorizedToProduceAt || row.authorizedtoproduceat);
  const poSubmittedAt = trimString_(latest.poSubmittedAt || row.posubmittedat);
  const poNumber = trimString_(latest.poNumber || row.ponumber);
  const lastOrderUpdatedAt = trimString_(latest.lastUpdatedAt || current.lastOrderUpdatedAt || row.lastorderupdatedat);
  const completionMap = normalizeTeamJobCompletionMap_(
    latest.teamJobCompletionByJobId ||
    current.teamJobCompletionByJobId ||
    (trimString_(row.teamjobcompletionjson) ? safeJsonParse_(row.teamjobcompletionjson, {}) : {})
  );
  const selectedJobs = Array.isArray(latest.selectedJobs) ? latest.selectedJobs : [];
  const actualCompletionMeta = deriveDashboardActualCompletionMeta_(selectedJobs, completionMap);
  const isPoFlow = deriveDashboardWorkflowVariant_(row, latest, current) === 'purchase_order';
  const isLocked = portalLockState === PORTAL_LOCK_STATES.locked;
  const isEditable = portalLockState === PORTAL_LOCK_STATES.editable;
  const isTeamHold = teamWorkflowMode === TEAM_WORKFLOW_MODES.team_hold;
  const isCheckoutReset = teamWorkflowMode === TEAM_WORKFLOW_MODES.checkout_reset;
  const isStripeMethod = paymentMethodSelected === PAYMENT_METHODS.card || paymentMethodSelected === PAYMENT_METHODS.ach;
  const isAchMethod = paymentMethodSelected === PAYMENT_METHODS.ach;
  const isManualMethod = paymentMethodSelected === PAYMENT_METHODS.check || paymentMethodSelected === PAYMENT_METHODS.cash;
  const isApPaymentLinkAch = isAchMethod && achPaymentSource === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link;
  const hasStripeCheckoutSignal = !!stripeSessionId || !!latestCheckoutAttemptId || !!stripePaymentIntentId;
  const isApPaymentLinkAwaitingPayment = isApPaymentLinkAch
    && paymentState === PAYMENT_STATES.not_started
    && !hasStripeCheckoutSignal;
  const isApPaymentLinkCheckoutStarted = isApPaymentLinkAch
    && paymentState === PAYMENT_STATES.checkout_created;
  const paymentPath = isPoFlow
    ? PAYMENT_METHODS.purchase_order
    : (isManualMethod ? 'manual' : (isStripeMethod ? 'stripe' : 'none'));
  const isPaymentReceived = !!paidAt
    || paymentState === PAYMENT_STATES.paid
    || paymentState === PAYMENT_STATES.manual_received;
  const isPoSubmitted = isPoFlow && (
    !!poSubmittedAt ||
    !!poNumber
  );
  const hasProductionStartTriggerSeed = isPortalProductionStartTriggerActive_({
    isPaymentReceived: isPaymentReceived,
    isPoSubmitted: isPoSubmitted,
    orderState: orderState,
    hasAnyCompletionSignal: false
  });
  const productionStartAt = derivePortalProductionStartAt_({
    paymentPath: paymentPath,
    poSubmittedAt: poSubmittedAt,
    paymentReceivedManuallyAt: paymentReceivedManuallyAt,
    paidAt: paidAt,
    authorizedToProduceAt: hasProductionStartTriggerSeed ? authorizedToProduceAt : '',
    lockedAt: lockedAt
  });
  const productionTargetMeta = derivePortalProductionTargetMeta_(selectedJobs, productionStartAt);
  const validatedCompletionMeta = derivePortalValidatedCompletionMeta_(selectedJobs, completionMap, {
    productionStartAt: productionStartAt,
    lastOrderUpdatedAt: lastOrderUpdatedAt
  });
  const hasAnyCompletionSignal = validatedCompletionMeta.hasAnyCompletionSignal === true;
  const allSelectedJobsCompleted = validatedCompletionMeta.allJobsCompleted === true;
  const deadlineCompletionReached = hasDashboardDateReached_(productionTargetMeta.dateValue);
  let productionCompletionSource = '';
  if (allSelectedJobsCompleted) productionCompletionSource = 'team_jobs';
  else if (deadlineCompletionReached) productionCompletionSource = 'deadline_reached';
  else if (orderState === ORDER_STATES.closed) productionCompletionSource = 'order_closed';
  const productionComplete = productionCompletionSource !== '';
  const productionCompletionAt = productionCompletionSource === 'team_jobs'
    ? trimString_(validatedCompletionMeta.iso)
    : (productionCompletionSource === 'deadline_reached'
      ? trimString_(productionTargetMeta.iso)
      : (productionCompletionSource === 'order_closed'
        ? (buildPortalLifecycleIsoDateString_(lastOrderUpdatedAt) || trimString_(productionTargetMeta.iso))
        : ''));
  const productionStartTriggerActive = isPortalProductionStartTriggerActive_({
    isPaymentReceived: isPaymentReceived,
    isPoSubmitted: isPoSubmitted,
    orderState: orderState,
    hasAnyCompletionSignal: hasAnyCompletionSignal
  });
  const isProductionAuthorized = productionStartTriggerActive || productionComplete;
  const hasProductionCompletion = productionComplete
    || orderState === ORDER_STATES.in_production
    || hasAnyCompletionSignal;
  const isAwaitingPoSubmission = isPoFlow
    && !isPoSubmitted
    && (
      !!purchaseOrderDraft ||
      orderState === ORDER_STATES.awaiting_po_submission ||
      productionAuthorizationState === PRODUCTION_AUTHORIZATION_STATES.po_pending ||
      paymentMethodSelected === PAYMENT_METHODS.purchase_order
    );
  const isCheckoutStarted = !isPoFlow
    && !isPaymentReceived
    && !isProductionAuthorized
    && !isApPaymentLinkAwaitingPayment
    && (
      orderState === ORDER_STATES.payment_in_progress ||
      paymentState === PAYMENT_STATES.checkout_created ||
      paymentState === PAYMENT_STATES.submitted ||
      paymentState === PAYMENT_STATES.pending ||
      (isStripeMethod && (!!activeOrderId || !!trimString_(lockedAt)))
    );
  const isManualPendingLocked = !isPoFlow
    && isLocked
    && !isPaymentReceived
    && !isProductionAuthorized
    && (
      orderState === ORDER_STATES.awaiting_manual_payment ||
      paymentState === PAYMENT_STATES.manual_pending ||
      isManualMethod
    );
  const achDetailState = isAchMethod
    ? deriveAchLifecycleState_({
      latest: latest,
      paymentState: paymentState,
      orderState: orderState,
      achPaymentSource: achPaymentSource,
      stripeSessionId: stripeSessionId,
      checkoutAttemptId: latestCheckoutAttemptId
    })
    : ACH_DETAIL_STATES.not_started;
  const isAchPaymentPendingLocked = !isPoFlow
    && isAchMethod
    && isLocked
    && !isPaymentReceived
    && !isProductionAuthorized
    && (
      paymentState === PAYMENT_STATES.pending
      || paymentState === PAYMENT_STATES.failed
      || orderState === ORDER_STATES.awaiting_payment_confirmation
    );
  const isLockedPoSubmittedUnpaid = isLocked
    && isPoFlow
    && isPoSubmitted
    && !isPaymentReceived;
  let lifecycleStage = PORTAL_LIFECYCLE_STAGES.editable;
  if (isTeamHold || isCheckoutReset) {
    lifecycleStage = PORTAL_LIFECYCLE_STAGES.editable;
  } else if (hasProductionCompletion) {
    lifecycleStage = PORTAL_LIFECYCLE_STAGES.in_production_or_complete;
  } else if (isLockedPoSubmittedUnpaid) {
    lifecycleStage = PORTAL_LIFECYCLE_STAGES.po_submitted_unpaid;
  } else if (isPaymentReceived || isProductionAuthorized) {
    lifecycleStage = PORTAL_LIFECYCLE_STAGES.paid_or_authorized;
  } else if (isAwaitingPoSubmission && isLocked) {
    lifecycleStage = PORTAL_LIFECYCLE_STAGES.po_draft_locked;
  } else if (isAchPaymentPendingLocked) {
    lifecycleStage = PORTAL_LIFECYCLE_STAGES.payment_pending_locked;
  } else if (isManualPendingLocked) {
    lifecycleStage = PORTAL_LIFECYCLE_STAGES.manual_pending_locked;
  } else if (isCheckoutStarted) {
    lifecycleStage = PORTAL_LIFECYCLE_STAGES.checkout_started;
  }
  const summaryDocumentMode = lifecycleStage === PORTAL_LIFECYCLE_STAGES.po_draft_locked
    ? SUMMARY_DOCUMENT_MODES.po_draft_invoice
    : (lifecycleStage === PORTAL_LIFECYCLE_STAGES.manual_pending_locked
      ? SUMMARY_DOCUMENT_MODES.manual_pending_invoice
      : ((lifecycleStage === PORTAL_LIFECYCLE_STAGES.payment_pending_locked
          || lifecycleStage === PORTAL_LIFECYCLE_STAGES.po_submitted_unpaid
          || lifecycleStage === PORTAL_LIFECYCLE_STAGES.paid_or_authorized
          || lifecycleStage === PORTAL_LIFECYCLE_STAGES.in_production_or_complete)
        ? SUMMARY_DOCUMENT_MODES.locked_invoice
        : SUMMARY_DOCUMENT_MODES.estimate));
  const hasPlacedOrder = !isTeamHold && !isCheckoutReset && (
    lifecycleStage === PORTAL_LIFECYCLE_STAGES.payment_pending_locked
    || lifecycleStage === PORTAL_LIFECYCLE_STAGES.manual_pending_locked
    || lifecycleStage === PORTAL_LIFECYCLE_STAGES.po_submitted_unpaid
    || lifecycleStage === PORTAL_LIFECYCLE_STAGES.paid_or_authorized
    || lifecycleStage === PORTAL_LIFECYCLE_STAGES.in_production_or_complete
  );
  const hasLockedInvoice = summaryDocumentMode !== SUMMARY_DOCUMENT_MODES.estimate;
  const hasSelectedJobs = selectedJobs.length > 0;
  const hasAnyActualJobCompletion = actualCompletionMeta.hasAnyActualCompletion === true;
  const isPaymentPending = lifecycleStage === PORTAL_LIFECYCLE_STAGES.checkout_started
    || lifecycleStage === PORTAL_LIFECYCLE_STAGES.payment_pending_locked
    || lifecycleStage === PORTAL_LIFECYCLE_STAGES.manual_pending_locked
    || lifecycleStage === PORTAL_LIFECYCLE_STAGES.po_submitted_unpaid;
  const canCancelPendingClientFlow = lifecycleStage === PORTAL_LIFECYCLE_STAGES.po_draft_locked
    || lifecycleStage === PORTAL_LIFECYCLE_STAGES.manual_pending_locked;
  const cancelFlowKind = lifecycleStage === PORTAL_LIFECYCLE_STAGES.po_draft_locked
    ? PAYMENT_METHODS.purchase_order
    : (lifecycleStage === PORTAL_LIFECYCLE_STAGES.manual_pending_locked ? 'manual_payment' : '');
  const manualPaymentPending = isManualPendingLocked
    || paymentState === PAYMENT_STATES.manual_pending;
  const manualPaymentReceived = paymentState === PAYMENT_STATES.manual_received
    || (isManualMethod && isPaymentReceived);
  const productionCurrent = !productionComplete && (
    isProductionAuthorized
    || orderState === ORDER_STATES.in_production
    || hasAnyCompletionSignal
  );
  const paymentRequired = isCheckoutStarted
    || isPaymentPending
    || (hasPlacedOrder && !isPaymentReceived);
  const paymentDue = hasPlacedOrder
    && !isPaymentReceived
    && (
      isLockedPoSubmittedUnpaid
      || isAchPaymentPendingLocked
      || manualPaymentPending
      || isPoSubmitted
      || paymentState === PAYMENT_STATES.failed
      || paymentState === PAYMENT_STATES.pending
      || paymentState === PAYMENT_STATES.submitted
      || paymentState === PAYMENT_STATES.checkout_created
      || orderState === ORDER_STATES.awaiting_payment_confirmation
    );
  const orderPlacedAt = derivePortalOrderPlacedAt_({
    paymentPath: paymentPath,
    poSubmittedAt: poSubmittedAt,
    paidAt: paidAt,
    lockedAt: lockedAt,
    createdAt: createdAt,
    lastOrderUpdatedAt: lastOrderUpdatedAt
  });
  const editorMode = (!hasPlacedOrder && !isLocked && (lifecycleStage === PORTAL_LIFECYCLE_STAGES.editable || lifecycleStage === PORTAL_LIFECYCLE_STAGES.checkout_started))
    ? 'editable'
    : 'locked';
  const saveAllowed = editorMode === 'editable';
  const orderAllowed = lifecycleStage === PORTAL_LIFECYCLE_STAGES.editable
    && !hasPlacedOrder
    && !isCheckoutStarted
    && !isLocked;
  const summaryControlsMode = lifecycleStage === PORTAL_LIFECYCLE_STAGES.po_draft_locked
    ? 'po_submission'
    : (lifecycleStage === PORTAL_LIFECYCLE_STAGES.manual_pending_locked
      ? 'manual_pending'
      : (summaryDocumentMode === SUMMARY_DOCUMENT_MODES.locked_invoice
        ? (paymentDue ? 'invoice_payment_due' : 'invoice_final')
        : 'estimate'));
  const lifecycleState = derivePortalLifecycleState_({
    row: row,
    lifecycleStage: lifecycleStage,
    paymentPath: paymentPath,
    isTeamHold: isTeamHold,
    isCheckoutReset: isCheckoutReset,
    isCheckoutStarted: isCheckoutStarted,
    isAchPaymentPendingLocked: isAchPaymentPendingLocked,
    achDetailState: achDetailState,
    isPoDraftLocked: lifecycleStage === PORTAL_LIFECYCLE_STAGES.po_draft_locked,
    isLockedPoSubmittedUnpaid: isLockedPoSubmittedUnpaid,
    isPoSubmitted: isPoSubmitted,
    isPaymentReceived: isPaymentReceived,
    isProductionAuthorized: isProductionAuthorized,
    productionCurrent: productionCurrent,
    productionComplete: productionComplete,
    manualPaymentPending: manualPaymentPending,
    manualPaymentReceived: manualPaymentReceived,
    paymentMethodSelected: paymentMethodSelected,
    readinessFlags: opts.readinessFlags
  });
  const canResetCreditTerms = true;
  const canResetTaxExemption = true;
  const canUnlock = lifecycleState === PORTAL_LIFECYCLE_STATES.po_draft_invoice_prepared
    || lifecycleState === PORTAL_LIFECYCLE_STATES.manual_payment_pending
    || lifecycleState === PORTAL_LIFECYCLE_STATES.canceled_or_reset
    || lifecycleState === PORTAL_LIFECYCLE_STATES.checkout_abandoned_or_reset;
  const canResetCheckout = lifecycleState === PORTAL_LIFECYCLE_STATES.checkout_started_unpaid
    || lifecycleState === PORTAL_LIFECYCLE_STATES.po_draft_invoice_prepared
    || lifecycleState === PORTAL_LIFECYCLE_STATES.manual_payment_pending;
  const canReopenPo = lifecycleState === PORTAL_LIFECYCLE_STATES.po_submitted_unpaid;
  const canMarkManualPayment = lifecycleState === PORTAL_LIFECYCLE_STATES.manual_payment_pending;
  const canMarkPoPayment = lifecycleState === PORTAL_LIFECYCLE_STATES.po_submitted_unpaid;
  const canResendLink = summaryDocumentMode !== SUMMARY_DOCUMENT_MODES.estimate
    && lifecycleState !== PORTAL_LIFECYCLE_STATES.canceled_or_reset
    && lifecycleState !== PORTAL_LIFECYCLE_STATES.checkout_abandoned_or_reset;
  const canLockWithoutOrdering = lifecycleState === PORTAL_LIFECYCLE_STATES.estimate_empty
    || lifecycleState === PORTAL_LIFECYCLE_STATES.estimate_quantities_incomplete
    || lifecycleState === PORTAL_LIFECYCLE_STATES.estimate_artwork_pending
    || lifecycleState === PORTAL_LIFECYCLE_STATES.estimate_ready_to_order;
  const canManageJobCompletion = hasSelectedJobs
    && (isProductionAuthorized || productionCurrent || productionComplete || hasAnyActualJobCompletion);
  const canInitiateProduction = hasSelectedJobs
    && hasLockedInvoice
    && isLocked
    && !productionCurrent
    && !productionComplete
    && !isTeamHold
    && !isCheckoutReset;
  const blockingReasons = buildPortalLifecycleBlockingReasons_({
    lifecycleState: lifecycleState,
    hasPlacedOrder: hasPlacedOrder,
    paymentDue: paymentDue,
    isPaymentReceived: isPaymentReceived,
    isProductionAuthorized: isProductionAuthorized,
    productionComplete: productionComplete,
    isAwaitingPoSubmission: isAwaitingPoSubmission,
    manualPaymentPending: manualPaymentPending,
    isCheckoutStarted: isCheckoutStarted || isAchPaymentPendingLocked,
    achDetailState: achDetailState
  });
  const nextClientAction = derivePortalLifecycleNextClientAction_({
    lifecycleState: lifecycleState,
    paymentDue: paymentDue,
    productionCurrent: productionCurrent,
    productionComplete: productionComplete,
    achDetailState: achDetailState,
    isApPaymentLinkAwaitingPayment: isApPaymentLinkAwaitingPayment,
    isApPaymentLinkCheckoutStarted: isApPaymentLinkCheckoutStarted
  });
  const nextTeamAction = derivePortalLifecycleNextTeamAction_({
    lifecycleState: lifecycleState,
    paymentDue: paymentDue,
    canMarkManualPayment: canMarkManualPayment,
    canMarkPoPayment: canMarkPoPayment,
    canInitiateProduction: canInitiateProduction,
    canManageJobCompletion: canManageJobCompletion,
    productionComplete: productionComplete,
    achDetailState: achDetailState
  });
  const dashboardState = buildPortalLifecycleDashboardState_({
    lifecycleState: lifecycleState,
    variant: isPoFlow ? 'purchase_order' : 'standard',
    orderPlaced: hasPlacedOrder,
    paymentReceived: isPaymentReceived,
    paymentDue: paymentDue,
    poSubmitted: isPoSubmitted,
    productionCurrent: productionCurrent,
    productionComplete: productionComplete
  });
  const peekState = buildPortalLifecyclePeekState_({
    lifecycleState: lifecycleState,
    orderPlaced: hasPlacedOrder,
    paymentReceived: isPaymentReceived,
    paymentDue: paymentDue,
    poSubmitted: isPoSubmitted,
    productionCurrent: productionCurrent,
    productionComplete: productionComplete
  });
  const diagnosticReasons = buildPortalLifecycleDiagnosticReasons_({
    lifecycleStage: lifecycleStage,
    lifecycleState: lifecycleState,
    paymentPath: paymentPath,
    hasPlacedOrder: hasPlacedOrder,
    paymentDue: paymentDue,
    isPaymentReceived: isPaymentReceived,
    isProductionAuthorized: isProductionAuthorized,
    productionCurrent: productionCurrent,
    productionComplete: productionComplete,
    isPoSubmitted: isPoSubmitted,
    manualPaymentPending: manualPaymentPending,
    isCheckoutStarted: isCheckoutStarted,
    achDetailState: achDetailState
  });

  return {
    variant: isPoFlow ? 'purchase_order' : 'standard',
    lifecycleStage: lifecycleStage,
    lifecycleState: lifecycleState,
    summaryDocumentMode: summaryDocumentMode,
    summaryControlsMode: summaryControlsMode,
    paymentPath: paymentPath,
    paymentMethod: paymentMethodSelected,
    achDetailState: achDetailState,
    achPaymentSource: achPaymentSource,
    isApPaymentLinkAwaitingPayment: isApPaymentLinkAwaitingPayment,
    isApPaymentLinkCheckoutStarted: isApPaymentLinkCheckoutStarted,
    achPaymentPendingProductionApproved: isAchMethod && isProductionAuthorized && !isPaymentReceived,
    orderPlaced: hasPlacedOrder,
    orderPlacedAt: orderPlacedAt,
    paymentRequired: paymentRequired,
    paymentDue: paymentDue,
    paymentReceived: isPaymentReceived,
    paymentReceivedAt: paidAt,
    poDraft: !!purchaseOrderDraft,
    poSubmitted: isPoSubmitted,
    manualPaymentPending: manualPaymentPending,
    manualPaymentReceived: manualPaymentReceived,
    productionAuthorized: isProductionAuthorized,
    productionStartAt: trimString_(productionStartAt),
    productionTargetCompleteAt: trimString_(productionTargetMeta.iso),
    productionCompletionAt: trimString_(productionCompletionAt),
    productionCompletionSource: trimString_(productionCompletionSource),
    productionCurrent: productionCurrent,
    productionComplete: productionComplete,
    editorMode: editorMode,
    saveAllowed: saveAllowed,
    orderAllowed: orderAllowed,
    dashboardState: dashboardState,
    peekState: peekState,
    nextClientAction: nextClientAction,
    nextTeamAction: nextTeamAction,
    blockingReasons: blockingReasons,
    diagnosticReasons: diagnosticReasons,
    isPoFlow: isPoFlow,
    hasPurchaseOrderDraft: !!purchaseOrderDraft,
    purchaseOrderDraftStatus: trimString_(purchaseOrderDraft && purchaseOrderDraft.status),
    isLocked: isLocked,
    isEditable: isEditable,
    isCheckoutStarted: lifecycleStage === PORTAL_LIFECYCLE_STAGES.checkout_started,
    isAchPaymentPendingLocked: isAchPaymentPendingLocked,
    isPoDraftLocked: lifecycleStage === PORTAL_LIFECYCLE_STAGES.po_draft_locked,
    isManualPendingLocked: lifecycleStage === PORTAL_LIFECYCLE_STAGES.manual_pending_locked,
    isTeamHold: isTeamHold,
    isCheckoutReset: isCheckoutReset,
    isAwaitingPoSubmission: isAwaitingPoSubmission,
    isPoSubmitted: isPoSubmitted,
    isPoSubmittedUnpaid: isLockedPoSubmittedUnpaid,
    isPaymentReceived: isPaymentReceived,
    isPaymentPending: isPaymentPending,
    isProductionAuthorized: isProductionAuthorized,
    hasPlacedOrder: hasPlacedOrder,
    hasLockedInvoice: hasLockedInvoice,
    hasSelectedJobs: hasSelectedJobs,
    hasAnyActualJobCompletion: hasAnyActualJobCompletion,
    allSelectedJobsCompleted: allSelectedJobsCompleted,
    teamWorkflowMode: teamWorkflowMode,
    paymentMethodSelected: paymentMethodSelected,
    orderState: orderState,
    paymentState: paymentState,
    productionAuthorizationState: productionAuthorizationState,
    activeOrderId: activeOrderId,
    latestCheckoutAttemptId: latestCheckoutAttemptId,
    stripeSessionId: stripeSessionId,
    stripePaymentIntentId: stripePaymentIntentId,
    paidAt: paidAt,
    paymentReceivedManuallyAt: paymentReceivedManuallyAt,
    poSubmittedAt: poSubmittedAt,
    poNumber: poNumber,
    approvedPaymentTermsDays: Math.max(0, parseInt(String(account.approvedPaymentTermsDays || 0), 10) || 0),
    canCancelPendingClientFlow: canCancelPendingClientFlow,
    cancelFlowKind: cancelFlowKind,
    canResetCreditTerms: canResetCreditTerms,
    canResetTaxExemption: canResetTaxExemption,
    canUnlock: canUnlock,
    canResetCheckout: canResetCheckout,
    canReopenPo: canReopenPo,
    canMarkManualPayment: canMarkManualPayment,
    canMarkPoPayment: canMarkPoPayment,
    canResendLink: canResendLink,
    canLockWithoutOrdering: canLockWithoutOrdering,
    canManageJobCompletion: canManageJobCompletion,
    canInitiateProduction: canInitiateProduction
  };
}

function buildTeamWorkflowContext_(options) {
  /* Canonical lifecycle alias — team/admin permissions intentionally share the
     same derivePortalLifecycle_() contract as dashboard and client surfaces. */
  return derivePortalLifecycle_(options);
}

function derivePortalLifecycleState_(context) {
  const ctx = (context && typeof context === 'object') ? context : {};
  const achDetailState = trimString_(ctx.achDetailState);
  if (achDetailState === ACH_DETAIL_STATES.disputed) return PORTAL_LIFECYCLE_STATES.ach_payment_disputed;
  if (achDetailState === ACH_DETAIL_STATES.failed || achDetailState === ACH_DETAIL_STATES.blocked_or_mandate_invalid) {
    return PORTAL_LIFECYCLE_STATES.ach_payment_failed;
  }
  if (ctx.isTeamHold === true) return PORTAL_LIFECYCLE_STATES.canceled_or_reset;
  if (ctx.isCheckoutReset === true) return PORTAL_LIFECYCLE_STATES.checkout_abandoned_or_reset;
  if (ctx.productionComplete === true) return PORTAL_LIFECYCLE_STATES.production_complete;
  if (ctx.isLockedPoSubmittedUnpaid === true) return PORTAL_LIFECYCLE_STATES.po_submitted_unpaid;
  if (ctx.isPoSubmitted === true && ctx.isPaymentReceived === true) {
    return ctx.productionCurrent === true
      ? PORTAL_LIFECYCLE_STATES.production_in_progress
      : PORTAL_LIFECYCLE_STATES.po_submitted_paid;
  }
  if (ctx.manualPaymentPending === true) return PORTAL_LIFECYCLE_STATES.manual_payment_pending;
  if (ctx.manualPaymentReceived === true) {
    return ctx.productionCurrent === true
      ? PORTAL_LIFECYCLE_STATES.production_in_progress
      : PORTAL_LIFECYCLE_STATES.manual_payment_received;
  }
  if (ctx.productionCurrent === true) return PORTAL_LIFECYCLE_STATES.production_in_progress;
  if (ctx.isProductionAuthorized === true) return PORTAL_LIFECYCLE_STATES.production_authorized;
  if (ctx.isPaymentReceived === true && ctx.paymentPath === 'stripe') {
    return PORTAL_LIFECYCLE_STATES.card_ach_paid;
  }
  if (ctx.isAchPaymentPendingLocked === true) return PORTAL_LIFECYCLE_STATES.ach_payment_pending;
  if (ctx.isPoDraftLocked === true) return PORTAL_LIFECYCLE_STATES.po_draft_invoice_prepared;
  if (ctx.isCheckoutStarted === true) return PORTAL_LIFECYCLE_STATES.checkout_started_unpaid;
  return derivePortalEstimateLifecycleState_(ctx.row, ctx.readinessFlags);
}

function derivePortalEstimateLifecycleState_(row, readinessFlags) {
  const flags = (readinessFlags && typeof readinessFlags === 'object') ? readinessFlags : {};
  if (flags.qtySizesComplete === true && flags.artworkApprovalComplete === true) {
    return PORTAL_LIFECYCLE_STATES.estimate_ready_to_order;
  }
  if (flags.qtySizesComplete === true || flags.hasIncludedJobs === true || flags.minimumsMet === true) {
    return PORTAL_LIFECYCLE_STATES.estimate_artwork_pending;
  }
  const portalState = safeJsonParse_(row && row.portalstatejson, {}) || {};
  if (hasPositivePortalQuantitySignal_(portalState)) {
    return PORTAL_LIFECYCLE_STATES.estimate_artwork_pending;
  }
  return PORTAL_LIFECYCLE_STATES.estimate_empty;
}

function hasPositivePortalQuantitySignal_(value, depth) {
  const level = Math.max(0, parseInt(String(depth || 0), 10) || 0);
  if (level > 8 || value == null) return false;
  if (typeof value === 'number') return value > 0;
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) return false;
    const numeric = Number(trimmed);
    if (Number.isFinite(numeric)) return numeric > 0;
    return false;
  }
  if (Array.isArray(value)) {
    return value.some(function(item) {
      return hasPositivePortalQuantitySignal_(item, level + 1);
    });
  }
  if (typeof value === 'object') {
    return Object.keys(value).some(function(key) {
      const normalizedKey = trimString_(key).toLowerCase();
      if (normalizedKey === 'version' || normalizedKey === 'savedat' || normalizedKey === 'isreadonly') return false;
      return hasPositivePortalQuantitySignal_(value[key], level + 1);
    });
  }
  return false;
}

function buildPortalLifecycleBlockingReasons_(context) {
  const ctx = (context && typeof context === 'object') ? context : {};
  const reasons = [];
  if (ctx.isCheckoutStarted === true) reasons.push('checkout_started_unpaid');
  if (ctx.isAwaitingPoSubmission === true) reasons.push('purchase_order_submission_required');
  if (ctx.manualPaymentPending === true) reasons.push('manual_payment_pending');
  if (ctx.paymentDue === true) reasons.push('payment_due');
  if (ctx.hasPlacedOrder === true) reasons.push('order_placed_locked');
  if (ctx.isPaymentReceived !== true && ctx.productionComplete === true) reasons.push('production_complete_payment_unreceived');
  return uniqueTrimmedStrings_(reasons);
}

function derivePortalLifecycleNextClientAction_(context) {
  const ctx = (context && typeof context === 'object') ? context : {};
  const state = trimString_(ctx.lifecycleState);
  if (state === PORTAL_LIFECYCLE_STATES.ach_payment_failed || state === PORTAL_LIFECYCLE_STATES.ach_payment_disputed) return 'retry_payment';
  if (ctx.isApPaymentLinkAwaitingPayment === true) return 'wait_for_ap_payment';
  if (ctx.isApPaymentLinkCheckoutStarted === true) return 'wait_for_ap_checkout';
  if (state === PORTAL_LIFECYCLE_STATES.ach_payment_pending) return 'wait_for_payment';
  if (state === PORTAL_LIFECYCLE_STATES.estimate_empty
      || state === PORTAL_LIFECYCLE_STATES.estimate_quantities_incomplete) return 'enter_quantities';
  if (state === PORTAL_LIFECYCLE_STATES.estimate_artwork_pending) return 'approve_artwork';
  if (state === PORTAL_LIFECYCLE_STATES.estimate_ready_to_order) return 'place_order';
  if (state === PORTAL_LIFECYCLE_STATES.checkout_started_unpaid) return 'complete_checkout';
  if (state === PORTAL_LIFECYCLE_STATES.po_draft_invoice_prepared) return 'submit_purchase_order';
  if (state === PORTAL_LIFECYCLE_STATES.manual_payment_pending) return 'send_manual_payment';
  if (ctx.paymentDue === true) return 'pay_invoice';
  if (ctx.productionComplete === true) return 'none';
  if (ctx.productionCurrent === true) return 'wait_for_production';
  return 'none';
}

function derivePortalLifecycleNextTeamAction_(context) {
  const ctx = (context && typeof context === 'object') ? context : {};
  const state = trimString_(ctx.lifecycleState);
  if (state === PORTAL_LIFECYCLE_STATES.ach_payment_failed || state === PORTAL_LIFECYCLE_STATES.ach_payment_disputed) return 'review_payment_issue';
  if (ctx.canMarkManualPayment === true) return 'mark_manual_payment_received';
  if (ctx.canMarkPoPayment === true) return 'mark_po_payment_received';
  if (ctx.canInitiateProduction === true) return 'initiate_production';
  if (ctx.canManageJobCompletion === true && ctx.productionComplete !== true) return 'mark_production_complete';
  if (ctx.paymentDue === true) return 'monitor_payment';
  return 'none';
}

function buildPortalLifecycleDashboardState_(context) {
  const ctx = (context && typeof context === 'object') ? context : {};
  return {
    variant: trimString_(ctx.variant) === 'purchase_order' ? 'purchase_order' : 'standard',
    orderStep: ctx.orderPlaced === true ? 'complete' : 'pending',
    paymentStep: ctx.paymentReceived === true ? 'complete' : (ctx.paymentDue === true ? 'due' : 'future'),
    productionStep: ctx.productionComplete === true ? 'complete' : (ctx.productionCurrent === true ? 'current' : 'future'),
    paymentDue: ctx.paymentDue === true,
    productionCurrent: ctx.productionCurrent === true,
    productionComplete: ctx.productionComplete === true
  };
}

function buildPortalLifecyclePeekState_(context) {
  const ctx = (context && typeof context === 'object') ? context : {};
  let mode = 'not_placed';
  if (ctx.productionComplete === true) mode = 'complete';
  else if (ctx.productionCurrent === true) mode = 'production';
  else if (ctx.poSubmitted === true) mode = 'po_submitted';
  else if (ctx.paymentReceived === true) mode = 'paid';
  else if (ctx.orderPlaced === true) mode = ctx.paymentDue === true ? 'payment_due' : 'placed';
  return {
    mode: mode,
    paymentDue: ctx.paymentDue === true,
    productionCurrent: ctx.productionCurrent === true,
    productionComplete: ctx.productionComplete === true
  };
}

function buildPortalLifecycleDiagnosticReasons_(context) {
  const ctx = (context && typeof context === 'object') ? context : {};
  const reasons = [
    'stage:' + trimString_(ctx.lifecycleStage),
    'state:' + trimString_(ctx.lifecycleState),
    'payment_path:' + trimString_(ctx.paymentPath)
  ];
  if (ctx.hasPlacedOrder === true) reasons.push('order_placed');
  if (ctx.paymentDue === true) reasons.push('payment_due');
  if (ctx.isPaymentReceived === true) reasons.push('payment_received');
  if (ctx.isProductionAuthorized === true) reasons.push('production_authorized');
  if (ctx.productionCurrent === true) reasons.push('production_current');
  if (ctx.productionComplete === true) reasons.push('production_complete');
  if (ctx.isPoSubmitted === true) reasons.push('po_submitted');
  if (ctx.manualPaymentPending === true) reasons.push('manual_payment_pending');
  if (ctx.isCheckoutStarted === true) reasons.push('checkout_started');
  return uniqueTrimmedStrings_(reasons);
}

function buildTeamWorkflowActionMeta_(workflowContext) {
  /* Canonical team/admin permission adapter — client visibility metadata should
     flow from canonical workflowContext, not from ad hoc state guesses. */
  const ctx = (workflowContext && typeof workflowContext === 'object') ? workflowContext : {};
  return {
    reset_terms: {
      visible: ctx.canResetCreditTerms === true,
      label: 'Reset Credit Terms'
    },
    reset_tax: {
      visible: ctx.canResetTaxExemption === true,
      label: 'Reset Tax Exemption'
    },
    manual_payment: {
      visible: ctx.canMarkManualPayment === true,
      label: 'Mark Manual Payment Received'
    },
    po_payment: {
      visible: ctx.canMarkPoPayment === true,
      label: 'Mark PO Payment Received'
    },
    unlock_project: {
      visible: ctx.canUnlock === true,
      label: 'Unlock Project Snapshot'
    },
    reset_checkout: {
      visible: ctx.canResetCheckout === true,
      label: 'Reset Checkout Selection'
    },
    reopen_po: {
      visible: ctx.canReopenPo === true,
      label: 'Reopen PO Submission'
    },
    resend_link: {
      visible: ctx.canResendLink === true,
      label: ctx.isPoFlow ? 'Resend PO Return Link' : 'Resend Invoice Link'
    },
    lock_project: {
      visible: ctx.canLockWithoutOrdering === true,
      label: 'Lock Project Without Ordering'
    },
    initiate_production: {
      visible: ctx.canInitiateProduction === true,
      label: 'Initiate Production'
    },
    mark_jobs_completed: {
      visible: ctx.canManageJobCompletion === true,
      label: ctx.hasAnyActualJobCompletion ? 'Manage Job Completion Dates' : 'Mark Jobs as Completed'
    }
  };
}

function buildPortalLifecycleDiagnosticForRow_(rowInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const projectionContext = (opts.projectionContext && typeof opts.projectionContext === 'object')
    ? opts.projectionContext
    : buildDashboardProjectProjectionContext_(rowInfo, opts);
  const row = (projectionContext.row && typeof projectionContext.row === 'object') ? projectionContext.row : {};
  const canonical = (projectionContext.workflowContext && typeof projectionContext.workflowContext === 'object')
    ? projectionContext.workflowContext
    : derivePortalLifecycle_({
        row: row,
        latestOrderSummary: projectionContext.latestOrderSummary,
        currentStateSummary: projectionContext.currentStateSummary,
        accountSummary: projectionContext.accountSummary
      });
  const surfaces = buildPortalLifecycleSurfaceInterpretations_(Object.assign({}, projectionContext, {
    includePeek: opts.includePeek,
    workflowContext: canonical
  }));
  const diagnostic = {
    ok: true,
    diagnosticVersion: 'lifecycle_tranche_3a_v1',
    token: trimString_(projectionContext.token || row.token),
    dealNumber: trimString_(projectionContext.dealNumber || row.dealnumber),
    generatedAt: new Date().toISOString(),
    canonical: canonical,
    contract: buildPortalLifecycleContractDiagnostic_(canonical),
    serverDashboard: surfaces.serverDashboard,
    serverProduction: surfaces.serverProduction,
    serverPeek: surfaces.serverPeek,
    legacyServer: surfaces.legacyServer,
    rawState: buildPortalLifecycleDiagnosticRawState_(projectionContext, canonical),
    mismatches: [],
    warnings: [],
    knownClientConsumersNotEvaluated: buildPortalLifecycleKnownClientConsumers_()
  };
  const comparison = comparePortalLifecycleInterpretations_(diagnostic);
  diagnostic.mismatches = comparison.mismatches;
  diagnostic.warnings = (surfaces.warnings || []).concat(comparison.warnings || []);
  return diagnostic;
}

function buildPortalLifecycleSurfaceInterpretations_(projectionContext) {
  /* Legacy compatibility/diagnostic layer — keep until Tranche 4C/4D deletion
     pass. This compares canonical lifecycle output against older server
     interpretations during the migration window.

     legacyDashboardFlags is forwarded here strictly as a diagnostic snapshot.
     It is not the live dashboard projection source after Tranche 4C.1. */
  const context = (projectionContext && typeof projectionContext === 'object') ? projectionContext : {};
  const row = (context.row && typeof context.row === 'object') ? context.row : {};
  const workflowContext = (context.workflowContext && typeof context.workflowContext === 'object') ? context.workflowContext : {};
  const flags = (context.flags && typeof context.flags === 'object') ? context.flags : {};
  const legacyDashboardFlags = (context.legacyDashboardFlags && typeof context.legacyDashboardFlags === 'object')
    ? context.legacyDashboardFlags
    : {};
  const timeline = (context.timeline && typeof context.timeline === 'object') ? context.timeline : {};
  const variant = trimString_(context.variant || workflowContext.variant).toLowerCase() === 'purchase_order'
    ? 'purchase_order'
    : 'standard';
  const warnings = [];
  let statusMeta = null;
  let productionMeta = null;
  let peekMeta = null;

  try {
    statusMeta = buildDashboardProjectStatusMetaFromProjectionContext_(context);
  } catch (err) {
    warnings.push(buildPortalLifecycleDiagnosticIssue_(
      'dashboard_status_unavailable',
      'Dashboard status meta could not be built for diagnostic comparison.',
      String(err && err.message || err || '')
    ));
  }

  try {
    productionMeta = buildDashboardProductionMeta_(flags, variant, {
      dateValue: timeline.completionDateValue,
      dateLabel: timeline.completionDateLabel
    });
  } catch (err) {
    warnings.push(buildPortalLifecycleDiagnosticIssue_(
      'production_meta_unavailable',
      'Dashboard production meta could not be built for diagnostic comparison.',
      String(err && err.message || err || '')
    ));
  }

  if (context.includePeek !== false) {
    try {
      peekMeta = buildDashboardProjectPeekMetaFromProjectionContext_(context);
    } catch (err) {
      warnings.push(buildPortalLifecycleDiagnosticIssue_(
        'peek_meta_unavailable',
        'Dashboard peek meta could not be built for diagnostic comparison.',
        String(err && err.message || err || '')
      ));
    }
  }

  return {
    serverDashboard: buildPortalLifecycleDiagnosticDashboard_(statusMeta, Object.assign({}, context, {
      legacyDashboardFlags: legacyDashboardFlags
    })),
    serverProduction: buildPortalLifecycleDiagnosticProduction_(productionMeta, statusMeta, context),
    serverPeek: buildPortalLifecycleDiagnosticPeek_(peekMeta),
    legacyServer: buildPortalLifecycleDiagnosticLegacyServer_(context, row),
    warnings: warnings
  };
}

function comparePortalLifecycleInterpretations_(diagnosticContext) {
  /* Legacy compatibility/diagnostic layer — no production lifecycle behavior
     should depend on these comparison results once clean-up is complete.

     Note: some legacy boolean comparisons are intentionally dormant right now.
     The legacy dashboard flag builder no longer emits fields like paymentDue
     or productionComplete, so those warnings remain only as deletion-prep
     markers until the diagnostic layer is retired. */
  const diagnostic = (diagnosticContext && typeof diagnosticContext === 'object') ? diagnosticContext : {};
  const canonical = (diagnostic.canonical && typeof diagnostic.canonical === 'object') ? diagnostic.canonical : {};
  const dashboard = (diagnostic.serverDashboard && typeof diagnostic.serverDashboard === 'object') ? diagnostic.serverDashboard : {};
  const dashboardFlags = (dashboard.flags && typeof dashboard.flags === 'object') ? dashboard.flags : {};
  const legacyDashboardFlags = (dashboard.legacyFlags && typeof dashboard.legacyFlags === 'object') ? dashboard.legacyFlags : {};
  const production = (diagnostic.serverProduction && typeof diagnostic.serverProduction === 'object') ? diagnostic.serverProduction : {};
  const legacy = (diagnostic.legacyServer && typeof diagnostic.legacyServer === 'object') ? diagnostic.legacyServer : {};
  const mismatches = [];
  const warnings = [];

  comparePortalLifecycleDiagnosticValue_(mismatches, 'variant', canonical.variant, dashboard.variant);
  comparePortalLifecycleDiagnosticBoolean_(mismatches, 'order_placed', canonical.hasPlacedOrder, dashboardFlags.orderPlaced);
  comparePortalLifecycleDiagnosticBoolean_(mismatches, 'payment_received', canonical.isPaymentReceived, dashboardFlags.paymentReceived);
  comparePortalLifecycleDiagnosticBoolean_(mismatches, 'po_submitted', canonical.isPoSubmitted, dashboardFlags.poSubmitted);
  comparePortalLifecycleDiagnosticBoolean_(
    mismatches,
    'po_awaiting_submission',
    canonical.isAwaitingPoSubmission,
    dashboardFlags.poInitiated === true && dashboardFlags.poSubmitted !== true
  );
  comparePortalLifecycleDiagnosticBoolean_(mismatches, 'locked_row', canonical.isLocked, legacy.isLockedPortalRow);
  comparePortalLifecycleDiagnosticBoolean_(mismatches, 'contract_order_placed', canonical.orderPlaced, dashboardFlags.orderPlaced);
  comparePortalLifecycleDiagnosticBoolean_(mismatches, 'contract_payment_received', canonical.paymentReceived, dashboardFlags.paymentReceived);
  comparePortalLifecycleDiagnosticBoolean_(mismatches, 'contract_payment_due', canonical.paymentDue, dashboardFlags.paymentDue);
  comparePortalLifecycleDiagnosticBoolean_(mismatches, 'contract_production_complete', canonical.productionComplete, dashboardFlags.productionComplete);

  comparePortalLifecycleDiagnosticLegacyBooleanWarning_(warnings, 'legacy_order_placed', canonical.orderPlaced, legacyDashboardFlags.orderPlaced);
  comparePortalLifecycleDiagnosticLegacyBooleanWarning_(warnings, 'legacy_payment_received', canonical.paymentReceived, legacyDashboardFlags.paymentReceived);
  comparePortalLifecycleDiagnosticLegacyBooleanWarning_(warnings, 'legacy_po_submitted', canonical.poSubmitted, legacyDashboardFlags.poSubmitted);
  /* Dormant deletion-prep check: legacyDashboardFlags no longer emits
     paymentDue, so this warning is currently passive unless another legacy
     source starts populating that field again. */
  comparePortalLifecycleDiagnosticLegacyBooleanWarning_(warnings, 'legacy_payment_due', canonical.paymentDue, legacyDashboardFlags.paymentDue);
  comparePortalLifecycleDiagnosticLegacyBooleanWarning_(warnings, 'legacy_production_begun', canonical.productionCurrent || canonical.productionAuthorized, legacyDashboardFlags.productionBegun);
  /* Dormant deletion-prep check: legacyDashboardFlags no longer emits
     productionComplete, so this warning is currently passive unless another
     legacy source starts populating that field again. */
  comparePortalLifecycleDiagnosticLegacyBooleanWarning_(warnings, 'legacy_production_complete', canonical.productionComplete, legacyDashboardFlags.productionComplete);

  if (canonical.isProductionAuthorized === true && dashboardFlags.productionBegun !== true) {
    warnings.push(buildPortalLifecycleDiagnosticIssue_(
      'production_authorized_without_dashboard_production',
      'Canonical lifecycle sees production as authorized, but dashboard flags do not show production begun.',
      {
        lifecycleStage: trimString_(canonical.lifecycleStage),
        productionMode: trimString_(production.mode),
        productionLabel: trimString_(production.label)
      }
    ));
  }
  if (canonical.productionCurrent === true && dashboardFlags.productionBegun !== true) {
    warnings.push(buildPortalLifecycleDiagnosticIssue_(
      'contract_production_current_without_dashboard_production',
      'Canonical contract sees production as current, but dashboard flags do not show production begun.',
      {
        lifecycleState: trimString_(canonical.lifecycleState),
        productionMode: trimString_(production.mode)
      }
    ));
  }
  if (canonical.paymentDue === true && dashboardFlags.paymentReceived === true) {
    mismatches.push(buildPortalLifecycleDiagnosticIssue_(
      'contract_payment_due_dashboard_complete',
      'Canonical contract sees payment due, but dashboard flags show payment received.',
      {
        lifecycleState: trimString_(canonical.lifecycleState),
        paymentPath: trimString_(canonical.paymentPath)
      }
    ));
  }
  if (canonical.saveAllowed === true && legacy.isLockedPortalRow === true) {
    warnings.push(buildPortalLifecycleDiagnosticIssue_(
      'contract_save_allowed_legacy_locked',
      'Canonical contract allows saving, but the legacy server lock helper treats the row as locked.',
      {
        lifecycleState: trimString_(canonical.lifecycleState),
        legacyDisplayOrderStatus: trimString_(legacy.displayOrderStatus)
      }
    ));
  }
  if (canonical.hasAnyActualJobCompletion === true && dashboardFlags.productionBegun !== true) {
    mismatches.push(buildPortalLifecycleDiagnosticIssue_(
      'job_completion_without_dashboard_production',
      'Canonical lifecycle has actual job completion, but dashboard flags do not show production begun.',
      {
        lifecycleStage: trimString_(canonical.lifecycleStage),
        productionMode: trimString_(production.mode)
      }
    ));
  }
  if (trimString_(legacy.displayOrderStatus) === PORTAL_DISPLAY_ORDER_STATUSES.editable
      && canonical.hasPlacedOrder === true) {
    mismatches.push(buildPortalLifecycleDiagnosticIssue_(
      'placed_order_displayed_editable',
      'Canonical lifecycle sees an order as placed, but legacy display status is editable.',
      {
        lifecycleStage: trimString_(canonical.lifecycleStage),
        displayOrderStatus: trimString_(legacy.displayOrderStatus)
      }
    ));
  }
  if (trimString_(legacy.displayOrderStatus) === PORTAL_DISPLAY_ORDER_STATUSES.processing
      && canonical.hasPlacedOrder !== true
      && canonical.isPaymentReceived !== true
      && canonical.isProductionAuthorized !== true) {
    warnings.push(buildPortalLifecycleDiagnosticIssue_(
      'processing_status_without_canonical_acceptance',
      'Legacy display status is processing without canonical placement, payment receipt, or production authorization.',
      {
        lifecycleStage: trimString_(canonical.lifecycleStage),
        displayOrderStatus: trimString_(legacy.displayOrderStatus)
      }
    ));
  }
  if (trimString_(legacy.displayOrderStatus) === PORTAL_DISPLAY_ORDER_STATUSES.locked
      && canonical.isEditable === true) {
    warnings.push(buildPortalLifecycleDiagnosticIssue_(
      'locked_status_while_canonical_editable',
      'Legacy display status is locked while canonical lifecycle is editable.',
      {
        lifecycleStage: trimString_(canonical.lifecycleStage),
        displayOrderStatus: trimString_(legacy.displayOrderStatus)
      }
    ));
  }

  return {
    mismatches: mismatches,
    warnings: warnings
  };
}

function buildPortalLifecycleContractDiagnostic_(canonicalLifecycle) {
  const lifecycle = (canonicalLifecycle && typeof canonicalLifecycle === 'object') ? canonicalLifecycle : {};
  return {
    lifecycleStage: trimString_(lifecycle.lifecycleStage),
    lifecycleState: trimString_(lifecycle.lifecycleState),
    paymentPath: trimString_(lifecycle.paymentPath),
    paymentMethod: trimString_(lifecycle.paymentMethod || lifecycle.paymentMethodSelected),
    orderPlaced: lifecycle.orderPlaced === true,
    paymentRequired: lifecycle.paymentRequired === true,
    paymentDue: lifecycle.paymentDue === true,
    paymentReceived: lifecycle.paymentReceived === true || lifecycle.isPaymentReceived === true,
    poDraft: lifecycle.poDraft === true || lifecycle.hasPurchaseOrderDraft === true,
    poSubmitted: lifecycle.poSubmitted === true || lifecycle.isPoSubmitted === true,
    manualPaymentPending: lifecycle.manualPaymentPending === true,
    manualPaymentReceived: lifecycle.manualPaymentReceived === true,
    productionAuthorized: lifecycle.productionAuthorized === true || lifecycle.isProductionAuthorized === true,
    productionCurrent: lifecycle.productionCurrent === true,
    productionComplete: lifecycle.productionComplete === true,
    editorMode: trimString_(lifecycle.editorMode),
    saveAllowed: lifecycle.saveAllowed === true,
    orderAllowed: lifecycle.orderAllowed === true,
    summaryDocumentMode: trimString_(lifecycle.summaryDocumentMode),
    summaryControlsMode: trimString_(lifecycle.summaryControlsMode),
    dashboardState: (lifecycle.dashboardState && typeof lifecycle.dashboardState === 'object') ? lifecycle.dashboardState : {},
    peekState: (lifecycle.peekState && typeof lifecycle.peekState === 'object') ? lifecycle.peekState : {},
    nextClientAction: trimString_(lifecycle.nextClientAction),
    nextTeamAction: trimString_(lifecycle.nextTeamAction),
    blockingReasons: Array.isArray(lifecycle.blockingReasons) ? lifecycle.blockingReasons : [],
    diagnosticReasons: Array.isArray(lifecycle.diagnosticReasons) ? lifecycle.diagnosticReasons : []
  };
}

function buildPortalLifecycleDiagnosticDashboard_(statusMeta, projectionContext) {
  /* Diagnostic dashboard wrapper — preserves both canonical live flags and the
     quarantined legacy flag snapshot for migration inspection. Do not route
     production dashboard behavior through legacyFlags. */
  const meta = (statusMeta && typeof statusMeta === 'object') ? statusMeta : {};
  const context = (projectionContext && typeof projectionContext === 'object') ? projectionContext : {};
  const presentation = (context.presentation && typeof context.presentation === 'object') ? context.presentation : {};
  const legacyDashboardFlags = (context.legacyDashboardFlags && typeof context.legacyDashboardFlags === 'object')
    ? context.legacyDashboardFlags
    : {};
  return {
    ok: meta.ok === true,
    variant: trimString_(meta.variant || context.variant),
    flags: (meta.flags && typeof meta.flags === 'object') ? meta.flags : (context.flags || {}),
    legacyFlags: legacyDashboardFlags,
    stateMode: trimString_(
      (meta.copy && meta.copy.stateMode)
      || presentation.stateMode
    ),
    stepStates: (presentation.stepStates && typeof presentation.stepStates === 'object') ? presentation.stepStates : {},
    currentStepKey: trimString_(
      (meta.copy && meta.copy.currentStepKey)
      || presentation.currentStepKey
    ),
    poStageMode: trimString_(
      (meta.copy && meta.copy.poStageMode)
      || presentation.poStageMode
    ),
    helperText: trimString_(meta.helperText),
    helperTone: trimString_(meta.helperTone),
    fallbackStatus: trimString_(meta.fallbackStatus || context.displayStatus),
    steps: Array.isArray(meta.steps) ? meta.steps : []
  };
}

function buildPortalLifecycleDiagnosticProduction_(productionMeta, statusMeta, projectionContext) {
  const meta = (productionMeta && typeof productionMeta === 'object') ? productionMeta : {};
  const statusProduction = statusMeta && statusMeta.production && typeof statusMeta.production === 'object'
    ? statusMeta.production
    : {};
  const context = (projectionContext && typeof projectionContext === 'object') ? projectionContext : {};
  const timeline = (context.timeline && typeof context.timeline === 'object') ? context.timeline : {};
  return {
    mode: trimString_(meta.mode),
    label: trimString_(meta.label),
    dateLabel: trimString_(meta.dateLabel),
    dateValue: Number.isFinite(Number(meta.dateValue)) ? Number(meta.dateValue) : null,
    statusMetaMode: trimString_(statusProduction.mode),
    statusMetaLabel: trimString_(statusProduction.label),
    printStartDateLabel: trimString_(timeline.printStartDateLabel),
    printStartDateValue: Number.isFinite(Number(timeline.printStartDateValue)) ? Number(timeline.printStartDateValue) : null,
    completionDateLabel: trimString_(timeline.completionDateLabel),
    completionDateValue: Number.isFinite(Number(timeline.completionDateValue)) ? Number(timeline.completionDateValue) : null,
    hasAnyActualJobCompletion: timeline.hasAnyActualJobCompletion === true,
    allJobsCompleted: timeline.allJobsCompleted === true
  };
}

function buildPortalLifecycleDiagnosticPeek_(peekMeta) {
  const meta = (peekMeta && typeof peekMeta === 'object') ? peekMeta : null;
  if (!meta) {
    return {
      ok: false,
      skipped: true
    };
  }
  const project = (meta.project && typeof meta.project === 'object') ? meta.project : {};
  const summary = (project.summary && typeof project.summary === 'object') ? project.summary : {};
  return {
    ok: meta.ok === true,
    sourceMode: trimString_(meta.sourceMode),
    jobSource: trimString_(meta.jobSource),
    projectMode: trimString_(project.mode),
    projectStatus: trimString_(project.status),
    headerMeta: (project.headerMeta && typeof project.headerMeta === 'object') ? project.headerMeta : {},
    summary: {
      priceLabel: trimString_(summary.priceLabel),
      completionLabel: trimString_(summary.completionLabel),
      completionValue: trimString_(summary.completionValue)
    },
    timelineFacts: (project.timelineFacts && typeof project.timelineFacts === 'object') ? project.timelineFacts : {}
  };
}

function buildPortalLifecycleDiagnosticLegacyServer_(projectionContext, row) {
  const context = (projectionContext && typeof projectionContext === 'object') ? projectionContext : {};
  const safeRow = (row && typeof row === 'object') ? row : {};
  const stateInput = Object.assign(
    {},
    safeRow,
    (context.currentStateSummary && typeof context.currentStateSummary === 'object') ? context.currentStateSummary : {},
    (context.latestOrderSummary && typeof context.latestOrderSummary === 'object') ? context.latestOrderSummary : {}
  );
  return {
    displayOrderStatus: derivePortalDisplayOrderStatus_(stateInput, safeRow.status),
    isLockedPortalRow: isLockedPortalRow_(safeRow, context.portalStateSource),
    rowStatus: trimString_(safeRow.status)
  };
}

function buildPortalLifecycleDiagnosticRawState_(projectionContext, canonical) {
  const context = (projectionContext && typeof projectionContext === 'object') ? projectionContext : {};
  const row = (context.row && typeof context.row === 'object') ? context.row : {};
  const current = (context.currentStateSummary && typeof context.currentStateSummary === 'object') ? context.currentStateSummary : {};
  const latest = (context.latestOrderSummary && typeof context.latestOrderSummary === 'object') ? context.latestOrderSummary : {};
  const lifecycle = (canonical && typeof canonical === 'object') ? canonical : {};
  return {
    portalLockState: trimString_(current.portalLockState || latest.portalLockState || row.portallockstate || row.currentportallockstate),
    orderState: trimString_(current.currentOrderState || latest.orderState || row.currentorderstate || row.orderstate || lifecycle.orderState),
    paymentState: trimString_(current.currentPaymentState || latest.paymentState || row.currentpaymentstate || row.paymentstate || lifecycle.paymentState),
    productionAuthorizationState: trimString_(
      current.currentProductionAuthorizationState ||
      latest.productionAuthorizationState ||
      row.currentproductionauthorizationstate ||
      row.productionauthorizationstate ||
      lifecycle.productionAuthorizationState
    ),
    paymentMethod: trimString_(current.currentPaymentMethod || latest.paymentMethodSelected || row.currentpaymentmethod || row.paymentmethodselected || lifecycle.paymentMethodSelected),
    activeOrderId: trimString_(current.activeOrderId || latest.orderId || row.activeorderid || lifecycle.activeOrderId),
    latestCheckoutAttemptId: trimString_(current.latestCheckoutAttemptId || row.latestcheckoutattemptid),
    poNumber: trimString_(latest.poNumber || row.ponumber || lifecycle.poNumber),
    poSubmittedAt: trimString_(latest.poSubmittedAt || row.posubmittedat || lifecycle.poSubmittedAt),
    paidAt: trimString_(latest.paidAt || row.paidat || lifecycle.paidAt),
    authorizedToProduceAt: trimString_(latest.authorizedToProduceAt || row.authorizedtoproduceat),
    teamWorkflowMode: normalizeTeamWorkflowMode_(current.teamWorkflowMode || latest.teamWorkflowMode || row.teamworkflowmode || lifecycle.teamWorkflowMode),
    latestInvoiceNumber: trimString_(current.latestInvoiceNumber || latest.invoiceNumber || row.latestinvoicenumber),
    hasPurchaseOrderDraft: lifecycle.hasPurchaseOrderDraft === true
  };
}

function buildPortalLifecycleKnownClientConsumers_() {
  /* Audit/quarantine map — documents remaining client consumers that still need
     to be steered fully onto canonical workflowContext during Tranche 4B/4D. */
  return [
    { surface: 'Summary / Invoice tab', status: 'client-side consumer to reroute in later tranche', functions: ['getSummaryDocumentMode_', 'isLockedSummaryInvoiceMode_', 'buildSummaryEstimateControlCard_', 'buildSummaryPurchaseOrderControlCard_', 'buildSummaryManualPendingControlCard_'] },
    { surface: 'Project editor gates', status: 'client-side consumer to reroute in later tranche', functions: ['isFinalizedPortal', 'describePortalStateForUi'] },
    { surface: 'Order-flow modal', status: 'client-side consumer to reroute in later tranche', functions: ['canAccessOrderFlow_', 'openOrderFlowModal', 'renderOrderFlowFulfillmentSection'] },
    { surface: 'Checkout return / resume', status: 'client-side consumer to reroute in later tranche', functions: ['describeCheckoutReturnNotice', 'startOrderFlowCheckout'] },
    { surface: 'PO continuation', status: 'client-side consumer to reroute in later tranche', functions: ['isAwaitingPurchaseOrderPortal_', 'submitOrderFlowPo'] },
    { surface: 'Manual payment continuation', status: 'client-side consumer to reroute in later tranche', functions: ['submitOrderFlowManual'] }
  ];
}

function comparePortalLifecycleDiagnosticValue_(mismatches, key, canonicalValue, surfaceValue) {
  const canonical = trimString_(canonicalValue).toLowerCase();
  const surface = trimString_(surfaceValue).toLowerCase();
  if (canonical === surface) return;
  mismatches.push(buildPortalLifecycleDiagnosticIssue_(
    key + '_mismatch',
    'Canonical lifecycle value differs from existing server interpretation.',
    {
      canonical: canonical,
      surface: surface
    }
  ));
}

function comparePortalLifecycleDiagnosticBoolean_(mismatches, key, canonicalValue, surfaceValue) {
  const canonical = canonicalValue === true;
  const surface = surfaceValue === true;
  if (canonical === surface) return;
  mismatches.push(buildPortalLifecycleDiagnosticIssue_(
    key + '_mismatch',
    'Canonical lifecycle boolean differs from existing server interpretation.',
    {
      canonical: canonical,
      surface: surface
    }
  ));
}

function comparePortalLifecycleDiagnosticLegacyBooleanWarning_(warnings, key, canonicalValue, legacyValue) {
  /* Legacy-only drift reporter. This helper exists for migration diagnostics
     and should not be treated as a live lifecycle decision surface. */
  if (legacyValue === undefined || legacyValue === null) return;
  const canonical = canonicalValue === true;
  const legacy = legacyValue === true;
  if (canonical === legacy) return;
  warnings.push(buildPortalLifecycleDiagnosticIssue_(
    key + '_drift',
    'Legacy dashboard interpretation differs from the canonical lifecycle contract.',
    {
      canonical: canonical,
      legacy: legacy
    }
  ));
}

function buildPortalLifecycleDiagnosticIssue_(code, message, details) {
  const issue = {
    code: trimString_(code),
    message: trimString_(message)
  };
  if (details !== undefined && details !== null && details !== '') {
    issue.details = details;
  }
  return issue;
}

function buildPortalLifecycleHydratedContext_(workflowContext) {
  /* Canonical lifecycle hydration — do not bypass. This is the contract shipped
     to client consumers via workflowContext on current state and latest order. */
  const context = (workflowContext && typeof workflowContext === 'object') ? workflowContext : {};
  return {
    variant: trimString_(context.variant),
    lifecycleStage: trimString_(context.lifecycleStage),
    lifecycleState: trimString_(context.lifecycleState),
    summaryDocumentMode: trimString_(context.summaryDocumentMode),
    summaryControlsMode: trimString_(context.summaryControlsMode),
    paymentPath: trimString_(context.paymentPath),
    paymentMethod: trimString_(context.paymentMethod),
    achDetailState: trimString_(context.achDetailState),
    achPaymentPendingProductionApproved: context.achPaymentPendingProductionApproved === true,
    orderPlaced: context.orderPlaced === true,
    orderPlacedAt: trimString_(context.orderPlacedAt),
    paymentDue: context.paymentDue === true,
    paymentReceived: context.paymentReceived === true,
    paymentReceivedAt: trimString_(context.paymentReceivedAt),
    poSubmittedAt: trimString_(context.poSubmittedAt),
    productionStartAt: trimString_(context.productionStartAt),
    productionTargetCompleteAt: trimString_(context.productionTargetCompleteAt),
    productionCompletionAt: trimString_(context.productionCompletionAt),
    productionCompletionSource: trimString_(context.productionCompletionSource),
    productionCurrent: context.productionCurrent === true,
    productionComplete: context.productionComplete === true,
    nextClientAction: trimString_(context.nextClientAction),
    nextTeamAction: trimString_(context.nextTeamAction),
    isPoFlow: context.isPoFlow === true,
    hasPurchaseOrderDraft: context.hasPurchaseOrderDraft === true,
    purchaseOrderDraftStatus: trimString_(context.purchaseOrderDraftStatus),
    isLocked: context.isLocked === true,
    isEditable: context.isEditable === true,
    isCheckoutStarted: context.isCheckoutStarted === true,
    isAchPaymentPendingLocked: context.isAchPaymentPendingLocked === true,
    isPoDraftLocked: context.isPoDraftLocked === true,
    isManualPendingLocked: context.isManualPendingLocked === true,
    isAwaitingPoSubmission: context.isAwaitingPoSubmission === true,
    isPoSubmitted: context.isPoSubmitted === true,
    isPoSubmittedUnpaid: context.isPoSubmittedUnpaid === true,
    isPaymentReceived: context.isPaymentReceived === true,
    isPaymentPending: context.isPaymentPending === true,
    isProductionAuthorized: context.isProductionAuthorized === true,
    hasPlacedOrder: context.hasPlacedOrder === true,
    hasLockedInvoice: context.hasLockedInvoice === true,
    hasSelectedJobs: context.hasSelectedJobs === true,
    hasAnyActualJobCompletion: context.hasAnyActualJobCompletion === true,
    allSelectedJobsCompleted: context.allSelectedJobsCompleted === true,
    teamWorkflowMode: normalizeTeamWorkflowMode_(context.teamWorkflowMode),
    canCancelPendingClientFlow: context.canCancelPendingClientFlow === true,
    cancelFlowKind: trimString_(context.cancelFlowKind),
    canResetCreditTerms: context.canResetCreditTerms === true,
    canResetTaxExemption: context.canResetTaxExemption === true,
    canUnlock: context.canUnlock === true,
    canResetCheckout: context.canResetCheckout === true,
    canReopenPo: context.canReopenPo === true,
    canMarkManualPayment: context.canMarkManualPayment === true,
    canMarkPoPayment: context.canMarkPoPayment === true,
    canResendLink: context.canResendLink === true,
    canLockWithoutOrdering: context.canLockWithoutOrdering === true,
    canManageJobCompletion: context.canManageJobCompletion === true,
    canInitiateProduction: context.canInitiateProduction === true
  };
}

function attachTeamWorkflowMetaToOrderSummary_(orderSummary, workflowContext) {
  const summary = Object.assign({}, (orderSummary && typeof orderSummary === 'object') ? orderSummary : {});
  summary.workflowContext = buildPortalLifecycleHydratedContext_(workflowContext);
  summary.teamControls = {
    actions: buildTeamWorkflowActionMeta_(workflowContext)
  };
  return summary;
}

function attachTeamWorkflowMetaToCurrentStateSummary_(currentStateSummary, workflowContext) {
  const summary = Object.assign({}, (currentStateSummary && typeof currentStateSummary === 'object') ? currentStateSummary : {});
  summary.workflowContext = buildPortalLifecycleHydratedContext_(workflowContext);
  return summary;
}

function assertTeamWorkflowActionAllowed_(workflowContext, actionName) {
  /* Canonical team/admin enforcement — do not bypass with raw state checks.
     Hidden or stale client actions must still be blocked here on the server. */
  const actions = buildTeamWorkflowActionMeta_(workflowContext);
  const actionKey = trimString_(actionName);
  const action = actions[actionKey];
  if (action && action.visible === true) return;
  const messages = {
    reset_terms: 'Credit terms can only be reset by an authorized team user.',
    reset_tax: 'Tax exemption can only be reset by an authorized team user.',
    manual_payment: 'Manual payment can only be marked on standard unpaid locked orders.',
    po_payment: 'PO payment can only be marked after purchase-order submission on an unpaid PO order.',
    unlock_project: 'This project cannot be unlocked in its current state.',
    reset_checkout: 'Checkout selection can only be reset while the order is awaiting checkout or PO upload.',
    reopen_po: 'PO submission can only be reopened on an unpaid submitted PO order.',
    resend_link: 'A resend link is not available for the current project state.',
    lock_project: 'Only editable pre-order projects can be locked without ordering.',
    initiate_production: 'Production can only be initiated by Team Mode on locked orders with selected jobs.',
    mark_jobs_completed: 'Job completion dates are only available once the order has entered production or already has completion data.',
    ach_pending_production_approval: 'ACH pending production approval has been retired. Use Initiate Production for a specific locked order.'
  };
  throw new Error(messages[actionKey] || 'That team action is not available for the current project state.');
}

function normalizePortalDocumentKind_(documentKind) {
  const normalized = trimString_(documentKind).toLowerCase();
  if (normalized === 'summary' || normalized === 'estimate_pdf') return PORTAL_DOCUMENT_KINDS.estimate;
  if (normalized === 'receipt' || normalized === 'paid_receipt') return PORTAL_DOCUMENT_KINDS.receipt;
  if (normalized === PORTAL_DOCUMENT_KINDS.ap_payment_request) return PORTAL_DOCUMENT_KINDS.ap_payment_request;
  if (normalized === PORTAL_DOCUMENT_KINDS.po_submission) return PORTAL_DOCUMENT_KINDS.po_submission;
  if (normalized === PORTAL_DOCUMENT_KINDS.summary_pdf) return PORTAL_DOCUMENT_KINDS.summary_pdf;
  return normalized === PORTAL_DOCUMENT_KINDS.estimate ? PORTAL_DOCUMENT_KINDS.estimate : PORTAL_DOCUMENT_KINDS.invoice;
}

function normalizePortalDocumentProjectNumber_(value) {
  const clean = trimString_(value).replace(/[^A-Za-z0-9_-]+/g, '');
  return clean || 'Project';
}

function isGenericPortalDocumentProjectNumber_(value) {
  const clean = normalizePortalDocumentProjectNumber_(value).toLowerCase();
  return !clean || clean === 'project' || clean === 'emailreview';
}

function zeroPadPortalDocumentVersion_(version) {
  const n = Math.max(1, parseInt(String(version || 1), 10) || 1);
  return n < 10 ? ('0' + n) : String(n);
}

function getPortalDocumentKindPrefix_(documentKind) {
  return normalizePortalDocumentKind_(documentKind) === PORTAL_DOCUMENT_KINDS.estimate ? 'EST' : 'INV';
}

function parsePortalDocumentReference_(value) {
  const source = (value && typeof value === 'object') ? value : null;
  const clean = source
    ? trimString_(source.documentRef || source.invoiceNumber || source.fileSafeRef)
    : trimString_(value);
  const match = clean.match(PORTAL_DOCUMENT_REF_RE);
  if (!match) return null;
  const prefix = trimString_(match[1]).toUpperCase();
  const projectNumber = normalizePortalDocumentProjectNumber_(match[2]);
  const version = Math.max(1, parseInt(String(match[3] || 1), 10) || 1);
  const documentKind = prefix === 'EST' ? PORTAL_DOCUMENT_KINDS.estimate : PORTAL_DOCUMENT_KINDS.invoice;
  return buildPortalDocumentReference_({
    projectNumber: projectNumber,
    documentKind: documentKind,
    version: version
  });
}

function getPortalDocumentProjectNumber_(source) {
  const s = (source && typeof source === 'object') ? source : {};
  const row = s.rowObjNormalized && typeof s.rowObjNormalized === 'object' ? s.rowObjNormalized : s;
  const draft = safeJsonParse_(row.orderdraftjson || row.orderDraftJson, null) || row.orderDraft || s.orderDraft || {};
  const lockedDraft = s.lockedOrderDraft && typeof s.lockedOrderDraft === 'object' ? s.lockedOrderDraft : {};
  const docReference = s.documentReference || s.invoiceDocumentReference || row.documentReference || draft.documentReference || {};
  const estimateReference = s.documentReferences && s.documentReferences.estimate
    ? s.documentReferences.estimate
    : (draft.documentReferences && draft.documentReferences.estimate ? draft.documentReferences.estimate : {});
  const parsedDocRef = parsePortalDocumentReference_(
    s.documentRef ||
    s.invoiceNumber ||
    s.invoicenumber ||
    row.documentRef ||
    row.invoiceNumber ||
    row.invoicenumber ||
    (docReference && docReference.documentRef) ||
    (estimateReference && estimateReference.documentRef)
  );
  const fileNameMatch = trimString_(s.fileName || s.invoiceFileName || s.invoicefilename || row.invoiceFileName || row.invoicefilename)
    .match(/\bProject\s+([A-Za-z0-9_-]+)/i);
  return trimString_(
    (parsedDocRef && parsedDocRef.projectNumber) ||
    (fileNameMatch && fileNameMatch[1]) ||
    s.projectNumber ||
    s.projectnumber ||
    row.projectNumber ||
    row.projectnumber ||
    s.dealNumber ||
    s.dealnumber ||
    s.dealId ||
    s.dealid ||
    row.dealnumber ||
    row.dealNumber ||
    row.dealid ||
    row.dealId ||
    (docReference && docReference.projectNumber) ||
    (docReference && docReference.projectnumber) ||
    (estimateReference && estimateReference.projectNumber) ||
    (estimateReference && estimateReference.projectnumber) ||
    draft.dealNumber ||
    draft.dealnumber ||
    draft.dealId ||
    draft.dealid ||
    draft.projectNumber ||
    draft.projectnumber ||
    lockedDraft.dealNumber ||
    lockedDraft.dealnumber ||
    lockedDraft.dealId ||
    lockedDraft.dealid ||
    lockedDraft.projectNumber ||
    lockedDraft.projectnumber
  ).replace(/[^A-Za-z0-9_-]+/g, '');
}

function buildPortalDocumentReference_(input) {
  const source = (input && typeof input === 'object') ? input : {};
  const documentKind = normalizePortalDocumentKind_(source.documentKind);
  const invoiceKind = documentKind === PORTAL_DOCUMENT_KINDS.receipt ? PORTAL_DOCUMENT_KINDS.invoice : documentKind;
  const projectNumber = normalizePortalDocumentProjectNumber_(source.projectNumber || getPortalDocumentProjectNumber_(source));
  const version = Math.max(1, parseInt(String(source.version || 1), 10) || 1);
  const padded = zeroPadPortalDocumentVersion_(version);
  const prefix = getPortalDocumentKindPrefix_(invoiceKind);
  const documentRef = prefix + '-' + projectNumber + '-v' + padded;
  const baseLabel = invoiceKind === PORTAL_DOCUMENT_KINDS.estimate
    ? ('Estimate ' + projectNumber + '-v' + version)
    : ('Invoice ' + projectNumber + '-v' + version);
  const displayLabel = documentKind === PORTAL_DOCUMENT_KINDS.receipt
    ? ('Receipt for ' + baseLabel)
    : baseLabel;
  return {
    projectNumber: projectNumber,
    documentKind: documentKind,
    version: version,
    documentRef: documentRef,
    displayLabel: displayLabel,
    fileSafeRef: prefix + '-' + projectNumber + '-v' + padded,
    fileName: buildPortalDocumentFileName_({
      projectNumber: projectNumber,
      documentKind: documentKind,
      version: version
    }),
    legacyInvoiceNumber: trimString_(source.legacyInvoiceNumber)
  };
}

function buildClientFacingDocumentLabel_(documentReference) {
  const parsed = parsePortalDocumentReference_(documentReference);
  if (parsed) return parsed.displayLabel;
  const source = (documentReference && typeof documentReference === 'object') ? documentReference : {};
  return trimString_(source.displayLabel) || trimString_(documentReference);
}

function buildPortalDocumentFileSafeRef_(documentReference) {
  const ref = (documentReference && typeof documentReference === 'object')
    ? buildPortalDocumentReference_(documentReference)
    : parsePortalDocumentReference_(documentReference);
  return ref ? ref.fileSafeRef : trimString_(documentReference);
}

function buildPortalDocumentFileName_(documentReference) {
  const source = (documentReference && typeof documentReference === 'object') ? documentReference : {};
  const kind = normalizePortalDocumentKind_(source.documentKind);
  const projectNumber = normalizePortalDocumentProjectNumber_(source.projectNumber || getPortalDocumentProjectNumber_(source));
  const padded = zeroPadPortalDocumentVersion_(source.version || 1);
  if (kind === PORTAL_DOCUMENT_KINDS.receipt) {
    return 'Red Threads - Project ' + projectNumber + ' - Receipt for Invoice v' + padded + '.pdf';
  }
  if (kind === PORTAL_DOCUMENT_KINDS.estimate) {
    return 'Red Threads - Project ' + projectNumber + ' - Estimate v' + padded + '.pdf';
  }
  return 'Red Threads - Project ' + projectNumber + ' - Invoice v' + padded + '.pdf';
}

function buildPortalEstimateEmailSubject_(documentReference) {
  const ref = buildPortalDocumentReference_(documentReference);
  const projectNumber = normalizePortalDocumentProjectNumber_(ref.projectNumber);
  return buildPortalEmailSubject_('Estimate copy', {
    projectNumber: projectNumber
  }, { documentLabel: ref.displayLabel });
}

function buildPortalEstimateEmailHeading_(documentReference) {
  const ref = buildPortalDocumentReference_(documentReference);
  const projectNumber = normalizePortalDocumentProjectNumber_(ref.projectNumber);
  if (projectNumber && projectNumber !== 'Project') {
    return 'Project ' + projectNumber + ' - Estimate Copy';
  }
  return 'Estimate Copy';
}

function buildPortalEstimateEmailAttachmentSentence_(documentReference) {
  const ref = buildPortalDocumentReference_(documentReference);
  const projectNumber = normalizePortalDocumentProjectNumber_(ref.projectNumber);
  const version = Math.max(1, parseInt(String(ref.version || 1), 10) || 1);
  const label = projectNumber && projectNumber !== 'Project'
    ? ('Project ' + projectNumber + ' Estimate-V' + version)
    : ('Estimate-V' + version);
  return label + ' is attached to this email.';
}

function buildPortalEstimateEmailReviewPanelHtml_(message) {
  const text = trimString_(message);
  if (!text) return '';
  const theme = getPortalNativeEmailTheme_();
  return '<div style="margin:0 0 18px;padding:12px 14px;border-left:4px solid ' + theme.currentAqua + ';background:' + theme.panelAltBg + ';color:' + theme.currentAqua + ';font-weight:900;border-radius:12px;">' + escapeHtml_(text) + '</div>';
}

function buildPortalNativeEmailGreenCalloutHtml_(message) {
  const text = trimString_(message);
  if (!text) return '';
  const theme = getPortalNativeEmailTheme_();
  return '<div style="margin:0 0 18px;padding:12px 14px;border-left:4px solid ' + theme.successGreen + ';background:' + theme.panelAltBg + ';color:' + theme.successGreen + ';font-weight:900;border-radius:12px;">' + escapeHtml_(text) + '</div>';
}

function resolvePortalDocumentVersion_(source, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const parsed = parsePortalDocumentReference_(
    opts.documentRef ||
    opts.invoiceNumber ||
    (source && source.documentRef) ||
    (source && source.invoiceNumber) ||
    (source && source.invoicenumber)
  );
  if (parsed) return parsed.version;
  return Math.max(1, parseInt(String(
    opts.version ||
    opts.orderRevision ||
    (source && (source.orderRevision || source.orderrevision)) ||
    1
  ), 10) || 1);
}

function buildPortalCommercialDocumentFingerprint_(source) {
  const s = (source && typeof source === 'object') ? source : {};
  const comparable = {
    projectNumber: getPortalDocumentProjectNumber_(s),
    fulfillmentMethod: trimString_(s.fulfillmentMethod || s.fulfillmentmethod),
    shippingChargeCents: Math.max(0, parseInt(String(s.shippingChargeCents || s.shippingchargecents || 0), 10) || 0),
    amountSubtotal: roundMoney_(s.amountSubtotal || s.amountsubtotal || 0),
    amountShipping: roundMoney_(s.amountShipping || s.amountshipping || 0),
    amountRush: roundMoney_(s.amountRush || s.amountrush || 0),
    amountTax: roundMoney_(s.amountTax || s.amounttax || 0),
    amountGrandTotal: roundMoney_(s.amountGrandTotal || s.amountgrandtotal || 0),
    selectedJobs: buildPortalOrderSelectedJobsSummary_(s.selectedJobs || s.selectedjobs)
  };
  const digest = Utilities.computeDigest(Utilities.DigestAlgorithm.SHA_256, JSON.stringify(comparable));
  return Utilities.base64EncodeWebSafe(digest).replace(/=+$/g, '');
}

function deriveNextEstimateVersion_(portalState, options) {
  const state = (portalState && typeof portalState === 'object') ? portalState : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const existing = state.documentReferences && state.documentReferences.estimate
    ? state.documentReferences.estimate
    : {};
  const currentVersion = Math.max(1, parseInt(String(existing.version || 1), 10) || 1);
  const nextFingerprint = trimString_(opts.fingerprint);
  const currentFingerprint = trimString_(existing.currentFingerprint || existing.fingerprint);
  return nextFingerprint && currentFingerprint && nextFingerprint !== currentFingerprint
    ? currentVersion + 1
    : currentVersion;
}

function deriveNextInvoiceVersion_(source, options) {
  return resolvePortalDocumentVersion_(source, options);
}

function getCurrentInvoiceReferenceForOrder_(orderInfo, invoiceInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : ((orderInfo && typeof orderInfo === 'object') ? orderInfo : {});
  const summary = row && (row.orderid || row.orderId || row.invoicenumber || row.invoiceNumber)
    ? buildPortalOrderSummary_(row)
    : {};
  const draft = safeJsonParse_(row.orderdraftjson || row.orderDraftJson, {}) || {};
  const invoice = (invoiceInfo && typeof invoiceInfo === 'object') ? invoiceInfo : {};
  const existingDocRef = invoice.documentRef ||
    (invoice.documentReference && invoice.documentReference.documentRef) ||
    invoice.invoiceNumber ||
    (draft.documentReference && draft.documentReference.documentRef) ||
    summary.invoiceNumber ||
    row.invoicenumber ||
    row.invoiceNumber;
  const parsed = parsePortalDocumentReference_(existingDocRef);
  const legacyInvoiceNumber = LEGACY_INVOICE_NUMBER_RE.test(trimString_(existingDocRef))
    ? trimString_(existingDocRef)
    : trimString_(invoice.legacyInvoiceNumber || (draft.documentReference && draft.documentReference.legacyInvoiceNumber));
  const version = parsed ? parsed.version : deriveNextInvoiceVersion_(summary, {
    orderRevision: summary.orderRevision || row.orderrevision || row.orderRevision || opts.orderRevision
  });
  return buildPortalDocumentReference_({
    projectNumber: (parsed && parsed.projectNumber) || getPortalDocumentProjectNumber_(invoice) || getPortalDocumentProjectNumber_(summary) || getPortalDocumentProjectNumber_(row),
    documentKind: opts.documentKind || PORTAL_DOCUMENT_KINDS.invoice,
    version: version,
    legacyInvoiceNumber: legacyInvoiceNumber
  });
}

function getCurrentEstimateReferenceForPortalState_(portalState, options) {
  const state = (portalState && typeof portalState === 'object') ? portalState : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const existing = state.documentReferences && state.documentReferences.estimate
    ? state.documentReferences.estimate
    : {};
  const parsed = parsePortalDocumentReference_(existing.documentRef || opts.documentRef);
  const version = parsed ? parsed.version : deriveNextEstimateVersion_(state, opts);
  return buildPortalDocumentReference_({
    projectNumber: (parsed && parsed.projectNumber) || opts.projectNumber,
    documentKind: PORTAL_DOCUMENT_KINDS.estimate,
    version: version
  });
}

function attachPortalDocumentReferenceToInvoiceInfo_(invoiceInfo, source, options) {
  const info = (invoiceInfo && typeof invoiceInfo === 'object') ? Object.assign({}, invoiceInfo) : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const ref = getCurrentInvoiceReferenceForOrder_(source, info, opts);
  info.invoiceNumber = ref.documentRef;
  info.documentRef = ref.documentRef;
  info.displayLabel = ref.displayLabel;
  info.documentReference = ref;
  if (!trimString_(info.fileName) || opts.forceFileName === true) {
    info.fileName = ref.fileName;
  }
  return info;
}

function nextInvoiceNumber_(source, options) {
  const ref = buildPortalDocumentReference_({
    projectNumber: getPortalDocumentProjectNumber_(source),
    documentKind: PORTAL_DOCUMENT_KINDS.invoice,
    version: deriveNextInvoiceVersion_(source, options)
  });
  return ref.documentRef;
}

function getDriveFolderByIdSafe_(folderId) {
  const id = trimString_(folderId);
  if (!id) return null;
  try {
    return DriveApp.getFolderById(id);
  } catch (_) {
    return null;
  }
}

function storePortalPdfBlobInInvoiceFolder_(opts) {
  const options = (opts && typeof opts === 'object') ? opts : {};
  const cfg = options.cfg || getConfig_();
  const folder = getDriveFolderByIdSafe_(cfg.invoiceDriveFolderId);
  if (!folder) {
    throw new Error('Invoice folder is not configured.');
  }
  const base64Data = trimString_(options.base64Data || options.fileBase64 || options.fileDataBase64);
  if (!base64Data) {
    throw new Error('Invoice PDF payload is missing.');
  }
  const bytes = Utilities.base64Decode(base64Data);
  if (!bytes || !bytes.length) {
    throw new Error('Unable to read the invoice PDF.');
  }
  const defaultName = trimString_(options.defaultFileName || options.fileName || 'Red-Threads-Invoice.pdf');
  const fileName = sanitizeUploadedDocumentName_(options.fileName, defaultName);
  const blob = Utilities.newBlob(bytes, trimString_(options.mimeType) || MimeType.PDF, fileName);
  if (doesPdfBlobContainLegacyInvoiceMarker_(blob)) {
    throw new Error(LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.non_portal_rendered_invoice);
  }
  const file = folder.createFile(blob);
  try {
    file.setDescription(PORTAL_RENDERED_INVOICE_DESCRIPTION_MARKER);
  } catch (_) {}
  return {
    fileId: file.getId(),
    fileName: file.getName(),
    mimeType: file.getMimeType(),
    fileUrl: buildDriveFileViewUrl_(file.getId()),
    previewUrl: buildDriveFilePreviewUrl_(file.getId()),
    downloadUrl: buildDriveFileDownloadUrl_(file.getId())
  };
}

function storePortalUploadBlobInInvoiceFolder_(opts) {
  const options = (opts && typeof opts === 'object') ? opts : {};
  const cfg = options.cfg || getConfig_();
  const folder = getDriveFolderByIdSafe_(cfg.invoiceDriveFolderId);
  if (!folder) {
    throw new Error('Invoice folder is not configured.');
  }
  const base64Data = trimString_(options.base64Data || options.fileBase64 || options.fileDataBase64);
  if (!base64Data) return null;
  const bytes = Utilities.base64Decode(base64Data);
  if (!bytes || !bytes.length) {
    throw new Error('Unable to read the uploaded purchase order document.');
  }
  const defaultName = trimString_(options.defaultFileName || options.fileName || 'Purchase-Order-Document');
  const fileName = sanitizeUploadedDocumentName_(options.fileName, defaultName);
  const blob = Utilities.newBlob(bytes, trimString_(options.mimeType) || 'application/octet-stream', fileName);
  const file = folder.createFile(blob);
  return {
    fileId: file.getId(),
    fileName: file.getName(),
    mimeType: file.getMimeType(),
    fileUrl: buildDriveFileViewUrl_(file.getId()),
    previewUrl: buildDriveFilePreviewUrl_(file.getId()),
    downloadUrl: buildDriveFileDownloadUrl_(file.getId())
  };
}

function buildPurchaseOrderInvoiceFileName_(ctx) {
  const draft = (ctx && ctx.orderDraft && typeof ctx.orderDraft === 'object') ? ctx.orderDraft : {};
  const reference = buildPortalDocumentReference_({
    projectNumber: getPortalDocumentProjectNumber_(draft),
    documentKind: PORTAL_DOCUMENT_KINDS.invoice,
    version: deriveNextInvoiceVersion_(draft, { orderRevision: ctx && ctx.orderRevision })
  });
  return sanitizeUploadedDocumentName_(reference.fileName, reference.fileName);
}

function preparePurchaseOrderDraftInvoiceArtifact_(ctx, payload, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const existingDraft = normalizePurchaseOrderDraftState_(opts.existingDraft);
  const base64Data = trimString_(payload && payload.base64Data);
  const existingReference = existingDraft && existingDraft.documentReference ? existingDraft.documentReference : null;
  const invoiceReference = existingReference && trimString_(existingReference.documentRef)
    ? buildPortalDocumentReference_(existingReference)
    : getCurrentInvoiceReferenceForOrder_(ctx && ctx.orderDraft, {
      invoiceNumber: trimString_(opts.invoiceNumber || (existingDraft && existingDraft.invoiceNumber))
    }, {
      orderRevision: ctx && ctx.orderRevision
    });
  const invoiceNumber = invoiceReference.documentRef;
  if (!base64Data) {
    if (!existingDraft || !trimString_(existingDraft.invoicePdfUrl)) {
      throw new Error('Invoice PDF payload is missing.');
    }
    return {
      invoiceNumber: invoiceNumber,
      documentRef: invoiceReference.documentRef,
      displayLabel: invoiceReference.displayLabel,
      documentReference: invoiceReference,
      invoicePdfUrl: trimString_(existingDraft.invoicePdfUrl),
      fileName: trimString_(opts.fileName || existingDraft.invoiceFileName || invoiceReference.fileName)
    };
  }
  const invoiceFile = storePortalPdfBlobInInvoiceFolder_({
    cfg: ctx.cfg,
    base64Data: base64Data,
    mimeType: payload && payload.mimeType,
    fileName: invoiceReference.fileName,
    defaultFileName: invoiceReference.fileName
  });
  return {
    invoiceNumber: invoiceNumber,
    documentRef: invoiceReference.documentRef,
    displayLabel: invoiceReference.displayLabel,
    documentReference: invoiceReference,
    invoicePdfUrl: trimString_(invoiceFile.fileUrl),
    fileName: trimString_(invoiceFile.fileName)
  };
}

function buildPurchaseOrderDraftResponse_(ctx, invoiceInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  return {
    ok: true,
    accountSummary: ctx.accountInfo.summary,
    invoice: {
      invoiceNumber: trimString_(invoiceInfo && invoiceInfo.invoiceNumber),
      invoicePdfUrl: trimString_(invoiceInfo && invoiceInfo.invoicePdfUrl),
      fileName: trimString_(opts.fileName || (invoiceInfo && invoiceInfo.fileName))
    },
    portalPayload: buildOrderActionPortalPayload_(ctx, ctx.rowInfo)
  };
}

function buildLockedOrderPaymentLinkBundle_(token) {
  const cleanToken = trimString_(token);
  const cfg = getConfig_();
  return {
    summaryUrl: buildPortalSummaryUrl_(cleanToken),
    cardUrl: buildLockedOrderPaymentPortalUrl_(cleanToken, PAYMENT_METHODS.card),
    achUrl: cfg.stripeAchEnabled === true ? buildLockedOrderPaymentPortalUrl_(cleanToken, PAYMENT_METHODS.ach) : ''
  };
}

function formatUsdAmount_(value) {
  return '$' + roundMoney_(Number(value) || 0).toFixed(2);
}

function buildCheckPaymentInstructionsText_(orderSummary) {
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  return [
    'Paying by check/cash',
    'Make the check out to: Red Threads LLC',
    'In the exact amount of: ' + formatUsdAmount_(summary.amountGrandTotal),
    '',
    'Mail/deliver the payment to:',
    'Red Threads',
    '505 South Saginaw Road',
    'Midland, Michigan 48640'
  ].join('\n');
}

function buildCheckPaymentInstructionsHtml_(orderSummary) {
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  return [
    '<div style="margin:16px 0 0;padding:14px 16px;border-radius:14px;border:1px solid #1e293b;background:#111827;color:#cbd5e1;">',
    '  <div style="font-weight:800;margin-bottom:6px;">Paying by check/cash</div>',
    '  <div style="font-size:14px;line-height:1.7;">Make the check out to: <strong>Red Threads LLC</strong><br>In the exact amount of: <strong>' + escapeHtml_(formatUsdAmount_(summary.amountGrandTotal)) + '</strong><br><br>Mail/deliver the payment to:<br>Red Threads<br>505 South Saginaw Road<br>Midland, Michigan 48640</div>',
    '</div>'
  ].join('\n');
}

function buildLockedOrderPaymentEmailContent_(ctx, orderSummary, options) {
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const token = trimString_(ctx && ctx.orderDraft && ctx.orderDraft.token);
  const links = buildLockedOrderPaymentLinkBundle_(token);
  const invoiceReference = getCurrentInvoiceReferenceForOrder_(opts.lifecycleOrderInfo || opts.orderInfo || summary || ctx, summary, {
    documentKind: PORTAL_DOCUMENT_KINDS.invoice
  });
  const invoiceNumber = invoiceReference.displayLabel;
  const projectName = trimString_(ctx && ctx.orderDraft && ctx.orderDraft.projectName);
  const dealNumber = trimString_(ctx && ctx.orderDraft && ctx.orderDraft.dealNumber);
  const projectNameDisplay = formatLifecycleEmailProjectNameValue_(projectName, dealNumber);
  const amountDue = formatUsdAmount_(summary.amountGrandTotal);
  const requestedIntro = trimString_(opts.intro);
  const isTeamRecipient = trimString_(opts.recipientClass) === 'team';
  const lifecycleSections = buildDirectLifecycleEmailSectionBlocks_(ctx, summary, {
    family: 'locked_order_confirmation',
    recipientClass: isTeamRecipient ? 'team' : 'client',
    lifecycleOrderInfo: opts.lifecycleOrderInfo || opts.orderInfo,
    cfg: opts.cfg || (ctx && ctx.cfg),
    ss: opts.ss || (ctx && ctx.ss),
    infra: opts.infra || (ctx && ctx.infra),
    token: token
  });
  const lifecycleEmailContext = (lifecycleSections.emailContext && typeof lifecycleSections.emailContext === 'object')
    ? lifecycleSections.emailContext
    : {};
  if (isTeamRecipient && !trimString_(lifecycleEmailContext.ctaUrl)) {
    lifecycleEmailContext.ctaUrl = buildLifecycleEmailTeamUrl_(token);
  }
  const workflowContext = (lifecycleEmailContext.workflowContext && typeof lifecycleEmailContext.workflowContext === 'object')
    ? lifecycleEmailContext.workflowContext
    : {};
  const communicationContract = buildPortalCommunicationContext_({
    emailContext: lifecycleEmailContext
  }, {
    family: 'locked_order_confirmation',
    trigger: trimString_(opts.trigger) || 'locked_order_confirmation',
    recipientClass: isTeamRecipient ? 'team' : 'client',
    documentLabel: invoiceNumber,
    cfg: opts.cfg || (ctx && ctx.cfg),
    ss: opts.ss || (ctx && ctx.ss),
    infra: opts.infra || (ctx && ctx.infra)
  });
  const paymentState = trimString_(summary.paymentState).toLowerCase();
  const paymentReceived = workflowContext.isPaymentReceived === true ||
    workflowContext.paymentReceived === true ||
    !!trimString_(workflowContext.paymentReceivedAt || summary.paidAt || summary.paymentReceivedManuallyAt) ||
    paymentState === PAYMENT_STATES.paid ||
    paymentState === PAYMENT_STATES.manual_received;
  const lifecycleText = lifecycleSections.blocks.map(function(block) {
    return trimString_(block && block.text);
  }).filter(Boolean).join('\n\n');
  const paymentOptionLines = [
    links.summaryUrl ? ('View your order summary: ' + links.summaryUrl) : '',
    links.cardUrl ? ('Pay by credit card (3% card fee applies): ' + links.cardUrl) : '',
    links.achUrl ? ('Pay by ACH bank transfer: ' + links.achUrl) : '',
    buildCheckPaymentInstructionsText_(summary)
  ].filter(Boolean);
  const theme = getPortalNativeEmailTheme_();
  const teamActionModel = isTeamRecipient
    ? resolveLifecycleTeamEmailActionModel_(lifecycleEmailContext, {
      family: 'locked_order_confirmation',
      intro: communicationContract.intro || 'A locked-order confirmation was resent for team review.',
      statusCopy: 'Use Team Mode to review the current project state and continue the correct operational workflow.',
      token: token
    })
    : null;
  const shouldSuppressPaymentOptions = isTeamRecipient ||
    paymentReceived ||
    communicationContract.suppressPaymentOptions !== false;
  const lockedHeadingUpdate = isTeamRecipient
    ? 'Team operational resend review'
    : (communicationContract.headingUpdateLabel || 'Order confirmation');
  const lockedIntro = teamActionModel
    ? teamActionModel.intro
    : (communicationContract.intro || requestedIntro || 'Your order is confirmed and the final invoice is attached.');
  const lockedNextStep = teamActionModel
    ? teamActionModel.nextStep
    : (paymentReceived
      ? (communicationContract.nextStep || 'No payment action is needed.')
      : (communicationContract.nextStep || 'Choose a payment option or send payment using the instructions on your invoice.'));
  const lockedAttachmentNote = isTeamRecipient
    ? 'The invoice/receipt for the client\'s order is attached to this email.'
    : 'The invoice/receipt for your order is attached to this email.';
  const paymentOptionsBlock = {
    kind: 'generic',
    text: buildLifecycleEmailTextBlock_('Payment options', paymentOptionLines),
    html: [
      '<div style="margin:0 0 18px;padding:14px 16px;border:1px solid ' + theme.panelBorder + ';border-radius:14px;background:' + theme.panelAltBg + ';color:' + theme.textMuted + ';">',
      '<div style="font-size:12px;text-transform:uppercase;color:' + theme.brandRedMid + ';font-weight:900;margin:0 0 8px;letter-spacing:.08em;">Payment options</div>',
      links.cardUrl
        ? ('<div style="margin:0 0 8px;"><a href="' + escapeHtml_(links.cardUrl) + '" style="color:' + theme.currentAqua + ';font-weight:900;text-decoration:underline;">Pay by credit card</a> <span style="color:' + theme.textSoft + ';">(3% card fee applies)</span></div>')
        : '',
      links.achUrl
        ? ('<div style="margin:0 0 8px;"><a href="' + escapeHtml_(links.achUrl) + '" style="color:' + theme.currentAqua + ';font-weight:900;text-decoration:underline;">Pay by ACH bank transfer</a></div>')
        : '',
      buildCheckPaymentInstructionsHtml_(summary),
      '</div>'
    ].filter(Boolean).join('\n')
  };
  const shell = buildLifecycleEmailShell_({
    eyebrow: isTeamRecipient ? getPortalNativeEmailEyebrow_('team') : '',
    heading: buildLifecycleEmailDocumentHeading_(invoiceNumber, lockedHeadingUpdate, isTeamRecipient ? 'Team operational resend review.' : 'Order confirmation.'),
    actionTitle: teamActionModel ? teamActionModel.title : '',
    intro: isTeamRecipient ? lockedIntro : normalizeLockedOrderInvoiceReceiptWording_(lockedIntro),
    statusCopy: teamActionModel ? teamActionModel.statusCopy : communicationContract.statusCopy,
    nextStep: isTeamRecipient ? lockedNextStep : normalizeLockedOrderInvoiceReceiptWording_(lockedNextStep),
    attachmentNote: lockedAttachmentNote,
    blocks: lifecycleSections.blocks.concat([
      teamActionModel ? buildLifecycleEmailCtaBlock_(teamActionModel.ctaLabel, teamActionModel.ctaUrl, {
        align: teamActionModel.ctaAlign,
        teamModePassword: teamActionModel.teamModePassword
      }) : null,
      shouldSuppressPaymentOptions ? null : paymentOptionsBlock,
      buildLifecycleEmailFooter_()
    ].filter(Boolean))
  });
  if (!lifecycleText) {
    const fallback = [
      invoiceNumber ? ('Invoice: ' + invoiceNumber) : '',
      projectNameDisplay ? ('Project name: ' + projectNameDisplay) : '',
      'Project total: ' + amountDue
    ].filter(Boolean).join('\n');
    if (fallback) shell.body += '\n\n' + fallback;
  }
  assertLifecycleCommunicationContentSafe_(communicationContract, {
    subject: '',
    body: shell.body,
    htmlBody: shell.htmlBody
  }, {
    hardBlock: true
  });
  return {
    body: shell.body,
    htmlBody: shell.htmlBody,
    links: links,
    reviewSurface: shell.reviewSurface,
    communicationContract: communicationContract
  };
}

function buildFinalInvoiceAttachment_(orderSummary, fileNameOverride) {
  const result = buildLifecycleEmailAttachmentSafe_(orderSummary, fileNameOverride, {
    requirePortalRenderedInvoice: true
  });
  return result && result.ok === true ? result.attachment : null;
}

function normalizeLifecycleEmailAttachmentPolicy_(policy) {
  const raw = trimString_(policy).toUpperCase();
  return Object.keys(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES).some(function(key) {
    return LIFECYCLE_EMAIL_ATTACHMENT_POLICIES[key] === raw;
  }) ? raw : LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.not_applicable;
}

function isRequiredLifecycleEmailAttachmentPolicy_(policy) {
  const normalized = normalizeLifecycleEmailAttachmentPolicy_(policy);
  return normalized === LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.required_blocking ||
    normalized === LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.required_queue_failed;
}

function resolveLifecycleEmailAttachmentPolicy_(family, milestone, context) {
  const source = (context && typeof context === 'object') ? context : {};
  const type = trimString_(family).toLowerCase();
  const policy = function(value, safeError, portalRenderedInvoice) {
    return {
      policy: normalizeLifecycleEmailAttachmentPolicy_(value),
      safeError: trimString_(safeError),
      portalRenderedInvoice: portalRenderedInvoice === true
    };
  };
  if (type === 'standard_ach') {
    const baseType = getAchLifecycleBaseEmailJobType_(milestone);
    if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_action_email) {
      return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.optional_send_without, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.optional_unavailable, true);
    }
    if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_bank_verification_reminder_email) {
      return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.optional_send_without, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.optional_unavailable, true);
    }
    if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_receipt_email) {
      return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.required_queue_failed, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice, true);
    }
    return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.required_queue_failed, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice, true);
  }
  if (type === 'ap_ach') {
    const normalized = normalizeApAchLifecycleEmailMilestone_(milestone);
    if (isApAchLifecycleFailureMilestone_(normalized) || normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.checkout_started) {
      return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.optional_send_without, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.optional_unavailable, true);
    }
    if (isApAchLifecycleReceiptMilestone_(normalized)) {
      return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.required_queue_failed, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice, true);
    }
    return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.required_queue_failed, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice, true);
  }
  if (type === 'payment_lifecycle') {
    const normalized = normalizePaymentLifecycleEmailMilestone_(milestone);
    if (isPaymentLifecycleFailureMilestone_(normalized) ||
        isScheduledPoPaymentReminderMilestone_(normalized)) {
      return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.optional_send_without, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.optional_unavailable, true);
    }
    if (isPaymentLifecycleReceiptMilestone_(normalized)) {
      return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.required_queue_failed, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice, true);
    }
    return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.required_queue_failed, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice, true);
  }
  if (type === 'ap_payment_link' ||
      type === 'locked_order_confirmation' ||
      type === 'purchase_order_invoice_email') {
    return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.required_blocking, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice, true);
  }
  if (type === 'account_document_source' || type === 'account_document_approved') {
    return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.required_blocking, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_document);
  }
  if (source.required === true) {
    return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.required_queue_failed, source.safeError || LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_document);
  }
  return policy(LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.not_applicable, '');
}

function getDriveFileDescriptionSafe_(file) {
  try {
    return trimString_(file && typeof file.getDescription === 'function' ? file.getDescription() : '');
  } catch (_) {
    return '';
  }
}

function doesPdfBlobContainLegacyInvoiceMarker_(blob) {
  try {
    const text = String(blob && typeof blob.getDataAsString === 'function' ? blob.getDataAsString() : '');
    return /Red Threads Portal Invoice/i.test(text);
  } catch (_) {
    return false;
  }
}

function validatePortalRenderedInvoiceAttachmentFile_(file, attachmentFileName, blob) {
  const driveName = trimString_(file && typeof file.getName === 'function' ? file.getName() : '');
  const outboundName = trimString_(attachmentFileName);
  const description = getDriveFileDescriptionSafe_(file);
  if (description.indexOf(PORTAL_RENDERED_INVOICE_DESCRIPTION_MARKER) !== -1) {
    return { ok: true, reason: 'portal_rendered_marker' };
  }
  if (doesPdfBlobContainLegacyInvoiceMarker_(blob)) {
    return { ok: false, reason: LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.non_portal_rendered_invoice };
  }
  if (LEGACY_SERVER_INVOICE_FILE_NAME_RE.test(driveName)) {
    return { ok: false, reason: LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.non_portal_rendered_invoice };
  }
  if (LEGACY_SERVER_INVOICE_FILE_NAME_RE.test(outboundName)) {
    return { ok: false, reason: LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.non_portal_rendered_invoice };
  }
  if (PORTAL_RENDERED_INVOICE_FILE_NAME_RE.test(driveName)) {
    return { ok: true, reason: 'portal_rendered_filename' };
  }
  return { ok: false, reason: LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.non_portal_rendered_invoice };
}

function shouldRequirePortalRenderedInvoiceAttachment_(policyInfo, options) {
  const info = (policyInfo && typeof policyInfo === 'object') ? policyInfo : {};
  const opts = (options && typeof options === 'object') ? options : {};
  return opts.requirePortalRenderedInvoice === true ||
    info.portalRenderedInvoice === true ||
    trimString_(opts.safeError || info.safeError) === LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice;
}

function buildLifecycleEmailAttachmentSafe_(invoiceOrFileSource, fileNameOverride, options) {
  const source = (invoiceOrFileSource && typeof invoiceOrFileSource === 'object') ? invoiceOrFileSource : {};
  const opts = (options && typeof options === 'object') ? options : {};
  let file = null;
  if (source && typeof source.getBlob === 'function' && typeof source.getName === 'function') {
    file = source;
  } else {
    const fileId = trimString_(
      source.fileId ||
      source.invoiceFileId ||
      source.driveFileId ||
      source.artifactFileId
    ) || extractDriveFileIdFromUrl_(
      trimString_(source.invoicePdfUrl || source.fileUrl || source.artifactUrl || source.url)
    );
    file = fileId ? getDriveFileByIdSafe_(fileId) : null;
  }
  if (!file) {
    return {
      ok: false,
      attachment: null,
      attachments: [],
      error: LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_document
    };
  }
  const fileName = sanitizeUploadedDocumentName_(
    fileNameOverride ||
      source.fileName ||
      source.invoiceFileName ||
      source.artifactName ||
      file.getName(),
    file.getName()
  );
  const blob = file.getBlob();
  if (opts.requirePortalRenderedInvoice === true) {
    const validation = validatePortalRenderedInvoiceAttachmentFile_(file, fileName, blob);
    if (!validation || validation.ok !== true) {
      return {
        ok: false,
        attachment: null,
        attachments: [],
        fileName: fileName,
        error: LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.non_portal_rendered_invoice
      };
    }
  }
  const attachment = blob.setName(fileName);
  return {
    ok: true,
    attachment: attachment,
    attachments: [attachment],
    fileName: fileName,
    error: ''
  };
}

function resolveLifecycleEmailAttachment_(source, policyInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const info = (policyInfo && typeof policyInfo === 'object')
    ? policyInfo
    : { policy: normalizeLifecycleEmailAttachmentPolicy_(policyInfo) };
  const policy = normalizeLifecycleEmailAttachmentPolicy_(info.policy);
  if (policy === LIFECYCLE_EMAIL_ATTACHMENT_POLICIES.not_applicable) {
    return {
      ok: true,
      policy: policy,
      attachment: null,
      attachments: [],
      error: ''
    };
  }
  const requirePortalRenderedInvoice = shouldRequirePortalRenderedInvoiceAttachment_(info, opts);
  const result = buildLifecycleEmailAttachmentSafe_(source, trimString_(opts.fileNameOverride || opts.fileName), {
    requirePortalRenderedInvoice: requirePortalRenderedInvoice
  });
  if (result && result.ok === true && result.attachment) {
    return Object.assign({}, result, {
      policy: policy
    });
  }
  const safeError = trimString_(result && result.error) || trimString_(opts.safeError || info.safeError) ||
    (isRequiredLifecycleEmailAttachmentPolicy_(policy)
      ? LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_document
      : LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.optional_unavailable);
  if (isRequiredLifecycleEmailAttachmentPolicy_(policy)) {
    return {
      ok: false,
      policy: policy,
      attachment: null,
      attachments: [],
      error: safeError
    };
  }
  return {
    ok: true,
    policy: policy,
    attachment: null,
    attachments: [],
    warning: safeError,
    error: ''
  };
}

function assertRequiredEmailAttachment_(attachmentResult, safeMessage) {
  const result = (attachmentResult && typeof attachmentResult === 'object') ? attachmentResult : {};
  if (result.ok === true && Array.isArray(result.attachments) && result.attachments.length) return result;
  if (isRequiredLifecycleEmailAttachmentPolicy_(result.policy)) {
    throw new Error(trimString_(safeMessage || result.error) || LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_document);
  }
  return result;
}

function sendLockedOrderConfirmationEmails_(ctx, orderSummary, options) {
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const invoiceNumber = getCurrentInvoiceReferenceForOrder_(opts.orderInfo || summary || ctx, summary, {
    documentKind: PORTAL_DOCUMENT_KINDS.invoice
  }).displayLabel;
  const paymentEmail = buildLockedOrderPaymentEmailContent_(ctx, summary, {
    intro: trimString_(opts.intro) || 'Your order is confirmed and the final invoice is attached.',
    trigger: trimString_(opts.trigger) || 'locked_order_confirmation',
    lifecycleOrderInfo: opts.lifecycleOrderInfo || opts.orderInfo,
    cfg: opts.cfg,
    ss: opts.ss,
    infra: opts.infra
  });
  const teamPaymentEmail = buildLockedOrderPaymentEmailContent_(ctx, summary, {
    recipientClass: 'team',
    trigger: trimString_(opts.trigger) || 'locked_order_confirmation',
    lifecycleOrderInfo: opts.lifecycleOrderInfo || opts.orderInfo,
    cfg: opts.cfg,
    ss: opts.ss,
    infra: opts.infra
  });
  const attachmentPolicy = resolveLifecycleEmailAttachmentPolicy_('locked_order_confirmation', '', {});
  const attachmentResult = resolveLifecycleEmailAttachment_(summary, attachmentPolicy, {
    fileNameOverride: trimString_(opts.fileName),
    safeError: LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice
  });
  assertRequiredEmailAttachment_(attachmentResult, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice);
  const attachments = attachmentResult.attachments;
  const subjectSource = Object.assign({},
    opts.lifecycleOrderInfo && opts.lifecycleOrderInfo.rowObjNormalized || {},
    opts.orderInfo && opts.orderInfo.rowObjNormalized || {},
    summary
  );
  const subject = buildPortalEmailSubject_('Order confirmation', subjectSource, {
    documentLabel: invoiceNumber
  });
  const clientRecipients = normalizeEmailRecipients_([
    ctx && ctx.orderDraft && ctx.orderDraft.personEmail,
    ctx && ctx.accountInfo && ctx.accountInfo.summary && ctx.accountInfo.summary.primaryEmail,
    ctx && ctx.accountInfo && ctx.accountInfo.summary && ctx.accountInfo.summary.billingContactEmail
  ]);
  if (clientRecipients.length) {
    sendNotificationEmail_({
      toList: clientRecipients,
      subject: subject,
      body: paymentEmail.body,
      htmlBody: paymentEmail.htmlBody,
      attachments: attachments,
      fromAlias: NOTIFICATION_FROM_ALIAS,
      replyTo: NOTIFICATION_FROM_ALIAS
    });
  }
  sendNotificationEmail_({
    toList: [DOCUMENT_REVIEW_EMAIL],
    subject: subject,
    body: teamPaymentEmail.body,
    htmlBody: teamPaymentEmail.htmlBody,
    attachments: attachments,
    fromAlias: NOTIFICATION_FROM_ALIAS,
    replyTo: NOTIFICATION_FROM_ALIAS
  });
  return {
    ok: true,
    summaryUrl: paymentEmail.links.summaryUrl,
    cardUrl: paymentEmail.links.cardUrl,
    achUrl: paymentEmail.links.achUrl
  };
}

function ensurePurchaseOrderInvoice_(payload) {
  const ctx = buildPreparedOrderActionContext_(payload);
  const validationError = validateOrderPlacementForAction_(ctx);
  if (validationError) return validationError;
  if (normalizeFulfillmentMethod_(ctx.orderDraft && ctx.orderDraft.fulfillmentMethod) === FULFILLMENT_METHODS.shipping) {
    const shippingError = validateRequiredOrderDraftShippingDetails_(ctx.orderDraft && ctx.orderDraft.shippingDetails);
    if (shippingError) return { ok: false, error: shippingError };
  }
  if (!ctx.accountInfo.summary.termsApproved) {
    return {
      ok: true,
      gated: true,
      termsRequired: true,
      accountSummary: ctx.accountInfo.summary,
      termsDocumentUrl: ctx.accountInfo.summary.termsDocumentUrl || ctx.cfg.termsDocumentUrl,
      message: 'Terms approval is required before you can submit a purchase order.'
    };
  }
  const latestOrder = getCurrentPortalOrderForRow_(ctx.rowInfo, {
    cfg: ctx.cfg,
    ss: ctx.ss,
    ordersSheet: ctx.infra.ordersSheet,
    token: ctx.orderDraft.token
  });
  if (latestOrder && !isSupersedableOrderRowForPaymentPathSwitch_(latestOrder)) {
    const latestSummary = buildPortalOrderSummary_(latestOrder.rowObjNormalized);
    return finalizeOrderActionResponse_({
      ok: false,
      error: trimString_(latestSummary.paymentMethodSelected).toLowerCase() === PAYMENT_METHODS.purchase_order
        ? 'This purchase order has already been submitted.'
        : 'This order has already moved past the editable checkout stage.'
    }, ctx);
  }
  const existingDraft = readPurchaseOrderDraftFromPortalState_(ctx.portalState);
  const invoiceInfo = preparePurchaseOrderDraftInvoiceArtifact_(ctx, payload, {
    existingDraft: existingDraft,
    invoiceNumber: existingDraft && existingDraft.invoiceNumber
  });
  supersedeCompetingUnpaidOrdersForPaymentPathSwitch_(ctx, {
    revisionReason: 'payment_method_superseded_to_purchase_order',
    notes: 'Superseded by purchase-order draft preparation.'
  });
  const nextDraftState = buildPurchaseOrderDraftStateFromInvoice_(ctx, invoiceInfo, {
    status: existingDraft && existingDraft.status === PURCHASE_ORDER_DRAFT_STATUSES.email_sent
      ? PURCHASE_ORDER_DRAFT_STATUSES.email_sent
      : PURCHASE_ORDER_DRAFT_STATUSES.draft_ready,
    invoiceSentToEmail: existingDraft && existingDraft.invoiceSentToEmail,
    invoiceSentAt: existingDraft && existingDraft.invoiceSentAt,
    lastPreparedAt: nowIso_(),
    resumeStage: 'submit'
  });
  lockCurrentOrderPointersToPurchaseOrderDraftState_(
    ctx,
    ctx.portalState,
    nextDraftState
  );
  return finalizeOrderActionResponse_(buildPurchaseOrderDraftResponse_(ctx, invoiceInfo, {
    fileName: invoiceInfo.fileName
  }), ctx);
}

function ensurePurchaseOrderInvoice(payload) {
  try {
    return ensurePurchaseOrderInvoice_(payload);
  } catch (err) {
    return { ok: false, error: String((err && err.message) || err) };
  }
}

function buildPurchaseOrderInvoiceEmailContent_(token, invoiceInfo, options) {
  const invoice = (invoiceInfo && typeof invoiceInfo === 'object') ? invoiceInfo : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const invoiceNumber = getCurrentInvoiceReferenceForOrder_(opts.lifecycleOrderInfo || opts.orderInfo || invoice, invoice, {
    documentKind: PORTAL_DOCUMENT_KINDS.invoice
  }).displayLabel;
  const projectName = trimString_(opts.projectName);
  const resumeUrl = buildPurchaseOrderResumePortalUrl_(token, { stage: 'submit' });
  let subject = '';
  const lifecycleSections = buildDirectLifecycleEmailSectionBlocks_({}, invoice, {
    family: 'purchase_order_invoice_email',
    recipientClass: 'client',
    lifecycleOrderInfo: opts.lifecycleOrderInfo || opts.orderInfo,
    cfg: opts.cfg,
    ss: opts.ss,
    infra: opts.infra,
    rowInfo: opts.rowInfo,
    token: token
  });
  const lifecycleEmailContext = (lifecycleSections.emailContext && typeof lifecycleSections.emailContext === 'object')
    ? lifecycleSections.emailContext
    : {};
  subject = buildPortalEmailSubject_(buildActionNeededSubject_('Submit your PO'), lifecycleEmailContext, {
    projectName: projectName,
    documentLabel: invoiceNumber
  });
  const lifecycleText = lifecycleSections.blocks.map(function(block) {
    return trimString_(block && block.text);
  }).filter(Boolean).join('\n\n');
  const communicationContract = buildPortalCommunicationContext_({
    emailContext: lifecycleEmailContext
  }, {
    family: 'purchase_order_invoice_email',
    trigger: 'purchase_order_invoice_prepared',
    recipientClass: 'client',
    documentLabel: invoiceNumber,
    cfg: opts.cfg,
    ss: opts.ss,
    infra: opts.infra
  });
  const poNextStep = communicationContract.nextStep || [
    'Forward this invoice to your Purchasing or Accounts Payable team so they can issue a company Purchase Order.',
    'Use the portal link below to reopen your project and complete the Purchase Order submission process to place your Red Threads order.'
  ].join(' ');
  const shell = buildLifecycleEmailShell_({
    heading: buildLifecycleEmailDocumentHeading_(invoiceNumber, communicationContract.headingUpdateLabel || 'Purchase order needed', 'Purchase order needed.'),
    intro: communicationContract.intro || 'The invoice for your Red Threads order is attached to this email.',
    statusCopy: communicationContract.statusCopy,
    nextStep: poNextStep,
    attachmentNote: communicationContract.attachmentNote,
    blocks: lifecycleSections.blocks.concat([
      buildLifecycleEmailCtaBlock_(buildLifecycleEmailProjectAccessCtaLabel_(lifecycleEmailContext, 'upload P.O.'), resumeUrl, {
        align: 'center'
      }),
      buildLifecycleEmailFooter_()
    ])
  });
  if (!lifecycleText) {
    const fallback = [
      invoiceNumber ? ('Invoice: ' + invoiceNumber) : '',
      projectName ? ('Project: ' + projectName) : ''
    ].filter(Boolean).join('\n');
    if (fallback) shell.body += '\n\n' + fallback;
  }
  assertLifecycleCommunicationContentSafe_(communicationContract, {
    subject: subject,
    body: shell.body,
    htmlBody: shell.htmlBody
  }, {
    hardBlock: true
  });
  return {
    subject: subject,
    body: shell.body,
    htmlBody: shell.htmlBody,
    reviewSurface: shell.reviewSurface,
    communicationContract: communicationContract
  };
}

function sendPurchaseOrderInvoiceEmailWithAttachment_(token, recipients, invoiceInfo, options) {
  const invoice = (invoiceInfo && typeof invoiceInfo === 'object') ? invoiceInfo : {};
  let contentOptions = (options && typeof options === 'object') ? Object.assign({}, options) : {};
  if (trimString_(token) && (!contentOptions.cfg || !contentOptions.ss || !contentOptions.infra)) {
    try {
      const displayCtx = buildOrderActionContext_({
        token: trimString_(token),
        createAccountIfMissing: false
      });
      contentOptions = Object.assign({}, contentOptions, {
        cfg: displayCtx.cfg,
        ss: displayCtx.ss,
        infra: displayCtx.infra,
        rowInfo: displayCtx.rowInfo
      });
    } catch (err) {
      // The invoice email remains valid without lifecycle display blocks.
    }
  }
  const attachmentPolicy = resolveLifecycleEmailAttachmentPolicy_('purchase_order_invoice_email', '', {});
  const attachmentResult = resolveLifecycleEmailAttachment_(invoice, attachmentPolicy, {
    fileNameOverride: invoice.fileName,
    safeError: LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice
  });
  assertRequiredEmailAttachment_(attachmentResult, LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice);
  const content = buildPurchaseOrderInvoiceEmailContent_(token, invoice, contentOptions);
  sendNotificationEmail_({
    toList: recipients,
    subject: content.subject,
    body: content.body,
    htmlBody: content.htmlBody,
    attachments: attachmentResult.attachments,
    fromAlias: NOTIFICATION_FROM_ALIAS,
    replyTo: NOTIFICATION_FROM_ALIAS
  });
}

function sendPurchaseOrderInvoiceEmail_(payload) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  const recipients = normalizeEmailRecipients_(p.recipients || p.to || p.toList);
  if (!recipients.length) {
    throw new Error('Enter at least one valid email address.');
  }
  const ensured = ensurePurchaseOrderInvoice_(payload);
  if (!ensured || ensured.ok !== true) return ensured;
  if (ensured.gated) return ensured;
  const invoiceInfo = {
    invoiceNumber: trimString_(ensured.invoice && ensured.invoice.invoiceNumber)
      || trimString_(ensured.orderSummary && ensured.orderSummary.invoiceNumber),
    invoicePdfUrl: trimString_(ensured.invoice && ensured.invoice.invoicePdfUrl)
      || trimString_(ensured.orderSummary && ensured.orderSummary.invoicePdfUrl),
    fileName: trimString_(ensured.invoice && ensured.invoice.fileName)
      || trimString_(ensured.orderSummary && ensured.orderSummary.invoiceFileName)
  };
  sendPurchaseOrderInvoiceEmailWithAttachment_(trimString_(p.token), recipients, invoiceInfo, {
    projectName: trimString_(p.projectName || (payload && payload.projectName))
  });
  const emailCtx = buildOrderActionContext_({
    token: trimString_(p.token),
    personEmail: trimString_(p.personEmail),
    personName: trimString_(p.personName),
    orgId: trimString_(p.orgId),
    orgName: trimString_(p.orgName)
  });
  const currentDraft = readPurchaseOrderDraftFromPortalState_(emailCtx.portalState)
    || buildPurchaseOrderDraftStateFromInvoice_(emailCtx, ensured.invoice, { resumeStage: 'submit' });
  const emailedDraftState = Object.assign({}, currentDraft, {
    status: PURCHASE_ORDER_DRAFT_STATUSES.email_sent,
    invoiceSentToEmail: recipients.join(', '),
    invoiceSentAt: nowIso_(),
    resumeStage: 'submit'
  });
  lockCurrentOrderPointersToPurchaseOrderDraftState_(
    emailCtx,
    emailCtx.portalState,
    emailedDraftState
  );
  return finalizeOrderActionResponse_({
    ok: true,
    accountSummary: emailCtx.accountInfo.summary,
    invoice: ensured.invoice,
    portalPayload: buildOrderActionPortalPayload_(emailCtx, emailCtx.rowInfo)
  }, emailCtx);
}

function sendPurchaseOrderInvoiceEmail(payload) {
  try {
    return sendPurchaseOrderInvoiceEmail_(payload);
  } catch (err) {
    return { ok: false, error: String((err && err.message) || err) };
  }
}

function normalizePortalEmailQueueStatus_(value) {
  const normalized = trimString_(value).toLowerCase();
  return Object.keys(PORTAL_EMAIL_QUEUE_STATUSES).some(function(key) {
    return PORTAL_EMAIL_QUEUE_STATUSES[key] === normalized;
  }) ? normalized : '';
}

function buildPortalEmailQueueIdempotencyKey_(token, recipients, draftFingerprint) {
  return buildPortalEmailQueueIdempotencyKeyForSource_({
    jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.purchase_order_invoice_email,
    token: trimString_(token),
    recipients: normalizeEmailRecipients_(recipients).map(function(email) {
      return normalizeEmail_(email);
    }).sort(),
    draftFingerprint: trimString_(draftFingerprint)
  });
}

function buildPortalEmailQueueIdempotencyKeyForSource_(source) {
  const safeSource = (source && typeof source === 'object') ? source : {};
  const normalized = {};
  Object.keys(safeSource).sort().forEach(function(key) {
    const value = safeSource[key];
    if (Array.isArray(value)) {
      normalized[key] = value.map(function(item) { return trimString_(item); }).filter(Boolean).sort();
    } else if (value && typeof value === 'object') {
      normalized[key] = JSON.stringify(value);
    } else {
      normalized[key] = trimString_(value);
    }
  });
  const digest = Utilities.computeDigest(
    Utilities.DigestAlgorithm.SHA_256,
    JSON.stringify(normalized)
  );
  return Utilities.base64EncodeWebSafe(digest).replace(/=+$/g, '');
}

function findPortalEmailQueueJobByField_(sheet, headerKey, value) {
  const cleanValue = trimString_(value);
  if (!sheet || !cleanValue) return null;
  const normalizedKey = normalizeHeaderKey_(headerKey);
  return listSheetRowInfos_(sheet).find(function(info) {
    return trimString_(info.rowObjNormalized[normalizedKey]) === cleanValue;
  }) || null;
}

function findPortalEmailQueueJobById_(sheet, jobId) {
  return findPortalEmailQueueJobByField_(sheet, 'jobId', jobId);
}

function findPortalEmailQueueJobByIdempotencyKey_(sheet, idempotencyKey) {
  return findPortalEmailQueueJobByField_(sheet, 'idempotencyKey', idempotencyKey);
}

function buildPortalEmailQueueStatusPayload_(jobInfo, portalPayload) {
  const row = jobInfo && jobInfo.rowObjNormalized ? jobInfo.rowObjNormalized : {};
  const status = normalizePortalEmailQueueStatus_(row.status) || PORTAL_EMAIL_QUEUE_STATUSES.queued;
  const payload = {
    jobId: trimString_(row.jobid),
    jobType: trimString_(row.jobtype),
    token: trimString_(row.token),
    status: status,
    attemptCount: Math.max(0, parseInt(String(row.attemptcount || 0), 10) || 0),
    lastError: trimString_(row.lasterror),
    createdAt: trimString_(row.createdat),
    updatedAt: trimString_(row.updatedat),
    startedAt: trimString_(row.startedat),
    completedAt: trimString_(row.completedat),
    leaseUntil: trimString_(row.leaseuntil)
  };
  if (portalPayload && typeof portalPayload === 'object') payload.portalPayload = portalPayload;
  return payload;
}

function normalizeAchLifecycleEmailJobType_(value) {
  const jobType = trimString_(value).toLowerCase();
  return [
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_invoice_email,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_receipt_email,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_action_email,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_bank_verification_reminder_email,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_team_alert_email,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_team_alert_email,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_team_alert_email,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_bank_verification_reminder_team_alert_email
  ].indexOf(jobType) >= 0 ? jobType : '';
}

function isAchLifecycleEmailJobType_(value) {
  return !!normalizeAchLifecycleEmailJobType_(value);
}

function isAchLifecycleTeamAlertEmailJobType_(value) {
  const type = normalizeAchLifecycleEmailJobType_(value);
  return type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_team_alert_email ||
    type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_team_alert_email ||
    type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_team_alert_email ||
    type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_bank_verification_reminder_team_alert_email;
}

function getAchLifecycleBaseEmailJobType_(value) {
  const type = normalizeAchLifecycleEmailJobType_(value);
  if (type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_team_alert_email) {
    return PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_invoice_email;
  }
  if (type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_team_alert_email) {
    return PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_receipt_email;
  }
  if (type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_team_alert_email) {
    return PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_action_email;
  }
  if (type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_bank_verification_reminder_team_alert_email) {
    return PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_bank_verification_reminder_email;
  }
  return type;
}

function getAchLifecycleTeamAlertEmailJobType_(value) {
  const baseType = getAchLifecycleBaseEmailJobType_(value);
  if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_invoice_email) {
    return PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_team_alert_email;
  }
  if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_receipt_email) {
    return PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_team_alert_email;
  }
  if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_action_email) {
    return PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_team_alert_email;
  }
  if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_bank_verification_reminder_email) {
    return PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_bank_verification_reminder_team_alert_email;
  }
  return '';
}

function getAchLifecycleEmailRecipientClass_(jobType) {
  return isAchLifecycleTeamAlertEmailJobType_(jobType) ? 'team' : 'client';
}

function extractSafeStripePayerEmail_(stripeObj) {
  const obj = (stripeObj && typeof stripeObj === 'object') ? stripeObj : {};
  const candidates = [];
  function collectFrom(source) {
    const item = (source && typeof source === 'object') ? source : {};
    candidates.push(item.email);
    if (item.customer_details && typeof item.customer_details === 'object') candidates.push(item.customer_details.email);
    if (item.customerDetails && typeof item.customerDetails === 'object') candidates.push(item.customerDetails.email);
    if (item.billing_details && typeof item.billing_details === 'object') candidates.push(item.billing_details.email);
    if (item.billingDetails && typeof item.billingDetails === 'object') candidates.push(item.billingDetails.email);
    if (item.payment_method && typeof item.payment_method === 'object') collectFrom(item.payment_method);
    if (item.paymentMethod && typeof item.paymentMethod === 'object') collectFrom(item.paymentMethod);
    if (item.latest_charge && typeof item.latest_charge === 'object') collectFrom(item.latest_charge);
    if (item.latestCharge && typeof item.latestCharge === 'object') collectFrom(item.latestCharge);
    if (item.charges && Array.isArray(item.charges.data)) {
      item.charges.data.forEach(collectFrom);
    }
  }
  collectFrom(obj);
  return firstNormalizedEmailFromValues_(candidates);
}

function buildAchLifecycleEmailRecipients_(orderInfo, stripeObj, accountInfo) {
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const draft = safeJsonParse_(row.orderdraftjson || row.orderDraftJson, {}) || {};
  const account = accountInfo && accountInfo.summary ? accountInfo.summary : {};
  const payerEmail = extractSafeStripePayerEmail_(stripeObj);
  const primaryEmail = firstNormalizedEmailFromValues_([
    row.personemail,
    row.personEmail,
    draft.personEmail,
    account.primaryEmail,
    account.billingContactEmail
  ]);
  const toList = primaryEmail ? [primaryEmail] : (payerEmail ? [payerEmail] : []);
  const ccList = primaryEmail && payerEmail && payerEmail !== primaryEmail ? [payerEmail] : [];
  return {
    toList: normalizeEmailRecipients_(toList),
    ccList: normalizeEmailRecipients_(ccList),
    payerEmail: payerEmail,
    primaryEmail: primaryEmail
  };
}

function buildAchLifecycleTeamAlertRecipients_() {
  return {
    toList: normalizeEmailRecipients_([DOCUMENT_REVIEW_EMAIL]),
    ccList: [],
    recipientClass: 'team'
  };
}

function summarizeEmailDomainsForLog_(emails) {
  const counts = {};
  normalizeEmailRecipients_(emails).forEach(function(email) {
    const domain = trimString_(email.split('@').slice(1).join('@')).toLowerCase();
    if (!domain) return;
    counts[domain] = (counts[domain] || 0) + 1;
  });
  return Object.keys(counts).sort().map(function(domain) {
    return domain + ':' + counts[domain];
  });
}

function logAchLifecycleEmailQueueEvent_(eventName, payload) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  const safe = {
    event: trimString_(eventName),
    ok: p.ok === true,
    reason: trimString_(p.reason),
    jobType: trimString_(p.jobType),
    recipientClass: trimString_(p.recipientClass),
    tokenPresent: !!trimString_(p.token),
    orderId: trimString_(p.orderId),
    paymentIntentPresent: !!trimString_(p.paymentIntentId),
    sessionPresent: !!trimString_(p.sessionId),
    recipientCount: Math.max(0, parseInt(String(p.recipientCount || 0), 10) || 0),
    ccCount: Math.max(0, parseInt(String(p.ccCount || 0), 10) || 0),
    recipientDomains: Array.isArray(p.recipientDomains) ? p.recipientDomains : [],
    invoicePdfPresent: p.invoicePdfPresent === true,
    attachmentRequired: p.attachmentRequired === true,
    attachmentPresent: p.attachmentPresent === true,
    status: trimString_(p.status),
    error: trimString_(p.error)
  };
  console.log('[RT-ACH-EMAIL-QUEUE] ' + JSON.stringify(safe));
}

function isStandardOrderCheckoutAchOrder_(orderInfo) {
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = buildPortalOrderSummary_(row);
  if (trimString_(summary.paymentMethodSelected).toLowerCase() !== PAYMENT_METHODS.ach) return false;
  const source = normalizeAchPaymentSource_(summary.achPaymentSource);
  if (source === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link) return false;
  return true;
}

function shouldQueueAchLifecycleEmailForOrder_(orderInfo, jobType) {
  if (!isStandardOrderCheckoutAchOrder_(orderInfo)) return false;
  const summary = buildPortalOrderSummary_(orderInfo.rowObjNormalized || {});
  const paymentState = trimString_(summary.paymentState).toLowerCase();
  const eventType = trimString_(summary.stripeLatestEventType).toLowerCase();
  const failureSignal = [
    summary.achFailureCode,
    summary.achFailureMessage,
    eventType
  ].join(' ').toLowerCase();
  const type = getAchLifecycleBaseEmailJobType_(jobType);
  if (type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_invoice_email) {
    return paymentState === PAYMENT_STATES.pending && !trimString_(summary.paidAt);
  }
  if (type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_receipt_email) {
    return paymentState === PAYMENT_STATES.paid || !!trimString_(summary.paidAt);
  }
  if (type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_action_email) {
    return paymentState === PAYMENT_STATES.failed ||
      eventType === 'charge.dispute.created' ||
      failureSignal.indexOf('dispute') >= 0 ||
      failureSignal.indexOf('mandate') >= 0 ||
      failureSignal.indexOf('blocked') >= 0;
  }
  if (type === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_bank_verification_reminder_email) {
    return (paymentState === PAYMENT_STATES.pending || paymentState === PAYMENT_STATES.submitted) &&
      !trimString_(summary.paidAt) &&
      !isCommunicationPaymentFailureActionState_(summary) &&
      isAchVerificationRequiredForEmail_(summary);
  }
  return false;
}

function isAchVerificationRequiredForEmail_(orderSummary) {
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const signal = [
    summary.achVerificationStatus,
    summary.achFailureCode,
    summary.achFailureMessage
  ].join(' ').toLowerCase();
  return /(microdeposit|requires_action|unverified|verification_pending|bank_verification_pending)/i.test(signal);
}

function buildAchLifecycleEmailIdempotencyKey_(jobType, orderSummary, recipients, meta) {
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const safeRecipients = (recipients && typeof recipients === 'object') ? recipients : {};
  const safeMeta = (meta && typeof meta === 'object') ? meta : {};
  return buildPortalEmailQueueIdempotencyKeyForSource_({
    jobType: normalizeAchLifecycleEmailJobType_(jobType),
    recipientClass: getAchLifecycleEmailRecipientClass_(jobType),
    orderId: trimString_(summary.orderId),
    token: trimString_(summary.token),
    stripePaymentIntentId: trimString_(summary.stripePaymentIntentId),
    invoiceNumber: trimString_(summary.invoiceNumber),
    scheduleKey: trimString_(safeMeta.scheduleKey),
    toList: normalizeEmailRecipients_(safeRecipients.toList),
    ccList: normalizeEmailRecipients_(safeRecipients.ccList)
  });
}

function findAchLifecycleEmailQueueJob_(queueSheet, jobType, orderSummary) {
  const type = normalizeAchLifecycleEmailJobType_(jobType);
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const orderId = trimString_(summary.orderId);
  const paymentIntentId = trimString_(summary.stripePaymentIntentId);
  if (!queueSheet || !type || (!orderId && !paymentIntentId)) return null;
  return listSheetRowInfos_(queueSheet).find(function(info) {
    const row = info && info.rowObjNormalized ? info.rowObjNormalized : {};
    if (trimString_(row.jobtype) !== type) return false;
    const meta = safeJsonParse_(row.portalstatejson, {}) || {};
    const metaOrderId = trimString_(meta.orderId);
    const metaPaymentIntentId = trimString_(meta.stripePaymentIntentId);
    return !!((orderId && metaOrderId === orderId) ||
      (paymentIntentId && metaPaymentIntentId === paymentIntentId));
  }) || null;
}

function parseAchLifecycleEmailQueueRecipients_(rawValue) {
  const parsed = safeJsonParse_(rawValue, []);
  if (Array.isArray(parsed)) {
    return {
      toList: normalizeEmailRecipients_(parsed),
      ccList: []
    };
  }
  const source = (parsed && typeof parsed === 'object') ? parsed : {};
  return {
    toList: normalizeEmailRecipients_(source.toList || source.to || source.recipients),
    ccList: normalizeEmailRecipients_(source.ccList || source.cc),
    payerEmail: normalizeEmail_(source.payerEmail),
    primaryEmail: normalizeEmail_(source.primaryEmail)
  };
}

function upsertPortalEmailQueueJob_(queueSheet, values) {
  const safeValues = (values && typeof values === 'object') ? values : {};
  const idempotencyKey = trimString_(safeValues.idempotencyKey);
  if (!idempotencyKey) throw new Error('Email queue job is missing an idempotency key.');
  let existingJob = findPortalEmailQueueJobByIdempotencyKey_(queueSheet, idempotencyKey);
  const now = nowIso_();
  if (existingJob) {
    const existingStatus = normalizePortalEmailQueueStatus_(existingJob.rowObjNormalized.status);
    if (existingStatus === PORTAL_EMAIL_QUEUE_STATUSES.sent ||
        existingStatus === PORTAL_EMAIL_QUEUE_STATUSES.processing) {
      return existingJob;
    }
    setRowValuesByHeaderMap_(queueSheet, existingJob.row, existingJob.colMap, Object.assign({}, safeValues, {
      status: PORTAL_EMAIL_QUEUE_STATUSES.queued,
      attemptCount: existingStatus === PORTAL_EMAIL_QUEUE_STATUSES.failed
        ? Math.max(0, parseInt(String(existingJob.rowObjNormalized.attemptcount || 0), 10) || 0)
        : Math.max(0, parseInt(String(safeValues.attemptCount || existingJob.rowObjNormalized.attemptcount || 0), 10) || 0),
      lastError: '',
      createdAt: trimString_(existingJob.rowObjNormalized.createdat) || trimString_(safeValues.createdAt) || now,
      updatedAt: now,
      startedAt: '',
      completedAt: '',
      leaseUntil: ''
    }));
    return buildRowInfoFromSheet_(queueSheet, existingJob.row);
  }
  return appendPortalEmailQueueJob_(queueSheet, Object.assign({
    jobId: newPortalId_('eml'),
    status: PORTAL_EMAIL_QUEUE_STATUSES.queued,
    attemptCount: 0,
    lastError: '',
    createdAt: now,
    updatedAt: now,
    startedAt: '',
    completedAt: '',
    leaseUntil: ''
  }, safeValues));
}

function queueAchLifecycleClientEmailSafely_(orderInfo, stripeObj, jobType, options) {
  return queueAchLifecycleEmailJobSafely_(orderInfo, stripeObj, jobType, Object.assign({}, options || {}, {
    recipientClass: 'client'
  }));
}

function queueAchLifecycleTeamAlertEmailSafely_(orderInfo, stripeObj, jobType, options) {
  const teamType = getAchLifecycleTeamAlertEmailJobType_(jobType);
  if (!teamType) return null;
  return queueAchLifecycleEmailJobSafely_(orderInfo, stripeObj, teamType, Object.assign({}, options || {}, {
    recipientClass: 'team'
  }));
}

function queueAchLifecycleClientAndTeamEmailsSafely_(orderInfo, stripeObj, jobType, options) {
  return {
    clientJob: queueAchLifecycleClientEmailSafely_(orderInfo, stripeObj, jobType, options),
    teamJob: queueAchLifecycleTeamAlertEmailSafely_(orderInfo, stripeObj, jobType, options)
  };
}

function queueAchLifecycleEmailJobSafely_(orderInfo, stripeObj, jobType, options) {
  const type = normalizeAchLifecycleEmailJobType_(jobType);
  if (!type) return null;
  const recipientClass = getAchLifecycleEmailRecipientClass_(type);
  try {
    const opts = (options && typeof options === 'object') ? options : {};
    const orderSummary = buildPortalOrderSummary_((orderInfo && orderInfo.rowObjNormalized) || {});
    const milestonePolicy = resolveCommunicationMilestonePolicy_(type, '', orderInfo, {
      meta: opts.meta,
      recipientClass: recipientClass,
      paymentOrigin: opts.paymentOrigin,
      achPaymentSource: opts.achPaymentSource
    });
    if (milestonePolicy.enabled === false) {
      logAchLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: milestonePolicy.reason,
        jobType: type,
        recipientClass: recipientClass,
        token: trimString_(orderSummary.token),
        orderId: trimString_(orderSummary.orderId),
        paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        sessionId: trimString_(orderSummary.stripeSessionId),
        invoicePdfPresent: !!trimString_(orderSummary.invoicePdfUrl)
      });
      return null;
    }
    if (!shouldQueueAchLifecycleEmailForOrder_(orderInfo, type)) {
      logAchLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: 'state_not_eligible',
        jobType: type,
        recipientClass: recipientClass,
        token: trimString_(orderSummary.token),
        orderId: trimString_(orderSummary.orderId),
        paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        sessionId: trimString_(orderSummary.stripeSessionId),
        invoicePdfPresent: !!trimString_(orderSummary.invoicePdfUrl)
      });
      return null;
    }
    const cfg = opts.cfg || getConfig_();
    const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
    const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
    const meta = (opts.meta && typeof opts.meta === 'object') ? opts.meta : {};
    const accountInfo = opts.accountInfo || getPortalAccountInfoForOrder_(orderInfo, {
      cfg: cfg,
      ss: ss,
      infra: infra
    });
    const recipients = recipientClass === 'team'
      ? buildAchLifecycleTeamAlertRecipients_()
      : buildAchLifecycleEmailRecipients_(orderInfo, stripeObj, accountInfo);
    if (!recipients.toList.length) {
      logAchLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: 'missing_recipients',
        jobType: type,
        recipientClass: recipientClass,
        token: trimString_(orderSummary.token),
        orderId: trimString_(orderSummary.orderId),
        paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        sessionId: trimString_(orderSummary.stripeSessionId),
        invoicePdfPresent: !!trimString_(orderSummary.invoicePdfUrl)
      });
      return null;
    }
    const queueSheet = getPortalEmailQueueSheet_(ss);
    const existingLifecycleJob = findAchLifecycleEmailQueueJob_(queueSheet, type, orderSummary);
    const idempotencyKey = trimString_(existingLifecycleJob && existingLifecycleJob.rowObjNormalized.idempotencykey) ||
      buildAchLifecycleEmailIdempotencyKey_(type, orderSummary, recipients, meta);
    const jobInfo = upsertPortalEmailQueueJob_(queueSheet, {
      jobType: type,
      idempotencyKey: idempotencyKey,
      token: trimString_(orderInfo.rowObjNormalized.token),
      recipientsJson: JSON.stringify(recipients),
      portalStateJson: JSON.stringify(Object.assign({}, meta, {
        jobType: type,
        recipientClass: recipientClass,
        orderId: trimString_(orderSummary.orderId),
        checkoutAttemptId: trimString_(orderSummary.checkoutAttemptId),
        stripePaymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        stripeSessionId: trimString_(orderSummary.stripeSessionId),
        invoiceNumber: trimString_(orderSummary.invoiceNumber),
        queuedFromEventType: trimString_(opts.eventType),
        queuedAt: nowIso_()
      })),
      orderDraftJson: trimString_(orderInfo.rowObjNormalized.orderdraftjson),
      invoicePdfUrl: trimString_(orderSummary.invoicePdfUrl),
      invoiceFileName: ''
    });
    logAchLifecycleEmailQueueEvent_('queued', {
      ok: true,
      jobType: type,
      recipientClass: recipientClass,
      token: trimString_(orderSummary.token),
      orderId: trimString_(orderSummary.orderId),
      paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
      sessionId: trimString_(orderSummary.stripeSessionId),
      recipientCount: recipients.toList.length,
      ccCount: recipients.ccList.length,
      recipientDomains: summarizeEmailDomainsForLog_(recipients.toList.concat(recipients.ccList)),
      invoicePdfPresent: !!trimString_(orderSummary.invoicePdfUrl),
      status: trimString_(jobInfo && jobInfo.rowObjNormalized && jobInfo.rowObjNormalized.status)
    });
    let finalJobInfo = jobInfo;
    if (isPortalEmailQueueJobEligible_(jobInfo, new Date())) {
      finalJobInfo = tryProcessPortalEmailQueueJobById_(trimString_(jobInfo && jobInfo.rowObjNormalized && jobInfo.rowObjNormalized.jobid), {
        cfg: cfg,
        ss: ss,
        infra: infra,
        queueSheet: queueSheet,
        token: trimString_(orderSummary.token)
      }) || jobInfo;
      if (isPortalEmailQueueJobEligible_(finalJobInfo, new Date())) schedulePortalEmailQueueProcessor_();
    }
    return finalJobInfo;
  } catch (err) {
    logAchLifecycleEmailQueueEvent_('error', {
      ok: false,
      jobType: type,
      recipientClass: recipientClass,
      orderId: trimString_(orderInfo && orderInfo.rowObjNormalized && orderInfo.rowObjNormalized.orderid),
      error: String((err && err.message) || err)
    });
    return null;
  }
}

function resolveAchLifecycleOrderForQueueJob_(jobInfo, options) {
  const row = jobInfo && jobInfo.rowObjNormalized ? jobInfo.rowObjNormalized : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const meta = safeJsonParse_(row.portalstatejson, {}) || {};
  const orderId = trimString_(meta.orderId);
  const paymentIntentId = trimString_(meta.stripePaymentIntentId);
  const token = trimString_(row.token || meta.token);
  return (orderId ? getPortalOrderByOrderId_(orderId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null) ||
    (paymentIntentId ? getPortalOrderByStripePaymentIntentId_(paymentIntentId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null) ||
    (token ? getLatestPortalOrderByToken_(token, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null);
}

function resolveAchLifecycleInvoiceInfo_(orderInfo, jobType, options) {
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = buildPortalOrderSummary_(row);
  const baseInfo = {
    invoiceNumber: trimString_(summary.invoiceNumber),
    invoicePdfUrl: trimString_(summary.invoicePdfUrl),
    fileName: trimString_(summary.invoiceFileName)
  };
  const baseType = getAchLifecycleBaseEmailJobType_(jobType);
  return attachPortalDocumentReferenceToInvoiceInfo_(baseInfo, orderInfo, {
    documentKind: baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_receipt_email
      ? PORTAL_DOCUMENT_KINDS.receipt
      : PORTAL_DOCUMENT_KINDS.invoice,
    forceFileName: baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_receipt_email
  });
}

function normalizeApAchLifecycleEmailMilestone_(value) {
  const milestone = trimString_(value).toLowerCase();
  return Object.keys(AP_ACH_LIFECYCLE_EMAIL_MILESTONES).some(function(key) {
    return AP_ACH_LIFECYCLE_EMAIL_MILESTONES[key] === milestone;
  }) ? milestone : '';
}

function isApAchLifecycleEmailJobType_(value) {
  return trimString_(value).toLowerCase() === PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email;
}

function isApAchLifecycleReceiptMilestone_(milestone) {
  return normalizeApAchLifecycleEmailMilestone_(milestone) === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_confirmed;
}

function isApAchLifecycleFailureMilestone_(milestone) {
  return normalizeApAchLifecycleEmailMilestone_(milestone) === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_failed;
}

function isApAchLifecycleAttachmentRequired_(milestone) {
  const normalized = normalizeApAchLifecycleEmailMilestone_(milestone);
  return normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_submitted ||
    normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_confirmed;
}

function getApAchLifecycleOrderToken_(orderInfo, orderSummary) {
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const draft = safeJsonParse_(row.orderdraftjson || row.orderDraftJson, {}) || {};
  return trimString_(summary.token || row.token || row.Token || draft.token);
}

function isApAchLifecycleOrder_(orderInfo) {
  const summary = buildPortalOrderSummary_((orderInfo && orderInfo.rowObjNormalized) || {});
  return trimString_(summary.paymentMethodSelected).toLowerCase() === PAYMENT_METHODS.ach &&
    normalizeAchPaymentSource_(summary.achPaymentSource) === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link;
}

function shouldQueueApAchLifecycleEmailForOrder_(orderInfo, milestone) {
  const normalized = normalizeApAchLifecycleEmailMilestone_(milestone);
  if (!normalized || !isApAchLifecycleOrder_(orderInfo)) return false;
  const summary = buildPortalOrderSummary_((orderInfo && orderInfo.rowObjNormalized) || {});
  const paymentState = trimString_(summary.paymentState).toLowerCase();
  const eventType = trimString_(summary.stripeLatestEventType).toLowerCase();
  const paid = paymentState === PAYMENT_STATES.paid || !!trimString_(summary.paidAt);
  const failureSignal = [
    summary.achFailureCode,
    summary.achFailureMessage,
    eventType
  ].join(' ').toLowerCase();
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.checkout_started) {
    return paymentState === PAYMENT_STATES.checkout_created && !paid &&
      (!!trimString_(summary.checkoutAttemptId) || !!trimString_(summary.stripeSessionId));
  }
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_submitted) {
    return paymentState === PAYMENT_STATES.pending && !paid;
  }
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_confirmed) {
    return paid;
  }
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_failed) {
    return paymentState === PAYMENT_STATES.failed ||
      eventType === 'charge.dispute.created' ||
      failureSignal.indexOf('dispute') >= 0 ||
      failureSignal.indexOf('mandate') >= 0 ||
      failureSignal.indexOf('blocked') >= 0;
  }
  return false;
}

function buildApAchLifecycleEmailRecipients_(orderInfo, stripeObj, accountInfo, recipientClass) {
  if (trimString_(recipientClass) === 'team') {
    return buildPaymentLifecycleTeamAlertRecipients_();
  }
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = buildPortalOrderSummary_(row);
  const draft = safeJsonParse_(row.orderdraftjson || row.orderDraftJson, {}) || {};
  const account = accountInfo && accountInfo.summary ? accountInfo.summary : {};
  const apRecipients = normalizeEmailRecipients_(summary.invoiceSentToEmail || row.invoicesenttoemail || draft.invoiceSentToEmail);
  const purchaserEmail = firstNormalizedEmailFromValues_([
    row.personemail,
    row.personEmail,
    draft.personEmail,
    account.primaryEmail,
    account.billingContactEmail
  ]);
  const ccList = purchaserEmail && apRecipients.indexOf(purchaserEmail) < 0 ? [purchaserEmail] : [];
  return {
    toList: apRecipients,
    ccList: normalizeEmailRecipients_(ccList),
    apEmail: apRecipients[0] || '',
    purchaserEmail: purchaserEmail,
    payerEmail: extractSafeStripePayerEmail_(stripeObj),
    recipientClass: 'ap'
  };
}

function buildApAchLifecycleEmailIdempotencyKey_(milestone, recipientClass, orderSummary, recipients, token) {
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const safeRecipients = (recipients && typeof recipients === 'object') ? recipients : {};
  return buildPortalEmailQueueIdempotencyKeyForSource_({
    jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email,
    milestone: normalizeApAchLifecycleEmailMilestone_(milestone),
    recipientClass: trimString_(recipientClass),
    token: trimString_(token),
    orderId: trimString_(summary.orderId),
    paymentMethodSelected: PAYMENT_METHODS.ach,
    achPaymentSource: ACH_PAYMENT_METHOD_SOURCES.ap_payment_link,
    checkoutAttemptId: trimString_(summary.checkoutAttemptId),
    stripePaymentIntentId: trimString_(summary.stripePaymentIntentId),
    stripeSessionId: trimString_(summary.stripeSessionId),
    invoiceNumber: trimString_(summary.invoiceNumber),
    toList: normalizeEmailRecipients_(safeRecipients.toList),
    ccList: normalizeEmailRecipients_(safeRecipients.ccList)
  });
}

function findApAchLifecycleEmailQueueJob_(queueSheet, milestone, recipientClass, orderSummary, token) {
  const normalized = normalizeApAchLifecycleEmailMilestone_(milestone);
  const safeRecipientClass = trimString_(recipientClass);
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const orderId = trimString_(summary.orderId);
  const paymentIntentId = trimString_(summary.stripePaymentIntentId);
  const sessionId = trimString_(summary.stripeSessionId);
  const checkoutAttemptId = trimString_(summary.checkoutAttemptId);
  const orderToken = trimString_(token || summary.token);
  if (!queueSheet || !normalized || !safeRecipientClass) return null;
  return listSheetRowInfos_(queueSheet).find(function(info) {
    const row = info && info.rowObjNormalized ? info.rowObjNormalized : {};
    if (trimString_(row.jobtype) !== PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email) return false;
    const meta = safeJsonParse_(row.portalstatejson, {}) || {};
    if (normalizeApAchLifecycleEmailMilestone_(meta.milestone) !== normalized) return false;
    if (trimString_(meta.recipientClass) !== safeRecipientClass) return false;
    return !!((orderId && trimString_(meta.orderId) === orderId) ||
      (paymentIntentId && trimString_(meta.stripePaymentIntentId) === paymentIntentId) ||
      (sessionId && trimString_(meta.stripeSessionId) === sessionId) ||
      (checkoutAttemptId && trimString_(meta.checkoutAttemptId) === checkoutAttemptId) ||
      (orderToken && trimString_(row.token || meta.token) === orderToken));
  }) || null;
}

function logApAchLifecycleEmailQueueEvent_(eventName, payload) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  const safe = {
    event: trimString_(eventName),
    ok: p.ok === true,
    reason: trimString_(p.reason),
    jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email,
    milestone: trimString_(p.milestone),
    recipientClass: trimString_(p.recipientClass),
    tokenPresent: !!trimString_(p.token),
    orderId: trimString_(p.orderId),
    paymentIntentPresent: !!trimString_(p.paymentIntentId),
    sessionPresent: !!trimString_(p.sessionId),
    recipientCount: Math.max(0, parseInt(String(p.recipientCount || 0), 10) || 0),
    ccCount: Math.max(0, parseInt(String(p.ccCount || 0), 10) || 0),
    recipientDomains: Array.isArray(p.recipientDomains) ? p.recipientDomains : [],
    invoicePdfPresent: p.invoicePdfPresent === true,
    attachmentRequired: p.attachmentRequired === true,
    attachmentPresent: p.attachmentPresent === true,
    status: trimString_(p.status),
    error: trimString_(p.error)
  };
  console.log('[RT-AP-ACH-LIFECYCLE-EMAIL-QUEUE] ' + JSON.stringify(safe));
}

function queueApAchLifecycleApAndTeamEmailsSafely_(orderInfo, stripeObj, milestone, options) {
  return {
    apJob: queueApAchLifecycleEmailJobSafely_(orderInfo, stripeObj, milestone, Object.assign({}, options || {}, {
      recipientClass: 'ap'
    })),
    teamJob: queueApAchLifecycleEmailJobSafely_(orderInfo, stripeObj, milestone, Object.assign({}, options || {}, {
      recipientClass: 'team'
    }))
  };
}

function queueOrderAchLifecycleEmailsSafely_(orderInfo, stripeObj, standardJobType, apMilestone, options) {
  if (isApAchLifecycleOrder_(orderInfo)) {
    return queueApAchLifecycleApAndTeamEmailsSafely_(orderInfo, stripeObj, apMilestone, options);
  }
  return queueAchLifecycleClientAndTeamEmailsSafely_(orderInfo, stripeObj, standardJobType, options);
}

function queueApAchLifecycleEmailJobSafely_(orderInfo, stripeObj, milestone, options) {
  const normalized = normalizeApAchLifecycleEmailMilestone_(milestone);
  if (!normalized) return null;
  const opts = (options && typeof options === 'object') ? options : {};
  const recipientClass = trimString_(opts.recipientClass) === 'team' ? 'team' : 'ap';
  try {
    const orderSummary = buildPortalOrderSummary_((orderInfo && orderInfo.rowObjNormalized) || {});
    const token = getApAchLifecycleOrderToken_(orderInfo, orderSummary);
    const attachmentRequired = isApAchLifecycleAttachmentRequired_(normalized);
    const emailPolicy = resolveLifecycleEmailPolicy_(
      PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email,
      normalized,
      recipientClass,
      opts.meta
    );
    if (emailPolicy.enabled === false) {
      logApAchLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: emailPolicy.reason,
        milestone: normalized,
        recipientClass: recipientClass,
        token: token,
        orderId: trimString_(orderSummary.orderId),
        paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        sessionId: trimString_(orderSummary.stripeSessionId),
        invoicePdfPresent: !!trimString_(orderSummary.invoicePdfUrl),
        attachmentRequired: attachmentRequired
      });
      return null;
    }
    const milestonePolicy = resolveCommunicationMilestonePolicy_(
      PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email,
      normalized,
      orderInfo,
      {
        meta: Object.assign({}, opts.meta || {}, {
          achPaymentSource: ACH_PAYMENT_METHOD_SOURCES.ap_payment_link
        }),
        recipientClass: recipientClass,
        paymentOrigin: opts.paymentOrigin,
        achPaymentSource: opts.achPaymentSource || ACH_PAYMENT_METHOD_SOURCES.ap_payment_link
      }
    );
    if (milestonePolicy.enabled === false) {
      logApAchLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: milestonePolicy.reason,
        milestone: normalized,
        recipientClass: recipientClass,
        token: token,
        orderId: trimString_(orderSummary.orderId),
        paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        sessionId: trimString_(orderSummary.stripeSessionId),
        invoicePdfPresent: !!trimString_(orderSummary.invoicePdfUrl),
        attachmentRequired: attachmentRequired
      });
      return null;
    }
    if (!shouldQueueApAchLifecycleEmailForOrder_(orderInfo, normalized)) {
      logApAchLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: 'state_not_eligible',
        milestone: normalized,
        recipientClass: recipientClass,
        token: token,
        orderId: trimString_(orderSummary.orderId),
        paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        sessionId: trimString_(orderSummary.stripeSessionId),
        invoicePdfPresent: !!trimString_(orderSummary.invoicePdfUrl),
        attachmentRequired: attachmentRequired
      });
      return null;
    }
    const cfg = opts.cfg || getConfig_();
    const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
    const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
    const accountInfo = opts.accountInfo || getPortalAccountInfoForOrder_(orderInfo, {
      cfg: cfg,
      ss: ss,
      infra: infra
    });
    const recipients = buildApAchLifecycleEmailRecipients_(orderInfo, stripeObj, accountInfo, recipientClass);
    if (!recipients.toList.length) {
      logApAchLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: 'missing_recipients',
        milestone: normalized,
        recipientClass: recipientClass,
        token: token,
        orderId: trimString_(orderSummary.orderId),
        paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        sessionId: trimString_(orderSummary.stripeSessionId),
        invoicePdfPresent: !!trimString_(orderSummary.invoicePdfUrl),
        attachmentRequired: attachmentRequired
      });
      return null;
    }
    const queueSheet = getPortalEmailQueueSheet_(ss);
    const invoiceInfo = (opts.invoiceInfo && typeof opts.invoiceInfo === 'object') ? opts.invoiceInfo : {};
    const existingLifecycleJob = findApAchLifecycleEmailQueueJob_(queueSheet, normalized, recipientClass, orderSummary, token);
    const idempotencyKey = trimString_(existingLifecycleJob && existingLifecycleJob.rowObjNormalized.idempotencykey) ||
      buildApAchLifecycleEmailIdempotencyKey_(normalized, recipientClass, orderSummary, recipients, token);
    const jobInfo = upsertPortalEmailQueueJob_(queueSheet, {
      jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email,
      idempotencyKey: idempotencyKey,
      token: token,
      recipientsJson: JSON.stringify(recipients),
      portalStateJson: JSON.stringify({
        jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email,
        milestone: normalized,
        recipientClass: recipientClass,
        token: token,
        orderId: trimString_(orderSummary.orderId),
        checkoutAttemptId: trimString_(orderSummary.checkoutAttemptId),
        stripePaymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        stripeSessionId: trimString_(orderSummary.stripeSessionId),
        paymentMethodSelected: PAYMENT_METHODS.ach,
        achPaymentSource: ACH_PAYMENT_METHOD_SOURCES.ap_payment_link,
        invoiceNumber: trimString_(invoiceInfo.invoiceNumber || orderSummary.invoiceNumber),
        attachmentRequired: attachmentRequired,
        queuedFromEventType: trimString_(opts.eventType),
        queuedAt: nowIso_()
      }),
      orderDraftJson: trimString_(orderInfo && orderInfo.rowObjNormalized && orderInfo.rowObjNormalized.orderdraftjson),
      invoicePdfUrl: trimString_(invoiceInfo.invoicePdfUrl || orderSummary.invoicePdfUrl),
      invoiceFileName: trimString_(invoiceInfo.fileName || invoiceInfo.invoiceFileName)
    });
    logApAchLifecycleEmailQueueEvent_('queued', {
      ok: true,
      milestone: normalized,
      recipientClass: recipientClass,
      token: token,
      orderId: trimString_(orderSummary.orderId),
      paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
      sessionId: trimString_(orderSummary.stripeSessionId),
      recipientCount: recipients.toList.length,
      ccCount: recipients.ccList.length,
      recipientDomains: summarizeEmailDomainsForLog_(recipients.toList.concat(recipients.ccList)),
      invoicePdfPresent: !!trimString_(invoiceInfo.invoicePdfUrl || orderSummary.invoicePdfUrl),
      attachmentRequired: attachmentRequired,
      status: trimString_(jobInfo && jobInfo.rowObjNormalized && jobInfo.rowObjNormalized.status)
    });
    let finalJobInfo = jobInfo;
    if (isPortalEmailQueueJobEligible_(jobInfo, new Date())) {
      finalJobInfo = tryProcessPortalEmailQueueJobById_(trimString_(jobInfo && jobInfo.rowObjNormalized && jobInfo.rowObjNormalized.jobid), {
        cfg: cfg,
        ss: ss,
        infra: infra,
        queueSheet: queueSheet,
        token: token
      }) || jobInfo;
      if (isPortalEmailQueueJobEligible_(finalJobInfo, new Date())) schedulePortalEmailQueueProcessor_();
    }
    return finalJobInfo;
  } catch (err) {
    logApAchLifecycleEmailQueueEvent_('error', {
      ok: false,
      milestone: normalized,
      recipientClass: recipientClass,
      orderId: trimString_(orderInfo && orderInfo.rowObjNormalized && orderInfo.rowObjNormalized.orderid),
      error: String((err && err.message) || err)
    });
    return null;
  }
}

function resolveApAchLifecycleOrderForQueueJob_(jobInfo, options) {
  const row = jobInfo && jobInfo.rowObjNormalized ? jobInfo.rowObjNormalized : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const meta = safeJsonParse_(row.portalstatejson, {}) || {};
  const orderId = trimString_(meta.orderId);
  const paymentIntentId = trimString_(meta.stripePaymentIntentId);
  const sessionId = trimString_(meta.stripeSessionId);
  const checkoutAttemptId = trimString_(meta.checkoutAttemptId);
  const token = trimString_(row.token || meta.token);
  return (orderId ? getPortalOrderByOrderId_(orderId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null) ||
    (paymentIntentId ? getPortalOrderByStripePaymentIntentId_(paymentIntentId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null) ||
    (sessionId ? getPortalOrderByStripeSessionId_(sessionId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null) ||
    (checkoutAttemptId ? getPortalOrderByCheckoutAttemptId_(checkoutAttemptId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null) ||
    (token ? getLatestPortalOrderByToken_(token, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null);
}

function resolveApAchLifecycleInvoiceInfo_(orderInfo, milestone, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = buildPortalOrderSummary_(row);
  const queued = (opts.queuedInvoiceInfo && typeof opts.queuedInvoiceInfo === 'object') ? opts.queuedInvoiceInfo : {};
  const baseInfo = {
    invoiceNumber: trimString_(queued.invoiceNumber) || trimString_(summary.invoiceNumber),
    invoicePdfUrl: trimString_(queued.invoicePdfUrl) || trimString_(summary.invoicePdfUrl),
    fileName: trimString_(queued.fileName || queued.invoiceFileName)
  };
  return attachPortalDocumentReferenceToInvoiceInfo_(baseInfo, orderInfo, {
    documentKind: isApAchLifecycleReceiptMilestone_(milestone)
      ? PORTAL_DOCUMENT_KINDS.receipt
      : PORTAL_DOCUMENT_KINDS.invoice,
    forceFileName: isApAchLifecycleReceiptMilestone_(milestone)
  });
}

function getApAchLifecycleCtaLabel_(milestone, recipientClass) {
  const normalized = normalizeApAchLifecycleEmailMilestone_(milestone);
  if (trimString_(recipientClass) === 'team') return 'View project in portal';
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.checkout_started) return 'Open AP ACH payment';
  if (isApAchLifecycleReceiptMilestone_(normalized)) return 'View Red Threads receipt';
  if (isApAchLifecycleFailureMilestone_(normalized)) return 'Return to Portal/Project and retry payment';
  return 'View AP payment status';
}

function getApAchLifecycleCtaUrl_(token, recipientClass, milestone) {
  if (trimString_(recipientClass) === 'team') return buildLifecycleEmailTeamUrl_(token);
  const normalized = normalizeApAchLifecycleEmailMilestone_(milestone);
  if (
    normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.checkout_started ||
    isApAchLifecycleFailureMilestone_(normalized)
  ) {
    return buildAchApPaymentPortalUrl_(token);
  }
  return buildLifecycleEmailApStatusUrl_(token);
}

function getApAchLifecycleNextStepText_(milestone, recipientClass, fallback) {
  const normalized = normalizeApAchLifecycleEmailMilestone_(milestone);
  const isTeamAlert = trimString_(recipientClass) === 'team';
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.checkout_started) {
    return isTeamAlert
      ? 'Monitor whether Accounts Payable completes ACH checkout.'
      : 'Complete the secure Stripe checkout for this Red Threads invoice.';
  }
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_submitted) {
    return isTeamAlert
      ? 'Monitor ACH verification and bank confirmation before production begins.'
      : 'Watch for any Stripe bank-verification emails and verify if needed. No action is required in the Red Threads portal at this time.';
  }
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_confirmed) {
    return isTeamAlert
      ? 'No AP payment action is required; continue with the production workflow.'
      : 'No payment action is needed.';
  }
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_failed) {
    return isTeamAlert
      ? 'Review the AP ACH payment issue before production continues.'
      : 'Click the button below to return to the Portal/Project and retry payment, or contact Red Threads for assistance.';
  }
  return trimString_(fallback);
}

function shouldRenderApAchLifecycleCta_(milestone, recipientClass) {
  const normalized = normalizeApAchLifecycleEmailMilestone_(milestone);
  if (trimString_(recipientClass) === 'team') return true;
  return normalized !== AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_submitted;
}

function buildApAchLifecycleEmailHistoryLines_(milestone, workflowContext, orderSummary) {
  const normalized = normalizeApAchLifecycleEmailMilestone_(milestone);
  const ctx = (workflowContext && typeof workflowContext === 'object') ? workflowContext : {};
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  let lines = buildLifecycleEmailHistoryLines_(ctx, summary, '', {});
  function addLine(label, value) {
    const dateLabel = buildLifecycleEmailDateLabel_(value);
    if (dateLabel) lines.push(label + ': ' + dateLabel);
  }
  function replaceOrAddPaymentReceivedLine(label, value) {
    const dateLabel = buildLifecycleEmailDateLabel_(value);
    if (!dateLabel) return;
    const nextLine = label + ': ' + dateLabel;
    let replaced = false;
    lines = lines.map(function(line) {
      const clean = trimString_(line);
      if (/^(?:ACH payment received|Payment received):/i.test(clean)) {
        replaced = true;
        return nextLine;
      }
      return line;
    });
    if (!replaced) lines.push(nextLine);
  }
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.checkout_started) {
    addLine('AP checkout started', summary.lastUpdatedAt);
  }
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_submitted) {
    addLine('AP ACH submitted', summary.lastUpdatedAt || summary.lockedAt);
  }
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_confirmed) {
    replaceOrAddPaymentReceivedLine('AP ACH payment received', ctx.paymentReceivedAt || summary.paidAt);
  }
  if (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_failed) {
    addLine('AP ACH issue recorded', summary.stripeLatestEventAt || summary.lastUpdatedAt);
  }
  return uniqueTrimmedStrings_(lines);
}

function buildApAchLifecycleEmailContent_(milestone, orderInfo, invoiceInfo, options) {
  const normalized = normalizeApAchLifecycleEmailMilestone_(milestone);
  const opts = (options && typeof options === 'object') ? options : {};
  const recipientClass = trimString_(opts.recipientClass) === 'team' ? 'team' : 'ap';
  const isTeamAlert = recipientClass === 'team';
  const emailContext = buildLifecycleEmailContextForOrder_(orderInfo, invoiceInfo, Object.assign({}, opts, {
    recipientClass: isTeamAlert ? 'team' : 'client',
    paymentMethodLabel: 'AP ACH',
    ctaLabel: getApAchLifecycleCtaLabel_(normalized, recipientClass),
    isReceipt: isApAchLifecycleReceiptMilestone_(normalized)
  }));
  if (isApAchLifecycleFailureMilestone_(normalized)) {
    applyPaymentBlockedLifecycleEmailContext_(emailContext, {
      paymentBlocked: true,
      nextStepText: getApAchLifecycleNextStepText_(normalized, recipientClass, emailContext.nextStepText)
    });
  }
  const summary = emailContext.orderSummary || {};
  const productionCompleteForReceipt = isLifecycleEmailProductionCompleteForReceipt_(emailContext);
  const copy = buildApAchLifecycleEmailCopy_(normalized, emailContext, {
    isTeamAlert: isTeamAlert
  });
  const token = getApAchLifecycleOrderToken_(orderInfo, summary);
  const ctaUrl = getApAchLifecycleCtaUrl_(token, recipientClass, normalized);
  const teamActionModel = isTeamAlert
    ? resolveLifecycleTeamEmailActionModel_(emailContext, {
      family: 'ap_ach',
      milestone: normalized,
      title: copy.actionTitle,
      intro: copy.intro,
      statusCopy: copy.statusCopy,
      nextStep: copy.nextStep,
      nextStepLabel: copy.nextStepLabel,
      nextStepTone: copy.nextStepTone,
      nextStepHtml: copy.nextStepHtml,
      statusAfterAttachment: copy.actionStatusAfterAttachment === true,
      suppressActionCardCta: copy.suppressActionCardCta === true,
      suppressStandaloneCta: copy.suppressStandaloneCta === true,
      token: token,
      teamAction: isApAchLifecycleFailureMilestone_(normalized)
        ? 'monitor_payment'
        : (normalized === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_confirmed
          ? (productionCompleteForReceipt ? '' : 'move_through_production')
          : '')
    })
    : null;
  const sectionBlocks = buildLifecycleEmailSectionBlocks_(emailContext, {
    family: 'ap_ach',
    milestone: normalized,
    recipientClass: recipientClass === 'team' ? 'team' : 'client',
    sectionPolicy: {
      history: false
    }
  });
  const ctaBlock = teamActionModel && teamActionModel.suppressStandaloneCta
    ? null
    : (shouldRenderApAchLifecycleCta_(normalized, recipientClass)
    ? buildLifecycleEmailCtaBlock_(
      teamActionModel ? teamActionModel.ctaLabel : emailContext.ctaLabel,
      teamActionModel ? teamActionModel.ctaUrl : ctaUrl,
      {
        align: teamActionModel ? teamActionModel.ctaAlign : (isApAchLifecycleFailureMilestone_(normalized) && recipientClass === 'ap' ? 'center' : ''),
        teamModePassword: teamActionModel ? teamActionModel.teamModePassword : ''
      })
    : null);
  const shell = buildLifecycleEmailShell_({
    eyebrow: isTeamAlert ? getPortalNativeEmailEyebrow_('team') : '',
    heading: copy.heading,
    badgeLabel: copy.badgeLabel || getLifecycleEmailCurrentStepLabel_(emailContext.steps),
    actionTitle: teamActionModel ? teamActionModel.title : '',
    intro: teamActionModel ? teamActionModel.intro : copy.intro,
    statusCopy: teamActionModel ? teamActionModel.statusCopy : copy.statusCopy,
    nextStep: teamActionModel ? teamActionModel.nextStep : getApAchLifecycleNextStepText_(normalized, recipientClass, emailContext.nextStepText),
    nextStepHtml: teamActionModel ? teamActionModel.nextStepHtml : copy.nextStepHtml,
    nextStepLabel: teamActionModel ? teamActionModel.nextStepLabel : '',
    nextStepTone: teamActionModel ? teamActionModel.nextStepTone : '',
    actionStatusAfterAttachment: teamActionModel ? teamActionModel.statusAfterAttachment === true : false,
    suppressActionCardCta: teamActionModel ? teamActionModel.suppressActionCardCta : false,
    attachmentNote: copy.attachmentNote,
    blocks: sectionBlocks.concat([
      buildLifecycleEmailHistoryBlock_(buildApAchLifecycleEmailHistoryLines_(normalized, emailContext.workflowContext, emailContext.orderSummary)),
      ctaBlock,
      buildLifecycleEmailFooter_()
    ].filter(Boolean))
  });
  const communicationContract = buildPortalCommunicationContext_({
    emailContext: emailContext
  }, {
    family: 'ap_ach',
    trigger: normalized,
    recipientClass: recipientClass,
    documentLabel: trimString_(emailContext.invoiceNumber),
    cfg: opts.cfg,
    ss: opts.ss,
    infra: opts.infra
  });
  return {
    subject: copy.subject,
    body: shell.body,
    htmlBody: shell.htmlBody,
    reviewSurface: shell.reviewSurface,
    communicationContract: communicationContract
  };
}

function processApAchLifecycleEmailQueueJob_(jobInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const row = jobInfo && jobInfo.rowObjNormalized ? jobInfo.rowObjNormalized : {};
  const meta = safeJsonParse_(row.portalstatejson, {}) || {};
  const milestone = normalizeApAchLifecycleEmailMilestone_(meta.milestone);
  const recipientClass = trimString_(meta.recipientClass) === 'team' ? 'team' : 'ap';
  if (!milestone) throw new Error('AP ACH lifecycle email queue job is missing a milestone.');
  if (isLifecycleEmailSuppressedByPolicy_(
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email,
    milestone,
    recipientClass,
    meta
  )) {
    return { skipped: true, skipReason: COMMUNICATION_POLICY_DISABLED_REASON, invoiceInfo: null };
  }
  const orderInfo = resolveApAchLifecycleOrderForQueueJob_(jobInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra
  });
  if (!orderInfo) throw new Error('AP ACH lifecycle queue order could not be found.');
  const milestonePolicy = resolveCommunicationMilestonePolicy_(
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email,
    milestone,
    orderInfo,
    {
      meta: meta,
      recipientClass: recipientClass
    }
  );
  if (milestonePolicy.enabled === false) {
    return { skipped: true, skipReason: milestonePolicy.reason, invoiceInfo: null };
  }
  if (!shouldQueueApAchLifecycleEmailForOrder_(orderInfo, milestone)) {
    return { skipped: true, skipReason: 'state_not_eligible_for_' + milestone, invoiceInfo: null };
  }
  const recipients = parseAchLifecycleEmailQueueRecipients_(row.recipientsjson);
  if (!recipients.toList.length) throw new Error('AP ACH lifecycle email queue job has no recipients.');
  const queuedInvoiceInfo = {
    invoiceNumber: trimString_(meta.invoiceNumber),
    invoicePdfUrl: trimString_(row.invoicepdfurl),
    fileName: trimString_(row.invoicefilename)
  };
  const invoiceInfo = resolveApAchLifecycleInvoiceInfo_(orderInfo, milestone, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    queuedInvoiceInfo: queuedInvoiceInfo
  });
  const summary = buildPortalOrderSummary_(orderInfo.rowObjNormalized);
  const attachmentPolicy = resolveLifecycleEmailAttachmentPolicy_('ap_ach', milestone, {});
  const attachmentResult = resolveLifecycleEmailAttachment_(Object.assign({}, summary, {
    invoiceNumber: trimString_(invoiceInfo && invoiceInfo.invoiceNumber) || trimString_(summary.invoiceNumber),
    invoicePdfUrl: trimString_(invoiceInfo && invoiceInfo.invoicePdfUrl) || trimString_(summary.invoicePdfUrl)
  }), attachmentPolicy, {
    fileNameOverride: trimString_(invoiceInfo && invoiceInfo.fileName)
  });
  if (attachmentResult.ok !== true) throw new Error(attachmentResult.error || LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice);
  const content = buildApAchLifecycleEmailContent_(milestone, orderInfo, invoiceInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    recipientClass: recipientClass
  });
  const emailResult = sendNotificationEmail_({
    toList: recipients.toList,
    ccList: recipients.ccList,
    subject: content.subject,
    body: content.body,
    htmlBody: content.htmlBody,
    attachments: attachmentResult.attachments,
    fromAlias: NOTIFICATION_FROM_ALIAS,
    replyTo: NOTIFICATION_FROM_ALIAS
  });
  if (!emailResult || emailResult.ok !== true) {
    throw new Error(trimString_(emailResult && emailResult.error) || 'AP ACH lifecycle email could not be sent.');
  }
  const token = getApAchLifecycleOrderToken_(orderInfo, summary);
  logApAchLifecycleEmailQueueEvent_('sent', {
    ok: true,
    milestone: milestone,
    recipientClass: recipientClass,
    token: token,
    orderId: trimString_(summary.orderId),
    paymentIntentId: trimString_(summary.stripePaymentIntentId),
    sessionId: trimString_(summary.stripeSessionId),
    recipientCount: recipients.toList.length,
    ccCount: recipients.ccList.length,
    recipientDomains: summarizeEmailDomainsForLog_(recipients.toList.concat(recipients.ccList)),
    invoicePdfPresent: !!trimString_(invoiceInfo && invoiceInfo.invoicePdfUrl),
    attachmentRequired: isRequiredLifecycleEmailAttachmentPolicy_(attachmentPolicy.policy),
    attachmentPresent: !!(attachmentResult.attachments && attachmentResult.attachments.length),
    status: PORTAL_EMAIL_QUEUE_STATUSES.sent
  });
  return {
    invoiceInfo: invoiceInfo
  };
}

function normalizePortalLifecycleEmailMilestone_(value) {
  const milestone = trimString_(value).toLowerCase();
  return Object.keys(PORTAL_LIFECYCLE_EMAIL_MILESTONES).some(function(key) {
    return PORTAL_LIFECYCLE_EMAIL_MILESTONES[key] === milestone;
  }) ? milestone : '';
}

function isPortalLifecycleEmailJobType_(value) {
  return trimString_(value).toLowerCase() === PORTAL_EMAIL_QUEUE_JOB_TYPES.portal_lifecycle_email;
}

function resolveLifecycleEmailPolicy_(jobType, milestone, recipientClass, meta) {
  const type = trimString_(jobType).toLowerCase();
  const source = (meta && typeof meta === 'object') ? meta : {};
  const requestedMilestone = trimString_(milestone || source.milestone);
  if (isPortalLifecycleEmailJobType_(type)) {
    const normalized = normalizePortalLifecycleEmailMilestone_(requestedMilestone);
    if (COMMUNICATION_POLICY_DISABLED_PORTAL_LIFECYCLE_MILESTONES.indexOf(normalized) >= 0) {
      return {
        enabled: false,
        reason: COMMUNICATION_POLICY_DISABLED_REASON,
        jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.portal_lifecycle_email,
        milestone: normalized,
        recipientClass: getPortalLifecycleEmailRecipientClass_(recipientClass || source.recipientClass)
      };
    }
    return {
      enabled: true,
      reason: '',
      jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.portal_lifecycle_email,
      milestone: normalized,
      recipientClass: getPortalLifecycleEmailRecipientClass_(recipientClass || source.recipientClass)
    };
  }
  if (isApAchLifecycleEmailJobType_(type)) {
    const apMilestone = normalizeApAchLifecycleEmailMilestone_(requestedMilestone);
    const apRecipientClass = trimString_(recipientClass || source.recipientClass) === 'team' ? 'team' : 'ap';
    if (COMMUNICATION_POLICY_DISABLED_AP_ACH_LIFECYCLE_MILESTONES.indexOf(apMilestone) >= 0) {
      return {
        enabled: false,
        reason: COMMUNICATION_POLICY_DISABLED_REASON,
        jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email,
        milestone: apMilestone,
        recipientClass: apRecipientClass
      };
    }
    return {
      enabled: true,
      reason: '',
      jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.ap_ach_lifecycle_email,
      milestone: apMilestone,
      recipientClass: apRecipientClass
    };
  }
  return {
    enabled: true,
    reason: '',
    jobType: type,
    milestone: requestedMilestone,
    recipientClass: trimString_(recipientClass || source.recipientClass)
  };
}

function isLifecycleEmailSuppressedByPolicy_(jobType, milestone, recipientClass, meta) {
  return resolveLifecycleEmailPolicy_(jobType, milestone, recipientClass, meta).enabled === false;
}

function resolvePaymentCommunicationMilestone_(jobType, milestone, orderInfo, options) {
  const type = trimString_(jobType).toLowerCase();
  if (normalizeAchLifecycleEmailJobType_(type)) {
    const baseType = getAchLifecycleBaseEmailJobType_(type);
    if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_invoice_email) return 'standard_ach_submitted';
    if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_confirmed_receipt_email) return 'standard_ach_confirmed';
    if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_action_email) return 'standard_ach_failed';
  }
  if (isApAchLifecycleEmailJobType_(type)) {
    return normalizeApAchLifecycleEmailMilestone_(milestone);
  }
  if (isPaymentLifecycleEmailJobType_(type)) {
    return normalizePaymentLifecycleEmailMilestone_(milestone);
  }
  const opts = (options && typeof options === 'object') ? options : {};
  const meta = opts.meta && typeof opts.meta === 'object' ? opts.meta : {};
  return trimString_(milestone || meta.milestone);
}

function isCommunicationPaymentPaid_(orderSummary) {
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const paymentState = trimString_(summary.paymentState).toLowerCase();
  return paymentState === PAYMENT_STATES.paid ||
    paymentState === PAYMENT_STATES.manual_received ||
    !!trimString_(summary.paidAt);
}

function isCommunicationPaymentFailureActionState_(orderSummary) {
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const paymentState = trimString_(summary.paymentState).toLowerCase();
  const eventType = trimString_(summary.stripeLatestEventType).toLowerCase();
  const failureSignal = [
    summary.achFailureCode,
    summary.achFailureMessage,
    eventType
  ].join(' ').toLowerCase();
  return paymentState === PAYMENT_STATES.failed ||
    eventType === 'charge.dispute.created' ||
    failureSignal.indexOf('dispute') >= 0 ||
    failureSignal.indexOf('mandate') >= 0 ||
    failureSignal.indexOf('blocked') >= 0;
}

function buildCommunicationMilestonePolicyResult_(enabled, jobType, milestone, recipientClass, detail) {
  return {
    enabled: enabled !== false,
    reason: enabled === false ? COMMUNICATION_MILESTONE_SUPERSEDED_REASON : '',
    jobType: trimString_(jobType).toLowerCase(),
    milestone: trimString_(milestone),
    recipientClass: trimString_(recipientClass),
    detail: trimString_(detail)
  };
}

function resolveCommunicationMilestonePolicy_(jobType, milestone, orderInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const meta = opts.meta && typeof opts.meta === 'object' ? opts.meta : {};
  const type = trimString_(jobType).toLowerCase();
  const recipientClass = trimString_(opts.recipientClass || meta.recipientClass);
  const resolvedMilestone = resolvePaymentCommunicationMilestone_(type, milestone, orderInfo, opts);
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = buildPortalOrderSummary_(row);
  const method = trimString_(summary.paymentMethodSelected).toLowerCase();
  const rawAchSource = trimString_(
    summary.achPaymentSource ||
    meta.achPaymentSource ||
    meta.paymentOrigin ||
    opts.achPaymentSource ||
    opts.paymentOrigin
  );
  const achSource = normalizeAchPaymentSource_(rawAchSource);
  const paid = isCommunicationPaymentPaid_(summary);
  const failureAction = isCommunicationPaymentFailureActionState_(summary);
  const allow = function() {
    return buildCommunicationMilestonePolicyResult_(true, type, resolvedMilestone, recipientClass, '');
  };
  const suppress = function(detail) {
    return buildCommunicationMilestonePolicyResult_(false, type, resolvedMilestone, recipientClass, detail);
  };

  if (normalizeAchLifecycleEmailJobType_(type)) {
    const baseType = getAchLifecycleBaseEmailJobType_(type);
    if (method && method !== PAYMENT_METHODS.ach) return suppress('standard_ach_competing_payment_method');
    if (achSource === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link) return suppress('standard_ach_ap_lane');
    if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_submitted_invoice_email && (paid || failureAction)) {
      return suppress('standard_ach_pending_terminal');
    }
    if (baseType === PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_payment_failed_action_email && paid && !failureAction) {
      return suppress('standard_ach_failure_already_paid');
    }
    return allow();
  }

  if (isApAchLifecycleEmailJobType_(type)) {
    const apMilestone = normalizeApAchLifecycleEmailMilestone_(milestone || meta.milestone);
    if (method && method !== PAYMENT_METHODS.ach) return suppress('ap_ach_competing_payment_method');
    if (achSource !== ACH_PAYMENT_METHOD_SOURCES.ap_payment_link) return suppress('ap_ach_standard_lane');
    if ((apMilestone === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.checkout_started ||
         apMilestone === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_submitted) &&
        (paid || failureAction)) {
      return suppress('ap_ach_pending_terminal');
    }
    if (apMilestone === AP_ACH_LIFECYCLE_EMAIL_MILESTONES.payment_failed && paid && !failureAction) {
      return suppress('ap_ach_failure_already_paid');
    }
    return allow();
  }

  if (isPaymentLifecycleEmailJobType_(type)) {
    const paymentMilestone = normalizePaymentLifecycleEmailMilestone_(milestone || meta.milestone);
    const manualMethod = method === PAYMENT_METHODS.check || method === PAYMENT_METHODS.cash;
    if (method === PAYMENT_METHODS.ach) return suppress('payment_lifecycle_ach_lane');
    if (paymentMilestone === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.card_paid &&
        method && method !== PAYMENT_METHODS.card) {
      return suppress('card_paid_competing_payment_method');
    }
    if (paymentMilestone === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.card_failed) {
      if (paid) return suppress('card_failed_already_paid');
      if (method && method !== PAYMENT_METHODS.card) return suppress('card_failed_competing_payment_method');
    }
    if (paymentMilestone === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.manual_pending) {
      if (paid || failureAction) return suppress('manual_pending_terminal');
      if (method && !manualMethod) return suppress('manual_pending_competing_payment_method');
    }
    if (paymentMilestone === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.manual_received &&
        method && !manualMethod) {
      return suppress('manual_received_competing_payment_method');
    }
    if (isScheduledPoPaymentReminderMilestone_(paymentMilestone)) {
      if (paid || failureAction) return suppress('po_payment_reminder_terminal');
      if (method && method !== PAYMENT_METHODS.purchase_order) return suppress('po_payment_reminder_competing_payment_method');
      if (!trimString_(summary.poSubmittedAt)) return suppress('po_payment_reminder_missing_po_submission');
      return allow();
    }
    if (paymentMilestone === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_submitted) {
      if (paid || failureAction) return suppress('po_submitted_terminal');
      if (method && method !== PAYMENT_METHODS.purchase_order) return suppress('po_submitted_competing_payment_method');
    }
    if (paymentMilestone === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_received &&
        method && method !== PAYMENT_METHODS.purchase_order) {
      return suppress('po_payment_received_competing_payment_method');
    }
    return allow();
  }

  return allow();
}

function isPortalLifecycleAccountDocumentMilestone_(milestone) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  return normalized.indexOf('tax_exempt_') === 0 || normalized.indexOf('credit_terms_') === 0;
}

function isPortalLifecycleAccountOnlyMilestone_(milestone) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  return normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_removed ||
    normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_removed;
}

function getPortalLifecycleEmailRecipientClass_(value) {
  const recipientClass = trimString_(value).toLowerCase();
  return recipientClass === 'team' ? 'team' : 'client';
}

function buildPortalLifecycleSyntheticOrderInfoFromRow_(rowInfo, accountSummary, options) {
  const row = rowInfo && rowInfo.rowObjNormalized ? rowInfo.rowObjNormalized : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const snapshot = safeJsonParse_(row.snapshotjson, {}) || {};
  const portalState = safeJsonParse_(row.portalstatejson, {}) || {};
  const orderDraft = buildOrderDraftFromSnapshotAndPortalState_({
    token: trimString_(row.token),
    rowInfo: rowInfo,
    row: row,
    snapshot: snapshot,
    portalState: portalState,
    accountSummary: accountSummary || null,
    currency: cfg.stripePriceCurrency
  });
  const syntheticRow = {
    token: trimString_(row.token),
    orderdraftjson: JSON.stringify(orderDraft),
    portallockstate: trimString_(row.currentportallockstate || row.portallockstate || orderDraft.portalLockState),
    orderstate: trimString_(row.currentorderstate || orderDraft.orderState),
    paymentmethodselected: trimString_(row.currentpaymentmethod || orderDraft.paymentMethodSelected),
    paymentstate: trimString_(row.currentpaymentstate || orderDraft.paymentState),
    productionauthorizationstate: trimString_(row.currentproductionauthorizationstate || orderDraft.productionAuthorizationState),
    invoicenumber: trimString_(row.latestinvoicenumber || row.invoicenumber),
    invoicepdfurl: trimString_(row.latestinvoicepdfurl || row.invoicepdfurl),
    amountgrandtotal: orderDraft.amountGrandTotal,
    amounttax: orderDraft.amountTax,
    amountcardfee: orderDraft.amountCardFee,
    currency: trimString_(orderDraft.currency || cfg.stripePriceCurrency || DEFAULT_STRIPE_PRICE_CURRENCY),
    paidat: trimString_(row.paidat),
    authorizedtoproduceat: trimString_(row.authorizedtoproduceat),
    lockedat: trimString_(row.lockedat),
    createdat: trimString_(row.exportedat || row.createdat) || nowIso_(),
    lastupdatedat: trimString_(row.lastorderupdatedat || row.updatedat || row.exportedat)
  };
  return {
    row: rowInfo && rowInfo.row ? rowInfo.row : 0,
    colMap: rowInfo && rowInfo.colMap ? rowInfo.colMap : {},
    rowObjNormalized: syntheticRow
  };
}

function resolvePortalLifecycleEmailContext_(source, options) {
  const src = (source && typeof source === 'object') ? source : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const sourceCtx = src.ctx && typeof src.ctx === 'object' ? src.ctx : {};
  const cfg = opts.cfg || src.cfg || sourceCtx.cfg || getConfig_();
  const ss = opts.ss || src.ss || sourceCtx.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || src.infra || sourceCtx.infra || ensurePortalInfrastructure_(ss, cfg);
  let orderInfo = opts.orderInfo || src.orderInfo || sourceCtx.latestOrderInfo || null;
  const orderSummary = orderInfo ? buildPortalOrderSummary_(orderInfo.rowObjNormalized) : null;
  const orderRow = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const token = trimString_(
    opts.token ||
    src.token ||
    sourceCtx.token ||
    (sourceCtx.orderDraft && sourceCtx.orderDraft.token) ||
    (sourceCtx.exportRowInfo && sourceCtx.exportRowInfo.rowObjNormalized && sourceCtx.exportRowInfo.rowObjNormalized.token) ||
    (sourceCtx.rowInfo && sourceCtx.rowInfo.rowObjNormalized && sourceCtx.rowInfo.rowObjNormalized.token) ||
    orderRow.token ||
    orderRow.Token
  );
  let rowInfo = opts.rowInfo || src.rowInfo || sourceCtx.rowInfo || sourceCtx.exportRowInfo || null;
  if (!rowInfo && token && infra && infra.exportSheet) rowInfo = findRowByToken_(infra.exportSheet, token);
  if (!orderInfo && token) {
    orderInfo = getLatestPortalOrderByToken_(token, {
      cfg: cfg,
      ss: ss,
      ordersSheet: infra.ordersSheet
    });
  }
  let accountInfo = opts.accountInfo || src.accountInfo || sourceCtx.accountInfo || null;
  const accountAccessToken = trimString_(
    opts.accountAccessToken ||
    src.accountAccessToken ||
    sourceCtx.accountAccessToken
  );
  const accountId = trimString_(
    opts.accountId ||
    src.accountId ||
    sourceCtx.accountId
  );
  if (!accountInfo && accountAccessToken) {
    try {
      accountInfo = getPortalAccountByAccessToken_(accountAccessToken, {
        cfg: cfg,
        ss: ss,
        infra: infra
      });
    } catch (_) {
      accountInfo = null;
    }
  }
  if (!accountInfo && accountId) {
    try {
      accountInfo = getPortalAccountByAccountId_(accountId, {
        cfg: cfg,
        ss: ss,
        infra: infra
      });
    } catch (_) {
      accountInfo = null;
    }
  }
  if (!accountInfo && orderInfo) {
    try {
      accountInfo = getPortalAccountInfoForOrder_(orderInfo, {
        cfg: cfg,
        ss: ss,
        infra: infra
      });
    } catch (_) {
      accountInfo = null;
    }
  }
  if (!orderInfo && rowInfo) {
    orderInfo = buildPortalLifecycleSyntheticOrderInfoFromRow_(
      rowInfo,
      accountInfo && accountInfo.summary ? accountInfo.summary : null,
      { cfg: cfg }
    );
  }
  return {
    cfg: cfg,
    ss: ss,
    infra: infra,
    token: token,
    rowInfo: rowInfo,
    orderInfo: orderInfo,
    accountInfo: accountInfo
  };
}

function buildPortalLifecycleEmailTeamRecipients_() {
  return {
    toList: normalizeEmailRecipients_([DOCUMENT_REVIEW_EMAIL]),
    ccList: [],
    recipientClass: 'team'
  };
}

function isPortalLifecycleReadyToOrderForEmail_(rowInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  if (!rowInfo) return false;
  try {
    const cfg = opts.cfg || getConfig_();
    const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
    const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
    const projection = buildDashboardProjectProjectionContext_(rowInfo, {
      cfg: cfg,
      ss: ss,
      infra: infra,
      includeLatestOrderSummary: true
    });
    return trimString_(projection && projection.workflowContext && projection.workflowContext.nextClientAction).toLowerCase() === 'place_order';
  } catch (_) {
    return false;
  }
}

function buildPortalLifecycleEmailClientRecipients_(ctx, meta) {
  const row = ctx && ctx.rowInfo && ctx.rowInfo.rowObjNormalized ? ctx.rowInfo.rowObjNormalized : {};
  const orderRow = ctx && ctx.orderInfo && ctx.orderInfo.rowObjNormalized ? ctx.orderInfo.rowObjNormalized : {};
  const draft = safeJsonParse_(orderRow.orderdraftjson || orderRow.orderDraftJson, {}) || {};
  const account = ctx && ctx.accountInfo && ctx.accountInfo.summary ? ctx.accountInfo.summary : {};
  const payload = (meta && typeof meta === 'object') ? meta : {};
  const primaryEmail = firstNormalizedEmailFromValues_([
    payload.clientEmail,
    payload.submittedByEmail,
    orderRow.personemail,
    orderRow.personEmail,
    draft.personEmail,
    row.personemail,
    row[EXPORT_LOG_PERSON_EMAIL_HEADER],
    account.primaryEmail,
    account.billingContactEmail
  ]);
  return {
    toList: normalizeEmailRecipients_(primaryEmail ? [primaryEmail] : []),
    ccList: [],
    primaryEmail: primaryEmail,
    recipientClass: 'client'
  };
}

function buildPortalLifecycleEmailIdempotencyKey_(milestone, recipientClass, ctx, recipients, meta) {
  const safeCtx = (ctx && typeof ctx === 'object') ? ctx : {};
  const orderSummary = safeCtx.orderInfo ? buildPortalOrderSummary_(safeCtx.orderInfo.rowObjNormalized) : {};
  const accountSummary = safeCtx.accountInfo && safeCtx.accountInfo.summary ? safeCtx.accountInfo.summary : {};
  const safeRecipients = (recipients && typeof recipients === 'object') ? recipients : {};
  const safeMeta = (meta && typeof meta === 'object') ? meta : {};
  return buildPortalEmailQueueIdempotencyKeyForSource_({
    jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.portal_lifecycle_email,
    milestone: normalizePortalLifecycleEmailMilestone_(milestone),
    recipientClass: getPortalLifecycleEmailRecipientClass_(recipientClass),
    token: trimString_(safeCtx.token),
    orderId: trimString_(orderSummary.orderId),
    accountId: trimString_(safeMeta.accountId || accountSummary.accountId),
    accountOrgId: trimString_(safeMeta.accountOrgId || accountSummary.orgId),
    accountEmail: normalizeEmail_(safeMeta.clientEmail || accountSummary.billingContactEmail || accountSummary.primaryEmail),
    eventKey: trimString_(safeMeta.eventKey),
    printJobIndex: trimString_(safeMeta.printJobIndex),
    documentType: trimString_(safeMeta.documentType),
    decision: trimString_(safeMeta.decision),
    flowKind: trimString_(safeMeta.flowKind),
    toList: normalizeEmailRecipients_(safeRecipients.toList),
    ccList: normalizeEmailRecipients_(safeRecipients.ccList)
  });
}

function logPortalLifecycleEmailQueueEvent_(eventName, payload) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  const safe = {
    event: trimString_(eventName),
    ok: p.ok === true,
    reason: trimString_(p.reason),
    jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.portal_lifecycle_email,
    milestone: trimString_(p.milestone),
    recipientClass: trimString_(p.recipientClass),
    tokenPresent: !!trimString_(p.token),
    orderId: trimString_(p.orderId),
    recipientCount: Math.max(0, parseInt(String(p.recipientCount || 0), 10) || 0),
    ccCount: Math.max(0, parseInt(String(p.ccCount || 0), 10) || 0),
    recipientDomains: Array.isArray(p.recipientDomains) ? p.recipientDomains : [],
    attachmentCount: Math.max(0, parseInt(String(p.attachmentCount || 0), 10) || 0),
    attachmentRequired: p.attachmentRequired === true,
    status: trimString_(p.status),
    error: trimString_(p.error)
  };
  console.log('[RT-PORTAL-LIFECYCLE-EMAIL-QUEUE] ' + JSON.stringify(safe));
}

function queuePortalLifecycleClientAndTeamEmailsSafely_(source, milestone, options) {
  return {
    clientJob: queuePortalLifecycleEmailJobSafely_(source, milestone, Object.assign({}, options || {}, {
      recipientClass: 'client'
    })),
    teamJob: queuePortalLifecycleEmailJobSafely_(source, milestone, Object.assign({}, options || {}, {
      recipientClass: 'team'
    }))
  };
}

function queuePortalLifecycleEmailJobSafely_(source, milestone, options) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  if (!normalized) return null;
  const opts = (options && typeof options === 'object') ? options : {};
  const recipientClass = getPortalLifecycleEmailRecipientClass_(opts.recipientClass);
  let meta = Object.assign({}, (opts.meta && typeof opts.meta === 'object') ? opts.meta : {}, {
    milestone: normalized,
    recipientClass: recipientClass
  });
  try {
    const ctx = resolvePortalLifecycleEmailContext_(source, opts);
    const orderSummary = ctx.orderInfo ? buildPortalOrderSummary_(ctx.orderInfo.rowObjNormalized) : {};
    const accountSummary = ctx.accountInfo && ctx.accountInfo.summary ? ctx.accountInfo.summary : {};
    if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.project_completed &&
        recipientClass === 'client') {
      meta = mergePortalLifecycleAttachmentMeta_(
        meta,
        buildPortalLifecycleInvoiceReceiptAttachmentMeta_(ctx.orderInfo)
      );
    }
    const emailPolicy = resolveLifecycleEmailPolicy_(
      PORTAL_EMAIL_QUEUE_JOB_TYPES.portal_lifecycle_email,
      normalized,
      recipientClass,
      meta
    );
    if (emailPolicy.enabled === false) {
      logPortalLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: emailPolicy.reason,
        milestone: normalized,
        recipientClass: recipientClass,
        token: ctx.token,
        orderId: trimString_(orderSummary.orderId),
        attachmentCount: Array.isArray(meta.attachmentFileIds) ? meta.attachmentFileIds.length : 0,
        attachmentRequired: meta.attachmentRequired === true
      });
      return null;
    }
    const recipients = recipientClass === 'team'
      ? buildPortalLifecycleEmailTeamRecipients_()
      : buildPortalLifecycleEmailClientRecipients_(ctx, meta);
    const hasAccountOnlyContext = isPortalLifecycleAccountOnlyMilestone_(normalized) &&
      hasPortalAccountDashboardIdentity_(accountSummary);
    if (!ctx.token && !trimString_(orderSummary.orderId) && !hasAccountOnlyContext) {
      logPortalLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: 'missing_context',
        milestone: normalized,
        recipientClass: recipientClass
      });
      return null;
    }
    if (!recipients.toList.length) {
      logPortalLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: 'missing_recipients',
        milestone: normalized,
        recipientClass: recipientClass,
        token: ctx.token,
        orderId: trimString_(orderSummary.orderId)
      });
      return null;
    }
    const queueSheet = getPortalEmailQueueSheet_(ctx.ss);
    const idempotencyKey = buildPortalLifecycleEmailIdempotencyKey_(normalized, recipientClass, ctx, recipients, meta);
    const jobInfo = upsertPortalEmailQueueJob_(queueSheet, {
      jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.portal_lifecycle_email,
      idempotencyKey: idempotencyKey,
      token: ctx.token,
      recipientsJson: JSON.stringify(recipients),
      portalStateJson: JSON.stringify(Object.assign({}, meta, {
        jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.portal_lifecycle_email,
        token: ctx.token,
        accountId: trimString_(meta.accountId || accountSummary.accountId),
        accountOrgId: trimString_(meta.accountOrgId || accountSummary.orgId),
        accountOrgName: trimString_(meta.accountOrgName || accountSummary.orgName),
        orderId: trimString_(orderSummary.orderId),
        queuedFromEventType: trimString_(opts.eventType),
        queuedAt: nowIso_()
      })),
      orderDraftJson: trimString_(ctx.orderInfo && ctx.orderInfo.rowObjNormalized && ctx.orderInfo.rowObjNormalized.orderdraftjson),
      invoicePdfUrl: trimString_(orderSummary.invoicePdfUrl),
      invoiceFileName: ''
    });
    logPortalLifecycleEmailQueueEvent_('queued', {
      ok: true,
      milestone: normalized,
      recipientClass: recipientClass,
      token: ctx.token,
      orderId: trimString_(orderSummary.orderId),
      recipientCount: recipients.toList.length,
      ccCount: recipients.ccList.length,
      recipientDomains: summarizeEmailDomainsForLog_(recipients.toList.concat(recipients.ccList)),
      attachmentCount: Array.isArray(meta.attachmentFileIds) ? meta.attachmentFileIds.length : 0,
      attachmentRequired: meta.attachmentRequired === true,
      status: trimString_(jobInfo && jobInfo.rowObjNormalized && jobInfo.rowObjNormalized.status)
    });
    let finalJobInfo = jobInfo;
    if (isPortalEmailQueueJobEligible_(jobInfo, new Date())) {
      finalJobInfo = tryProcessPortalEmailQueueJobById_(trimString_(jobInfo && jobInfo.rowObjNormalized && jobInfo.rowObjNormalized.jobid), {
        cfg: ctx.cfg,
        ss: ctx.ss,
        infra: ctx.infra,
        queueSheet: queueSheet,
        token: ctx.token
      }) || jobInfo;
      if (isPortalEmailQueueJobEligible_(finalJobInfo, new Date())) schedulePortalEmailQueueProcessor_();
    }
    return finalJobInfo;
  } catch (err) {
    logPortalLifecycleEmailQueueEvent_('error', {
      ok: false,
      milestone: normalized,
      recipientClass: recipientClass,
      error: String((err && err.message) || err)
    });
    return null;
  }
}

function getAccountDocumentPortalLifecycleMilestone_(documentType, eventName, options) {
  const type = trimString_(documentType);
  const event = trimString_(eventName).toLowerCase();
  const hardDenied = options && options.hardDenied === true;
  if (type === ACCOUNT_DOCUMENT_TYPES.tax_exempt) {
    if (event === 'submitted') return PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_submitted;
    if (event === 'approved') return PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_approved;
    if (event === 'denied') return PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_denied;
    if (event === 'removed') return PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_removed;
    if (event === 'reset') return PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_reset;
  }
  if (type === ACCOUNT_DOCUMENT_TYPES.credit_terms) {
    if (event === 'submitted') return PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_submitted;
    if (event === 'approved') return PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_approved;
    if (event === 'denied' || hardDenied) return PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_denied;
    if (event === 'removed') return PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_removed;
    if (event === 'reset') return PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_reset;
  }
  return '';
}

function buildAccountDocumentLifecycleAttachmentMeta_(submissionEntry) {
  const attachmentFileIds = [];
  const attachmentFileNames = {};
  getAccountDocumentSubmissionArtifactFiles_(submissionEntry).forEach(function(item) {
    const fileId = trimString_(item && item.fileId);
    if (!fileId) return;
    attachmentFileIds.push(fileId);
    attachmentFileNames[fileId] = trimString_(item && item.fileName);
  });
  return {
    attachmentFileIds: uniqueTrimmedStrings_(attachmentFileIds),
    attachmentFileNames: attachmentFileNames
  };
}

function buildAccountDocumentLifecycleMeta_(ctx, definition, submissionEntry, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const accountSummary = ctx && ctx.accountInfo && ctx.accountInfo.summary ? ctx.accountInfo.summary : {};
  const decision = trimString_(opts.decision);
  const attachmentMeta = buildAccountDocumentLifecycleAttachmentMeta_(submissionEntry);
  const submittedAt = trimString_(submissionEntry && submissionEntry.submittedAt);
  const decidedAt = trimString_(opts.decidedAt);
  const eventKey = trimString_(opts.eventKey) || [
    trimString_(definition && definition.type),
    trimString_(opts.eventName),
    submittedAt,
    decidedAt,
    decision
  ].filter(Boolean).join('_');
  return Object.assign({}, attachmentMeta, {
    eventKey: eventKey,
    accountId: trimString_(accountSummary.accountId),
    accountOrgId: trimString_(accountSummary.orgId),
    accountOrgName: trimString_(accountSummary.orgName),
    documentType: trimString_(definition && definition.type),
    documentLabel: trimString_(definition && definition.label || definition && definition.shortLabel),
    submittedByEmail: normalizeEmail_(submissionEntry && submissionEntry.submittedByEmail),
    submittedByName: trimString_(submissionEntry && submissionEntry.submittedByName),
    clientEmail: firstNormalizedEmailFromValues_([
      submissionEntry && submissionEntry.submittedByEmail,
      accountSummary.billingContactEmail,
      accountSummary.primaryEmail,
      ctx && ctx.identity && ctx.identity.personEmail
    ]),
    submissionSource: trimString_(submissionEntry && submissionEntry.submissionSource),
    decision: decision,
    reason: trimString_(opts.reason),
    hardDenied: opts.hardDenied === true ? 'true' : '',
    paymentTermsLabel: trimString_(opts.paymentTermsLabel),
    clearedAt: trimString_(opts.clearedAt),
    clearedByName: trimString_(opts.clearedByName),
    clearedByEmail: normalizeEmail_(opts.clearedByEmail),
    previousStatus: trimString_(opts.previousStatus),
    previousSubmittedAt: trimString_(opts.previousSubmittedAt),
    previousExpiresAt: trimString_(opts.previousExpiresAt),
    attachmentRequired: opts.attachmentRequired === true
  });
}

function queueAccountDocumentLifecycleEmailSafely_(ctx, definition, submissionEntry, eventName, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const milestone = getAccountDocumentPortalLifecycleMilestone_(
    definition && definition.type,
    eventName,
    opts
  );
  if (!milestone) return null;
  const token = resolveAccountDocumentPortalToken_(ctx);
  const rowInfo = (ctx && ctx.exportRowInfo) || (token ? findRowByToken_(ctx.infra.exportSheet, token) : null);
  const meta = buildAccountDocumentLifecycleMeta_(ctx, definition, submissionEntry, Object.assign({}, opts, {
    eventName: eventName
  }));
  const source = {
    ctx: ctx,
    token: token,
    rowInfo: rowInfo,
    accountInfo: ctx && ctx.accountInfo
  };
  if (trimString_(eventName).toLowerCase() === 'submitted') {
    const teamMeta = Object.assign({}, meta, {
      attachmentRequired: true
    });
    const clientMeta = Object.assign({}, meta, {
      attachmentFileIds: [],
      attachmentFileNames: {},
      attachmentRequired: false
    });
    return {
      clientJob: queuePortalLifecycleEmailJobSafely_(source, milestone, {
        recipientClass: 'client',
        eventType: 'account_document_submitted',
        meta: clientMeta
      }),
      teamJob: queuePortalLifecycleEmailJobSafely_(source, milestone, {
        recipientClass: 'team',
        eventType: 'account_document_submitted',
        meta: teamMeta
      })
    };
  }
  return queuePortalLifecycleClientAndTeamEmailsSafely_(source, milestone, {
    eventType: 'account_document_' + trimString_(eventName).toLowerCase(),
    meta: meta
  });
}

function resolvePortalLifecycleOrderForQueueJob_(jobInfo, options) {
  const row = jobInfo && jobInfo.rowObjNormalized ? jobInfo.rowObjNormalized : {};
  const meta = safeJsonParse_(row.portalstatejson, {}) || {};
  const ctx = resolvePortalLifecycleEmailContext_({
    token: trimString_(row.token || meta.token)
  }, options);
  return ctx.orderInfo;
}

function getPortalLifecycleEmailCta_(milestone, recipientClass, ctx, meta) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  const isTeam = getPortalLifecycleEmailRecipientClass_(recipientClass) === 'team';
  const token = trimString_(ctx && ctx.token);
  const documentType = trimString_(meta && meta.documentType);
  if (isTeam) {
    if (documentType) {
      return {
        label: 'Open team review',
        url: buildAccountDocumentTeamReviewUrl_(documentType, token, ctx && ctx.cfg)
      };
    }
    return {
      label: 'Open Team Mode',
      url: buildTeamSnapshotPortalUrl_(token)
    };
  }
  if (isPortalLifecycleAccountDocumentMilestone_(normalized)) {
    const accountDocUrl = buildPortalLifecycleAccountDocumentClientUrl_(ctx, meta, normalized);
    if (!accountDocUrl) return { label: '', url: '' };
    return {
      label: getPortalLifecycleAccountDocumentCtaLabel_(normalized, meta),
      url: accountDocUrl
    };
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.project_ready_to_order) {
    return { label: 'Open project and place order', url: buildExternalPortalUrl_(token) };
  }
  return {
    label: isPortalLifecycleAccountDocumentMilestone_(normalized) ? 'Open Red Threads portal' : 'View project status',
    url: buildPortalSummaryUrl_(token)
  };
}

function buildPortalLifecycleInvoiceReceiptAttachmentMeta_(orderInfo) {
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = buildPortalOrderSummary_(row);
  const invoicePdfUrl = trimString_(summary.invoicePdfUrl || row.invoicepdfurl || row.invoicePdfUrl);
  const fileId = trimString_(row.invoicefileid || row.invoiceFileId) || extractDriveFileIdFromUrl_(invoicePdfUrl);
  if (!fileId) return {};
  const fileName = trimString_(row.invoicefilename || row.invoiceFileName || summary.invoiceFileName || summary.fileName);
  try {
    const result = buildLifecycleEmailAttachmentSafe_({
      invoicePdfUrl: invoicePdfUrl,
      invoiceFileId: fileId,
      fileName: fileName
    }, fileName, {
      requirePortalRenderedInvoice: true
    });
    if (!result || result.ok !== true) return {};
    const attachmentFileNames = {};
    attachmentFileNames[fileId] = trimString_(result.fileName || fileName);
    return {
      attachmentFileIds: [fileId],
      attachmentFileNames: attachmentFileNames,
      invoiceReceiptAttached: true
    };
  } catch (_) {
    return {};
  }
}

function mergePortalLifecycleAttachmentMeta_(baseMeta, attachmentMeta) {
  const base = (baseMeta && typeof baseMeta === 'object') ? baseMeta : {};
  const extra = (attachmentMeta && typeof attachmentMeta === 'object') ? attachmentMeta : {};
  const fileIds = uniqueTrimmedStrings_([].concat(
    Array.isArray(base.attachmentFileIds) ? base.attachmentFileIds : [],
    Array.isArray(extra.attachmentFileIds) ? extra.attachmentFileIds : []
  ));
  if (!fileIds.length) return Object.assign({}, base);
  const fileNames = Object.assign({},
    (base.attachmentFileNames && typeof base.attachmentFileNames === 'object') ? base.attachmentFileNames : {},
    (extra.attachmentFileNames && typeof extra.attachmentFileNames === 'object') ? extra.attachmentFileNames : {}
  );
  return Object.assign({}, base, {
    attachmentFileIds: fileIds,
    attachmentFileNames: fileNames,
    invoiceReceiptAttached: base.invoiceReceiptAttached === true || extra.invoiceReceiptAttached === true
  });
}

function getAccountDocumentEmailLabels_(meta) {
  const source = (meta && typeof meta === 'object') ? meta : {};
  const type = trimString_(source.documentType).toLowerCase();
  if (type === ACCOUNT_DOCUMENT_TYPES.credit_terms) {
    return {
      title: 'Credit terms',
      noun: 'credit terms',
      submission: 'credit terms application',
      dashboardParam: 'credit_terms'
    };
  }
  if (type === ACCOUNT_DOCUMENT_TYPES.tax_exempt) {
    return {
      title: 'Tax exemption',
      noun: 'tax exemption',
      submission: 'tax exemption form',
      dashboardParam: 'tax_exempt'
    };
  }
  const label = trimString_(source.documentLabel) || 'Account document';
  return {
    title: label,
    noun: label.charAt(0).toLowerCase() + label.slice(1),
    submission: label,
    dashboardParam: ''
  };
}

function getPortalLifecycleAccountDocumentCtaLabel_(milestone, meta) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  const labels = getAccountDocumentEmailLabels_(meta);
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_approved ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_approved) {
    return 'Open Red Threads Portal Account Dashboard';
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_reset) {
    return 'Complete New Credit Terms Application';
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_removed) {
    return 'Upload New Credit Terms Document';
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_reset) {
    return 'Complete Sales Tax Exemption Form';
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_removed) {
    return 'Upload New Sales Tax Exemption Document';
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_denied) {
    return 'Resubmit Credit Terms Document';
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_denied) {
    return 'Resubmit Sales Tax Exemption Form';
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_denied ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_reset ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_denied ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_reset) {
    return 'Update ' + labels.noun;
  }
  return 'Open account dashboard';
}

function buildPortalLifecycleAccountDocumentClientUrl_(ctx, meta, milestone) {
  const context = (ctx && typeof ctx === 'object') ? ctx : {};
  const accountSummary = context.accountInfo && context.accountInfo.summary ? context.accountInfo.summary : {};
  if (!hasPortalAccountDashboardIdentity_(accountSummary)) return '';
  const dashboardUrl = buildExternalPortalDashboardUrl_(accountSummary, {
    cfg: context.cfg
  });
  if (!dashboardUrl) return '';
  const labels = getAccountDocumentEmailLabels_(meta);
  const params = {};
  if (labels.dashboardParam) params.accountDoc = labels.dashboardParam;
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_denied ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_removed ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_reset ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_denied ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_removed ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_reset) {
    params.accountDocAction = 'resubmit';
  }
  return Object.keys(params).length ? appendQueryParamsToUrl_(dashboardUrl, params) : dashboardUrl;
}

function buildPortalLifecycleEmailDetailBlock_(lines) {
  const cleanLines = uniqueTrimmedStrings_(lines);
  if (!cleanLines.length) return { text: '', html: '' };
  const htmlRows = cleanLines.map(function(line) {
    return '<div style="margin:0 0 6px;color:#cbd5e1;">' + escapeHtml_(line) + '</div>';
  }).join('');
  return {
    kind: 'account_details',
    text: buildLifecycleEmailTextBlock_('Details', cleanLines),
    html: [
      '<div style="margin:0 0 18px;padding:14px 16px;border:1px solid #1e293b;border-radius:12px;background:#0f172a;">',
      '<div style="font-size:12px;text-transform:uppercase;color:#55dfff;font-weight:800;margin:0 0 8px;letter-spacing:.08em;">Details</div>',
      htmlRows,
      '</div>'
    ].join('')
  };
}

function isAccountDocumentApprovedTeamMilestone_(milestone, recipientClass) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  return getPortalLifecycleEmailRecipientClass_(recipientClass) === 'team' &&
    (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_approved ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_approved);
}

function isCreditTermsSubmittedTeamMilestone_(milestone, recipientClass) {
  return getPortalLifecycleEmailRecipientClass_(recipientClass) === 'team' &&
    normalizePortalLifecycleEmailMilestone_(milestone) === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_submitted;
}

function isTaxExemptSubmittedTeamMilestone_(milestone, recipientClass) {
  return getPortalLifecycleEmailRecipientClass_(recipientClass) === 'team' &&
    normalizePortalLifecycleEmailMilestone_(milestone) === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_submitted;
}

function isAccountDocumentSubmittedTeamReviewMilestone_(milestone, recipientClass) {
  return isCreditTermsSubmittedTeamMilestone_(milestone, recipientClass) ||
    isTaxExemptSubmittedTeamMilestone_(milestone, recipientClass);
}

function buildAccountDocumentTeamIdentityDetails_(meta, emailContext) {
  const source = (meta && typeof meta === 'object') ? meta : {};
  const ctx = (emailContext && typeof emailContext === 'object') ? emailContext : {};
  const account = (ctx.accountSummary && typeof ctx.accountSummary === 'object') ? ctx.accountSummary : {};
  const clientName = trimString_(
    source.clientName ||
    source.submittedByName ||
    account.billingContactName ||
    account.primaryContactName
  );
  const organizationName = trimString_(source.organizationName || source.orgName || account.orgName);
  const clientEmail = firstNormalizedEmailFromValues_([
    source.clientEmail,
    source.submittedByEmail,
    account.billingContactEmail,
    account.primaryEmail
  ]);
  const details = [];
  if (clientName) details.push('Client name: ' + clientName);
  if (organizationName) details.push('Organization: ' + organizationName);
  if (clientEmail) details.push('Client email: ' + clientEmail);
  return details;
}

function shouldRenderPortalLifecycleEmailCta_(milestone, recipientClass) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  if (getPortalLifecycleEmailRecipientClass_(recipientClass) === 'client' &&
      (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_submitted ||
        normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_submitted)) {
    return false;
  }
  if (getPortalLifecycleEmailRecipientClass_(recipientClass) === 'team') {
    if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_removed ||
        normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_removed) {
      return false;
    }
  }
  return !isAccountDocumentApprovedTeamMilestone_(milestone, recipientClass);
}

function formatCreditTermsApprovedPaymentDueLabel_(paymentTermsLabel) {
  const clean = trimString_(paymentTermsLabel);
  if (!clean) return 'your approved payment terms';
  if (/^net\s+\d+$/i.test(clean)) return clean + ' Days';
  if (/^net\s+\d+\s+days?$/i.test(clean)) return clean.replace(/\bdays?$/i, 'Days');
  return clean;
}

function buildAccountDocumentEmailCopy_(milestone, recipientClass, meta) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  const isTeam = getPortalLifecycleEmailRecipientClass_(recipientClass) === 'team';
  const labels = getAccountDocumentEmailLabels_(meta);
  const documentLabel = trimString_(meta && meta.documentLabel) || labels.title;
  const reason = trimString_(meta && meta.reason);
  const paymentTermsLabel = trimString_(meta && meta.paymentTermsLabel);
  const teamIdentityDetails = Array.isArray(meta && meta.teamIdentityDetails)
    ? meta.teamIdentityDetails
    : [];
  const details = isTeam ? teamIdentityDetails.slice() : [];
  if (paymentTermsLabel) details.push('Approved payment terms: ' + paymentTermsLabel);
  if (reason) details.push('Reason: ' + reason);
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_submitted ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_submitted) {
    const creditTermsSubmitted = normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_submitted;
    const clientIntro = creditTermsSubmitted
      ? 'Red Threads received your credit terms document.'
      : 'Red Threads received your sales tax exemption document.';
    const submittedTeamReview = isAccountDocumentSubmittedTeamReviewMilestone_(normalized, recipientClass);
    const submittedTeamIntro = creditTermsSubmitted
      ? 'A client submitted a credit terms application for Red Threads review. Open Team Mode to review the document and update the account status.'
      : 'A client submitted a Michigan sales tax exemption form for Red Threads review. Open Team Mode to review the document and update the account status.';
    return {
      subject: isTeam
        ? (creditTermsSubmitted
          ? buildTeamSubject_('Review credit terms application')
          : buildTeamSubject_('Review sales tax exemption form'))
        : (creditTermsSubmitted
          ? 'Credit terms document received'
          : 'Sales tax exemption document received'),
      heading: isTeam
        ? ('Review ' + labels.submission)
        : (creditTermsSubmitted ? 'Credit terms document received' : 'Sales tax exemption document received'),
      intro: isTeam
        ? (submittedTeamReview
          ? submittedTeamIntro
          : ('A client submitted a ' + labels.submission + ' for review.'))
        : clientIntro,
      statusCopy: isTeam
        ? (submittedTeamReview ? '' : 'Review the submitted document in Team Mode.')
        : 'Your document is under review. No action is required from you at this time. Red Threads will be in touch if we have any questions, if changes are needed, or when your document is approved. Review typically takes up to five business days.',
      details: details
    };
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_approved ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_approved) {
    const approvedIntro = normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_approved
      ? 'Red Threads approved the credit terms associated with your account.'
      : 'Red Threads approved the tax exemption associated with your account.';
    const taxExemptClientApproved = !isTeam && normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_approved;
    const creditTermsClientApproved = !isTeam && normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_approved;
    const paymentDueLabel = formatCreditTermsApprovedPaymentDueLabel_(paymentTermsLabel);
    return {
      subject: normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_approved
        ? (isTeam ? buildTeamSubject_('Credit terms approved') : 'Credit terms approved')
        : (isTeam ? buildTeamSubject_('Sales tax exemption approved') : 'Sales tax exemption approved'),
      heading: isTeam ? (labels.title + ' approved') : approvedIntro.replace(/[.]+$/g, ''),
      intro: isTeam ? '' : approvedIntro,
      statusCopy: normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_approved
        ? (creditTermsClientApproved
          ? ('Orders will go to production immediately upon Purchase Order receipt. Payment will be required within ' + paymentDueLabel + ' of your Purchase Order placement, according to the terms in your credit application. Late fees will be automatically applied.')
          : isTeam
          ? ''
          : 'Approved payment terms are now associated with your account.')
        : (isTeam
          ? ''
          : ''),
      nextStep: taxExemptClientApproved
        ? 'You can now toggle sales tax on and off your orders.'
        : creditTermsClientApproved
        ? 'Your Organization can now place Purchase Orders with Red Threads.'
        : 'No action required',
      details: details
    };
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_denied ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_denied) {
    const deniedIntro = normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_denied
      ? 'The credit terms associated with your Red Threads account was not approved.'
      : (!isTeam
        ? 'The tax exemption associated with your Red Threads account was not approved.'
        : 'Red Threads reviewed the tax exemption associated with your account.');
    const creditTermsClientDenied = !isTeam && normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_denied;
    const taxExemptClientDenied = !isTeam && normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_denied;
    const accountDocumentClientDenied = creditTermsClientDenied || taxExemptClientDenied;
    return {
      subject: normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_denied
        ? (isTeam ? buildTeamSubject_('Credit terms need attention') : buildActionNeededSubject_('Credit terms need attention'))
        : (isTeam ? buildTeamSubject_('Sales tax exemption needs attention') : buildActionNeededSubject_('Sales tax exemption needs attention')),
      heading: isTeam ? (labels.title + ' needs attention') : deniedIntro.replace(/[.]+$/g, ''),
      intro: isTeam ? ('Red Threads reviewed the ' + labels.noun + ' associated with this account.') : deniedIntro,
      statusCopy: accountDocumentClientDenied
        ? ''
        : trimString_(meta && meta.hardDenied) === 'true'
        ? (isTeam
          ? 'The submission was not approved. Review the account status in Team Mode.'
          : 'The submission was not approved. Review your account dashboard for the current status.')
        : (isTeam
          ? 'A correction is needed before approval. Review the account status in Team Mode.'
          : 'A correction is needed before approval. Review your account dashboard for the next step.'),
      nextStep: accountDocumentClientDenied ? '' : isTeam
        ? ('Review the ' + labels.noun + ' workflow in Team Mode.')
        : ('Upload an updated ' + labels.submission + ' from your account dashboard.'),
      details: details
    };
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_removed ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_removed) {
    const creditTermsRemoved = normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_removed;
    const clearedAtLabel = buildLifecycleEmailDateLabel_(trimString_(meta && meta.clearedAt));
    const clearedByName = trimString_(meta && meta.clearedByName);
    const clearedByEmail = normalizeEmail_(meta && meta.clearedByEmail);
    const removedDetails = isTeam ? details.slice() : [];
    const includeRemovedActorDetails = !isTeam;
    if (clearedAtLabel) removedDetails.push('Removed: ' + clearedAtLabel);
    if (includeRemovedActorDetails && clearedByName) removedDetails.push('Removed by: ' + clearedByName);
    if (includeRemovedActorDetails && clearedByEmail) removedDetails.push('Removed by email: ' + clearedByEmail);
    return {
      subject: isTeam
        ? buildTeamSubject_(creditTermsRemoved ? 'Credit terms document removed' : 'Sales tax exemption document removed')
        : (creditTermsRemoved
          ? 'Credit Terms removed from Red Threads portal account'
          : 'Sales tax exemption document removed from Red Threads account'),
      heading: isTeam
        ? (creditTermsRemoved ? 'Credit terms document removed' : 'Sales tax exemption document removed')
        : (creditTermsRemoved ? 'Credit terms agreement was removed' : 'Upload a new sales tax exemption document'),
      intro: isTeam
        ? (creditTermsRemoved
          ? 'A client removed the credit terms document that was on file for their Red Threads account.'
          : 'A client removed the sales tax exemption document that was on file for their Red Threads account.')
        : (creditTermsRemoved
          ? 'The credit terms document that was on file for your Red Threads account has been removed.'
          : 'The sales tax exemption document that was on file for your Red Threads account has been removed.'),
      statusCopy: isTeam
        ? 'The client was directed to upload a replacement from the account dashboard. No review action is available until a replacement document is submitted.'
        : (creditTermsRemoved
          ? 'Account credit terms cannot be used until a new credit terms document is submitted and approved.\n\nYou will no longer have the ability to place purchase orders until new terms are established.'
          : 'Sales tax cannot be toggled on/off orders again until a new document is submitted and approved.'),
      nextStep: isTeam
        ? ''
        : (creditTermsRemoved
          ? 'Upload a new credit terms document from your account dashboard.'
          : 'Upload a new sales tax exemption document from your account dashboard.'),
      nextStepLabel: !isTeam && !creditTermsRemoved ? 'Potential next step:' : '',
      details: removedDetails
    };
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_reset ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_reset) {
    const resetIntro = normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_reset
      ? 'Red Threads reset the credit terms associated with your account.'
      : 'Red Threads reset the tax exemption associated with your account.';
    return {
      subject: normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_reset
        ? (isTeam ? buildTeamSubject_('Credit terms reset') : buildActionNeededSubject_('Complete credit terms application'))
        : (isTeam ? buildTeamSubject_('Sales tax exemption reset') : buildActionNeededSubject_('Complete sales tax exemption form')),
      heading: isTeam ? (labels.title + ' reset') : resetIntro.replace(/[.]+$/g, ''),
      intro: isTeam ? ('Red Threads reset the ' + labels.noun + ' associated with this account.') : resetIntro,
      statusCopy: isTeam
        ? 'If a new submission is required, it can be updated from the account dashboard.'
        : (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_reset
          ? 'If you would like Sales Tax Exemption added to your account, please resubmit the sales tax exemption form in your account dashboard.'
          : 'If a new submission is required, update it from your account dashboard.'),
      nextStep: isTeam
        ? ('Review the ' + labels.noun + ' workflow in Team Mode.')
        : (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_reset
          ? ''
          : ('Upload a new ' + labels.submission + ' from your account dashboard.')),
      details: details
    };
  }
  return null;
}

function getAccountDocumentLifecycleNonOrderLayout_(milestone, recipientClass) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  if (isAccountDocumentSubmittedTeamReviewMilestone_(normalized, recipientClass)) return 'details_first_cta_after_copy';
  if (isAccountDocumentApprovedTeamMilestone_(normalized, recipientClass)) return 'no_action_first';
  if (getPortalLifecycleEmailRecipientClass_(recipientClass) !== 'client') return '';
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_approved ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_approved) {
    return 'no_action_first';
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_denied ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_removed ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_reset ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_denied ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_reset) {
    return 'next_step_first';
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_removed) {
    return 'copy_first_next_step';
  }
  return '';
}

function resolveAccountDocumentLifecycleNextStep_(copy, milestone, recipientClass) {
  const source = (copy && typeof copy === 'object') ? copy : {};
  if (Object.prototype.hasOwnProperty.call(source, 'nextStep')) return trimString_(source.nextStep);
  const explicitStep = trimString_(source.nextStep);
  if (explicitStep) return explicitStep;
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_approved ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_approved) {
    return 'No action is required.';
  }
  return '';
}

function buildProductionCompleteFulfillmentEmailCopy_(recipientClass, fulfillmentMethod, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const method = normalizeFulfillmentMethod_(fulfillmentMethod);
  const isTeam = trimString_(recipientClass).toLowerCase() === 'team';
  const paymentLine = trimString_(opts.paymentLine);
  const paymentStillOpen = opts.paymentStillOpen === true;
  const poPaymentDue = opts.poPaymentDue === true;
  const invoiceReceiptAttached = opts.invoiceReceiptAttached === true;
  const completionDateLabel = trimString_(opts.completionDateLabel);
  const clientDisplayName = trimString_(opts.clientName) || 'The client';
  const completedCount = Math.max(0, parseInt(String(opts.completedCount || 0), 10) || 0);
  const totalCount = Math.max(0, parseInt(String(opts.totalCount || 0), 10) || 0);
  const countLine = completedCount && totalCount
    ? (completedCount + ' of ' + totalCount + ' tracked jobs are marked complete.')
    : 'All tracked jobs are marked complete.';
  const completedLine = completionDateLabel
    ? ('All job production completed: ' + completionDateLabel)
    : countLine;
  let subject = isTeam ? 'Project complete' : 'Your Red Threads project is complete';
  let heading = 'Production complete';
  let actionTitle = '';
  let actionTitleTone = '';
  let intro = isTeam
    ? 'All tracked jobs are marked complete for the client\'s order.'
    : 'Production is complete for your Red Threads order.';
  let fulfillmentLine = '';
  let nextStep = isTeam
    ? (paymentStillOpen ? 'Monitor the open payment until it is resolved.' : 'No team action is required right now.')
    : (paymentStillOpen ? 'Review your portal for current payment status.' : 'No action is needed right now.');
  let nextStepLabel = '';
  let productionTimingLine = '';
  let attachmentNote = '';
  let ctaLabel = '';
  let ctaAlign = '';
  let suppressActionCardCta = false;

  if (method === FULFILLMENT_METHODS.shipping) {
    subject = isTeam ? buildTeamSubject_('Order complete — ready to ship') : 'Order complete — shipping in progress';
    heading = isTeam ? 'Order complete, Shipping in progress' : 'Order complete, shipping in progress';
    if (isTeam) {
      intro = clientDisplayName + ' has been notified via email that their order is complete and will be shipping via UPS ground. No tracking has been provided.';
      fulfillmentLine = '';
      suppressActionCardCta = true;
    } else {
      intro = 'Your Red Threads order has finished production, and is shipping via UPS ground.';
      fulfillmentLine = 'No tracking link is included with this notification, but can be provided upon request.';
      productionTimingLine = completedLine;
      ctaAlign = 'center';
      suppressActionCardCta = true;
      if (invoiceReceiptAttached) {
        attachmentNote = 'Your project invoice/receipt is attached to this email.';
      }
      if (poPaymentDue) {
        actionTitle = 'Action required';
        actionTitleTone = 'blue';
        nextStep = buildProductionCompletePoPaymentNextStepText_(opts);
        nextStepLabel = 'Next action:';
      } else {
        actionTitle = 'No action required';
        nextStep = 'No action is needed right now.';
      }
    }
  } else if (method === FULFILLMENT_METHODS.pickup) {
    subject = isTeam ? buildTeamSubject_('Order complete — ready for pickup') : 'Order ready for pickup';
    heading = isTeam ? 'Order complete, Ready for pickup' : 'Ready for pickup';
    if (isTeam) {
      intro = 'Client has been notified via email that their order is ready for pickup at Red Threads M-F 9-5.';
      fulfillmentLine = '';
      productionTimingLine = completedLine;
      suppressActionCardCta = true;
    } else {
      fulfillmentLine = 'Your order is ready for pickup at Red Threads, 505 South Saginaw Rd, Midland, Michigan 48640. Stop by any time Monday - Friday from 9am - 5pm.';
      actionTitle = 'Action required';
      actionTitleTone = 'blue';
      suppressActionCardCta = true;
      if (!paymentStillOpen) nextStep = 'Pick up your order from Red Threads.';
    }
  }
  const suppressClientCompletionStatusLines = !isTeam && method === FULFILLMENT_METHODS.pickup;
  const suppressTeamFulfillmentStatusLines = isTeam &&
    (method === FULFILLMENT_METHODS.shipping || method === FULFILLMENT_METHODS.pickup);

  return {
    subject: subject,
    heading: heading,
    actionTitle: actionTitle,
    actionTitleTone: actionTitleTone,
    intro: intro,
    statusCopy: uniqueTrimmedStrings_([
      fulfillmentLine,
      (!isTeam && method === FULFILLMENT_METHODS.shipping) || suppressClientCompletionStatusLines || suppressTeamFulfillmentStatusLines ? '' : countLine,
      ((!isTeam && method === FULFILLMENT_METHODS.shipping && !paymentStillOpen) || suppressClientCompletionStatusLines || suppressTeamFulfillmentStatusLines) ? '' : paymentLine
    ]).join('\n'),
    nextStep: nextStep,
    nextStepLabel: nextStepLabel,
    productionTimingLine: productionTimingLine,
    attachmentNote: attachmentNote,
    ctaLabel: ctaLabel,
    ctaAlign: ctaAlign,
    suppressActionCardCta: suppressActionCardCta
  };
}

function buildProductionCompletePoPaymentNextStepText_(options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const paymentDueDateLabel = trimString_(opts.paymentDueDateLabel);
  const paymentTermsLabel = trimString_(opts.paymentTermsLabel);
  const duePhrase = paymentDueDateLabel ? ('by ' + paymentDueDateLabel) : 'by the due date';
  const termsPhrase = paymentTermsLabel
    ? (' under your account terms: ' + paymentTermsLabel)
    : ' under your approved terms';
  return 'Return to your Red Threads project invoice tab and make a payment ' + duePhrase + termsPhrase + '. Late fees will automatically be applied.';
}

function buildPortalLifecycleEmailCopy_(milestone, recipientClass, emailContext, meta, cfg) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  const isTeam = getPortalLifecycleEmailRecipientClass_(recipientClass) === 'team';
  const projectName = trimString_(emailContext && emailContext.projectName) || 'Red Threads project';
  const invoiceNumber = trimString_(emailContext && emailContext.invoiceNumber);
  const printJobIndex = trimString_(meta && meta.printJobIndex);
  const documentLabel = trimString_(meta && meta.documentLabel);
  const flowKind = trimString_(meta && meta.flowKind);
  const completedCount = Math.max(0, parseInt(String(meta && meta.completedJobCount || 0), 10) || 0);
  const totalCount = Math.max(0, parseInt(String(meta && meta.totalJobCount || 0), 10) || 0);
  const subjectParts = [];
  let intro = '';
  let statusCopy = '';
  let details = [];
  let heading = '';
  let nextStep = '';
  let actionTitle = '';
  let actionTitleTone = '';
  let nextStepLabel = '';
  let productionTimingLine = '';
  let attachmentNote = '';
  let ctaLabel = '';
  let ctaAlign = '';
  let suppressActionCardCta = false;
  const accountDocumentMilestone = isPortalLifecycleAccountDocumentMilestone_(normalized);

  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.artwork_approved) {
    subjectParts.push(isTeam ? 'Artwork approved' : 'Artwork approved');
    intro = isTeam ? 'A client approved artwork in the portal.' : 'Artwork approval has been recorded.';
    statusCopy = printJobIndex ? ('Print job ' + printJobIndex + ' was approved.') : 'Artwork was approved.';
  } else if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.artwork_disapproved) {
    subjectParts.push(isTeam ? 'Artwork change requested' : 'Artwork change requested');
    intro = isTeam ? 'A client requested an artwork change in the portal.' : 'An artwork change request was recorded.';
    statusCopy = printJobIndex ? ('Print job ' + printJobIndex + ' needs artwork review.') : 'Artwork needs review.';
  } else if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.project_ready_to_order) {
    subjectParts.push(isTeam ? 'Project ready to order' : 'Your Red Threads project is ready to order');
    intro = isTeam ? 'A project reached the ready-to-order state.' : 'Your project is ready for order placement.';
    statusCopy = isTeam
      ? 'Quantities and artwork appear ready. The client can place the order from the portal.'
      : 'Quantities and artwork are ready. Return to the portal when you are ready to place the order.';
  } else if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.project_unlocked) {
    subjectParts.push(isTeam ? 'Project reopened' : 'Your Red Threads project was reopened');
    intro = isTeam ? 'A project was reopened for client changes.' : 'Your project has been reopened for updates.';
    statusCopy = 'Review the portal before placing the order again.';
  } else if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.checkout_reset) {
    subjectParts.push(isTeam ? 'Checkout reset' : 'Your Red Threads checkout was reset');
    intro = isTeam ? 'Checkout selection was reset by the team.' : 'Your checkout selection was reset by Red Threads.';
    statusCopy = 'Return to the portal to select payment and continue.';
  } else if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.po_reopened) {
    subjectParts.push(isTeam ? 'PO submission reopened' : 'Purchase-order submission reopened');
    intro = isTeam ? 'Purchase-order submission was reopened.' : 'Your purchase-order submission step has been reopened.';
    statusCopy = 'Return to the portal to upload the corrected purchase order.';
  } else if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.team_hold) {
    subjectParts.push(isTeam ? 'Project paused' : 'Your Red Threads project is paused');
    intro = isTeam ? 'The project was placed on a team hold.' : 'Red Threads temporarily paused this project.';
    statusCopy = 'The portal will show the current hold state while the team resolves the next step.';
  } else if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.client_flow_canceled) {
    subjectParts.push(isTeam ? 'Client canceled payment flow' : 'Payment flow canceled');
    intro = isTeam ? 'A client canceled an in-progress payment workflow.' : 'Your payment workflow was canceled.';
    statusCopy = flowKind === PAYMENT_METHODS.purchase_order
      ? 'The purchase-order workflow returned to editable estimate mode.'
      : 'The manual-payment workflow returned to editable estimate mode.';
  } else if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.production_authorized) {
    subjectParts.push(isTeam ? 'Production authorized' : 'Your Red Threads order is authorized for production');
    intro = isTeam ? 'Production has been authorized for this order.' : 'Your order has been authorized for production.';
    statusCopy = 'The portal progress snapshot below reflects the current production status.';
  } else if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.jobs_completed ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.project_completed) {
    const complete = normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.project_completed;
    if (complete) {
      const summary = (emailContext && emailContext.orderSummary && typeof emailContext.orderSummary === 'object')
        ? emailContext.orderSummary
        : {};
      const workflow = (emailContext && emailContext.workflowContext && typeof emailContext.workflowContext === 'object')
        ? emailContext.workflowContext
        : {};
      const paymentReceived = isPortalCommunicationPaymentReceived_(workflow, summary);
      const poSubmitted = isPortalCommunicationPoSubmitted_(workflow, summary);
      const productionDisposition = resolveOrderCommunicationProductionDisposition_(workflow, summary);
      const poTermsOpen = poSubmitted && !paymentReceived &&
        (productionDisposition === 'authorized' || productionDisposition === 'in_progress' || productionDisposition === 'complete');
      const paymentStillOpen = !paymentReceived && !poTermsOpen;
      const paymentLine = paymentReceived
        ? 'Payment has been received.'
        : (poTermsOpen ? 'Payment remains open under the approved terms.' : 'Payment remains open.');
      const timeline = (emailContext && emailContext.timeline && typeof emailContext.timeline === 'object')
        ? emailContext.timeline
        : {};
      const accountSummary = (emailContext && emailContext.accountSummary && typeof emailContext.accountSummary === 'object')
        ? emailContext.accountSummary
        : {};
      const productionTimingMeta = resolveLifecycleEmailProductionTimingMeta_(workflow, summary, {
        timeline: timeline
      });
      const completionDateLabel = buildLifecycleEmailDateLabel_(productionTimingMeta.completionDate) ||
        trimString_(timeline.completionDateLabel);
      const invoiceReceiptAttached = meta.invoiceReceiptAttached === true ||
        uniqueTrimmedStrings_(meta.attachmentFileIds).length > 0;
      const completionCopy = buildProductionCompleteFulfillmentEmailCopy_(recipientClass, summary.fulfillmentMethod, {
        completedCount: completedCount,
        totalCount: totalCount,
        paymentLine: paymentLine,
        paymentStillOpen: paymentStillOpen,
        poPaymentDue: poTermsOpen,
        paymentDueDateLabel: trimString_(timeline.paymentDueDateLabel),
        paymentTermsLabel: trimString_(timeline.paymentTermsLabel || accountSummary.approvedPaymentTermsLabel),
        completionDateLabel: completionDateLabel,
        clientName: trimString_(emailContext.clientName),
        invoiceReceiptAttached: invoiceReceiptAttached
      });
      subjectParts.push(completionCopy.subject);
      heading = completionCopy.heading;
      intro = completionCopy.intro;
      statusCopy = completionCopy.statusCopy;
      nextStep = completionCopy.nextStep;
      actionTitle = trimString_(completionCopy.actionTitle);
      actionTitleTone = trimString_(completionCopy.actionTitleTone);
      nextStepLabel = trimString_(completionCopy.nextStepLabel);
      productionTimingLine = trimString_(completionCopy.productionTimingLine);
      attachmentNote = trimString_(completionCopy.attachmentNote);
      ctaAlign = trimString_(completionCopy.ctaAlign);
      suppressActionCardCta = completionCopy.suppressActionCardCta === true;
      const projectNumber = getLifecycleEmailProjectNumberLabel_(emailContext);
      if (completionCopy.ctaLabel) {
        ctaLabel = trimString_(completionCopy.ctaLabel);
      } else if (!isTeam && normalizeFulfillmentMethod_(summary.fulfillmentMethod) === FULFILLMENT_METHODS.shipping) {
        ctaLabel = poTermsOpen
          ? (projectNumber ? ('Click to access Project #' + projectNumber + ' and make a payment.') : 'Click to access your project and make a payment.')
          : (projectNumber ? ('View project #' + projectNumber + ' in the portal') : 'View your project in the portal');
      }
    } else {
      subjectParts.push(isTeam ? 'Job completion updated' : 'Red Threads job completion update');
      intro = isTeam ? 'Job completion dates were updated.' : 'A production completion update was recorded for your project.';
      statusCopy = completedCount && totalCount
        ? (completedCount + ' of ' + totalCount + ' tracked jobs are marked complete.')
        : 'The current completion status is shown below.';
    }
  } else if (isPortalLifecycleAccountDocumentMilestone_(normalized)) {
    const docCopy = buildAccountDocumentEmailCopy_(normalized, recipientClass, meta);
    const hasDocStatusCopy = docCopy && typeof docCopy === 'object' && Object.prototype.hasOwnProperty.call(docCopy, 'statusCopy');
    const hasDocNextStep = docCopy && typeof docCopy === 'object' && Object.prototype.hasOwnProperty.call(docCopy, 'nextStep');
    subjectParts.push(docCopy && docCopy.subject ? docCopy.subject : (isTeam ? 'Account document update' : 'Account document update'));
    heading = docCopy && docCopy.heading ? docCopy.heading : '';
    intro = docCopy && docCopy.intro ? docCopy.intro : 'An account document update was recorded.';
    statusCopy = hasDocStatusCopy ? trimString_(docCopy.statusCopy) : 'Review the portal for the current status.';
    nextStep = hasDocNextStep ? trimString_(docCopy.nextStep) : '';
    nextStepLabel = trimString_(docCopy && docCopy.nextStepLabel);
    details = docCopy && Array.isArray(docCopy.details) ? docCopy.details : details;
  } else {
    subjectParts.push(isTeam ? 'Red Threads portal update' : 'Red Threads portal update');
    intro = 'A portal lifecycle update was recorded.';
    statusCopy = 'Review the current project status below.';
  }

  const baseSubject = subjectParts.filter(Boolean).join(' - ');
  return {
    subject: accountDocumentMilestone
      ? baseSubject
      : buildLifecycleEmailSubject_(baseSubject, emailContext, {
        projectName: projectName,
        documentLabel: invoiceNumber
      }),
    heading: heading,
    actionTitle: actionTitle,
    actionTitleTone: actionTitleTone,
    intro: intro,
    statusCopy: statusCopy,
    nextStep: nextStep,
    nextStepLabel: nextStepLabel,
    productionTimingLine: productionTimingLine,
    attachmentNote: attachmentNote,
    ctaLabel: ctaLabel,
    ctaAlign: ctaAlign,
    suppressActionCardCta: suppressActionCardCta || meta.suppressActionCardCta === true,
    details: Array.isArray(details) ? details : []
  };
}

function buildPortalLifecycleEmailAttachments_(meta) {
  const source = (meta && typeof meta === 'object') ? meta : {};
  const attachments = [];
  const fileIds = uniqueTrimmedStrings_(source.attachmentFileIds);
  fileIds.forEach(function(fileId) {
    const file = getDriveFileByIdSafe_(fileId);
    if (!file) return;
    attachments.push(file.getBlob().setName(
      sanitizeUploadedDocumentName_(
        (source.attachmentFileNames && source.attachmentFileNames[fileId]) || file.getName(),
        file.getName()
      )
    ));
  });
  return attachments;
}

function buildPortalLifecycleEmailContent_(milestone, orderInfo, options) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  const opts = (options && typeof options === 'object') ? options : {};
  const recipientClass = getPortalLifecycleEmailRecipientClass_(opts.recipientClass);
  const ctx = opts.lifecycleContext || {};
  const meta = (opts.meta && typeof opts.meta === 'object') ? opts.meta : {};
  const cta = getPortalLifecycleEmailCta_(normalized, recipientClass, ctx, meta);
  const emailContext = buildLifecycleEmailContextForOrder_(orderInfo, null, Object.assign({}, opts, {
    recipientClass: recipientClass,
    accountInfo: ctx.accountInfo,
    ctaLabel: cta.label
  }));
  emailContext.ctaUrl = trimString_(cta.url);
  emailContext.ctaLabel = trimString_(cta.label);
  const emailMeta = Object.assign({}, meta, {
    teamIdentityDetails: buildAccountDocumentTeamIdentityDetails_(meta, emailContext)
  });
  const copy = buildPortalLifecycleEmailCopy_(normalized, recipientClass, emailContext, emailMeta, ctx.cfg || opts.cfg);
  if (copy.ctaLabel) emailContext.ctaLabel = trimString_(copy.ctaLabel);
  const accountDocumentMilestone = isPortalLifecycleAccountDocumentMilestone_(normalized);
  const resolvedNextStep = accountDocumentMilestone
    ? resolveAccountDocumentLifecycleNextStep_(copy, normalized, recipientClass)
    : (copy.nextStep || emailContext.nextStepText);
  const teamActionModel = recipientClass === 'team' && !accountDocumentMilestone
    ? resolveLifecycleTeamEmailActionModel_(emailContext, {
      family: 'portal_lifecycle',
      milestone: normalized,
      intro: copy.intro,
      statusCopy: copy.statusCopy
    })
    : null;
  const sectionBlocks = buildLifecycleEmailSectionBlocks_(emailContext, {
    family: 'portal_lifecycle',
    milestone: normalized,
    recipientClass: recipientClass
  });
  const ctaBlock = shouldRenderPortalLifecycleEmailCta_(normalized, recipientClass)
    ? buildLifecycleEmailCtaBlock_(
      teamActionModel ? teamActionModel.ctaLabel : emailContext.ctaLabel,
      teamActionModel ? teamActionModel.ctaUrl : emailContext.ctaUrl,
      {
        align: teamActionModel
          ? teamActionModel.ctaAlign
          : (trimString_(copy.ctaAlign) || (isAccountDocumentSubmittedTeamReviewMilestone_(normalized, recipientClass) ? 'center' : '')),
        teamModePassword: teamActionModel
          ? teamActionModel.teamModePassword
          : (recipientClass === 'team' ? emailContext.teamModePassword : '')
      }
    )
    : null;
  const shell = buildLifecycleEmailShell_({
    eyebrow: recipientClass === 'team' ? getPortalNativeEmailEyebrow_('team') : '',
    heading: copy.heading,
    badgeLabel: copy.badgeLabel || getLifecycleEmailCurrentStepLabel_(emailContext.steps),
    actionTitle: teamActionModel ? teamActionModel.title : copy.actionTitle,
    actionTitleTone: teamActionModel ? '' : copy.actionTitleTone,
    intro: teamActionModel ? teamActionModel.intro : copy.intro,
    statusCopy: teamActionModel ? teamActionModel.statusCopy : copy.statusCopy,
    nextStep: teamActionModel ? teamActionModel.nextStep : resolvedNextStep,
    nextStepLabel: teamActionModel ? teamActionModel.nextStepLabel : copy.nextStepLabel,
    nextStepTone: teamActionModel ? teamActionModel.nextStepTone : '',
    suppressActionCardCta: (teamActionModel ? teamActionModel.suppressActionCardCta === true : false) || copy.suppressActionCardCta === true,
    attachmentNote: copy.attachmentNote,
    productionTimingLine: copy.productionTimingLine,
    nonOrderLayout: getAccountDocumentLifecycleNonOrderLayout_(normalized, recipientClass),
    blocks: sectionBlocks.concat([
      buildPortalLifecycleEmailDetailBlock_(copy.details),
      ctaBlock,
      buildLifecycleEmailFooter_()
    ].filter(Boolean))
  });
  const communicationContract = buildPortalCommunicationContext_({
    emailContext: emailContext
  }, {
    family: 'portal_lifecycle',
    trigger: normalized,
    recipientClass: recipientClass,
    documentLabel: trimString_(emailContext.invoiceNumber),
    cfg: opts.cfg,
    ss: opts.ss,
    infra: opts.infra
  });
  if (accountDocumentMilestone) {
    const accountIntent = resolveAccountDocumentCommunicationIntent_(normalized);
    if (accountIntent) {
      communicationContract.intent = accountIntent;
      communicationContract.lifecycleState = accountIntent;
      communicationContract.lifecycleStage = 'account_document';
      communicationContract.paymentDisposition = 'not_applicable';
      communicationContract.productionDisposition = 'not_applicable';
      communicationContract.ctaMode = isAccountDocumentSubmittedTeamReviewMilestone_(normalized, recipientClass)
        ? 'team_review'
        : (recipientClass === 'team' ? 'none' : 'account_document');
      communicationContract.allowedCtaMode = communicationContract.ctaMode;
      communicationContract.forbiddenCtaModes = [];
    }
  }
  return {
    subject: copy.subject,
    body: shell.body,
    htmlBody: shell.htmlBody,
    reviewSurface: shell.reviewSurface,
    communicationContract: communicationContract
  };
}

function resolveAccountDocumentCommunicationIntent_(milestone) {
  const normalized = normalizePortalLifecycleEmailMilestone_(milestone);
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_submitted ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_submitted) {
    return 'account_document_review_required';
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_approved ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_approved) {
    return 'account_document_approved';
  }
  if (normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_denied ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_removed ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.tax_exempt_reset ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_denied ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_removed ||
      normalized === PORTAL_LIFECYCLE_EMAIL_MILESTONES.credit_terms_reset) {
    return 'account_document_needs_attention';
  }
  return '';
}

function processPortalLifecycleEmailQueueJob_(jobInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const row = jobInfo && jobInfo.rowObjNormalized ? jobInfo.rowObjNormalized : {};
  const meta = safeJsonParse_(row.portalstatejson, {}) || {};
  const milestone = normalizePortalLifecycleEmailMilestone_(meta.milestone);
  const recipientClass = getPortalLifecycleEmailRecipientClass_(meta.recipientClass);
  if (!milestone) throw new Error('Portal lifecycle email queue job is missing a milestone.');
  if (isLifecycleEmailSuppressedByPolicy_(
    PORTAL_EMAIL_QUEUE_JOB_TYPES.portal_lifecycle_email,
    milestone,
    recipientClass,
    meta
  )) {
    return { skipped: true, skipReason: COMMUNICATION_POLICY_DISABLED_REASON, invoiceInfo: null };
  }
  const lifecycleContext = resolvePortalLifecycleEmailContext_({
    token: trimString_(row.token || meta.token),
    accountId: trimString_(meta.accountId),
    accountAccessToken: trimString_(meta.accountAccessToken)
  }, {
    cfg: cfg,
    ss: ss,
    infra: infra
  });
  const orderInfo = lifecycleContext.orderInfo || resolvePortalLifecycleOrderForQueueJob_(jobInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra
  });
  const accountOnlyMilestone = isPortalLifecycleAccountOnlyMilestone_(milestone);
  if (!orderInfo && !accountOnlyMilestone) return { skipped: true, skipReason: 'missing_project_context', invoiceInfo: null };
  if (!orderInfo && accountOnlyMilestone &&
      !hasPortalAccountDashboardIdentity_(lifecycleContext.accountInfo && lifecycleContext.accountInfo.summary)) {
    return { skipped: true, skipReason: 'missing_account_context', invoiceInfo: null };
  }
  const recipients = parseAchLifecycleEmailQueueRecipients_(row.recipientsjson);
  if (!recipients.toList.length) return { skipped: true, skipReason: 'missing_recipients', invoiceInfo: null };
  const attachments = buildPortalLifecycleEmailAttachments_(meta);
  if (meta.attachmentRequired === true && !attachments.length) {
    throw new Error('Portal lifecycle attachment could not be found.');
  }
  const content = buildPortalLifecycleEmailContent_(milestone, orderInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    recipientClass: recipientClass,
    lifecycleContext: lifecycleContext,
    meta: meta
  });
  const emailResult = sendNotificationEmail_({
    toList: recipients.toList,
    ccList: recipients.ccList,
    subject: content.subject,
    body: content.body,
    htmlBody: content.htmlBody,
    attachments: attachments,
    fromAlias: NOTIFICATION_FROM_ALIAS,
    replyTo: NOTIFICATION_FROM_ALIAS
  });
  if (!emailResult || emailResult.ok !== true) {
    throw new Error(trimString_(emailResult && emailResult.error) || 'Portal lifecycle email could not be sent.');
  }
  const summary = orderInfo ? buildPortalOrderSummary_(orderInfo.rowObjNormalized) : {};
  logPortalLifecycleEmailQueueEvent_('sent', {
    ok: true,
    milestone: milestone,
    recipientClass: recipientClass,
    token: trimString_(row.token || meta.token),
    orderId: trimString_(summary.orderId),
    recipientCount: recipients.toList.length,
    ccCount: recipients.ccList.length,
    recipientDomains: summarizeEmailDomainsForLog_(recipients.toList.concat(recipients.ccList)),
    attachmentCount: attachments.length,
    attachmentRequired: meta.attachmentRequired === true,
    status: PORTAL_EMAIL_QUEUE_STATUSES.sent
  });
  return {
    invoiceInfo: null
  };
}

function normalizePaymentLifecycleEmailMilestone_(value) {
  const milestone = trimString_(value).toLowerCase();
  return Object.keys(PAYMENT_LIFECYCLE_EMAIL_MILESTONES).some(function(key) {
    return PAYMENT_LIFECYCLE_EMAIL_MILESTONES[key] === milestone;
  }) ? milestone : '';
}

function isPaymentLifecycleEmailJobType_(value) {
  return trimString_(value).toLowerCase() === PORTAL_EMAIL_QUEUE_JOB_TYPES.payment_lifecycle_email;
}

function isPaymentLifecycleReceiptMilestone_(milestone) {
  const normalized = normalizePaymentLifecycleEmailMilestone_(milestone);
  return normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.card_paid ||
    normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.manual_received ||
    normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_received;
}

function isPaymentLifecycleFailureMilestone_(milestone) {
  return normalizePaymentLifecycleEmailMilestone_(milestone) === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.card_failed;
}

function isScheduledPoPaymentReminderMilestone_(milestone) {
  const normalized = normalizePaymentLifecycleEmailMilestone_(milestone);
  return normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_due_5bd_before ||
    normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_due_1bd_before ||
    normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_past_due ||
    normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_late_fee_notice ||
    normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_60_day_team_escalation;
}

function isClientScheduledPoPaymentReminderMilestone_(milestone) {
  return isScheduledPoPaymentReminderMilestone_(milestone) &&
    normalizePaymentLifecycleEmailMilestone_(milestone) !== PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_60_day_team_escalation;
}

function isPaymentLifecycleAttachmentRequired_(milestone) {
  if (isScheduledPoPaymentReminderMilestone_(milestone)) return false;
  return !isPaymentLifecycleFailureMilestone_(milestone);
}

function getPaymentLifecycleOrderToken_(orderInfo, orderSummary) {
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const draft = safeJsonParse_(row.orderdraftjson || row.orderDraftJson, {}) || {};
  return trimString_(summary.token || row.token || row.Token || draft.token);
}

function getPaymentLifecycleMethodLabel_(method) {
  const normalized = trimString_(method).toLowerCase();
  if (normalized === PAYMENT_METHODS.card) return 'Credit card';
  if (normalized === PAYMENT_METHODS.check) return 'Check';
  if (normalized === PAYMENT_METHODS.cash) return 'Cash';
  if (normalized === PAYMENT_METHODS.purchase_order) return 'Purchase order';
  if (normalized === PAYMENT_METHODS.ach) return 'ACH';
  return normalized ? normalized : 'Payment';
}

function buildPaymentLifecycleTeamAlertRecipients_() {
  return {
    toList: normalizeEmailRecipients_([DOCUMENT_REVIEW_EMAIL]),
    ccList: [],
    recipientClass: 'team'
  };
}

function buildPaymentLifecycleEmailRecipients_(orderInfo, stripeObj, accountInfo) {
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const draft = safeJsonParse_(row.orderdraftjson || row.orderDraftJson, {}) || {};
  const account = accountInfo && accountInfo.summary ? accountInfo.summary : {};
  const payerEmail = extractSafeStripePayerEmail_(stripeObj);
  const primaryEmail = firstNormalizedEmailFromValues_([
    row.personemail,
    row.personEmail,
    draft.personEmail,
    account.primaryEmail,
    account.billingContactEmail
  ]);
  const toList = primaryEmail ? [primaryEmail] : (payerEmail ? [payerEmail] : []);
  const ccList = primaryEmail && payerEmail && payerEmail !== primaryEmail ? [payerEmail] : [];
  return {
    toList: normalizeEmailRecipients_(toList),
    ccList: normalizeEmailRecipients_(ccList),
    payerEmail: payerEmail,
    primaryEmail: primaryEmail,
    recipientClass: 'client'
  };
}

function copyDocumentReviewOnScheduledPoReminderRecipients_(recipients) {
  const source = (recipients && typeof recipients === 'object') ? recipients : {};
  const ccList = normalizeEmailRecipients_([].concat(source.ccList || [], [DOCUMENT_REVIEW_EMAIL]))
    .filter(function(email) {
      return normalizeEmailRecipients_(source.toList).indexOf(email) < 0;
    });
  return Object.assign({}, source, {
    ccList: ccList
  });
}

function shouldQueuePaymentLifecycleEmailForOrder_(orderInfo, milestone) {
  const normalized = normalizePaymentLifecycleEmailMilestone_(milestone);
  if (!normalized) return false;
  const summary = buildPortalOrderSummary_((orderInfo && orderInfo.rowObjNormalized) || {});
  const method = trimString_(summary.paymentMethodSelected).toLowerCase();
  const paymentState = trimString_(summary.paymentState).toLowerCase();
  const paid = !!trimString_(summary.paidAt) || paymentState === PAYMENT_STATES.paid ||
    paymentState === PAYMENT_STATES.manual_received;
  if (method === PAYMENT_METHODS.ach) return false;
  if (normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.card_paid) {
    return method === PAYMENT_METHODS.card && paid;
  }
  if (normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.card_failed) {
    return method === PAYMENT_METHODS.card && paymentState === PAYMENT_STATES.failed && !paid;
  }
  if (normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.manual_pending) {
    return (method === PAYMENT_METHODS.check || method === PAYMENT_METHODS.cash) &&
      paymentState === PAYMENT_STATES.manual_pending &&
      !paid;
  }
  if (normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.manual_received) {
    return (method === PAYMENT_METHODS.check || method === PAYMENT_METHODS.cash) && paid;
  }
  if (isScheduledPoPaymentReminderMilestone_(normalized)) {
    return method === PAYMENT_METHODS.purchase_order &&
      !!trimString_(summary.poSubmittedAt) &&
      trimString_(summary.productionAuthorizationState).toLowerCase() !== PRODUCTION_AUTHORIZATION_STATES.canceled &&
      !paid;
  }
  if (normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_submitted) {
    return method === PAYMENT_METHODS.purchase_order &&
      !!trimString_(summary.poSubmittedAt) &&
      !paid;
  }
  if (normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_received) {
    return method === PAYMENT_METHODS.purchase_order && paid;
  }
  return false;
}

function buildPaymentLifecycleEmailIdempotencyKey_(milestone, recipientClass, orderSummary, recipients, token, meta) {
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const safeRecipients = (recipients && typeof recipients === 'object') ? recipients : {};
  const safeMeta = (meta && typeof meta === 'object') ? meta : {};
  return buildPortalEmailQueueIdempotencyKeyForSource_({
    jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.payment_lifecycle_email,
    milestone: normalizePaymentLifecycleEmailMilestone_(milestone),
    recipientClass: trimString_(recipientClass),
    token: trimString_(token),
    orderId: trimString_(summary.orderId),
    paymentMethodSelected: trimString_(summary.paymentMethodSelected),
    checkoutAttemptId: trimString_(summary.checkoutAttemptId),
    stripePaymentIntentId: trimString_(summary.stripePaymentIntentId),
    stripeSessionId: trimString_(summary.stripeSessionId),
    invoiceNumber: trimString_(summary.invoiceNumber),
    scheduleKey: trimString_(safeMeta.scheduleKey),
    paymentDueDate: trimString_(safeMeta.paymentDueDate),
    noticeDate: trimString_(safeMeta.noticeDate),
    feePercent: trimString_(safeMeta.feePercent),
    toList: normalizeEmailRecipients_(safeRecipients.toList),
    ccList: normalizeEmailRecipients_(safeRecipients.ccList)
  });
}

function logPaymentLifecycleEmailQueueEvent_(eventName, payload) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  const safe = {
    event: trimString_(eventName),
    ok: p.ok === true,
    reason: trimString_(p.reason),
    jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.payment_lifecycle_email,
    milestone: trimString_(p.milestone),
    recipientClass: trimString_(p.recipientClass),
    tokenPresent: !!trimString_(p.token),
    orderId: trimString_(p.orderId),
    paymentIntentPresent: !!trimString_(p.paymentIntentId),
    sessionPresent: !!trimString_(p.sessionId),
    recipientCount: Math.max(0, parseInt(String(p.recipientCount || 0), 10) || 0),
    ccCount: Math.max(0, parseInt(String(p.ccCount || 0), 10) || 0),
    recipientDomains: Array.isArray(p.recipientDomains) ? p.recipientDomains : [],
    invoicePdfPresent: p.invoicePdfPresent === true,
    attachmentRequired: p.attachmentRequired === true,
    attachmentPresent: p.attachmentPresent === true,
    status: trimString_(p.status),
    error: trimString_(p.error)
  };
  console.log('[RT-PAYMENT-LIFECYCLE-EMAIL-QUEUE] ' + JSON.stringify(safe));
}

function queuePaymentLifecycleClientAndTeamEmailsSafely_(orderInfo, stripeObj, milestone, options) {
  return {
    clientJob: queuePaymentLifecycleEmailJobSafely_(orderInfo, stripeObj, milestone, Object.assign({}, options || {}, {
      recipientClass: 'client'
    })),
    teamJob: queuePaymentLifecycleEmailJobSafely_(orderInfo, stripeObj, milestone, Object.assign({}, options || {}, {
      recipientClass: 'team'
    }))
  };
}

function queuePaymentLifecycleEmailJobSafely_(orderInfo, stripeObj, milestone, options) {
  const normalized = normalizePaymentLifecycleEmailMilestone_(milestone);
  if (!normalized) return null;
  const opts = (options && typeof options === 'object') ? options : {};
  const recipientClass = trimString_(opts.recipientClass) === 'team' ? 'team' : 'client';
  try {
    const scheduleMeta = (opts.meta && typeof opts.meta === 'object') ? opts.meta : {};
    const orderSummary = buildPortalOrderSummary_((orderInfo && orderInfo.rowObjNormalized) || {});
    const token = getPaymentLifecycleOrderToken_(orderInfo, orderSummary);
    const attachmentRequired = isPaymentLifecycleAttachmentRequired_(normalized);
    const milestonePolicy = resolveCommunicationMilestonePolicy_(
      PORTAL_EMAIL_QUEUE_JOB_TYPES.payment_lifecycle_email,
      normalized,
      orderInfo,
      {
        meta: opts.meta,
        recipientClass: recipientClass,
        paymentOrigin: opts.paymentOrigin,
        achPaymentSource: opts.achPaymentSource
      }
    );
    if (milestonePolicy.enabled === false) {
      logPaymentLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: milestonePolicy.reason,
        milestone: normalized,
        recipientClass: recipientClass,
        token: token,
        orderId: trimString_(orderSummary.orderId),
        paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        sessionId: trimString_(orderSummary.stripeSessionId),
        invoicePdfPresent: !!trimString_(orderSummary.invoicePdfUrl),
        attachmentRequired: attachmentRequired
      });
      return null;
    }
    if (!shouldQueuePaymentLifecycleEmailForOrder_(orderInfo, normalized)) {
      logPaymentLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: 'state_not_eligible',
        milestone: normalized,
        recipientClass: recipientClass,
        token: token,
        orderId: trimString_(orderSummary.orderId),
        paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        sessionId: trimString_(orderSummary.stripeSessionId),
        invoicePdfPresent: !!trimString_(orderSummary.invoicePdfUrl),
        attachmentRequired: attachmentRequired
      });
      return null;
    }
    const cfg = opts.cfg || getConfig_();
    const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
    const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
    const accountInfo = opts.accountInfo || getPortalAccountInfoForOrder_(orderInfo, {
      cfg: cfg,
      ss: ss,
      infra: infra
    });
    let recipients = recipientClass === 'team'
      ? buildPaymentLifecycleTeamAlertRecipients_()
      : buildPaymentLifecycleEmailRecipients_(orderInfo, stripeObj, accountInfo);
    if (recipientClass === 'client' && isScheduledPoPaymentReminderMilestone_(normalized)) {
      recipients = copyDocumentReviewOnScheduledPoReminderRecipients_(recipients);
    }
    if (!recipients.toList.length) {
      logPaymentLifecycleEmailQueueEvent_('not_queued', {
        ok: false,
        reason: 'missing_recipients',
        milestone: normalized,
        recipientClass: recipientClass,
        token: token,
        orderId: trimString_(orderSummary.orderId),
        paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        sessionId: trimString_(orderSummary.stripeSessionId),
        invoicePdfPresent: !!trimString_(orderSummary.invoicePdfUrl),
        attachmentRequired: attachmentRequired
      });
      return null;
    }
    const queueSheet = getPortalEmailQueueSheet_(ss);
    const invoiceInfo = (opts.invoiceInfo && typeof opts.invoiceInfo === 'object') ? opts.invoiceInfo : {};
    const idempotencyKey = buildPaymentLifecycleEmailIdempotencyKey_(normalized, recipientClass, orderSummary, recipients, token, scheduleMeta);
    const jobInfo = upsertPortalEmailQueueJob_(queueSheet, {
      jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.payment_lifecycle_email,
      idempotencyKey: idempotencyKey,
      token: token,
      recipientsJson: JSON.stringify(recipients),
      portalStateJson: JSON.stringify(Object.assign({}, scheduleMeta, {
        jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.payment_lifecycle_email,
        milestone: normalized,
        recipientClass: recipientClass,
        token: token,
        orderId: trimString_(orderSummary.orderId),
        checkoutAttemptId: trimString_(orderSummary.checkoutAttemptId),
        stripePaymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
        stripeSessionId: trimString_(orderSummary.stripeSessionId),
        paymentMethodSelected: trimString_(orderSummary.paymentMethodSelected),
        invoiceNumber: trimString_(invoiceInfo.invoiceNumber || orderSummary.invoiceNumber),
        attachmentRequired: attachmentRequired,
        queuedFromEventType: trimString_(opts.eventType),
        queuedAt: nowIso_()
      })),
      orderDraftJson: trimString_(orderInfo && orderInfo.rowObjNormalized && orderInfo.rowObjNormalized.orderdraftjson),
      invoicePdfUrl: trimString_(invoiceInfo.invoicePdfUrl || orderSummary.invoicePdfUrl),
      invoiceFileName: trimString_(invoiceInfo.fileName || invoiceInfo.invoiceFileName)
    });
    logPaymentLifecycleEmailQueueEvent_('queued', {
      ok: true,
      milestone: normalized,
      recipientClass: recipientClass,
      token: token,
      orderId: trimString_(orderSummary.orderId),
      paymentIntentId: trimString_(orderSummary.stripePaymentIntentId),
      sessionId: trimString_(orderSummary.stripeSessionId),
      recipientCount: recipients.toList.length,
      ccCount: recipients.ccList.length,
      recipientDomains: summarizeEmailDomainsForLog_(recipients.toList.concat(recipients.ccList)),
      invoicePdfPresent: !!trimString_(invoiceInfo.invoicePdfUrl || orderSummary.invoicePdfUrl),
      attachmentRequired: attachmentRequired,
      status: trimString_(jobInfo && jobInfo.rowObjNormalized && jobInfo.rowObjNormalized.status)
    });
    let finalJobInfo = jobInfo;
    if (isPortalEmailQueueJobEligible_(jobInfo, new Date())) {
      finalJobInfo = tryProcessPortalEmailQueueJobById_(trimString_(jobInfo && jobInfo.rowObjNormalized && jobInfo.rowObjNormalized.jobid), {
        cfg: cfg,
        ss: ss,
        infra: infra,
        queueSheet: queueSheet,
        token: token
      }) || jobInfo;
      if (isPortalEmailQueueJobEligible_(finalJobInfo, new Date())) schedulePortalEmailQueueProcessor_();
    }
    return finalJobInfo;
  } catch (err) {
    logPaymentLifecycleEmailQueueEvent_('error', {
      ok: false,
      milestone: normalized,
      recipientClass: recipientClass,
      orderId: trimString_(orderInfo && orderInfo.rowObjNormalized && orderInfo.rowObjNormalized.orderid),
      error: String((err && err.message) || err)
    });
    return null;
  }
}

function getPurchaseOrderPaymentReminderFeePercentForDays_(daysPastDue) {
  const days = Math.max(0, parseInt(String(daysPastDue || 0), 10) || 0);
  if (days >= PO_PAYMENT_LATE_FEE_MONTH_2_DAY_) return 12.5;
  if (days >= PO_PAYMENT_LATE_FEE_MONTH_1_DAY_) return 7.5;
  if (days >= PO_PAYMENT_LATE_FEE_FIRST_DAY_) return PO_PAYMENT_LATE_FEE_FIRST_PERCENT_;
  return 0;
}

function derivePurchaseOrderPaymentReminderDueMeta_(orderInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = buildPortalOrderSummary_(row);
  const accountInfo = opts.accountInfo || (opts.cfg && opts.ss && opts.infra
    ? getPortalAccountInfoForOrder_(orderInfo, {
      cfg: opts.cfg,
      ss: opts.ss,
      infra: opts.infra
    })
    : null);
  const accountSummary = accountInfo && accountInfo.summary ? accountInfo.summary : {};
  const termsDays = Math.max(
    0,
    parseInt(String(
      accountSummary.approvedPaymentTermsDays ||
      row.approvedpaymenttermsdays ||
      row.approvedPaymentTermsDays ||
      0
    ), 10) || 0
  );
  const termsLabel = trimString_(
    accountSummary.approvedPaymentTermsLabel ||
    row.approvedpaymenttermslabel ||
    row.approvedPaymentTermsLabel
  ) || (termsDays > 0 ? ('Net ' + termsDays) : '');
  const poSubmittedDate = normalizeDashboardCalendarDate_(summary.poSubmittedAt || row.posubmittedat);
  if (!poSubmittedDate) {
    return { ok: false, reason: 'missing_po_submission_date' };
  }
  if (termsDays <= 0) {
    return { ok: false, reason: 'missing_po_payment_terms' };
  }
  const paymentDueDate = addCalendarDaysForDashboard_(termsDays, poSubmittedDate);
  if (!paymentDueDate) {
    return { ok: false, reason: 'missing_payment_due_date' };
  }
  return {
    ok: true,
    accountInfo: accountInfo,
    paymentTermsDays: termsDays,
    paymentTermsLabel: termsLabel || 'approved terms',
    poNumber: trimString_(summary.poNumber),
    poSubmittedDate: poSubmittedDate,
    poSubmittedDateIso: formatScheduleIsoDate_(poSubmittedDate),
    poSubmittedDateLabel: formatDashboardShortDate_(poSubmittedDate),
    paymentDueDate: paymentDueDate,
    paymentDueDateIso: formatScheduleIsoDate_(paymentDueDate),
    paymentDueDateLabel: formatDashboardShortDate_(paymentDueDate),
    projectTotal: roundMoney_(summary.amountGrandTotal || 0),
    projectTotalLabel: formatUsdAmount_(summary.amountGrandTotal || 0)
  };
}

function buildPurchaseOrderPaymentReminderScheduleMeta_(orderInfo, dueMeta, milestone, noticeDate, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const normalized = normalizePaymentLifecycleEmailMilestone_(milestone);
  const meta = (dueMeta && typeof dueMeta === 'object') ? dueMeta : {};
  const summary = buildPortalOrderSummary_((orderInfo && orderInfo.rowObjNormalized) || {});
  const cleanNoticeDate = normalizeDashboardCalendarDate_(noticeDate) || normalizeDashboardCalendarDate_(new Date());
  const dueDate = normalizeDashboardCalendarDate_(meta.paymentDueDate);
  const daysPastDue = dueDate && cleanNoticeDate
    ? Math.max(0, calendarDaysBetweenScheduleDates_(dueDate, cleanNoticeDate))
    : 0;
  const feePercent = Number(opts.feePercent || getPurchaseOrderPaymentReminderFeePercentForDays_(daysPastDue) || 0);
  const feeAmount = feePercent > 0 ? roundMoney_((summary.amountGrandTotal || meta.projectTotal || 0) * (feePercent / 100)) : 0;
  const feeEffectiveDate = opts.feeEffectiveDate ? normalizeDashboardCalendarDate_(opts.feeEffectiveDate) : null;
  const scheduleKey = trimString_(opts.scheduleKey) || [
    normalized,
    trimString_(meta.paymentDueDateIso) || formatScheduleIsoDate_(dueDate),
    formatScheduleIsoDate_(cleanNoticeDate),
    feePercent ? String(feePercent).replace(/\./g, '_') : ''
  ].filter(Boolean).join('_');
  return {
    scheduleKey: scheduleKey,
    paymentDueDate: trimString_(meta.paymentDueDateIso) || formatScheduleIsoDate_(dueDate),
    paymentDueDateLabel: trimString_(meta.paymentDueDateLabel) || (dueDate ? formatDashboardShortDate_(dueDate) : ''),
    paymentTermsDays: Math.max(0, parseInt(String(meta.paymentTermsDays || 0), 10) || 0),
    paymentTermsLabel: trimString_(meta.paymentTermsLabel) || 'your approved terms',
    poNumber: trimString_(meta.poNumber || summary.poNumber),
    poSubmittedDate: trimString_(meta.poSubmittedDateIso) || formatScheduleIsoDate_(meta.poSubmittedDate),
    poSubmittedDateLabel: trimString_(meta.poSubmittedDateLabel),
    noticeDate: formatScheduleIsoDate_(cleanNoticeDate),
    noticeDateLabel: cleanNoticeDate ? formatDashboardShortDate_(cleanNoticeDate) : '',
    daysPastDue: daysPastDue,
    feePercent: feePercent,
    feeAmount: feeAmount,
    feeAmountLabel: feeAmount > 0 ? formatUsdAmount_(feeAmount) : '',
    feeEffectiveDate: feeEffectiveDate ? formatScheduleIsoDate_(feeEffectiveDate) : '',
    feeEffectiveDateLabel: feeEffectiveDate ? formatDashboardShortDate_(feeEffectiveDate) : '',
    projectTotal: roundMoney_(summary.amountGrandTotal || meta.projectTotal || 0),
    projectTotalLabel: trimString_(meta.projectTotalLabel) || formatUsdAmount_(summary.amountGrandTotal || 0),
    scheduledBy: PO_PAYMENT_REMINDER_SCHEDULE_TRIGGER_
  };
}

function buildPurchaseOrderPaymentReminderNotice_(orderInfo, dueMeta, milestone, noticeDate, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const normalized = normalizePaymentLifecycleEmailMilestone_(milestone);
  return {
    milestone: normalized,
    recipientClass: trimString_(opts.recipientClass) === 'team' ? 'team' : 'client',
    meta: buildPurchaseOrderPaymentReminderScheduleMeta_(orderInfo, dueMeta, normalized, noticeDate, opts)
  };
}

function listDuePurchaseOrderPaymentReminderNotices_(orderInfo, dueMeta, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const today = normalizeDashboardCalendarDate_(opts.nowDate || new Date());
  const dueDate = normalizeDashboardCalendarDate_(dueMeta && dueMeta.paymentDueDate);
  if (!today || !dueDate || !isBusinessDayForSchedule_(today)) return [];
  const notices = [];
  const addNotice = function(milestone, noticeDate, extra) {
    notices.push(buildPurchaseOrderPaymentReminderNotice_(orderInfo, dueMeta, milestone, noticeDate, extra));
  };
  const due5BusinessDaysBefore = nextBusinessDayOnOrAfterForSchedule_(addBusinessDaysForSchedule_(-5, dueDate));
  const due1BusinessDayBefore = nextBusinessDayOnOrAfterForSchedule_(addBusinessDaysForSchedule_(-1, dueDate));
  const firstPastDueNoticeDate = nextBusinessDayAfterForSchedule_(dueDate);
  const firstFeeEffectiveDate = addCalendarDaysForDashboard_(PO_PAYMENT_LATE_FEE_FIRST_DAY_, dueDate);
  const firstFeeNoticeDate = nextBusinessDayOnOrAfterForSchedule_(firstFeeEffectiveDate);
  const monthOneFeeEffectiveDate = addCalendarDaysForDashboard_(PO_PAYMENT_LATE_FEE_MONTH_1_DAY_, dueDate);
  const monthOneFeeNoticeDate = nextBusinessDayOnOrAfterForSchedule_(monthOneFeeEffectiveDate);
  const monthTwoFeeEffectiveDate = addCalendarDaysForDashboard_(PO_PAYMENT_LATE_FEE_MONTH_2_DAY_, dueDate);
  const monthTwoFeeNoticeDate = nextBusinessDayOnOrAfterForSchedule_(monthTwoFeeEffectiveDate);

  if (isSameScheduleDate_(today, due5BusinessDaysBefore)) {
    addNotice(PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_due_5bd_before, today, {
      scheduleKey: 'po_payment_due_5bd_before_' + formatScheduleIsoDate_(dueDate)
    });
  }
  if (isSameScheduleDate_(today, due1BusinessDayBefore)) {
    addNotice(PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_due_1bd_before, today, {
      scheduleKey: 'po_payment_due_1bd_before_' + formatScheduleIsoDate_(dueDate)
    });
  }
  if (isSameScheduleDate_(today, firstPastDueNoticeDate)) {
    addNotice(PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_past_due, today, {
      scheduleKey: 'po_payment_past_due_' + formatScheduleIsoDate_(dueDate)
    });
  }
  if (isSameScheduleDate_(today, firstFeeNoticeDate)) {
    addNotice(PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_late_fee_notice, today, {
      scheduleKey: 'po_payment_late_fee_2_5_' + formatScheduleIsoDate_(dueDate),
      feePercent: PO_PAYMENT_LATE_FEE_FIRST_PERCENT_,
      feeEffectiveDate: firstFeeEffectiveDate
    });
  }
  if (firstFeeNoticeDate && monthOneFeeNoticeDate &&
      today.getTime() > firstFeeNoticeDate.getTime() &&
      today.getTime() < monthOneFeeNoticeDate.getTime() &&
      businessDaysBetweenScheduleDates_(firstFeeNoticeDate, today) % 5 === 0) {
    addNotice(PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_late_fee_notice, today, {
      scheduleKey: 'po_payment_late_fee_2_5_followup_' + formatScheduleIsoDate_(today) + '_' + formatScheduleIsoDate_(dueDate),
      feePercent: PO_PAYMENT_LATE_FEE_FIRST_PERCENT_,
      feeEffectiveDate: firstFeeEffectiveDate
    });
  }
  if (isSameScheduleDate_(today, monthOneFeeNoticeDate)) {
    addNotice(PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_late_fee_notice, today, {
      scheduleKey: 'po_payment_late_fee_7_5_' + formatScheduleIsoDate_(dueDate),
      feePercent: PO_PAYMENT_LATE_FEE_FIRST_PERCENT_ + PO_PAYMENT_LATE_FEE_MONTHLY_INCREMENT_PERCENT_,
      feeEffectiveDate: monthOneFeeEffectiveDate
    });
  }
  if (monthOneFeeNoticeDate && monthTwoFeeNoticeDate &&
      today.getTime() > monthOneFeeNoticeDate.getTime() &&
      today.getTime() < monthTwoFeeNoticeDate.getTime() &&
      businessDaysBetweenScheduleDates_(monthOneFeeNoticeDate, today) % 5 === 0) {
    addNotice(PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_late_fee_notice, today, {
      scheduleKey: 'po_payment_late_fee_7_5_followup_' + formatScheduleIsoDate_(today) + '_' + formatScheduleIsoDate_(dueDate),
      feePercent: PO_PAYMENT_LATE_FEE_FIRST_PERCENT_ + PO_PAYMENT_LATE_FEE_MONTHLY_INCREMENT_PERCENT_,
      feeEffectiveDate: monthOneFeeEffectiveDate
    });
  }
  if (isSameScheduleDate_(today, monthTwoFeeNoticeDate)) {
    addNotice(PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_late_fee_notice, today, {
      scheduleKey: 'po_payment_late_fee_12_5_' + formatScheduleIsoDate_(dueDate),
      feePercent: PO_PAYMENT_LATE_FEE_FIRST_PERCENT_ + (PO_PAYMENT_LATE_FEE_MONTHLY_INCREMENT_PERCENT_ * 2),
      feeEffectiveDate: monthTwoFeeEffectiveDate
    });
    addNotice(PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_60_day_team_escalation, today, {
      recipientClass: 'team',
      scheduleKey: 'po_payment_60_day_team_escalation_' + formatScheduleIsoDate_(dueDate),
      feePercent: PO_PAYMENT_LATE_FEE_FIRST_PERCENT_ + (PO_PAYMENT_LATE_FEE_MONTHLY_INCREMENT_PERCENT_ * 2),
      feeEffectiveDate: monthTwoFeeEffectiveDate
    });
  }
  return notices;
}

function listLatestPortalOrderInfosForPaymentReminderSchedule_(ordersSheet) {
  const byToken = {};
  listSheetRowInfos_(ordersSheet).forEach(function(info) {
    const row = info && info.rowObjNormalized ? info.rowObjNormalized : {};
    const summary = buildPortalOrderSummary_(row);
    const token = trimString_(summary.token || row.token);
    if (!token) return;
    if (!byToken[token] || comparePortalOrderInfosDesc_(info, byToken[token]) < 0) {
      byToken[token] = info;
    }
  });
  return Object.keys(byToken).map(function(token) {
    return byToken[token];
  });
}

function resolveAchVerificationReminderAnchorDate_(orderInfo) {
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = buildPortalOrderSummary_(row);
  const candidates = [
    summary.stripeLatestEventAt,
    row.stripelatesteventat,
    row.stripeLatestEventAt,
    summary.lockedAt,
    row.lockedat,
    row.lockedAt,
    summary.createdAt,
    row.createdat,
    row.createdAt
  ];
  for (let i = 0; i < candidates.length; i += 1) {
    const date = normalizeDashboardCalendarDate_(candidates[i]);
    if (date) return date;
  }
  return null;
}

function buildAchVerificationReminderScheduleMeta_(orderInfo, anchorDate, noticeDate) {
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = buildPortalOrderSummary_(row);
  const anchor = normalizeDashboardCalendarDate_(anchorDate);
  const notice = normalizeDashboardCalendarDate_(noticeDate || new Date());
  const reminderDue = anchor ? addCalendarDaysForDashboard_(ACH_VERIFICATION_REMINDER_CALENDAR_DAYS_, anchor) : null;
  return {
    scheduleKey: ACH_VERIFICATION_REMINDER_SCHEDULE_KEY_,
    verificationRequiredDate: formatScheduleIsoDate_(anchor),
    verificationRequiredDateLabel: anchor ? formatDashboardShortDate_(anchor) : '',
    reminderDueDate: formatScheduleIsoDate_(reminderDue),
    reminderDueDateLabel: reminderDue ? formatDashboardShortDate_(reminderDue) : '',
    noticeDate: formatScheduleIsoDate_(notice),
    noticeDateLabel: notice ? formatDashboardShortDate_(notice) : '',
    calendarDaysSinceVerificationRequired: anchor && notice ? Math.max(0, calendarDaysBetweenScheduleDates_(anchor, notice)) : 0,
    stripePaymentIntentId: trimString_(summary.stripePaymentIntentId),
    scheduledBy: PO_PAYMENT_REMINDER_SCHEDULE_TRIGGER_
  };
}

function shouldQueueAchVerificationReminderForOrder_(orderInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  if (!shouldQueueAchLifecycleEmailForOrder_(orderInfo, PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_bank_verification_reminder_email)) return false;
  const anchor = resolveAchVerificationReminderAnchorDate_(orderInfo);
  const today = normalizeDashboardCalendarDate_(opts.nowDate || new Date());
  if (!anchor || !today) return false;
  const reminderDue = addCalendarDaysForDashboard_(ACH_VERIFICATION_REMINDER_CALENDAR_DAYS_, anchor);
  return !!(reminderDue && today.getTime() >= reminderDue.getTime());
}

function queueAchVerificationReminderNotice_(orderInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const anchor = resolveAchVerificationReminderAnchorDate_(orderInfo);
  const meta = buildAchVerificationReminderScheduleMeta_(orderInfo, anchor, opts.nowDate || new Date());
  return queueAchLifecycleClientAndTeamEmailsSafely_(
    orderInfo,
    null,
    PORTAL_EMAIL_QUEUE_JOB_TYPES.ach_bank_verification_reminder_email,
    {
      cfg: opts.cfg,
      ss: opts.ss,
      infra: opts.infra,
      accountInfo: opts.accountInfo,
      meta: meta,
      eventType: 'ach_verification_reminder_schedule'
    }
  );
}

function processAchVerificationReminderSchedule_(options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const result = {
    ok: true,
    scanned: 0,
    eligible: 0,
    queued: 0,
    skipped: 0,
    errors: [],
    achVerification: null
  };
  try {
    const cfg = opts.cfg || getConfig_();
    const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
    const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
    const nowDate = normalizeDashboardCalendarDate_(opts.nowDate || new Date()) || new Date();
    const orderInfos = listLatestPortalOrderInfosForPaymentReminderSchedule_(infra.ordersSheet);
    orderInfos.forEach(function(orderInfo) {
      result.scanned += 1;
      try {
        if (!shouldQueueAchVerificationReminderForOrder_(orderInfo, { nowDate: nowDate })) {
          result.skipped += 1;
          return;
        }
        const accountInfo = getPortalAccountInfoForOrder_(orderInfo, {
          cfg: cfg,
          ss: ss,
          infra: infra
        });
        const queued = queueAchVerificationReminderNotice_(orderInfo, {
          cfg: cfg,
          ss: ss,
          infra: infra,
          accountInfo: accountInfo,
          nowDate: nowDate
        });
        result.eligible += 1;
        if (queued && queued.clientJob) result.queued += 1;
        if (queued && queued.teamJob) result.queued += 1;
      } catch (err) {
        result.errors.push(String((err && err.message) || err));
      }
    });
    if (result.errors.length) result.ok = false;
    console.log('[RT-ACH-VERIFICATION-REMINDER-SCHEDULE] ' + JSON.stringify(result));
    return result;
  } catch (err) {
    result.ok = false;
    result.errors.push(String((err && err.message) || err));
    console.log('[RT-ACH-VERIFICATION-REMINDER-SCHEDULE] ' + JSON.stringify(result));
    return result;
  }
}

function processAchVerificationReminderSchedule(options) {
  const lock = LockService.getScriptLock();
  if (!lock.tryLock(30000)) {
    return { ok: false, reason: 'lock_busy' };
  }
  try {
    return processAchVerificationReminderSchedule_(options);
  } finally {
    lock.releaseLock();
  }
}

function queuePurchaseOrderPaymentReminderNotice_(orderInfo, notice, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const safeNotice = (notice && typeof notice === 'object') ? notice : {};
  const milestone = normalizePaymentLifecycleEmailMilestone_(safeNotice.milestone);
  if (!milestone) return null;
  return queuePaymentLifecycleEmailJobSafely_(orderInfo, null, milestone, {
    cfg: opts.cfg,
    ss: opts.ss,
    infra: opts.infra,
    accountInfo: opts.accountInfo,
    recipientClass: trimString_(safeNotice.recipientClass) === 'team' ? 'team' : 'client',
    meta: (safeNotice.meta && typeof safeNotice.meta === 'object') ? safeNotice.meta : {},
    eventType: 'po_payment_reminder_schedule'
  });
}

function processPurchaseOrderPaymentReminderSchedule(options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const lock = LockService.getScriptLock();
  if (!lock.tryLock(30000)) {
    return { ok: false, reason: 'lock_busy' };
  }
  const result = {
    ok: true,
    scanned: 0,
    eligible: 0,
    queued: 0,
    skipped: 0,
    errors: []
  };
  try {
    const cfg = opts.cfg || getConfig_();
    const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
    const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
    const nowDate = normalizeDashboardCalendarDate_(opts.nowDate || new Date()) || new Date();
    const orderInfos = listLatestPortalOrderInfosForPaymentReminderSchedule_(infra.ordersSheet);
    orderInfos.forEach(function(orderInfo) {
      result.scanned += 1;
      try {
        if (!shouldQueuePaymentLifecycleEmailForOrder_(orderInfo, PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_due_5bd_before)) {
          result.skipped += 1;
          return;
        }
        const accountInfo = getPortalAccountInfoForOrder_(orderInfo, {
          cfg: cfg,
          ss: ss,
          infra: infra
        });
        const dueMeta = derivePurchaseOrderPaymentReminderDueMeta_(orderInfo, {
          cfg: cfg,
          ss: ss,
          infra: infra,
          accountInfo: accountInfo
        });
        if (!dueMeta.ok) {
          result.skipped += 1;
          return;
        }
        const notices = listDuePurchaseOrderPaymentReminderNotices_(orderInfo, dueMeta, {
          nowDate: nowDate
        });
        if (!notices.length) {
          result.eligible += 1;
          result.skipped += 1;
          return;
        }
        result.eligible += 1;
        notices.forEach(function(notice) {
          const jobInfo = queuePurchaseOrderPaymentReminderNotice_(orderInfo, notice, {
            cfg: cfg,
            ss: ss,
            infra: infra,
            accountInfo: accountInfo
          });
          if (jobInfo) result.queued += 1;
        });
      } catch (err) {
        result.errors.push(String((err && err.message) || err));
      }
    });
    const achVerificationResult = processAchVerificationReminderSchedule_({
      cfg: cfg,
      ss: ss,
      infra: infra,
      nowDate: nowDate
    });
    result.achVerification = achVerificationResult;
    if (!achVerificationResult || achVerificationResult.ok !== true) result.ok = false;
    if (result.errors.length) result.ok = false;
    console.log('[RT-PO-PAYMENT-REMINDER-SCHEDULE] ' + JSON.stringify(result));
    return result;
  } catch (err) {
    result.ok = false;
    result.errors.push(String((err && err.message) || err));
    console.log('[RT-PO-PAYMENT-REMINDER-SCHEDULE] ' + JSON.stringify(result));
    return result;
  } finally {
    lock.releaseLock();
  }
}

function resolvePaymentLifecycleOrderForQueueJob_(jobInfo, options) {
  const row = jobInfo && jobInfo.rowObjNormalized ? jobInfo.rowObjNormalized : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const meta = safeJsonParse_(row.portalstatejson, {}) || {};
  const orderId = trimString_(meta.orderId);
  const paymentIntentId = trimString_(meta.stripePaymentIntentId);
  const sessionId = trimString_(meta.stripeSessionId);
  const checkoutAttemptId = trimString_(meta.checkoutAttemptId);
  const token = trimString_(row.token || meta.token);
  return (orderId ? getPortalOrderByOrderId_(orderId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null) ||
    (paymentIntentId ? getPortalOrderByStripePaymentIntentId_(paymentIntentId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null) ||
    (sessionId ? getPortalOrderByStripeSessionId_(sessionId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null) ||
    (checkoutAttemptId ? getPortalOrderByCheckoutAttemptId_(checkoutAttemptId, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null) ||
    (token ? getLatestPortalOrderByToken_(token, { cfg: cfg, ss: ss, ordersSheet: infra.ordersSheet }) : null);
}

function resolvePaymentLifecycleInvoiceInfo_(orderInfo, milestone, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const row = orderInfo && orderInfo.rowObjNormalized ? orderInfo.rowObjNormalized : {};
  const summary = buildPortalOrderSummary_(row);
  const queued = (opts.queuedInvoiceInfo && typeof opts.queuedInvoiceInfo === 'object') ? opts.queuedInvoiceInfo : {};
  const baseInfo = {
    invoiceNumber: trimString_(queued.invoiceNumber) || trimString_(summary.invoiceNumber),
    invoicePdfUrl: trimString_(queued.invoicePdfUrl) || trimString_(summary.invoicePdfUrl),
    fileName: trimString_(queued.fileName || queued.invoiceFileName)
  };
  return attachPortalDocumentReferenceToInvoiceInfo_(baseInfo, orderInfo, {
    documentKind: isPaymentLifecycleReceiptMilestone_(milestone)
      ? PORTAL_DOCUMENT_KINDS.receipt
      : PORTAL_DOCUMENT_KINDS.invoice,
    forceFileName: isPaymentLifecycleReceiptMilestone_(milestone)
  });
}

function getPaymentLifecycleCtaLabel_(milestone) {
  const normalized = normalizePaymentLifecycleEmailMilestone_(milestone);
  if (isPaymentLifecycleReceiptMilestone_(normalized)) return 'View Red Threads receipt';
  if (isPaymentLifecycleFailureMilestone_(normalized)) return 'View Red Threads invoice';
  return 'View Red Threads invoice';
}

function buildPaymentLifecycleInstructionsBlock_(milestone, orderSummary) {
  const normalized = normalizePaymentLifecycleEmailMilestone_(milestone);
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const method = trimString_(summary.paymentMethodSelected).toLowerCase();
  if (normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.manual_pending &&
      (method === PAYMENT_METHODS.check || method === PAYMENT_METHODS.cash)) {
    return {
      text: buildLifecycleEmailTextBlock_('Payment instructions', [buildCheckPaymentInstructionsText_(summary)]),
      html: buildCheckPaymentInstructionsHtml_(summary)
    };
  }
  return { text: '', html: '' };
}

function resolvePaymentLifecycleEmailNextStepText_(milestone, fallbackNextStepText, options) {
  const normalized = normalizePaymentLifecycleEmailMilestone_(milestone);
  const opts = (options && typeof options === 'object') ? options : {};
  const isTeamAlert = opts.isTeamAlert === true;
  if (!isTeamAlert && normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_submitted) {
    return 'Return to the portal/project to pay for the order within your approved terms. Late fees will automatically be applied.';
  }
  if (isPaymentLifecycleReceiptMilestone_(normalized)) {
    return isTeamAlert
      ? 'Continue production and update job completion dates in Team Mode when work is finished.'
      : 'No action is needed while production continues.';
  }
  return trimString_(fallbackNextStepText);
}

function buildPaymentLifecycleEmailContent_(milestone, orderInfo, invoiceInfo, options) {
  const normalized = normalizePaymentLifecycleEmailMilestone_(milestone);
  const opts = (options && typeof options === 'object') ? options : {};
  const recipientClass = trimString_(opts.recipientClass) === 'team' ? 'team' : 'client';
  const scheduleMeta = (opts.scheduleMeta && typeof opts.scheduleMeta === 'object')
    ? opts.scheduleMeta
    : ((opts.meta && typeof opts.meta === 'object') ? opts.meta : {});
  const emailContext = buildLifecycleEmailContextForOrder_(orderInfo, invoiceInfo, Object.assign({}, opts, {
    milestone: normalized,
    recipientClass: recipientClass,
    ctaLabel: getPaymentLifecycleCtaLabel_(normalized)
  }));
  if (isPaymentLifecycleFailureMilestone_(normalized)) {
    if (recipientClass !== 'team') {
      const retryProjectNumber = getLifecycleEmailProjectNumberLabel_(emailContext);
      emailContext.ctaLabel = retryProjectNumber
        ? ('Click to access Project #' + retryProjectNumber + ' and retry payment')
        : 'Click to access your project and retry payment';
    }
    applyPaymentBlockedLifecycleEmailContext_(emailContext, {
      paymentBlocked: true,
      nextStepText: recipientClass === 'team'
        ? 'Review the failed payment in Team Mode.'
        : 'Open your Red Threads project/portal below and retry payment to begin order production.'
    });
  }
  if (recipientClass !== 'team' &&
      (normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.manual_pending ||
        normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_submitted)) {
    emailContext.ctaLabel = buildLifecycleEmailProjectAccessCtaLabel_(emailContext, 'make a payment.');
  }
  if (isClientScheduledPoPaymentReminderMilestone_(normalized)) {
    const projectNumber = getLifecycleEmailProjectNumberLabel_(emailContext);
    emailContext.ctaLabel = projectNumber
      ? ('Click to access Project #' + projectNumber + ' and make a payment.')
      : 'Click to access your project and make a payment.';
  }
  if (recipientClass === 'team' &&
      normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_60_day_team_escalation) {
    emailContext.ctaLabel = buildLifecycleEmailTeamModeProjectCtaLabel_(
      getLifecycleEmailProjectNumberLabel_(emailContext),
      ''
    );
  }
  const summary = emailContext.orderSummary || {};
  const productionCompleteForReceipt = isLifecycleEmailProductionCompleteForReceipt_(emailContext);
  const method = trimString_(summary.paymentMethodSelected).toLowerCase();
  const methodLabel = getPaymentLifecycleMethodLabel_(method);
  const isTeamAlert = recipientClass === 'team';
  const isCardFailedTeamAlert = isTeamAlert && normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.card_failed;
  const copy = buildPaymentLifecycleEmailCopy_(normalized, emailContext, {
    isTeamAlert: isTeamAlert,
    methodLabel: methodLabel,
    scheduleMeta: scheduleMeta,
    attachmentPresent: opts.attachmentPresent === true
  });
  const nextStepText = resolvePaymentLifecycleEmailNextStepText_(normalized, emailContext.nextStepText, {
    isTeamAlert: isTeamAlert
  });
  const useTeamActionModel = isTeamAlert && !isScheduledPoPaymentReminderMilestone_(normalized);
  const teamActionOverride = isCardFailedTeamAlert
    ? 'monitor_payment'
    : (isPaymentLifecycleFailureMilestone_(normalized)
      ? 'review_payment_issue'
      : ([
        PAYMENT_LIFECYCLE_EMAIL_MILESTONES.card_paid,
        PAYMENT_LIFECYCLE_EMAIL_MILESTONES.manual_received,
        PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_payment_received
      ].indexOf(normalized) >= 0
        ? (productionCompleteForReceipt ? '' : 'move_through_production')
        : ''));
  const teamActionModel = useTeamActionModel
    ? resolveLifecycleTeamEmailActionModel_(emailContext, {
      family: 'payment_lifecycle',
      milestone: normalized,
      title: copy.actionTitle,
      intro: copy.intro,
      statusCopy: copy.statusCopy,
      nextStep: copy.nextStep,
      nextStepLabel: copy.nextStepLabel,
      nextStepTone: copy.nextStepTone,
      nextStepHtml: copy.nextStepHtml,
      statusAfterAttachment: copy.actionStatusAfterAttachment === true,
      suppressActionCardCta: copy.suppressActionCardCta === true,
      suppressStandaloneCta: copy.suppressStandaloneCta === true,
      teamAction: teamActionOverride
    })
    : null;
  const sectionBlocks = buildLifecycleEmailSectionBlocks_(emailContext, {
    family: 'payment_lifecycle',
    milestone: normalized,
    recipientClass: recipientClass
  });
  const paymentLifecycleCtaBlock = teamActionModel && teamActionModel.suppressStandaloneCta
    ? null
    : buildLifecycleEmailCtaBlock_(
      teamActionModel ? teamActionModel.ctaLabel : (copy.ctaLabel || emailContext.ctaLabel),
      teamActionModel ? teamActionModel.ctaUrl : emailContext.ctaUrl,
      {
        align: teamActionModel
          ? teamActionModel.ctaAlign
          : (copy.ctaAlign || (recipientClass !== 'team' && (
            isPaymentLifecycleFailureMilestone_(normalized) ||
            isClientScheduledPoPaymentReminderMilestone_(normalized) ||
            normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.manual_pending ||
            normalized === PAYMENT_LIFECYCLE_EMAIL_MILESTONES.po_submitted
          ) ? 'center' : '')),
        teamModePassword: teamActionModel ? teamActionModel.teamModePassword : ''
      }
    );
  const shell = buildLifecycleEmailShell_({
    eyebrow: isTeamAlert ? getPortalNativeEmailEyebrow_('team') : '',
    heading: copy.heading,
    badgeLabel: copy.badgeLabel || getLifecycleEmailCurrentStepLabel_(emailContext.steps),
    actionTitle: teamActionModel ? teamActionModel.title : copy.actionTitle,
    actionTitleTone: teamActionModel ? '' : copy.actionTitleTone,
    intro: teamActionModel ? teamActionModel.intro : copy.intro,
    statusCopy: teamActionModel ? teamActionModel.statusCopy : copy.statusCopy,
    nextStep: teamActionModel ? teamActionModel.nextStep : (copy.nextStep || nextStepText),
    nextStepHtml: teamActionModel ? teamActionModel.nextStepHtml : copy.nextStepHtml,
    nextStepLabel: teamActionModel ? teamActionModel.nextStepLabel : copy.nextStepLabel,
    nextStepTone: teamActionModel ? teamActionModel.nextStepTone : copy.nextStepTone,
    actionStatusAfterAttachment: teamActionModel ? teamActionModel.statusAfterAttachment === true : false,
    suppressActionCardCta: teamActionModel ? teamActionModel.suppressActionCardCta : copy.suppressActionCardCta === true,
    attachmentNote: copy.attachmentNote,
    productionTimingLine: copy.productionTimingLine,
    recipientClass: recipientClass,
    blocks: sectionBlocks.concat([
      buildPaymentLifecycleInstructionsBlock_(normalized, emailContext.orderSummary),
      paymentLifecycleCtaBlock,
      buildLifecycleEmailFooter_()
    ].filter(Boolean))
  });
  const communicationContract = buildPortalCommunicationContext_({
    emailContext: emailContext
  }, {
    family: 'payment_lifecycle',
    trigger: normalized,
    recipientClass: recipientClass,
    meta: scheduleMeta,
    documentLabel: trimString_(emailContext.invoiceNumber),
    cfg: opts.cfg,
    ss: opts.ss,
    infra: opts.infra
  });
  return {
    subject: copy.subject,
    body: shell.body,
    htmlBody: shell.htmlBody,
    reviewSurface: shell.reviewSurface,
    communicationContract: communicationContract
  };
}

function processPaymentLifecycleEmailQueueJob_(jobInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const row = jobInfo && jobInfo.rowObjNormalized ? jobInfo.rowObjNormalized : {};
  const meta = safeJsonParse_(row.portalstatejson, {}) || {};
  const milestone = normalizePaymentLifecycleEmailMilestone_(meta.milestone);
  const recipientClass = trimString_(meta.recipientClass) === 'team' ? 'team' : 'client';
  if (!milestone) throw new Error('Payment lifecycle email queue job is missing a milestone.');
  const orderInfo = resolvePaymentLifecycleOrderForQueueJob_(jobInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra
  });
  if (!orderInfo) throw new Error('Payment lifecycle queue order could not be found.');
  const milestonePolicy = resolveCommunicationMilestonePolicy_(
    PORTAL_EMAIL_QUEUE_JOB_TYPES.payment_lifecycle_email,
    milestone,
    orderInfo,
    {
      meta: meta,
      recipientClass: recipientClass
    }
  );
  if (milestonePolicy.enabled === false) {
    return { skipped: true, skipReason: milestonePolicy.reason, invoiceInfo: null };
  }
  if (!shouldQueuePaymentLifecycleEmailForOrder_(orderInfo, milestone)) {
    return { skipped: true, skipReason: 'state_not_eligible_for_' + milestone, invoiceInfo: null };
  }
  const recipients = parseAchLifecycleEmailQueueRecipients_(row.recipientsjson);
  if (!recipients.toList.length) throw new Error('Payment lifecycle email queue job has no recipients.');
  const queuedInvoiceInfo = {
    invoiceNumber: trimString_(meta.invoiceNumber),
    invoicePdfUrl: trimString_(row.invoicepdfurl),
    fileName: trimString_(row.invoicefilename)
  };
  const invoiceInfo = resolvePaymentLifecycleInvoiceInfo_(orderInfo, milestone, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    queuedInvoiceInfo: queuedInvoiceInfo
  });
  const attachmentPolicy = resolveLifecycleEmailAttachmentPolicy_('payment_lifecycle', milestone, {});
  const attachmentResult = resolveLifecycleEmailAttachment_(Object.assign({}, buildPortalOrderSummary_(orderInfo.rowObjNormalized), {
    invoiceNumber: trimString_(invoiceInfo && invoiceInfo.invoiceNumber),
    invoicePdfUrl: trimString_(invoiceInfo && invoiceInfo.invoicePdfUrl)
  }), attachmentPolicy, {
    fileNameOverride: trimString_(invoiceInfo && invoiceInfo.fileName)
  });
  if (attachmentResult.ok !== true) throw new Error(attachmentResult.error || LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.required_portal_rendered_invoice);
  const content = buildPaymentLifecycleEmailContent_(milestone, orderInfo, invoiceInfo, {
    cfg: cfg,
    ss: ss,
    infra: infra,
    recipientClass: recipientClass,
    scheduleMeta: meta,
    attachmentPresent: !!(attachmentResult.attachments && attachmentResult.attachments.length)
  });
  const emailResult = sendNotificationEmail_({
    toList: recipients.toList,
    ccList: recipients.ccList,
    subject: content.subject,
    body: content.body,
    htmlBody: content.htmlBody,
    attachments: attachmentResult.attachments,
    fromAlias: NOTIFICATION_FROM_ALIAS,
    replyTo: NOTIFICATION_FROM_ALIAS
  });
  if (!emailResult || emailResult.ok !== true) {
    throw new Error(trimString_(emailResult && emailResult.error) || 'Payment lifecycle email could not be sent.');
  }
  const summary = buildPortalOrderSummary_(orderInfo.rowObjNormalized);
  const token = getPaymentLifecycleOrderToken_(orderInfo, summary);
  logPaymentLifecycleEmailQueueEvent_('sent', {
    ok: true,
    milestone: milestone,
    recipientClass: recipientClass,
    token: token,
    orderId: trimString_(summary.orderId),
    paymentIntentId: trimString_(summary.stripePaymentIntentId),
    sessionId: trimString_(summary.stripeSessionId),
    recipientCount: recipients.toList.length,
    ccCount: recipients.ccList.length,
    recipientDomains: summarizeEmailDomainsForLog_(recipients.toList.concat(recipients.ccList)),
    invoicePdfPresent: !!trimString_(invoiceInfo && invoiceInfo.invoicePdfUrl),
    attachmentRequired: isRequiredLifecycleEmailAttachmentPolicy_(attachmentPolicy.policy),
    attachmentPresent: !!(attachmentResult.attachments && attachmentResult.attachments.length),
    status: PORTAL_EMAIL_QUEUE_STATUSES.sent
  });
  return {
    invoiceInfo: invoiceInfo
  };
}

function buildLifecycleEmailDateLabel_(value) {
  const label = trimString_(value) ? formatDashboardShortDate_(value) : '';
  return label || '';
}

function isLifecycleEmailProductionActive_(workflowContext, orderSummary) {
  const ctx = (workflowContext && typeof workflowContext === 'object') ? workflowContext : {};
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const orderState = trimString_(ctx.orderState || summary.orderState).toLowerCase();
  const paymentState = trimString_(ctx.paymentState || summary.paymentState).toLowerCase();
  const productionComplete = ctx.productionComplete === true
    || orderState === ORDER_STATES.closed;
  if (
    ctx.productionCurrent === true ||
    ctx.isProductionAuthorized === true ||
    ctx.productionAuthorized === true ||
    productionComplete
  ) {
    return true;
  }
  return isPortalProductionStartTriggerActive_({
    isPaymentReceived: ctx.isPaymentReceived === true
      || ctx.paymentReceived === true
      || !!trimString_(ctx.paymentReceivedAt || summary.paymentReceivedManuallyAt || summary.paidAt)
      || paymentState === PAYMENT_STATES.paid
      || paymentState === PAYMENT_STATES.manual_received,
    isPoSubmitted: ctx.isPoSubmitted === true
      || ctx.poSubmitted === true
      || !!trimString_(ctx.poSubmittedAt || summary.poSubmittedAt || ctx.poNumber || summary.poNumber),
    orderState: orderState,
    hasAnyCompletionSignal: productionComplete
  });
}

function resolveLifecycleEmailProductionStartAt_(workflowContext, orderSummary) {
  if (!isLifecycleEmailProductionActive_(workflowContext, orderSummary)) return '';
  const ctx = (workflowContext && typeof workflowContext === 'object') ? workflowContext : {};
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  return trimString_(ctx.productionStartAt || summary.authorizedToProduceAt);
}

function buildLifecycleEmailFallbackTimeline_(workflowContext, orderSummary) {
  const ctx = (workflowContext && typeof workflowContext === 'object') ? workflowContext : {};
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const termsDays = Math.max(0, parseInt(String(ctx.approvedPaymentTermsDays || summary.approvedPaymentTermsDays || 0), 10) || 0);
  const poSubmittedDate = normalizeDashboardCalendarDate_(ctx.poSubmittedAt || summary.poSubmittedAt);
  const paymentDueDate = termsDays > 0 && poSubmittedDate ? addCalendarDaysForDashboard_(termsDays, poSubmittedDate) : null;
  return {
    orderPlacedDateLabel: buildLifecycleEmailDateLabel_(ctx.orderPlacedAt || summary.lockedAt || summary.createdAt),
    paidDateLabel: buildLifecycleEmailDateLabel_(ctx.paymentReceivedAt || summary.paidAt),
    printStartDateLabel: buildLifecycleEmailDateLabel_(resolveLifecycleEmailProductionStartAt_(ctx, summary)),
    completionDateLabel: buildLifecycleEmailDateLabel_(ctx.productionCompletionAt),
    poSubmittedDateLabel: buildLifecycleEmailDateLabel_(ctx.poSubmittedAt || summary.poSubmittedAt),
    paymentDueDateValue: paymentDueDate ? paymentDueDate.getTime() : null,
    paymentDueDateLabel: paymentDueDate ? formatDashboardShortDate_(paymentDueDate) : '',
    paymentTermsLabel: trimString_(ctx.approvedPaymentTermsLabel || summary.approvedPaymentTermsLabel) || (termsDays > 0 ? ('Net ' + termsDays) : ''),
    paymentMethodLabel: 'ACH',
    poNumber: trimString_(ctx.poNumber || summary.poNumber)
  };
}

function buildLifecycleEmailFallbackReadiness_(workflowContext, orderSummary) {
  const ctx = (workflowContext && typeof workflowContext === 'object') ? workflowContext : {};
  const summary = (orderSummary && typeof orderSummary === 'object') ? orderSummary : {};
  const includedJobCount = Array.isArray(summary.selectedJobs) ? summary.selectedJobs.length : 0;
  const hasPlacedOrder = ctx.hasPlacedOrder === true || ctx.orderPlaced === true;
  return {
    hasIncludedJobs: includedJobCount > 0 || hasPlacedOrder,
    minimumsMet: includedJobCount > 0 || hasPlacedOrder,
    qtySizesComplete: hasPlacedOrder,
    artworkApprovalComplete: hasPlacedOrder,
    includedJobCount: includedJobCount
  };
}

function buildLifecycleEmailTextBlock_(title, lines) {
  const cleanTitle = trimString_(title);
  const cleanLines = uniqueTrimmedStrings_(lines);
  if (!cleanLines.length) return '';
  return [cleanTitle ? (cleanTitle + ':') : ''].concat(cleanLines).filter(Boolean).join('\n');
}

