function sendNotificationEmail_(options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const recipients = normalizeEmailRecipients_(opts.toList || opts.to);
  const ccRecipients = normalizeEmailRecipients_(opts.ccList || opts.cc);
  if (!recipients.length) return { ok: false, skipped: true, reason: 'missing-email' };

  const message = {
    to: recipients.join(','),
    subject: trimString_(opts.subject),
    body: String(opts.body || '').trim() || 'Red Threads notification.',
    name: NOTIFICATION_SENDER_NAME,
    noReply: true
  };
  const htmlBody = trimString_(opts.htmlBody);
  if (htmlBody) {
    message.htmlBody = htmlBody;
  }
  if (ccRecipients.length) {
    message.cc = ccRecipients.join(',');
  }
  if (Array.isArray(opts.attachments) && opts.attachments.length) {
    message.attachments = opts.attachments;
  }

  MailApp.sendEmail(message);
  return {
    ok: true,
    email: recipients[0],
    emails: recipients,
    ccEmails: ccRecipients,
    noReply: true,
    senderName: NOTIFICATION_SENDER_NAME,
    transport: 'mailapp_noreply'
  };
}

function fetchSummaryExportImageData(payload) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  const urls = Array.isArray(p.urls) ? p.urls : [];
  const assets = [];
  const seen = {};
  urls.forEach(function(item) {
    const sourceUrl = trimString_(item);
    if (!/^https?:\/\//i.test(sourceUrl) || seen[sourceUrl]) return;
    seen[sourceUrl] = true;
    try {
      const driveFileId = extractDriveFileIdFromUrl_(sourceUrl);
      if (driveFileId) {
        const driveAsset = buildDriveBinaryDataPayload_(driveFileId, 'summary-export-image', 'image/png');
        if (driveAsset && trimString_(driveAsset.base64Data)) {
          assets.push({
            url: sourceUrl,
            mimeType: trimString_(driveAsset.mimeType) || 'image/png',
            dataUrl: 'data:' + (trimString_(driveAsset.mimeType) || 'image/png') + ';base64,' + trimString_(driveAsset.base64Data)
          });
          return;
        }
      }
      const response = UrlFetchApp.fetch(sourceUrl, {
        followRedirects: true,
        muteHttpExceptions: true
      });
      const statusCode = Number(response && response.getResponseCode && response.getResponseCode()) || 0;
      if (statusCode < 200 || statusCode >= 300) return;
      const blob = response.getBlob();
      const bytes = blob && typeof blob.getBytes === 'function' ? blob.getBytes() : [];
      if (!bytes || !bytes.length) return;
      const mimeType = trimString_(blob.getContentType()) || 'image/png';
      assets.push({
        url: sourceUrl,
        mimeType: mimeType,
        dataUrl: 'data:' + mimeType + ';base64,' + Utilities.base64Encode(bytes)
      });
    } catch (_) {}
  });
  return {
    ok: true,
    assets: assets
  };
}

function sendSummaryEstimatePdfEmail(payload) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  const recipients = normalizeEmailRecipients_(p.recipients || p.to || p.toList);
  if (!recipients.length) {
    throw new Error('Enter at least one valid email address.');
  }
  const base64Data = trimString_(p.base64Data || p.fileDataBase64 || p.fileBase64);
  if (!base64Data) {
    throw new Error('Summary PDF payload is missing.');
  }
  const bytes = Utilities.base64Decode(base64Data);
  if (!bytes || !bytes.length) {
    throw new Error('Unable to read the Summary PDF.');
  }
  if (bytes.length > MAX_SUMMARY_EXPORT_PDF_BYTES) {
    throw new Error('Summary PDF must be 20 MB or smaller.');
  }

  const dealNumber = trimString_(p.dealNumber);
  const projectName = trimString_(p.projectName);
  const token = trimString_(p.token);
  const documentKind = trimString_(p.documentKind).toLowerCase() === 'invoice'
    ? PORTAL_DOCUMENT_KINDS.invoice
    : PORTAL_DOCUMENT_KINDS.estimate;
  const parsedPayloadRef = parsePortalDocumentReference_(p.documentRef || p.documentReference);
  const payloadProjectNumber = getPortalDocumentProjectNumber_({
    projectNumber: dealNumber,
    dealNumber: dealNumber,
    documentReference: p.documentReference,
    documentRef: p.documentRef,
    fileName: p.fileName
  });
  const shouldUseParsedRef = parsedPayloadRef && !isGenericPortalDocumentProjectNumber_(parsedPayloadRef.projectNumber);
  const documentReference = shouldUseParsedRef ? parsedPayloadRef : buildPortalDocumentReference_({
    projectNumber: payloadProjectNumber || (parsedPayloadRef && parsedPayloadRef.projectNumber),
    documentKind: documentKind,
    version: p.documentVersion || (parsedPayloadRef && parsedPayloadRef.version) || 1
  });
  const fileName = sanitizeUploadedDocumentName_(documentReference.fileName, documentReference.fileName);
  const blob = Utilities.newBlob(bytes, trimString_(p.mimeType) || MimeType.PDF, fileName);
  if (doesPdfBlobContainLegacyInvoiceMarker_(blob)) {
    throw new Error(LIFECYCLE_EMAIL_ATTACHMENT_SAFE_ERRORS.non_portal_rendered_invoice);
  }
  const subject = documentKind === PORTAL_DOCUMENT_KINDS.estimate
    ? buildPortalEstimateEmailSubject_(documentReference)
    : buildPortalEmailSubject_(buildActionNeededSubject_('Payment needed'), documentReference);
  let lifecycleSections = { blocks: [] };
  let senderName = trimString_(
    p.clientName ||
    p.senderName ||
    p.sentByName ||
    p.personName ||
    p.purchaserName ||
    p.contactName
  );
  if (token) {
    try {
      const displayCtx = buildOrderActionContext_({
        token: token,
        createAccountIfMissing: false
      });
      lifecycleSections = buildDirectLifecycleEmailSectionBlocks_(displayCtx, null, {
        family: 'summary_pdf',
        recipientClass: 'client'
      });
      if (!senderName) {
        const accountSummary = displayCtx && displayCtx.accountInfo && displayCtx.accountInfo.summary;
        senderName = trimString_(
          displayCtx && displayCtx.orderDraft && displayCtx.orderDraft.personName ||
          accountSummary && (accountSummary.billingContactName || accountSummary.primaryContactName) ||
          displayCtx && displayCtx.row && (displayCtx.row.personname || displayCtx.row.clientname || displayCtx.row.primarycontactname)
        );
      }
    } catch (err) {
      lifecycleSections = { blocks: [] };
    }
  }
  if (token && documentKind === PORTAL_DOCUMENT_KINDS.estimate) {
    try {
      const cfg = getConfig_();
      const ss = SpreadsheetApp.openById(cfg.sheetId);
      const exportSheet = ss.getSheetByName(cfg.exportLogSheetName);
      const rowInfo = exportSheet ? findRowByToken_(exportSheet, token) : null;
      if (rowInfo) {
        const existingState = safeJsonParse_(rowInfo.rowObjNormalized.portalstatejson, {}) || { printJobs: {} };
        const nextState = JSON.parse(JSON.stringify(existingState));
        if (!nextState.documentReferences || typeof nextState.documentReferences !== 'object' || Array.isArray(nextState.documentReferences)) {
          nextState.documentReferences = {};
        }
        const digest = Utilities.computeDigest(Utilities.DigestAlgorithm.SHA_256, bytes);
        const fingerprint = trimString_(p.documentFingerprint) || Utilities.base64EncodeWebSafe(digest).replace(/=+$/g, '');
        nextState.documentReferences.estimate = {
          projectNumber: documentReference.projectNumber,
          documentKind: PORTAL_DOCUMENT_KINDS.estimate,
          version: documentReference.version,
          documentRef: documentReference.documentRef,
          displayLabel: documentReference.displayLabel,
          fileName: documentReference.fileName,
          currentFingerprint: fingerprint,
          currentComparableKey: trimString_(p.documentFingerprint),
          updatedAt: nowIso_()
        };
        persistPortalStateForRow_(exportSheet, rowInfo, nextState, {
          token: token,
          locked: isLockedPortalRow_(rowInfo.rowObjNormalized, existingState),
          clearSubmittedAt: false
        });
      }
    } catch (err) {
      console.log('[RT-DOCUMENT-REFERENCE-PERSIST] ' + String((err && err.message) || err));
    }
  }
  const lifecycleText = lifecycleSections.blocks.map(function(block) {
    return trimString_(block && block.text);
  }).filter(Boolean).join('\n\n');
  const lifecycleHtml = lifecycleSections.blocks.map(function(block) {
    return trimString_(block && block.html);
  }).filter(Boolean).join('\n');
  const isEstimateDocument = documentKind === PORTAL_DOCUMENT_KINDS.estimate;
  const communicationContract = !isEstimateDocument
    ? buildPortalCommunicationContext_({
      emailContext: lifecycleSections.emailContext
    }, {
      family: 'summary_pdf',
      trigger: 'direct_document_send',
      recipientClass: 'client',
      documentLabel: documentReference.displayLabel
    })
    : null;
  const attachmentSentence = isEstimateDocument
    ? buildPortalEstimateEmailAttachmentSentence_(documentReference)
    : ((communicationContract && communicationContract.intro) || (documentReference.displayLabel + ' is attached.'));
  const fallbackDetailText = isEstimateDocument
    ? ''
    : [
      dealNumber ? ('Project #: ' + dealNumber) : '',
      projectName ? ('Project Name: ' + projectName) : ''
    ].filter(Boolean).join('\n');
  const estimateIntroText = isEstimateDocument
    ? [
      senderName ? ('This Red Threads Project Estimate was sent to you by ' + senderName + ' for review.') : '',
      projectName ? ('Project Name: ' + projectName) : '',
      attachmentSentence
    ].filter(Boolean).join('\n')
    : [
      attachmentSentence,
      communicationContract && communicationContract.statusCopy,
      communicationContract && communicationContract.nextStep && !isLifecycleEmailNoActionText_(communicationContract.nextStep)
        ? ('Next action: ' + communicationContract.nextStep)
        : ''
    ].filter(Boolean).join('\n');
  const fallbackDetailHtml = isEstimateDocument
    ? ''
    : [
      dealNumber ? ('  <p style="margin:0 0 6px;"><strong>Project #:</strong> ' + escapeHtml_(dealNumber) + '</p>') : '',
      projectName ? ('  <p style="margin:0 0 16px;"><strong>Project Name:</strong> ' + escapeHtml_(projectName) + '</p>') : ''
    ].filter(Boolean).join('\n');
  const estimateIntroHtml = isEstimateDocument
    ? [
      buildPortalEstimateEmailReviewPanelHtml_(senderName ? ('This Red Threads Project Estimate was sent to you by ' + senderName + ' for review.') : ''),
      projectName ? ('  <p style="margin:0 0 6px;"><strong>Project Name:</strong> ' + escapeHtml_(projectName) + '</p>') : '',
      '  <p style="margin:0 0 16px;">' + escapeHtml_(attachmentSentence) + '</p>'
    ].filter(Boolean).join('\n')
    : [
      '  <p style="margin:0 0 14px;">' + escapeHtml_(attachmentSentence) + '</p>',
      communicationContract && communicationContract.statusCopy
        ? ('  <p style="margin:0 0 14px;color:#cbd5e1;">' + escapeHtml_(communicationContract.statusCopy) + '</p>')
        : '',
      communicationContract && communicationContract.nextStep && !isLifecycleEmailNoActionText_(communicationContract.nextStep)
        ? ('  <p style="margin:0 0 14px;color:#00c8ff;font-weight:900;"><strong style="color:#00c8ff;">Next action:</strong> ' + escapeHtml_(communicationContract.nextStep) + '</p>')
        : ''
    ].filter(Boolean).join('\n');
  const body = [
    estimateIntroText,
    '',
    lifecycleText || fallbackDetailText,
    '',
    NOTIFICATION_REPLY_NOTICE
  ].filter(Boolean).join('\n');
  const htmlBody = [
    '<div style="font-family:Arial,sans-serif;font-size:14px;line-height:1.65;color:#f8fafc;">',
    estimateIntroHtml,
    lifecycleHtml || fallbackDetailHtml,
    '  <p style="margin:0;color:#94a3b8;">' + escapeHtml_(NOTIFICATION_REPLY_NOTICE) + '</p>',
    '</div>'
  ].filter(Boolean).join('\n');

  const emailPayload = {
    toList: recipients,
    subject: subject,
    body: body,
    htmlBody: buildPortalNativeEmailShellHtml_({
      heading: isEstimateDocument
        ? buildPortalEstimateEmailHeading_(documentReference)
        : buildLifecycleEmailDocumentHeading_(
          documentReference.displayLabel,
          'document attached',
          'Invoice document attached.'
        ),
      badgeLabel: 'Document Ready',
      bodyHtml: htmlBody
    }),
    attachments: [blob],
    fromAlias: NOTIFICATION_FROM_ALIAS,
    replyTo: NOTIFICATION_FROM_ALIAS
  };
  if (communicationContract) {
    assertLifecycleCommunicationContentSafe_(communicationContract, {
      subject: subject,
      body: body,
      htmlBody: emailPayload.htmlBody
    }, {
      hardBlock: true
    });
    emailPayload.communicationContract = communicationContract;
  }
  return sendNotificationEmail_(emailPayload);
}

