function sendEmailReviewUtilityExamples_(results, fixture, recipients) {
  const order = fixture.baseOrder || fixture.standardAchPaid || fixture.standardAchPending;
  if (!order) {
    skipEmailReviewResult_(results, 'Utility emails', 'utility', 'client', 'fixture_missing');
    return;
  }
  const invoiceInfo = buildEmailReviewInvoiceInfo_(fixture, order, { fresh: true });
  const attachments = buildEmailReviewAttachments_('locked_order_confirmation', '', order, invoiceInfo);
  const summary = Object.assign({}, buildPortalOrderSummary_(order.rowObjNormalized), invoiceInfo);
  const subjectSource = Object.assign({}, order.rowObjNormalized || {}, summary);
  const summaryInvoiceLabel = getCurrentInvoiceReferenceForOrder_(order, invoiceInfo, {
    documentKind: PORTAL_DOCUMENT_KINDS.invoice
  }).displayLabel;
  const draft = safeJsonParse_(order.rowObjNormalized.orderdraftjson, {}) || {};
  const lockedContent = buildLockedOrderPaymentEmailContent_({ orderDraft: draft }, summary, {
    intro: 'Your order confirmation has been resent for review.',
    lifecycleOrderInfo: order,
    cfg: fixture.cfg,
    ss: fixture.ss,
    infra: fixture.infra
  });
  const lockedTeamContent = buildLockedOrderPaymentEmailContent_({ orderDraft: draft }, summary, {
    recipientClass: 'team',
    lifecycleOrderInfo: order,
    cfg: fixture.cfg,
    ss: fixture.ss,
    infra: fixture.infra
  });
  const poInvoiceContent = buildPurchaseOrderInvoiceEmailContent_(trimString_(summary.token), invoiceInfo, {
    projectName: trimString_(summary.projectName),
    lifecycleOrderInfo: order,
    cfg: fixture.cfg,
    ss: fixture.ss,
    infra: fixture.infra
  });
  sendEmailReviewContent_(results, 'PO invoice prepared client', 'purchase_order_invoice', 'client', [recipients.client],
    poInvoiceContent,
    attachments);
  sendEmailReviewContent_(results, 'Explicit locked-order resend client', 'locked_order_resend', 'client', [recipients.client], {
    subject: buildPortalEmailSubject_('Order confirmation', subjectSource, {
      documentLabel: summaryInvoiceLabel
    }),
    body: lockedContent.body,
    htmlBody: lockedContent.htmlBody,
    reviewSurface: lockedContent.reviewSurface,
    communicationContract: lockedContent.communicationContract
  }, attachments);
  sendEmailReviewContent_(results, 'Explicit locked-order resend team', 'locked_order_resend', 'team', [recipients.team], {
    subject: buildPortalEmailSubject_(buildTeamSubject_('Order confirmation resent'), subjectSource, {
      documentLabel: summaryInvoiceLabel
    }),
    body: lockedTeamContent.body,
    htmlBody: lockedTeamContent.htmlBody,
    reviewSurface: lockedTeamContent.reviewSurface,
    communicationContract: lockedTeamContent.communicationContract
  }, attachments);

  if (!omitEmailReviewSuiteItemIfNeeded_(results, 'Summary/invoice explicit send client', 'summary_pdf', 'client')) {
    try {
      const sourceAttachment = attachments[0];
      if (sourceAttachment && typeof sourceAttachment.getBytes === 'function') {
        if (EMAIL_REVIEW_SUITE_RENDER_ONLY_ === true) {
          results.push(appendEmailReviewDocumentCopySummary_({
            ok: true,
            dryRun: true,
            sent: false,
            label: 'Summary/invoice explicit send client',
            family: 'summary_pdf',
            recipientClass: 'client',
            attachmentCount: 1,
            subject: buildPortalEmailSubject_('Estimate copy', subjectSource)
          }));
        } else {
          const estimateRow = findEmailReviewEstimateRow_(fixture);
          const estimateProjectNumber = resolveEmailReviewEstimateProjectNumber_(fixture, summary);
          const estimateReference = buildPortalDocumentReference_({
            projectNumber: estimateProjectNumber,
            documentKind: PORTAL_DOCUMENT_KINDS.estimate,
            version: 1
          });
          const summaryResult = sendSummaryEstimatePdfEmail({
            recipients: [recipients.client],
            base64Data: Utilities.base64Encode(sourceAttachment.getBytes()),
            mimeType: MimeType.PDF,
            fileName: estimateReference.fileName,
            documentKind: 'summary',
            documentRef: estimateReference.documentRef,
            documentVersion: 1,
            token: '',
            dealNumber: estimateProjectNumber,
            projectName: getEmailReviewEstimateProjectName_(estimateRow, summary),
            clientName: getEmailReviewEstimateClientName_(estimateRow, summary)
          });
          results.push(appendEmailReviewDocumentCopySummary_({
            ok: summaryResult && summaryResult.ok === true,
            sent: summaryResult && summaryResult.ok === true,
            label: 'Summary/invoice explicit send client',
            family: 'summary_pdf',
            recipientClass: 'client',
            attachmentCount: 1,
            transport: trimString_(summaryResult && summaryResult.transport),
            noReply: summaryResult && summaryResult.noReply === true
          }, {
            subject: buildPortalEmailSubject_('Estimate copy', subjectSource)
          }));
        }
      } else {
        skipEmailReviewResult_(results, 'Summary/invoice explicit send client', 'summary_pdf', 'client', 'fixture_missing');
      }
    } catch (err) {
      results.push({
        ok: false,
        label: 'Summary/invoice explicit send client',
        family: 'summary_pdf',
        recipientClass: 'client',
        attachmentCount: 0,
        error: normalizeEmailReviewError_(err)
      });
    }
  }

  sendEmailReviewAccountDocumentSource_(results, fixture, recipients, ACCOUNT_DOCUMENT_TYPES.tax_exempt, 'Blank tax document source client');
  sendEmailReviewAccountDocumentSource_(results, fixture, recipients, ACCOUNT_DOCUMENT_TYPES.credit_terms, 'Blank credit terms source client');
  skipEmailReviewResult_(results, 'Submitted tax-form copy client', 'submitted_tax_copy', 'client', 'fixture_missing_submission_artifact');

  if (!omitEmailReviewSuiteItemIfNeeded_(results, 'Password reset client', 'password_reset', 'client')) {
    if (EMAIL_REVIEW_SUITE_RENDER_ONLY_ === true) {
      results.push(appendEmailReviewDocumentCopySummary_({
        ok: true,
        dryRun: true,
        sent: false,
        label: 'Password reset client',
        family: 'password_reset',
        recipientClass: 'client',
        attachmentCount: 0,
        subject: 'Reset your Red Threads portal password'
      }));
      return;
    }
    const passwordResult = authSendResetCode({
      email: recipients.client
    });
    if (passwordResult && passwordResult.ok === true) {
      results.push(appendEmailReviewDocumentCopySummary_({
        ok: true,
        sent: true,
        label: 'Password reset client',
        family: 'password_reset',
        recipientClass: 'client',
        attachmentCount: 0,
        transport: 'mailapp_noreply',
        noReply: true
      }, {
        subject: 'Reset your Red Threads portal password'
      }));
    } else {
      sendEmailReviewPasswordResetFallback_(results, recipients.client);
    }
  }
}

function sendEmailReviewAccountDocumentSource_(results, fixture, recipients, documentType, label) {
  try {
    if (omitEmailReviewSuiteItemIfNeeded_(results, label, 'account_document_source', 'client')) return;
    const definition = getAccountDocumentDefinition_(documentType, fixture.cfg);
    if (!definition) {
      skipEmailReviewResult_(results, label, 'account_document_source', 'client', 'fixture_missing');
      return;
    }
    const payload = buildAccountDocumentBlankEmailPayload_(fixture.accountContext, definition, [recipients.client]);
    if (EMAIL_REVIEW_SUITE_RENDER_ONLY_ === true) {
      results.push(appendEmailReviewDocumentCopySummary_({
        ok: true,
        dryRun: true,
        sent: false,
        label: label,
        family: 'account_document_source',
        recipientClass: 'client',
        attachmentCount: Array.isArray(payload.attachments) ? payload.attachments.length : 0,
        subject: trimString_(payload.subject)
      }));
      return;
    }
    const result = sendNotificationEmail_(Object.assign({}, payload, {
      subject: '[EMAIL REVIEW] ' + label + ' - ' + trimString_(payload.subject)
    }));
    results.push(appendEmailReviewDocumentCopySummary_({
      ok: result && result.ok === true,
      sent: result && result.ok === true,
      label: label,
      family: 'account_document_source',
      recipientClass: 'client',
      attachmentCount: Array.isArray(payload.attachments) ? payload.attachments.length : 0,
      transport: trimString_(result && result.transport),
      noReply: result && result.noReply === true
    }, {
      subject: trimString_(payload.subject)
    }));
  } catch (err) {
    results.push({
      ok: false,
      label: label,
      family: 'account_document_source',
      recipientClass: 'client',
      attachmentCount: 0,
      error: normalizeEmailReviewError_(err)
    });
  }
}

function sendEmailReviewPasswordResetFallback_(results, recipient) {
  if (omitEmailReviewSuiteItemIfNeeded_(results, 'Password reset client', 'password_reset', 'client')) return;
  const code = '000000';
  const resetUrl = buildPasswordResetReturnUrl_('00000000-0000-4000-8000-000000000000');
  const content = buildPasswordResetEmailContent_(code, resetUrl);
  if (EMAIL_REVIEW_SUITE_RENDER_ONLY_ === true) {
    results.push(appendEmailReviewDocumentCopySummary_({
      ok: true,
      dryRun: true,
      sent: false,
      label: 'Password reset client',
      family: 'password_reset',
      recipientClass: 'client',
      attachmentCount: 0,
      subject: trimString_(content.subject)
    }));
    return;
  }
  const htmlBody = buildPortalNativeEmailReviewBannerHtml_('Password reset client') + content.htmlBody;
  const result = sendNotificationEmail_({
    to: recipient,
    subject: '[EMAIL REVIEW] Password reset client - ' + content.subject,
    body: '[EMAIL REVIEW: Password reset client]\n\n' + content.body,
    htmlBody: htmlBody
  });
  results.push(appendEmailReviewDocumentCopySummary_({
    ok: result && result.ok === true,
    sent: result && result.ok === true,
    label: 'Password reset client',
    family: 'password_reset',
    recipientClass: 'client',
    attachmentCount: 0,
    transport: trimString_(result && result.transport),
    noReply: result && result.noReply === true
  }, {
    subject: trimString_(content.subject)
  }));
}

/* ---------------- Hosted Stripe Checkout Builders + Transport ---------------- */

function uniqueTrimmedStrings_(values) {
  const seen = {};
  const out = [];
  (Array.isArray(values) ? values : []).forEach((value) => {
    const text = trimString_(value);
    if (!text || seen[text]) return;
    seen[text] = true;
    out.push(text);
  });
  return out;
}

function truncateStripeCheckoutText_(value, maxLen) {
  const text = trimString_(String(value || '').replace(/\s+/g, ' '));
  const limit = Math.max(0, parseInt(String(maxLen || 0), 10) || 0);
  if (!text || !limit || text.length <= limit) return text;
  return text.slice(0, Math.max(0, limit - 3)).trim() + '...';
}

function sortStripeCheckoutSizes_(sizes) {
  const orderMap = {
    XS: 1,
    S: 2,
    M: 3,
    L: 4,
    XL: 5,
    '2X': 6,
    '2XL': 6,
    XXL: 6,
    '3X': 7,
    '3XL': 7,
    XXXL: 7,
    '4X': 8,
    '4XL': 8,
    '5X': 9,
    '5XL': 9,
    '6X': 10,
    '6XL': 10
  };
  return (Array.isArray(sizes) ? sizes : []).slice().sort((a, b) => {
    const left = trimString_(a).toUpperCase();
    const right = trimString_(b).toUpperCase();
    const leftOrder = Object.prototype.hasOwnProperty.call(orderMap, left) ? orderMap[left] : 100;
    const rightOrder = Object.prototype.hasOwnProperty.call(orderMap, right) ? orderMap[right] : 100;
    if (leftOrder !== rightOrder) return leftOrder - rightOrder;
    return left.localeCompare(right);
  });
}

function collectStripeCheckoutColorNames_(skuSummary) {
  const colors = Array.isArray(skuSummary && skuSummary.colors) ? skuSummary.colors : [];
  return uniqueTrimmedStrings_(colors.map((entry) => entry && entry.colorway));
}

function buildStripeCheckoutColorLabel_(skuSummary) {
  const colors = collectStripeCheckoutColorNames_(skuSummary);
  if (!colors.length) return '';
  if (colors.length === 1) return colors[0];
  if (colors.length === 2 && (colors[0].length + colors[1].length) <= 24) {
    return colors.join(' / ');
  }
  return 'Mixed Colors';
}

function buildStripeCheckoutColorSummary_(skuSummary) {
  const colors = collectStripeCheckoutColorNames_(skuSummary);
  if (colors.length <= 1) return '';
  if (colors.length <= 3) {
    return 'Colors: ' + colors.join(' / ');
  }
  return 'Colors: ' + colors.length + ' variants';
}

function formatStripeCheckoutClientLabel_(text) {
  const clean = trimString_(text).replace(/\s+/g, ' ');
  if (!clean) return '';
  const normalized = clean
    .toLowerCase()
    .replace(/\bt[\s-]?shirt\b/g, 't-shirt')
    .replace(/\bsweat[\s-]?shirt\b/g, 'sweatshirt')
    .replace(/\bfront[\s-]?center\b/g, 'front-center');
  return normalized.replace(/(^|[\s\/-])([a-z])/g, function (_, prefix, chr) {
    return prefix + chr.toUpperCase();
  });
}

function isClientSafePrintJobLabel_(label) {
  const clean = trimString_(label).replace(/\s+/g, ' ');
  if (!clean) return false;
  const normalized = clean.toLowerCase();
  if (/^pj\s*\d+$/i.test(clean)) return false;
  if (/^(print\s*job|project|job)\s*\d+$/i.test(clean)) return false;
  if (/^new\s+job$/i.test(clean)) return false;
  if (normalized.indexOf('just another job') >= 0) return false;
  if (/\bplaceholder\b|\btest\b|\bdummy\b|\bsample\b|\bunnamed\b|\binternal\b/.test(normalized)) return false;
  return true;
}

function getStripeDisplayPrintJobLabel_(job) {
  const fallbackNumber = Math.max(1, parseInt(String(job && job.printJobNumber || 1), 10) || 1);
  const candidate = trimString_(job && job.printJobName);
  if (isClientSafePrintJobLabel_(candidate)) {
    return truncateStripeCheckoutText_(formatStripeCheckoutClientLabel_(candidate), 60);
  }
  return 'Print Job ' + fallbackNumber;
}

function normalizeStripeCheckoutDecorationLocation_(location) {
  const clean = trimString_(location)
    .replace(/\(.*?\)/g, '')
    .replace(/\s+/g, ' ')
    .toLowerCase();
  if (!clean) return '';
  if (/left sleeve|left side/.test(clean)) return 'left sleeve';
  if (/right sleeve|right side/.test(clean)) return 'right sleeve';
  if (/front right|right front/.test(clean)) return 'front right';
  if (/front left|left front/.test(clean)) return 'front left';
  if (/full front/.test(clean)) return 'full front';
  if (/full back/.test(clean)) return 'full back';
  if (/front center|front centre/.test(clean)) return 'front-center';
  if (/back center|back centre/.test(clean)) return 'back-center';
  if (/left chest/.test(clean)) return 'left chest';
  if (/right chest/.test(clean)) return 'right chest';
  if (/front/.test(clean)) return 'front';
  if (/back/.test(clean)) return 'back';
  return clean.replace(/\s*\/\s*/g, ' / ');
}

function formatStripeCheckoutCompactDecorationLocation_(location) {
  const normalized = normalizeStripeCheckoutDecorationLocation_(location);
  if (!normalized) return '';
  const map = {
    'left sleeve': 'Left Sleeve',
    'right sleeve': 'Right Sleeve',
    'full front': 'Full Front',
    'full back': 'Full Back',
    'front-center': 'Front Center',
    'back-center': 'Back Center',
    'left chest': 'Left Chest',
    'right chest': 'Right Chest',
    'front right': 'Front Right',
    'front left': 'Front Left',
    front: 'Front',
    back: 'Back'
  };
  return map[normalized] || formatStripeCheckoutClientLabel_(normalized);
}

function normalizeStripeCheckoutDecorationMethod_(method) {
  const clean = trimString_(method)
    .replace(/\(.*?\)/g, '')
    .replace(/\s+/g, ' ')
    .toLowerCase();
  if (!clean) return '';
  if (clean.indexOf('embroid') >= 0) return 'embroidery';
  const colorMatch = clean.match(/(\d+)\s*color/);
  if (colorMatch && colorMatch[1]) return colorMatch[1] + '-color';
  if (clean.indexOf('screen print') >= 0 || /\bprint\b/.test(clean)) return 'print';
  if (clean.indexOf('direct to film') >= 0 || /\bdtf\b/.test(clean)) return 'DTF';
  if (clean.indexOf('direct to garment') >= 0 || /\bdtg\b/.test(clean)) return 'DTG';
  if (clean.indexOf('transfer') >= 0) return 'heat transfer';
  return clean;
}

function buildStripeCheckoutDecorationSummary_(job) {
  const decorations = Array.isArray(job && job.decorations) ? job.decorations : [];
  const parts = [];
  decorations.forEach((item) => {
    const method = normalizeStripeCheckoutDecorationMethod_(item && (item.decorationMethod || item.method || item.type || item.decoType));
    const location = normalizeStripeCheckoutDecorationLocation_(item && item.location);
    let piece = '';
    if (method === 'embroidery') {
      piece = location ? (location + ' embroidery') : 'embroidery';
    } else if (/^\d+-color$/.test(method)) {
      piece = location ? (method + ' ' + location) : method;
    } else if (method === 'print') {
      piece = location ? (location + ' print') : 'print';
    } else if (method === 'DTF' || method === 'DTG') {
      piece = location ? (method + ' ' + location) : method;
    } else {
      piece = trimString_([method, location].filter(Boolean).join(' '));
    }
    if (!piece || parts.indexOf(piece) >= 0) return;
    parts.push(piece);
  });
  const limitedParts = parts.slice(0, 2);
  const colorPrefixMatches = limitedParts.map(function (piece) {
    return piece.match(/^(\d+-color)\s+(.+)$/);
  });
  const sharedColorPrefix = colorPrefixMatches.length > 1 && colorPrefixMatches.every(function (match) {
    return match && match[1] === colorPrefixMatches[0][1] && trimString_(match[2]);
  });
  if (sharedColorPrefix) {
    return truncateStripeCheckoutText_(
      colorPrefixMatches[0][1] + ' ' + colorPrefixMatches.map(function (match) {
        return trimString_(match[2]);
      }).join(' + '),
      90
    );
  }
  return truncateStripeCheckoutText_(limitedParts.join(' + '), 90);
}

function buildStripeCheckoutCompactDecorationSummary_(job) {
  const decorations = Array.isArray(job && job.decorations) ? job.decorations : [];
  const parts = [];
  decorations.forEach((item) => {
    const method = normalizeStripeCheckoutDecorationMethod_(item && (item.decorationMethod || item.method || item.type || item.decoType));
    const location = formatStripeCheckoutCompactDecorationLocation_(item && item.location);
    let piece = '';
    if (method === 'embroidery') {
      piece = trimString_([location, 'Emb'].filter(Boolean).join(' '));
    } else if (/^\d+-color$/.test(method)) {
      const colors = method.replace('-color', 'C');
      piece = trimString_([location, 'SP', colors].filter(Boolean).join(' '));
    } else if (method === 'print') {
      piece = trimString_([location, 'SP'].filter(Boolean).join(' '));
    } else if (method === 'DTF' || method === 'DTG') {
      piece = trimString_([location, method].filter(Boolean).join(' '));
    } else if (method === 'heat transfer') {
      piece = trimString_([location, 'Transfer'].filter(Boolean).join(' '));
    } else {
      piece = trimString_([location, formatStripeCheckoutClientLabel_(method)].filter(Boolean).join(' '));
    }
    if (!piece || parts.indexOf(piece) >= 0) return;
    parts.push(piece);
  });
  const summary = parts.slice(0, 3).join(' + ');
  return summary ? truncateStripeCheckoutText_(summary, 80) : '';
}

function buildStripeCheckoutSizeSummary_(skuSummary) {
  const colors = Array.isArray(skuSummary && skuSummary.colors) ? skuSummary.colors : [];
  const totals = {};
  colors.forEach((color) => {
    const qtyBySize = (color && color.qtyBySize && typeof color.qtyBySize === 'object') ? color.qtyBySize : {};
    Object.keys(qtyBySize).forEach((size) => {
      const qty = Math.max(0, parseInt(String(qtyBySize[size] || 0), 10) || 0);
      if (!qty) return;
      const cleanSize = trimString_(size);
      if (!cleanSize) return;
      if (!Object.prototype.hasOwnProperty.call(totals, cleanSize)) totals[cleanSize] = 0;
      totals[cleanSize] += qty;
    });
  });
  return buildStripeCheckoutSizeSummaryFromQtyMap_(totals);
}

function buildStripeCheckoutPrintJobLabel_(job) {
  return getStripeDisplayPrintJobLabel_(job);
}

function buildStripeCheckoutSizeSummaryFromQtyMap_(qtyBySize) {
  const map = (qtyBySize && typeof qtyBySize === 'object') ? qtyBySize : {};
  const orderedSizes = sortStripeCheckoutSizes_(Object.keys(map));
  const sortedSizes = orderedSizes.filter((size) => Math.max(0, parseInt(String(map[size] || 0), 10) || 0) > 0);
  if (!sortedSizes.length) return '';
  const quantities = sortedSizes.map((size) => Math.max(0, parseInt(String(map[size] || 0), 10) || 0));
  const allSameQty = quantities.length > 1 && quantities.every((qty) => qty === quantities[0]);
  if (allSameQty) {
    return 'Sizes: ' + sortedSizes.join('/') + ' ×' + quantities[0];
  }
  return 'Sizes: ' + sortedSizes.map((size) => size + ' ' + Math.max(0, parseInt(String(map[size] || 0), 10) || 0)).join(' / ');
}

function buildStripeCheckoutQtySizeSummaryFromQtyMap_(qtyBySize) {
  const map = (qtyBySize && typeof qtyBySize === 'object') ? qtyBySize : {};
  const orderedSizes = sortStripeCheckoutSizes_(Object.keys(map));
  const sortedSizes = orderedSizes.filter((size) => Math.max(0, parseInt(String(map[size] || 0), 10) || 0) > 0);
  if (!sortedSizes.length) return '';
  return 'Sizes: ' + sortedSizes.map((size) => Math.max(0, parseInt(String(map[size] || 0), 10) || 0) + ' ' + size).join(' / ');
}

function buildStripeCheckoutUnitsSummary_(units) {
  const safeUnits = Math.max(0, parseInt(String(units || 0), 10) || 0);
  if (!safeUnits) return '';
  return safeUnits + ' units';
}

function buildStripeCheckoutDisplayName_(job, skuSummary, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const baseName = trimString_(opts.baseName || (skuSummary && skuSummary.uiName)) || trimString_(job && job.printJobName) || 'Custom Item';
  const colorLabel = formatStripeCheckoutClientLabel_(trimString_(opts.colorLabel || opts.colorway) || buildStripeCheckoutColorLabel_(skuSummary));
  return truncateStripeCheckoutText_(colorLabel ? (baseName + ' — ' + colorLabel) : baseName, 80);
}

function buildStripeCheckoutSkuLineName_(job) {
  const printJobLabel = trimString_(buildStripeCheckoutPrintJobLabel_(job));
  const decorationSummary = trimString_(buildStripeCheckoutCompactDecorationSummary_(job) || buildStripeCheckoutDecorationSummary_(job));
  return truncateStripeCheckoutText_(
    [printJobLabel, decorationSummary].filter(Boolean).join(' • ') || 'Red Threads Item',
    80
  );
}

function buildStripeCheckoutSkuDescriptionParts_(job, skuSummary, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const parts = [];
  const colorLabel = formatStripeCheckoutClientLabel_(trimString_(opts.colorLabel || opts.colorway) || buildStripeCheckoutColorLabel_(skuSummary));
  if (colorLabel) parts.push(colorLabel);
  const productName = trimString_(skuSummary && skuSummary.uiName);
  if (productName) parts.push(productName);
  const sizeSummary = trimString_(buildStripeCheckoutQtySizeSummaryFromQtyMap_(opts.qtyBySize) || buildStripeCheckoutSizeSummary_(skuSummary));
  if (sizeSummary) parts.push(sizeSummary);
  const totalUnits = Math.max(0, parseInt(String(opts.totalUnits || skuSummary && skuSummary.units || 0), 10) || 0);
  if (totalUnits > 0) parts.push('Total Qty: ' + totalUnits);
  return uniqueTrimmedStrings_(parts);
}

function buildStripeCheckoutDescriptionParts_(job, skuSummary, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const parts = [];
  const printJobLabel = trimString_(opts.printJobLabel || buildStripeCheckoutPrintJobLabel_(job));
  if (printJobLabel) parts.push(printJobLabel);
  const sizeSummary = trimString_(opts.sizeSummary || buildStripeCheckoutSizeSummaryFromQtyMap_(opts.qtyBySize) || buildStripeCheckoutSizeSummary_(skuSummary));
  if (sizeSummary) parts.push(sizeSummary);
  const unitsSummary = trimString_(opts.unitsSummary || buildStripeCheckoutUnitsSummary_(opts.totalUnits));
  if (unitsSummary) parts.push(unitsSummary);
  const decorationSummary = trimString_(opts.decorationSummary || buildStripeCheckoutCompactDecorationSummary_(job) || buildStripeCheckoutDecorationSummary_(job));
  if (decorationSummary) parts.push(decorationSummary);
  const extraParts = Array.isArray(opts.extraParts) ? opts.extraParts : [];
  if (extraParts.length) Array.prototype.push.apply(parts, extraParts);
  return uniqueTrimmedStrings_(parts);
}

function determineStripeCheckoutUnitLabel_(name) {
  const text = trimString_(name).toLowerCase();
  if (!text) return '';
  if (/hoodie|sweatshirt/.test(text)) return 'hoodie';
  if (/shirt|tee|t-shirt/.test(text)) return 'shirt';
  if (/tank/.test(text)) return 'tank';
  if (/hat|cap|beanie/.test(text)) return 'hat';
  if (/jacket/.test(text)) return 'jacket';
  return 'item';
}

function normalizeStripeHostedImageUrl_(url) {
  const clean = trimString_(url);
  if (!clean) return '';
  try {
    const parsed = new URL(clean);
    if (parsed.protocol !== 'https:') return '';
    const host = String(parsed.hostname || '').trim().toLowerCase();
    if (!host) return '';
    if (host.indexOf('drive.google.com') >= 0 || host.indexOf('docs.google.com') >= 0) return '';
    if (host === 'drive.usercontent.google.com') return '';
    if (host === 'work.fife.usercontent.google.com') return '';
    return parsed.toString();
  } catch (_) {
    return '';
  }
}

function isStripeHostedImageUrlFetchable_(url) {
  const normalized = normalizeStripeHostedImageUrl_(url);
  if (!normalized) return false;
  try {
    const parsed = new URL(normalized);
    const host = String(parsed.hostname || '').trim().toLowerCase();
    if (!host) return false;
    // Prefer the same public, direct image URL shapes the portal already renders
    // rather than requiring server-side fetch validation, which can falsely reject
    // otherwise usable Stripe-hosted product thumbnails.
    if (host === 'lh3.googleusercontent.com') return true;
    if (host.indexOf('googleusercontent.com') >= 0) return true;
    return parsed.protocol === 'https:';
  } catch (_) {
    return false;
  }
}

function buildPublicDriveImageUrlForStripeCheckout_(fileId) {
  const id = trimString_(fileId);
  if (!id) return '';
  return 'https://lh3.googleusercontent.com/d/' + encodeURIComponent(id);
}

function chooseStripeCheckoutImageUrl_(job, skuSummary) {
  const candidates = [];
  const safeSkuImageUrl = normalizeStripeHostedImageUrl_(skuSummary && skuSummary.imageUrl);
  if (safeSkuImageUrl) candidates.push(safeSkuImageUrl);

  const safePreviewUrl = normalizeStripeHostedImageUrl_(job && job.mockups && job.mockups.previewUrl);
  if (safePreviewUrl) candidates.push(safePreviewUrl);

  const driveFileIds = [
    trimString_(job && job.mockups && job.mockups.previewMockupFileId),
    trimString_(job && job.mockups && job.mockups.artMockupFileId),
    trimString_(job && job.mockups && job.mockups.garmentMockupFileId)
  ];
  for (let i = 0; i < driveFileIds.length; i += 1) {
    const derivedUrl = buildPublicDriveImageUrlForStripeCheckout_(driveFileIds[i]);
    if (derivedUrl) candidates.push(derivedUrl);
  }
  const uniqueCandidates = uniqueTrimmedStrings_(candidates);
  for (let i = 0; i < uniqueCandidates.length; i += 1) {
    if (isStripeHostedImageUrlFetchable_(uniqueCandidates[i])) {
      return uniqueCandidates[i];
    }
  }
  return '';
}

function finalizeStripeCheckoutLineItemPricing_(lineItem) {
  const item = Object.assign({}, (lineItem && typeof lineItem === 'object') ? lineItem : {});
  const safeAmountCents = Math.max(0, parseInt(String(item.amountCents || 0), 10) || 0);
  const safeQuantity = Math.max(1, parseInt(String(item.quantity || 1), 10) || 1);
  item.quantity = safeQuantity;
  item.displayQuantity = Math.max(1, parseInt(String(item.displayQuantity || safeQuantity), 10) || safeQuantity);
  item.amountCents = safeAmountCents;
  delete item.roundingAdjustmentCents;
  delete item.requiresQuantityFallback;
  delete item.unitAmountDecimal;
  delete item.unitAmountCents;
  if (safeQuantity <= 1) {
    item.unitAmountCents = safeAmountCents;
    return item;
  }
  if (safeAmountCents % safeQuantity !== 0) {
    item.quantity = 1;
    item.displayQuantity = safeQuantity;
    item.unitAmountCents = safeAmountCents;
    item.unitLabel = '';
    item.requiresQuantityFallback = true;
    return item;
  }
  const baseUnitAmountCents = Math.floor(safeAmountCents / safeQuantity);
  if (baseUnitAmountCents <= 0) {
    item.quantity = 1;
    item.displayQuantity = safeQuantity;
    item.unitAmountCents = safeAmountCents;
    item.unitLabel = '';
    item.requiresQuantityFallback = true;
    return item;
  }
  item.unitAmountCents = baseUnitAmountCents;
  return item;
}

function applyStripeCheckoutConvenienceFeeToLineItems_(lineItems, feeRate) {
  const rate = Number(feeRate);
  const items = Array.isArray(lineItems) ? lineItems : [];
  if (!Number.isFinite(rate) || rate <= 0 || !items.length) {
    return items.slice();
  }
  return items.map((lineItem) => {
    const item = Object.assign({}, (lineItem && typeof lineItem === 'object') ? lineItem : {});
    const baseAmountCents = Math.max(0, parseInt(String(item.amountCents || 0), 10) || 0);
    if (!baseAmountCents) return finalizeStripeCheckoutLineItemPricing_(item);
    item.amountCents = baseAmountCents + Math.round(baseAmountCents * rate);
    if (Math.max(0, parseInt(String(item.__stripeDiscountReductionCents || 0), 10) || 0) > 0) {
      const baseReductionCents = Math.max(0, parseInt(String(item.__stripeDiscountReductionCents || 0), 10) || 0);
      item.__stripeDiscountDisplayCents = baseReductionCents + Math.round(baseReductionCents * rate);
      renameStripeCheckoutLineItemForDiscount_(item);
    }
    return finalizeStripeCheckoutLineItemPricing_(item);
  });
}

function buildStripeCheckoutSortedPriceBuckets_(skuSummary) {
  return (Array.isArray(skuSummary && skuSummary.priceBuckets) ? skuSummary.priceBuckets.slice() : []).sort((left, right) => {
    const leftColor = trimString_(left && left.colorway).toLowerCase();
    const rightColor = trimString_(right && right.colorway).toLowerCase();
    if (leftColor !== rightColor) return leftColor.localeCompare(rightColor);
    const leftPrice = toFiniteNumber_(left && left.unitPrice, 0);
    const rightPrice = toFiniteNumber_(right && right.unitPrice, 0);
    if (leftPrice !== rightPrice) return leftPrice - rightPrice;
    return 0;
  });
}

function buildStripeCheckoutGroupedColorwayEntries_(skuSummary) {
  const colors = Array.isArray(skuSummary && skuSummary.colors) ? skuSummary.colors : [];
  const priceBuckets = buildStripeCheckoutSortedPriceBuckets_(skuSummary);
  const bucketTotalsByColor = {};
  priceBuckets.forEach((bucket) => {
    const colorKey = trimString_(bucket && bucket.colorway).toLowerCase();
    if (!colorKey) return;
    if (!bucketTotalsByColor[colorKey]) {
      bucketTotalsByColor[colorKey] = {
        totalCents: 0
      };
    }
    bucketTotalsByColor[colorKey].totalCents += Math.max(0, parseInt(String(bucket && bucket.totalCents || 0), 10) || 0);
  });
  return colors.map((colorSummary) => {
    const colorLabel = trimString_(colorSummary && colorSummary.colorway);
    const colorKey = colorLabel.toLowerCase();
    const totals = bucketTotalsByColor[colorKey] || null;
    const units = Math.max(0, parseInt(String(colorSummary && colorSummary.units || 0), 10) || 0);
    const amountCents = totals
      ? Math.max(0, parseInt(String(totals.totalCents || 0), 10) || 0)
      : 0;
    return {
      colorway: colorLabel,
      qtyBySize: (colorSummary && colorSummary.qtyBySize && typeof colorSummary.qtyBySize === 'object') ? colorSummary.qtyBySize : {},
      units: units,
      totalCents: amountCents
    };
  }).filter((entry) => entry.units > 0 && entry.totalCents > 0);
}

function buildStripeCheckoutColorwayLineItems_(job, skuSummary) {
  const imageUrl = chooseStripeCheckoutImageUrl_(job, skuSummary);
  const colorwayEntries = buildStripeCheckoutGroupedColorwayEntries_(skuSummary);
  const lineItems = [];

  colorwayEntries.forEach((entry) => {
    const units = Math.max(0, parseInt(String(entry && entry.units || 0), 10) || 0);
    const amountCents = Math.max(0, parseInt(String(entry && entry.totalCents || 0), 10) || 0);
    if (!units || !amountCents) return;
    const name = buildStripeCheckoutSkuLineName_(job);
    const apparelLineItem = finalizeStripeCheckoutLineItemPricing_({
      type: 'apparel',
      name: name,
      descriptionParts: buildStripeCheckoutSkuDescriptionParts_(job, skuSummary, {
        colorLabel: trimString_(entry && entry.colorway),
        totalUnits: units,
        qtyBySize: entry && entry.qtyBySize
      }),
      quantity: 1,
      displayQuantity: 1,
      amountCents: amountCents,
      imageUrl: imageUrl,
      unitLabel: '',
      printJobLabel: buildStripeCheckoutPrintJobLabel_(job)
    });
    lineItems.push(apparelLineItem);
  });

  if (lineItems.length) return lineItems;

  const amountCents = Math.max(0, Math.round(roundMoney_(skuSummary && skuSummary.total) * 100));
  if (!amountCents) return [];
  const name = buildStripeCheckoutSkuLineName_(job);
  const units = Math.max(1, parseInt(String(skuSummary && skuSummary.units || 1), 10) || 1);
  return [{
    type: 'apparel',
    name: name,
    descriptionParts: buildStripeCheckoutSkuDescriptionParts_(job, skuSummary, {
      totalUnits: units
    }),
    quantity: 1,
    displayQuantity: 1,
    amountCents: amountCents,
    imageUrl: imageUrl,
    unitLabel: '',
    printJobLabel: buildStripeCheckoutPrintJobLabel_(job)
  }].map(finalizeStripeCheckoutLineItemPricing_);
}

function buildStripeCheckoutAddOnLineItem_(job, addOnSummary) {
  const amountCents = Math.round(roundMoney_(addOnSummary && addOnSummary.amount) * 100);
  if (!amountCents) return null;
  const fallbackName = addOnSummary && addOnSummary.type === 'rush'
    ? 'Rush Service'
    : (addOnSummary && addOnSummary.type === 'shipping' ? 'Shipping' : 'Additional Fee');
  const lineItem = {
    type: trimString_(addOnSummary && addOnSummary.type) || 'fee',
    name: truncateStripeCheckoutText_(trimString_(addOnSummary && addOnSummary.label) || fallbackName, 80),
    descriptionParts: uniqueTrimmedStrings_([
      'Applies to ' + buildStripeCheckoutPrintJobLabel_(job)
    ]),
    quantity: 1,
    displayQuantity: 1,
    amountCents: amountCents,
    imageUrl: '',
    unitLabel: '',
    printJobLabel: buildStripeCheckoutPrintJobLabel_(job)
  };
  return amountCents > 0 ? finalizeStripeCheckoutLineItemPricing_(lineItem) : lineItem;
}

function buildStripeCheckoutTaxLineItem_(orderDraft, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const amountCents = Math.round(roundMoney_(orderDraft && orderDraft.amountTax) * 100)
    + Math.max(0, parseInt(String(opts.additionalTaxCents || 0), 10) || 0);
  if (!amountCents) return null;
  return finalizeStripeCheckoutLineItemPricing_({
    type: 'tax',
    name: 'Michigan Sales Tax',
    descriptionParts: ['Applied based on your current order selections.'],
    quantity: 1,
    displayQuantity: 1,
    amountCents: amountCents,
    imageUrl: '',
    unitLabel: ''
  });
}

function calculateStripeCheckoutAdditionalShippingTaxCents_(orderDraft, shippingChargeCents) {
  const draft = (orderDraft && typeof orderDraft === 'object') ? orderDraft : {};
  const shippingCents = Math.max(0, parseInt(String(shippingChargeCents || 0), 10) || 0);
  if (!shippingCents || draft.taxShouldApply !== true) return 0;
  return Math.max(0, Math.round(shippingCents * 0.06));
}

function buildStripeCheckoutDefaultLineItems_(orderDraft) {
  const grandTotalCents = Math.max(0, Math.round(roundMoney_(orderDraft && orderDraft.amountGrandTotal) * 100));
  if (!grandTotalCents) return [];
  const selectedJobs = Array.isArray(orderDraft && orderDraft.selectedJobs) ? orderDraft.selectedJobs : [];
  const firstJob = selectedJobs[0] || null;
  const firstSku = firstJob && Array.isArray(firstJob.skus) ? (firstJob.skus[0] || null) : null;
  const descriptionParts = [];
  const totalUnits = Math.max(0, parseInt(String(orderDraft && orderDraft.totalUnits || 0), 10) || 0);
  if (totalUnits > 0) descriptionParts.push('Qty ' + totalUnits);
  const dealNumber = trimString_(orderDraft && orderDraft.dealNumber);
  if (dealNumber) descriptionParts.push('Job #' + dealNumber);
  return [finalizeStripeCheckoutLineItemPricing_({
    type: 'summary',
    name: truncateStripeCheckoutText_(trimString_(orderDraft && orderDraft.projectName) || 'Red Threads Order', 80),
    descriptionParts: descriptionParts,
    quantity: 1,
    displayQuantity: 1,
    amountCents: grandTotalCents,
    imageUrl: firstJob && firstSku ? chooseStripeCheckoutImageUrl_(firstJob, firstSku) : '',
    unitLabel: ''
  })];
}

function getStripeCheckoutLineItemAmountCents_(lineItem) {
  return parseInt(String(lineItem && lineItem.amountCents || 0), 10) || 0;
}

function isStripeCheckoutTaxLineItem_(lineItem) {
  return trimString_(lineItem && lineItem.type).toLowerCase() === 'tax';
}

function getStripeCheckoutReductionPriority_(lineItem) {
  const type = trimString_(lineItem && lineItem.type).toLowerCase();
  if (type === 'fee' || type === 'shipping' || type === 'rush') return 0;
  if (type === 'summary') return 2;
  if (type === 'tax') return 99;
  return 1;
}

function isStripeCheckoutApparelLineItem_(lineItem) {
  return trimString_(lineItem && lineItem.type).toLowerCase() === 'apparel';
}

function isStripeCheckoutDiscountReductionEligible_(lineItem) {
  const type = trimString_(lineItem && lineItem.type).toLowerCase();
  if (type === 'tax' || type === 'discount_info' || type === 'adjustment') return false;
  return getStripeCheckoutLineItemAmountCents_(lineItem) > 1;
}

function getStripeCheckoutDiscountReductionPriority_(lineItem, relatedPrintJobLabels) {
  const relatedLabels = Array.isArray(relatedPrintJobLabels) ? relatedPrintJobLabels : [];
  const type = trimString_(lineItem && lineItem.type).toLowerCase();
  const printJobLabel = trimString_(lineItem && lineItem.printJobLabel);
  if (type === 'apparel') {
    return printJobLabel && relatedLabels.indexOf(printJobLabel) >= 0 ? 0 : 1;
  }
  if (type === 'fee' || type === 'shipping' || type === 'rush') return 2;
  if (type === 'summary') return 3;
  return 99;
}

function reduceStripeCheckoutLineItems_(lineItems, reductionCents, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const trackDiscountAllocation = opts.trackDiscountAllocation === true;
  const relatedPrintJobLabels = uniqueTrimmedStrings_(opts.relatedPrintJobLabels || []);
  const reductionTarget = Math.max(0, parseInt(String(reductionCents || 0), 10) || 0);
  const adjustedItems = (Array.isArray(lineItems) ? lineItems : [])
    .filter(Boolean)
    .map((item, idx) => Object.assign({}, item, { __stripeReductionSortIndex: idx }));
  if (!reductionTarget) {
    return { ok: true, lineItems: adjustedItems, remainingReductionCents: 0, allocations: [] };
  }
  const targets = adjustedItems
    .filter((item) => {
      return trackDiscountAllocation
        ? isStripeCheckoutDiscountReductionEligible_(item)
        : (!isStripeCheckoutTaxLineItem_(item) && getStripeCheckoutLineItemAmountCents_(item) > 1);
    })
    .sort((left, right) => {
      const leftPriority = trackDiscountAllocation
        ? getStripeCheckoutDiscountReductionPriority_(left, relatedPrintJobLabels)
        : getStripeCheckoutReductionPriority_(left);
      const rightPriority = trackDiscountAllocation
        ? getStripeCheckoutDiscountReductionPriority_(right, relatedPrintJobLabels)
        : getStripeCheckoutReductionPriority_(right);
      const priorityDiff = leftPriority - rightPriority;
      if (priorityDiff !== 0) return priorityDiff;
      if (trackDiscountAllocation) {
        return (parseInt(String(left.__stripeReductionSortIndex || 0), 10) || 0)
          - (parseInt(String(right.__stripeReductionSortIndex || 0), 10) || 0);
      }
      return getStripeCheckoutLineItemAmountCents_(right) - getStripeCheckoutLineItemAmountCents_(left);
    });
  let remainingReductionCents = reductionTarget;
  const allocations = [];
  targets.forEach((item) => {
    if (!remainingReductionCents) return;
    const currentAmountCents = Math.max(0, getStripeCheckoutLineItemAmountCents_(item));
    const availableReductionCents = Math.max(0, currentAmountCents - 1);
    const reduction = Math.min(remainingReductionCents, availableReductionCents);
    if (!reduction) return;
    const originalAmountCents = Math.max(
      currentAmountCents,
      parseInt(String(item.__stripeOriginalAmountCents || currentAmountCents), 10) || currentAmountCents
    );
    item.amountCents = currentAmountCents - reduction;
    if (trackDiscountAllocation) {
      item.__stripeOriginalAmountCents = originalAmountCents;
      item.__stripeDiscountReductionCents = Math.max(0, parseInt(String(item.__stripeDiscountReductionCents || 0), 10) || 0) + reduction;
      allocations.push({
        type: trimString_(item && item.type),
        name: trimString_(item && item.name),
        printJobLabel: trimString_(item && item.printJobLabel),
        originalAmountCents: originalAmountCents,
        reductionCents: reduction,
        remainingAmountCents: item.amountCents
      });
    }
    remainingReductionCents -= reduction;
  });
  return {
    ok: remainingReductionCents === 0,
    lineItems: adjustedItems.filter((item) => getStripeCheckoutLineItemAmountCents_(item) > 0),
    remainingReductionCents: remainingReductionCents,
    allocations: allocations
  };
}

function buildStripeCheckoutAdjustmentLineItem_(amountCents) {
  const safeAmountCents = Math.max(0, parseInt(String(amountCents || 0), 10) || 0);
  if (!safeAmountCents) return null;
  return finalizeStripeCheckoutLineItemPricing_({
    type: 'adjustment',
    name: 'Order Adjustment',
    descriptionParts: ['Aligns itemized pricing with your current order total.'],
    quantity: 1,
    displayQuantity: 1,
    amountCents: safeAmountCents,
    imageUrl: '',
    unitLabel: ''
  });
}

function buildStripeCheckoutFallbackLineItems_(draft, paymentMethodSelected, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const additionalTaxCents = Math.max(0, parseInt(String(opts.additionalTaxCents || 0), 10) || 0);
  const fallbackDraft = additionalTaxCents > 0
    ? Object.assign({}, (draft && typeof draft === 'object') ? draft : {}, {
      amountGrandTotal: roundMoney_(roundMoney_(draft && draft.amountGrandTotal) + (additionalTaxCents / 100))
    })
    : draft;
  const fallbackItems = buildStripeCheckoutDefaultLineItems_(fallbackDraft);
  const pricedFallbackItems = trimString_(paymentMethodSelected).toLowerCase() === PAYMENT_METHODS.card
    ? applyStripeCheckoutConvenienceFeeToLineItems_(fallbackItems, 0.03)
    : fallbackItems;
  return finalizeStripeCheckoutLineItemDescriptions_(pricedFallbackItems);
}

function buildStripeCheckoutDiscountSummaries_(negativeItems) {
  const items = Array.isArray(negativeItems) ? negativeItems : [];
  return items.map((item, idx) => {
    const amountCents = Math.abs(getStripeCheckoutLineItemAmountCents_(item));
    const name = truncateStripeCheckoutText_(trimString_(item && item.name) || ('Discount ' + (idx + 1)), 48);
    return {
      name: name,
      amountCents: amountCents,
      label: name + ': -' + formatUsdAmount_(amountCents / 100)
    };
  }).filter((item) => item.amountCents > 0);
}

function buildStripeCheckoutDiscountNameSuffix_(discountSummaries) {
  const names = uniqueTrimmedStrings_((Array.isArray(discountSummaries) ? discountSummaries : []).map((item) => item && item.name));
  return names.length ? truncateStripeCheckoutText_(names.join(' + '), 48) : 'Discount';
}

function renameStripeCheckoutLineItemForDiscount_(lineItem, discountSummaries) {
  const item = (lineItem && typeof lineItem === 'object') ? lineItem : {};
  const baseName = truncateStripeCheckoutText_(trimString_(item.__stripeDiscountBaseName || item.name) || 'Item', 58);
  const reductionCents = Math.max(0, parseInt(String(item.__stripeDiscountDisplayCents || item.__stripeDiscountReductionCents || 0), 10) || 0);
  const discountCount = Math.max(0, parseInt(String(item.__stripeDiscountCount || (Array.isArray(discountSummaries) ? discountSummaries.length : 0)), 10) || 0);
  const suffix = reductionCents > 0
    ? (' • ' + formatUsdAmount_(reductionCents / 100) + (discountCount > 1 ? ' Discounts Applied' : ' Discount Applied'))
    : (' • ' + buildStripeCheckoutDiscountNameSuffix_(discountSummaries) + ' Applied');
  item.__stripeDiscountBaseName = baseName;
  item.name = truncateStripeCheckoutText_(baseName + suffix, 80);
}

function applyNegativeStripeCheckoutAdjustments_(lineItems) {
  const allItems = (Array.isArray(lineItems) ? lineItems : []).filter(Boolean);
  const positiveItems = allItems.filter((item) => item.amountCents > 0);
  const negativeItems = allItems.filter((item) => item.amountCents < 0);
  if (!negativeItems.length) {
    return { ok: true, lineItems: positiveItems };
  }
  if (!positiveItems.length) {
    return { ok: false, lineItems: [] };
  }

  let remainingDiscountCents = negativeItems.reduce((sum, item) => sum + Math.abs(item.amountCents), 0);
  const relatedPrintJobLabels = uniqueTrimmedStrings_(negativeItems.map((item) => item && item.printJobLabel));
  const reduced = reduceStripeCheckoutLineItems_(positiveItems, remainingDiscountCents, {
    trackDiscountAllocation: true,
    relatedPrintJobLabels: relatedPrintJobLabels
  });
  remainingDiscountCents = reduced.remainingReductionCents;
  const cleanedItems = reduced.lineItems;
  const discountSummaries = buildStripeCheckoutDiscountSummaries_(negativeItems);
  const allocationTargets = cleanedItems.filter((item) => {
    return Math.max(0, parseInt(String(item && item.__stripeDiscountReductionCents || 0), 10) || 0) > 0;
  });
  allocationTargets.forEach((item) => {
    item.__stripeDiscountCount = discountSummaries.length;
    renameStripeCheckoutLineItemForDiscount_(item, discountSummaries);
  });
  return {
    ok: remainingDiscountCents === 0,
    lineItems: cleanedItems
  };
}

function finalizeStripeCheckoutLineItemDescriptions_(lineItems) {
  return (Array.isArray(lineItems) ? lineItems : []).map((item) => {
    const parts = uniqueTrimmedStrings_(item.descriptionParts || []);
    if (item.displayQuantity > 1 && item.quantity !== item.displayQuantity) {
      parts.push('Qty ' + item.displayQuantity);
      item.unitLabel = '';
    }
    item.description = truncateStripeCheckoutText_(parts.join(' • '), 180);
    delete item.descriptionParts;
    delete item.__stripeOriginalAmountCents;
    delete item.__stripeDiscountReductionCents;
    delete item.__stripeDiscountDisplayCents;
    delete item.__stripeDiscountBaseName;
    delete item.__stripeDiscountCount;
    delete item.__stripeReductionSortIndex;
    return item;
  });
}

function buildStripeCheckoutLineItemsFromOrderDraft_(orderDraft, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const paymentMethodSelected = trimString_(opts.paymentMethodSelected).toLowerCase();
  const draft = (orderDraft && typeof orderDraft === 'object') ? orderDraft : {};
  const additionalTaxCents = Math.max(0, parseInt(String(opts.additionalTaxCents || 0), 10) || 0);
  const rawLineItems = [];
  const selectedJobs = Array.isArray(draft.selectedJobs) ? draft.selectedJobs : [];
  selectedJobs.forEach((job) => {
    (Array.isArray(job && job.skus) ? job.skus : []).forEach((skuSummary) => {
      const skuLineItems = buildStripeCheckoutColorwayLineItems_(job, skuSummary);
      if (skuLineItems && skuLineItems.length) Array.prototype.push.apply(rawLineItems, skuLineItems);
    });
    (Array.isArray(job && job.addOns) ? job.addOns : []).forEach((addOnSummary) => {
      const addOnLineItem = buildStripeCheckoutAddOnLineItem_(job, addOnSummary);
      if (addOnLineItem) rawLineItems.push(addOnLineItem);
    });
  });

  const taxLineItem = buildStripeCheckoutTaxLineItem_(draft, {
    additionalTaxCents: additionalTaxCents
  });
  if (taxLineItem) rawLineItems.push(taxLineItem);

  const adjusted = applyNegativeStripeCheckoutAdjustments_(rawLineItems);
  if (!adjusted.ok) {
    return buildStripeCheckoutFallbackLineItems_(draft, paymentMethodSelected, { additionalTaxCents: additionalTaxCents });
  }
  let lineItems = adjusted.lineItems;
  if (!lineItems.length) {
    return buildStripeCheckoutFallbackLineItems_(draft, paymentMethodSelected, { additionalTaxCents: additionalTaxCents });
  }

  const grandTotalCents = Math.max(0, Math.round(roundMoney_(draft.amountGrandTotal) * 100)) + additionalTaxCents;
  const lineItemsTotalCents = lineItems.reduce((sum, item) => sum + Math.max(0, parseInt(String(item && item.amountCents || 0), 10) || 0), 0);
  const diffCents = grandTotalCents - lineItemsTotalCents;
  if (diffCents > 0) {
    const adjustmentLineItem = buildStripeCheckoutAdjustmentLineItem_(diffCents);
    if (adjustmentLineItem) lineItems.push(adjustmentLineItem);
  } else if (diffCents < 0) {
    const reduced = reduceStripeCheckoutLineItems_(lineItems, Math.abs(diffCents));
    if (!reduced.ok) {
      return buildStripeCheckoutFallbackLineItems_(draft, paymentMethodSelected, { additionalTaxCents: additionalTaxCents });
    }
    lineItems = reduced.lineItems;
  }
  if (lineItems.length > 100) {
    return buildStripeCheckoutFallbackLineItems_(draft, paymentMethodSelected, { additionalTaxCents: additionalTaxCents });
  }
  const pricedLineItems = lineItems.map(finalizeStripeCheckoutLineItemPricing_);
  const pricedCheckoutLineItems = paymentMethodSelected === PAYMENT_METHODS.card
    ? applyStripeCheckoutConvenienceFeeToLineItems_(pricedLineItems, 0.03)
    : pricedLineItems;
  if (pricedCheckoutLineItems.length > 100) {
    return buildStripeCheckoutFallbackLineItems_(draft, paymentMethodSelected, { additionalTaxCents: additionalTaxCents });
  }
  return finalizeStripeCheckoutLineItemDescriptions_(pricedCheckoutLineItems);
}

function appendStripeCheckoutLineItemToPayload_(payload, index, lineItem, currency) {
  const item = (lineItem && typeof lineItem === 'object') ? lineItem : {};
  const idx = Math.max(0, parseInt(String(index || 0), 10) || 0);
  payload['line_items[' + idx + '][quantity]'] = String(Math.max(1, parseInt(String(item.quantity || 1), 10) || 1));
  payload['line_items[' + idx + '][price_data][currency]'] = trimString_(currency || DEFAULT_STRIPE_PRICE_CURRENCY).toLowerCase();
  payload['line_items[' + idx + '][price_data][unit_amount]'] = String(Math.max(0, parseInt(String(item.unitAmountCents || 0), 10) || 0));
  payload['line_items[' + idx + '][price_data][product_data][name]'] = truncateStripeCheckoutText_(item.name, 80) || 'Red Threads Item';
  const description = truncateStripeCheckoutText_(item.description, 180);
  if (description) {
    payload['line_items[' + idx + '][price_data][product_data][description]'] = description;
  }
  const imageUrl = normalizeStripeHostedImageUrl_(item.imageUrl);
  if (imageUrl) {
    payload['line_items[' + idx + '][price_data][product_data][images][]'] = imageUrl;
  }
  const unitLabel = truncateStripeCheckoutText_(item.unitLabel, 12);
  if (unitLabel) {
    payload['line_items[' + idx + '][price_data][product_data][unit_label]'] = unitLabel;
  }
}

function summarizeStripeCheckoutLineItemsForLog_(lineItems) {
  return (Array.isArray(lineItems) ? lineItems : []).map((item, idx) => ({
    index: idx,
    type: trimString_(item && item.type),
    name: trimString_(item && item.name),
    quantity: Math.max(1, parseInt(String(item && item.quantity || 1), 10) || 1),
    displayQuantity: Math.max(1, parseInt(String(item && item.displayQuantity || item && item.quantity || 1), 10) || 1),
    unitAmountCents: Math.max(0, parseInt(String(item && item.unitAmountCents || 0), 10) || 0),
    amountCents: Math.max(0, parseInt(String(item && item.amountCents || 0), 10) || 0),
    roundingAdjustmentCents: Math.max(0, parseInt(String(item && item.roundingAdjustmentCents || 0), 10) || 0),
    requiresQuantityFallback: item && item.requiresQuantityFallback === true,
    hasImage: !!trimString_(item && item.imageUrl),
    imageUrl: trimString_(item && item.imageUrl)
  }));
}

function calculateStripeCheckoutLineItemsTotalCents_(lineItems) {
  return (Array.isArray(lineItems) ? lineItems : []).reduce((sum, item) => {
    return sum + Math.max(0, getStripeCheckoutLineItemAmountCents_(item));
  }, 0);
}

function summarizeStripeCheckoutChargeAmounts_(orderDraft, paymentMethodSelected, checkoutLineItems, shippingChargeCents, options) {
  const draft = (orderDraft && typeof orderDraft === 'object') ? orderDraft : {};
  const opts = (options && typeof options === 'object') ? options : {};
  const method = trimString_(paymentMethodSelected).toLowerCase();
  const lineSubtotalCents = calculateStripeCheckoutLineItemsTotalCents_(checkoutLineItems);
  const shippingCents = Math.max(0, parseInt(String(shippingChargeCents || 0), 10) || 0);
  const baseLineTotalCents = Object.prototype.hasOwnProperty.call(opts, 'baseLineTotalCents')
    ? Math.max(0, parseInt(String(opts.baseLineTotalCents || 0), 10) || 0)
    : Math.max(0, Math.round(roundMoney_(draft.amountGrandTotal) * 100));
  const stripeAmountTotalCents = lineSubtotalCents + shippingCents;
  const chargedTaxCents = (Array.isArray(checkoutLineItems) ? checkoutLineItems : [])
    .filter(isStripeCheckoutTaxLineItem_)
    .reduce((sum, item) => sum + Math.max(0, getStripeCheckoutLineItemAmountCents_(item)), 0);
  const cardFeeCents = method === PAYMENT_METHODS.card
    ? Math.max(0, lineSubtotalCents - baseLineTotalCents)
    : 0;
  return {
    amountCardFee: roundMoney_(cardFeeCents / 100),
    amountChargedTax: roundMoney_(chargedTaxCents / 100),
    amountChargedTotal: roundMoney_(stripeAmountTotalCents / 100),
    stripeAmountSubtotalCents: lineSubtotalCents,
    stripeAmountTotalCents: stripeAmountTotalCents
  };
}

function applyStripeCheckoutChargeSummaryToOrderDraft_(orderDraft, chargeSummary) {
  const draft = Object.assign({}, (orderDraft && typeof orderDraft === 'object') ? orderDraft : {});
  const summary = (chargeSummary && typeof chargeSummary === 'object') ? chargeSummary : {};
  [
    'amountCardFee',
    'amountChargedTax',
    'amountChargedTotal',
    'stripeAmountSubtotalCents',
    'stripeAmountTotalCents'
  ].forEach((key) => {
    if (!Object.prototype.hasOwnProperty.call(summary, key)) return;
    if (key.indexOf('Cents') >= 0) {
      draft[key] = Math.max(0, parseInt(String(summary[key] || 0), 10) || 0);
    } else {
      draft[key] = roundMoney_(summary[key]);
    }
  });
  return draft;
}

function buildStripeCheckoutActualAmountSummary_(sessionObj, fallbackDraft) {
  const session = (sessionObj && typeof sessionObj === 'object') ? sessionObj : {};
  const draft = (fallbackDraft && typeof fallbackDraft === 'object') ? fallbackDraft : {};
  const summary = {};
  const subtotalCents = parseInt(String(session.amount_subtotal || ''), 10);
  const totalCents = parseInt(String(session.amount_total || ''), 10);
  if (Number.isFinite(subtotalCents) && subtotalCents >= 0) {
    summary.stripeAmountSubtotalCents = subtotalCents;
    const baseLineTotalCents = Math.max(0, Math.round(roundMoney_(draft.amountGrandTotal) * 100));
    summary.amountCardFee = roundMoney_(Math.max(0, subtotalCents - baseLineTotalCents) / 100);
  }
  if (Number.isFinite(totalCents) && totalCents >= 0) {
    summary.stripeAmountTotalCents = totalCents;
    summary.amountChargedTotal = roundMoney_(totalCents / 100);
    if (!Object.prototype.hasOwnProperty.call(summary, 'amountCardFee')) {
      const baseLineTotalCents = Math.max(0, Math.round(roundMoney_(draft.amountGrandTotal) * 100));
      summary.amountCardFee = roundMoney_(Math.max(0, totalCents - baseLineTotalCents) / 100);
    }
  }
  if (Object.prototype.hasOwnProperty.call(draft, 'amountChargedTax')) {
    summary.amountChargedTax = roundMoney_(draft.amountChargedTax);
  }
  return summary;
}

function getHttpHeaderValue_(headers, key) {
  const wanted = trimString_(key).toLowerCase();
  if (!wanted || !headers || typeof headers !== 'object') return '';
  const keys = Object.keys(headers);
  for (let i = 0; i < keys.length; i += 1) {
    const name = String(keys[i] || '').trim().toLowerCase();
    if (name === wanted) return trimString_(headers[keys[i]]);
  }
  return '';
}

function buildStripeCheckoutSessionRequestData_(orderDraft, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const paymentMethodSelected = trimString_(opts.paymentMethodSelected).toLowerCase();
  const paymentMethodType = paymentMethodSelected === PAYMENT_METHODS.ach ? 'us_bank_account' : 'card';
  const paymentOrigin = paymentMethodSelected === PAYMENT_METHODS.ach
    ? normalizeAchPaymentSource_(opts.paymentOrigin || orderDraft.paymentOrigin || orderDraft.checkoutOrigin)
    : '';
  const isApPaymentLink = paymentOrigin === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link;
  const stripeCustomerId = trimString_(opts.stripeCustomerId);
  const prefillPayerEmail = opts.prefillPayerEmail === true;
  const collectPayerEmailInCheckout = shouldCollectPayerEmailInCheckout_(paymentMethodSelected, opts);
  const shouldAttachCustomerToCheckout = paymentMethodType === 'us_bank_account'
    && collectPayerEmailInCheckout !== true
    && !!stripeCustomerId;
  const accountSummary = (opts.accountSummary && typeof opts.accountSummary === 'object') ? opts.accountSummary : {};
  const suppressShippingAddressCollection = opts.suppressShippingAddressCollection === true;
  const returnBaseUrl = buildStripeReturnBaseUrl_(orderDraft.token, { returnUrl: opts.returnUrl });
  const successUrl = buildStripeCheckoutReturnUrl_(orderDraft.token, {
    returnUrl: returnBaseUrl,
    queryParams: {
      checkoutResult: 'success',
      stripeSessionId: '{CHECKOUT_SESSION_ID}',
      payNow: paymentMethodSelected === PAYMENT_METHODS.ach ? 'ach' : '',
      summary: isApPaymentLink ? '1' : '',
      paymentOrigin: isApPaymentLink ? 'ap' : ''
    }
  });
  const cancelUrl = buildStripeCheckoutReturnUrl_(orderDraft.token, {
    returnUrl: returnBaseUrl,
    queryParams: {
      checkoutResult: 'cancel',
      payNow: paymentMethodSelected === PAYMENT_METHODS.ach ? 'ach' : '',
      summary: isApPaymentLink ? '1' : '',
      paymentOrigin: isApPaymentLink ? 'ap' : ''
    }
  });
  const currency = trimString_(orderDraft.currency || getConfig_().stripePriceCurrency || DEFAULT_STRIPE_PRICE_CURRENCY).toLowerCase();
  const fulfillmentMethod = normalizeFulfillmentMethod_(orderDraft && orderDraft.fulfillmentMethod);
  const shippingChargeCents = Math.max(0, parseInt(String(orderDraft && orderDraft.shippingChargeCents || 0), 10) || 0);
  const shippingModeLabel = trimString_(orderDraft && orderDraft.shippingModeLabel);
  const checkoutShippingChargeCents = fulfillmentMethod === FULFILLMENT_METHODS.shipping && !suppressShippingAddressCollection
    ? shippingChargeCents
    : 0;
  const additionalTaxCents = calculateStripeCheckoutAdditionalShippingTaxCents_(orderDraft, checkoutShippingChargeCents);
  const lineItems = buildStripeCheckoutLineItemsFromOrderDraft_(orderDraft, {
    paymentMethodSelected: paymentMethodSelected,
    additionalTaxCents: additionalTaxCents
  });
  const checkoutLineItems = lineItems.length ? lineItems : finalizeStripeCheckoutLineItemDescriptions_(buildStripeCheckoutDefaultLineItems_(orderDraft));
  const chargeSummary = summarizeStripeCheckoutChargeAmounts_(
    orderDraft,
    paymentMethodSelected,
    checkoutLineItems,
    checkoutShippingChargeCents,
    {
      baseLineTotalCents: Math.max(0, Math.round(roundMoney_(orderDraft && orderDraft.amountGrandTotal) * 100)) + additionalTaxCents
    }
  );
  const metadata = {
    token: trimString_(orderDraft.token),
    checkoutAttemptId: trimString_(opts.checkoutAttemptId),
    orderId: trimString_(opts.orderId),
    paymentMethodSelected: paymentMethodSelected,
    paymentOrigin: paymentOrigin,
    preferredAchPaymentMethodId: paymentMethodSelected === PAYMENT_METHODS.ach
      ? trimString_(opts.preferredAchPaymentMethodId || orderDraft.preferredAchPaymentMethodId)
      : '',
    achCheckoutIntent: paymentMethodSelected === PAYMENT_METHODS.ach
      ? normalizeAchCheckoutIntent_(opts.achCheckoutIntent || orderDraft.achCheckoutIntent)
      : '',
    accountId: trimString_(accountSummary.accountId),
    orgId: trimString_(accountSummary.orgId),
    fulfillmentMethod: fulfillmentMethod,
    shippingChargeCents: String(shippingChargeCents),
    shippingModeLabel: shippingModeLabel,
    amountChargedTotal: String(chargeSummary.amountChargedTotal || ''),
    amountCardFee: String(chargeSummary.amountCardFee || '')
  };
  const payload = {
    mode: 'payment',
    success_url: successUrl,
    cancel_url: cancelUrl,
    'payment_method_types[0]': paymentMethodType
  };
  if (paymentMethodType === 'card') {
    const payerEmail = prefillPayerEmail ? normalizeEmail_(opts.paymentActorEmail || opts.payerEmail || orderDraft.personEmail) : '';
    if (payerEmail) payload.customer_email = payerEmail;
    payload['wallet_options[link][display]'] = 'never';
  } else if (shouldAttachCustomerToCheckout) {
    payload.customer = stripeCustomerId;
  }
  checkoutLineItems.forEach((lineItem, idx) => {
    appendStripeCheckoutLineItemToPayload_(payload, idx, lineItem, currency);
  });
  Object.keys(metadata).forEach((key) => {
    if (!metadata[key]) return;
    payload['metadata[' + key + ']'] = metadata[key];
    payload['payment_intent_data[metadata][' + key + ']'] = metadata[key];
  });
  if (fulfillmentMethod === FULFILLMENT_METHODS.shipping && !suppressShippingAddressCollection) {
    STRIPE_FULFILLMENT_ALLOWED_COUNTRIES.forEach(function (countryCode, idx) {
      payload['shipping_address_collection[allowed_countries][' + idx + ']'] = trimString_(countryCode).toUpperCase();
    });
    payload['shipping_options[0][shipping_rate_data][type]'] = 'fixed_amount';
    payload['shipping_options[0][shipping_rate_data][fixed_amount][amount]'] = String(shippingChargeCents);
    payload['shipping_options[0][shipping_rate_data][fixed_amount][currency]'] = currency;
    payload['shipping_options[0][shipping_rate_data][display_name]'] = shippingModeLabel || STRIPE_FULFILLMENT_SHIPPING_SERVICE_LABEL;
  }
  if (paymentMethodType === 'us_bank_account') {
    const permissions = Array.isArray(cfg.stripeAchFinancialConnectionsPermissions) && cfg.stripeAchFinancialConnectionsPermissions.length
      ? cfg.stripeAchFinancialConnectionsPermissions
      : DEFAULT_STRIPE_ACH_FINANCIAL_CONNECTIONS_PERMISSIONS;
    const shouldSaveAchForFuture = shouldAttachCustomerToCheckout && cfg.stripeAchSaveForFuture === true && opts.saveAchForFuture !== false;
    payload['payment_method_options[us_bank_account][verification_method]'] = trimString_(cfg.stripeAchVerificationMethod) || DEFAULT_STRIPE_ACH_VERIFICATION_METHOD;
    permissions.forEach(function(permission, idx) {
      payload['payment_method_options[us_bank_account][financial_connections][permissions][' + idx + ']'] = trimString_(permission);
    });
    if (shouldAttachCustomerToCheckout && opts.allowSavedPaymentMethodRedisplay !== false) {
      payload['saved_payment_method_options[allow_redisplay_filters][0]'] = 'unspecified';
      payload['saved_payment_method_options[allow_redisplay_filters][1]'] = 'always';
      if (shouldSaveAchForFuture) {
        payload['payment_method_data[allow_redisplay]'] = 'always';
      }
    }
    if (shouldSaveAchForFuture) {
      payload['payment_intent_data[setup_future_usage]'] = 'off_session';
    }
  }
  return {
    payload: payload,
    checkoutLineItems: checkoutLineItems,
    chargeSummary: chargeSummary,
    stripeVersion: DEFAULT_STRIPE_CHECKOUT_SESSION_API_VERSION
  };
}

function buildStripeCheckoutSessionRequest_(orderDraft, options) {
  return buildStripeCheckoutSessionRequestData_(orderDraft, options).payload;
}

function createStripeCheckoutSession_(orderDraft, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const timing = opts.timing || null;
  const cfg = opts.cfg || getConfig_();
  markCheckoutTiming_(timing, 'stripe_total_validation_start');
  const grandTotal = roundMoney_(toFiniteNumber_(orderDraft && orderDraft.amountGrandTotal, 0));
  markCheckoutTiming_(timing, 'stripe_total_validation_end', { ok: grandTotal > 0 });
  if (grandTotal <= 0) {
    return {
      ok: false,
      configured: true,
      error: 'Hosted card and ACH checkout are only available when the order total is greater than $0. Please contact Red Threads to place this order.',
      code: 'non_positive_checkout_total',
      amountGrandTotal: grandTotal,
      currency: trimString_(orderDraft && orderDraft.currency) || DEFAULT_STRIPE_PRICE_CURRENCY
    };
  }
  if (!trimString_(cfg.stripeSecretKey)) {
    console.log('[RT-STRIPE-CHECKOUT] ' + JSON.stringify({
      ok: false,
      paymentMethodSelected: trimString_(opts.paymentMethodSelected),
      error: 'stripe_config_missing'
    }));
    return {
      ok: false,
      configured: false,
      error: 'Stripe secret key is not configured.',
      code: 'stripe_config_missing'
    };
  }
  if (trimString_(opts.paymentMethodSelected).toLowerCase() === PAYMENT_METHODS.ach) {
    if (cfg.stripeAchEnabled !== true) {
      return {
        ok: false,
        configured: true,
        error: 'ACH bank payments are not currently available.',
        code: 'ach_checkout_disabled'
      };
    }
    if (cfg.stripeAchRequireCustomer === true &&
        shouldAttachStripeCustomerToPaymentCheckout_(PAYMENT_METHODS.ach, opts) &&
        !trimString_(opts.stripeCustomerId)) {
      return {
        ok: false,
        configured: true,
        error: 'ACH checkout requires a Stripe Customer.',
        code: 'ach_customer_required'
      };
    }
  }

  markCheckoutTiming_(timing, 'stripe_payload_build_start');
  const sessionRequestData = buildStripeCheckoutSessionRequestData_(orderDraft, opts);
  const lineItemDiagnostics = summarizeStripeCheckoutLineItemsForLog_(sessionRequestData.checkoutLineItems);
  const hasAnyImages = lineItemDiagnostics.some((item) => item.hasImage === true);
  markCheckoutTiming_(timing, 'stripe_payload_build_end', {
    method: trimString_(opts.paymentMethodSelected)
  });
  console.log('[RT-STRIPE-CHECKOUT-PAYLOAD] ' + JSON.stringify({
    ok: true,
    paymentMethodSelected: trimString_(opts.paymentMethodSelected),
    checkoutAttemptId: trimString_(opts.checkoutAttemptId),
    orderId: trimString_(opts.orderId),
    stripeVersion: sessionRequestData.stripeVersion,
    chargeSummary: sessionRequestData.chargeSummary,
    hasAnyImages: hasAnyImages,
    imageLineItemCount: lineItemDiagnostics.filter((item) => item.hasImage === true).length,
    lineItems: lineItemDiagnostics
  }));

  markCheckoutTiming_(timing, 'stripe_api_call_start');
  let response;
  try {
    response = UrlFetchApp.fetch('https://api.stripe.com/v1/checkout/sessions', {
      method: 'post',
      payload: sessionRequestData.payload,
      headers: {
        Authorization: 'Bearer ' + cfg.stripeSecretKey,
        'Stripe-Version': sessionRequestData.stripeVersion
      },
      muteHttpExceptions: true
    });
  } finally {
    markCheckoutTiming_(timing, 'stripe_api_call_end');
  }
  const statusCode = Number(response.getResponseCode() || 0);
  markCheckoutTiming_(timing, 'stripe_api_response_parse_start', { statusCode: statusCode });
  const responseHeaders = response.getAllHeaders() || {};
  const responseStripeVersion = getHttpHeaderValue_(responseHeaders, 'Stripe-Version');
  const body = safeJsonParse_(response.getContentText(), null);
  markCheckoutTiming_(timing, 'stripe_api_response_parse_end', { statusCode: statusCode });
  if (statusCode < 200 || statusCode >= 300 || !body || typeof body !== 'object') {
    console.log('[RT-STRIPE-CHECKOUT] ' + JSON.stringify({
      ok: false,
      paymentMethodSelected: trimString_(opts.paymentMethodSelected),
      checkoutAttemptId: trimString_(opts.checkoutAttemptId),
      orderId: trimString_(opts.orderId),
      statusCode: statusCode,
      stripeVersion: sessionRequestData.stripeVersion,
      responseStripeVersion: responseStripeVersion,
      hasAnyImages: hasAnyImages,
      imageLineItemCount: lineItemDiagnostics.filter((item) => item.hasImage === true).length
    }));
    return {
      ok: false,
      configured: true,
      error: 'Stripe Checkout Session creation failed.',
      code: 'checkout_session_create_failed',
      statusCode: statusCode,
      body: body || String(response.getContentText() || '').slice(0, 500)
    };
  }
  const sessionId = trimString_(body.id);
  const checkoutUrl = trimString_(body.url);
  const returnBaseUrl = buildStripeReturnBaseUrl_(orderDraft.token, { returnUrl: opts.returnUrl || cfg.stripeReturnUrl });
  const successUrl = buildStripeCheckoutReturnUrl_(orderDraft.token, {
    returnUrl: returnBaseUrl,
    queryParams: {
      checkoutResult: 'success',
      stripeSessionId: '{CHECKOUT_SESSION_ID}',
      payNow: trimString_(opts.paymentMethodSelected).toLowerCase() === PAYMENT_METHODS.ach ? 'ach' : '',
      summary: normalizeAchPaymentSource_(opts.paymentOrigin) === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link ? '1' : '',
      paymentOrigin: normalizeAchPaymentSource_(opts.paymentOrigin) === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link ? 'ap' : ''
    }
  });
  const cancelUrl = buildStripeCheckoutReturnUrl_(orderDraft.token, {
    returnUrl: returnBaseUrl,
    queryParams: {
      checkoutResult: 'cancel',
      payNow: trimString_(opts.paymentMethodSelected).toLowerCase() === PAYMENT_METHODS.ach ? 'ach' : '',
      summary: normalizeAchPaymentSource_(opts.paymentOrigin) === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link ? '1' : '',
      paymentOrigin: normalizeAchPaymentSource_(opts.paymentOrigin) === ACH_PAYMENT_METHOD_SOURCES.ap_payment_link ? 'ap' : ''
    }
  });
  console.log('[RT-STRIPE-CHECKOUT] ' + JSON.stringify({
    ok: true,
    paymentMethodSelected: trimString_(opts.paymentMethodSelected),
    checkoutAttemptId: trimString_(opts.checkoutAttemptId),
    orderId: trimString_(opts.orderId),
    sessionId: sessionId,
    hasCheckoutUrl: !!checkoutUrl,
    stripeVersion: sessionRequestData.stripeVersion,
    responseStripeVersion: responseStripeVersion,
    chargeSummary: sessionRequestData.chargeSummary,
    hasAnyImages: hasAnyImages,
    imageLineItemCount: lineItemDiagnostics.filter((item) => item.hasImage === true).length
  }));
  if (!sessionId) {
    console.log('[RT-STRIPE-CHECKOUT] ' + JSON.stringify({
      ok: false,
      paymentMethodSelected: trimString_(opts.paymentMethodSelected),
      error: 'checkout_session_id_missing'
    }));
    return {
      ok: false,
      configured: true,
      code: 'checkout_session_id_missing',
      error: 'Stripe Checkout session identifier missing from session response.',
      statusCode: statusCode,
      body: body
    };
  }
  if (!checkoutUrl) {
    console.log('[RT-STRIPE-CHECKOUT] ' + JSON.stringify({
      ok: false,
      paymentMethodSelected: trimString_(opts.paymentMethodSelected),
      sessionId: sessionId,
      error: 'checkout_url_missing'
    }));
    return {
      ok: false,
      configured: true,
      code: 'checkout_url_missing',
      error: 'Stripe Checkout URL missing from session response.',
      statusCode: statusCode,
      body: body
    };
  }
  return {
    ok: true,
    configured: true,
    publishableKey: cfg.stripePublishableKey,
    mode: cfg.stripeMode,
    uiMode: 'hosted',
    paymentUi: 'hosted',
    sessionId: sessionId,
    checkoutUrl: checkoutUrl,
    url: checkoutUrl,
    returnUrl: returnBaseUrl,
    successUrl: successUrl,
    cancelUrl: cancelUrl,
    amountCardFee: sessionRequestData.chargeSummary.amountCardFee,
    amountChargedTax: sessionRequestData.chargeSummary.amountChargedTax,
    amountChargedTotal: sessionRequestData.chargeSummary.amountChargedTotal,
    stripeAmountSubtotalCents: sessionRequestData.chargeSummary.stripeAmountSubtotalCents,
    stripeAmountTotalCents: sessionRequestData.chargeSummary.stripeAmountTotalCents,
    chargeSummary: sessionRequestData.chargeSummary
  };
}

function setPortalClientLockForRow_(sheet, rowInfo, locked, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const currentPortalState = safeJsonParse_(rowInfo.rowObjNormalized.portalstatejson, null) || { printJobs: {} };
  const currentChatLog = readChatLogForRow_(sheet, rowInfo);
  return persistPortalStateForRow_(sheet, rowInfo, currentPortalState, {
    token: trimString_(opts.token || rowInfo.rowObjNormalized.token),
    locked: locked === true,
    chatLog: currentChatLog,
    clearSubmittedAt: locked !== true
  });
}

function buildSafeSnapshotLoadResponse_(rowInfo, token, mode) {
  const built = buildPortalVmForRow_(rowInfo, token, mode || 'client');
  if (!built.ok) return null;
  return makeClientSafe_(built.vm);
}

function deriveProjectNameForNotification_(row, snapshot, overrides) {
  const opts = (overrides && typeof overrides === 'object') ? overrides : {};
  const overrideName = String(opts.projectName || '').trim();
  if (overrideName) return overrideName;

  const normalizedRow = (row && typeof row === 'object') ? row : {};
  const snapshotObj = (snapshot && typeof snapshot === 'object') ? snapshot : {};
  const meta = snapshotObj.meta && typeof snapshotObj.meta === 'object' ? snapshotObj.meta : {};

  const dealTitle = String(
    normalizedRow.dealtitle ||
    normalizedRow.projectname ||
    meta.dealTitle ||
    meta.projectName ||
    ''
  ).trim();
  const dealNumber = String(
    normalizedRow.dealnumber ||
    meta.dealNumber ||
    ''
  ).trim();

  if (dealNumber && dealTitle) return dealNumber + ' - ' + dealTitle;
  if (dealTitle) return dealTitle;
  if (dealNumber) return dealNumber;

  const printJobId = String(opts.printJobId || '').trim();
  return printJobId ? ('Print Job ' + printJobId) : '';
}

function getVisibleTeamAuthorName_(row) {
  const normalizedRow = (row && typeof row === 'object') ? row : {};
  return String(
    normalizedRow.sentby ||
    normalizedRow.assigneddesigner ||
    normalizedRow.assignedto ||
    normalizedRow.projectowner ||
    'Red Threads Team'
  ).trim() || 'Red Threads Team';
}

function deriveSenderNameForNotification_(row, senderType) {
  const opts = arguments[2] && typeof arguments[2] === 'object' ? arguments[2] : {};
  const normalizedRow = (row && typeof row === 'object') ? row : {};
  if (String(senderType || '').trim().toLowerCase() === 'team') {
    const override = String(opts.teamSenderName || '').trim();
    if (override) return override;
    return getVisibleTeamAuthorName_(normalizedRow);
  }
  return String(
    normalizedRow.personname ||
    normalizedRow.clientname ||
    normalizedRow.orgname ||
    normalizedRow[EXPORT_LOG_PERSON_EMAIL_HEADER] ||
    'Client'
  ).trim();
}

function buildChatNotificationPayload_(rowInfo, message, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const row = rowInfo && rowInfo.rowObjNormalized ? rowInfo.rowObjNormalized : {};
  const senderType = String(opts.senderType || message.sender || 'client').trim().toLowerCase() || 'client';
  const normalizedMessage = normalizeChatLog_([message])[0] || createChatMessage_(senderType, String(opts.messageText || '').trim());
  const snapshot = safeJsonParse_(row.snapshotjson, null);
  const token = String(opts.token || row.token || '').trim();
  const personEmail = normalizeEmail_(row[EXPORT_LOG_PERSON_EMAIL_HEADER]);
  const teamMemberName = String(opts.teamSenderName || '').trim() || getVisibleTeamAuthorName_(row);
  const projectName = deriveProjectNameForNotification_(row, snapshot, opts);
  const messageText = String(opts.messageText || normalizedMessage.text || '').trim() || String(normalizedMessage.text || '').trim();

  return {
    eventType: 'chat_message_created',
    token: token,
    senderType: senderType === 'team' ? 'team' : 'client',
    messageText: messageText,
    messageCreatedAt: String(normalizedMessage.ts || new Date().toISOString()),
    senderName: deriveSenderNameForNotification_(row, senderType, opts),
    teamMemberName: teamMemberName,
    projectName: projectName,
    personEmail: personEmail,
    teamInboxEmail: DOCUMENT_REVIEW_EMAIL,
    portalDirectUrl: buildPortalDirectUrl_(token)
  };
}

function isChatMessageDigestEmailJobType_(value) {
  return trimString_(value).toLowerCase() === PORTAL_EMAIL_QUEUE_JOB_TYPES.chat_message_digest_email;
}

function normalizeChatMessageDigestDirection_(value) {
  const clean = trimString_(value).toLowerCase();
  return clean === CHAT_MESSAGE_DIGEST_DIRECTIONS.client_to_team ||
    clean === CHAT_MESSAGE_DIGEST_DIRECTIONS.team_to_client
    ? clean
    : '';
}

function getChatMessageDigestDirectionForSender_(sender) {
  const clean = trimString_(sender).toLowerCase();
  if (clean === 'team') return CHAT_MESSAGE_DIGEST_DIRECTIONS.team_to_client;
  if (clean === 'client') return CHAT_MESSAGE_DIGEST_DIRECTIONS.client_to_team;
  return '';
}

function getChatMessageDigestRecipientClass_(direction) {
  const clean = normalizeChatMessageDigestDirection_(direction);
  if (clean === CHAT_MESSAGE_DIGEST_DIRECTIONS.client_to_team) return 'team';
  if (clean === CHAT_MESSAGE_DIGEST_DIRECTIONS.team_to_client) return 'client';
  return '';
}

function getChatMessageDigestExpectedSender_(direction) {
  const clean = normalizeChatMessageDigestDirection_(direction);
  if (clean === CHAT_MESSAGE_DIGEST_DIRECTIONS.client_to_team) return 'client';
  if (clean === CHAT_MESSAGE_DIGEST_DIRECTIONS.team_to_client) return 'team';
  return '';
}

function parseChatMessageDigestRecipients_(rawValue) {
  const parsed = safeJsonParse_(rawValue, []);
  if (Array.isArray(parsed)) {
    return {
      toList: normalizeEmailRecipients_(parsed),
      ccList: []
    };
  }
  const source = (parsed && typeof parsed === 'object') ? parsed : {};
  return {
    toList: normalizeEmailRecipients_(source.toList || source.to || source.recipients),
    ccList: normalizeEmailRecipients_(source.ccList || source.cc),
    recipientClass: trimString_(source.recipientClass),
    direction: normalizeChatMessageDigestDirection_(source.direction)
  };
}

function buildChatMessageDigestRecipients_(rowInfo, direction, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const row = rowInfo && rowInfo.rowObjNormalized ? rowInfo.rowObjNormalized : {};
  const cleanDirection = normalizeChatMessageDigestDirection_(direction);
  if (cleanDirection === CHAT_MESSAGE_DIGEST_DIRECTIONS.client_to_team) {
    return {
      toList: normalizeEmailRecipients_([opts.teamInboxEmail || DOCUMENT_REVIEW_EMAIL]),
      ccList: [],
      recipientClass: 'team',
      direction: cleanDirection
    };
  }
  if (cleanDirection === CHAT_MESSAGE_DIGEST_DIRECTIONS.team_to_client) {
    return {
      toList: normalizeEmailRecipients_([opts.personEmail || row[EXPORT_LOG_PERSON_EMAIL_HEADER]]),
      ccList: [],
      recipientClass: 'client',
      direction: cleanDirection
    };
  }
  return {
    toList: [],
    ccList: [],
    recipientClass: '',
    direction: ''
  };
}

function buildChatMessageDigestEmailIdempotencyKey_(source) {
  const safe = (source && typeof source === 'object') ? source : {};
  return buildPortalEmailQueueIdempotencyKeyForSource_({
    jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.chat_message_digest_email,
    token: trimString_(safe.token),
    direction: normalizeChatMessageDigestDirection_(safe.direction),
    recipientClass: trimString_(safe.recipientClass),
    firstMessageId: trimString_(safe.firstMessageId),
    windowStartedAt: trimString_(safe.windowStartedAt),
    toList: normalizeEmailRecipients_(safe.toList),
    ccList: normalizeEmailRecipients_(safe.ccList)
  });
}

function findOpenChatMessageDigestEmailQueueJob_(queueSheet, token, direction) {
  const cleanToken = trimString_(token);
  const cleanDirection = normalizeChatMessageDigestDirection_(direction);
  if (!queueSheet || !cleanToken || !cleanDirection) return null;
  return listSheetRowInfos_(queueSheet).find(function(info) {
    const row = info && info.rowObjNormalized ? info.rowObjNormalized : {};
    if (!isChatMessageDigestEmailJobType_(row.jobtype)) return false;
    if (trimString_(row.token) !== cleanToken) return false;
    const meta = safeJsonParse_(row.portalstatejson, {}) || {};
    if (normalizeChatMessageDigestDirection_(meta.direction) !== cleanDirection) return false;
    const status = normalizePortalEmailQueueStatus_(row.status);
    const attemptCount = Math.max(0, parseInt(String(row.attemptcount || 0), 10) || 0);
    if (status === PORTAL_EMAIL_QUEUE_STATUSES.queued) return true;
    return status === PORTAL_EMAIL_QUEUE_STATUSES.failed && attemptCount < PORTAL_EMAIL_QUEUE_MAX_ATTEMPTS;
  }) || null;
}

function logChatMessageDigestQueueEvent_(eventName, payload) {
  const p = (payload && typeof payload === 'object') ? payload : {};
  const safe = {
    event: trimString_(eventName),
    ok: p.ok === true,
    reason: trimString_(p.reason),
    jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.chat_message_digest_email,
    direction: normalizeChatMessageDigestDirection_(p.direction),
    recipientClass: trimString_(p.recipientClass),
    tokenPresent: !!trimString_(p.token),
    recipientCount: Math.max(0, parseInt(String(p.recipientCount || 0), 10) || 0),
    ccCount: Math.max(0, parseInt(String(p.ccCount || 0), 10) || 0),
    recipientDomains: Array.isArray(p.recipientDomains) ? p.recipientDomains : [],
    messageCount: Math.max(0, parseInt(String(p.messageCount || 0), 10) || 0),
    notBefore: trimString_(p.notBefore),
    due: p.due === true,
    status: trimString_(p.status),
    error: trimString_(p.error)
  };
  console.log('[RT-CHAT-DIGEST-QUEUE] ' + JSON.stringify(safe));
}

function queuePortalMessageDigestEmailSafely_(rowInfo, message, options) {
  try {
    const opts = (options && typeof options === 'object') ? options : {};
    const row = rowInfo && rowInfo.rowObjNormalized ? rowInfo.rowObjNormalized : {};
    const normalizedMessage = normalizeChatLog_([message])[0];
    const token = trimString_(opts.token || row.token);
    const direction = normalizeChatMessageDigestDirection_(opts.direction) ||
      getChatMessageDigestDirectionForSender_(opts.senderType || (normalizedMessage && normalizedMessage.sender));
    const recipientClass = getChatMessageDigestRecipientClass_(direction);
    if (!token || !normalizedMessage || !direction) {
      logChatMessageDigestQueueEvent_('not_queued', {
        ok: false,
        reason: 'invalid_chat_digest_context',
        direction: direction,
        recipientClass: recipientClass,
        token: token,
        messageCount: normalizedMessage ? 1 : 0
      });
      return null;
    }
    const expectedSender = getChatMessageDigestExpectedSender_(direction);
    if (expectedSender && trimString_(normalizedMessage.sender).toLowerCase() !== expectedSender) {
      logChatMessageDigestQueueEvent_('not_queued', {
        ok: false,
        reason: 'direction_sender_mismatch',
        direction: direction,
        recipientClass: recipientClass,
        token: token,
        messageCount: 1
      });
      return null;
    }
    const recipients = buildChatMessageDigestRecipients_(rowInfo, direction, opts);
    if (!recipients.toList.length) {
      logChatMessageDigestQueueEvent_('not_queued', {
        ok: false,
        reason: 'missing_recipients',
        direction: direction,
        recipientClass: recipientClass,
        token: token,
        recipientCount: 0,
        ccCount: 0,
        messageCount: 1
      });
      return { ok: false, skipped: true, reason: 'missing_recipients' };
    }
    const cfg = opts.cfg || getConfig_();
    const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
    const queueSheet = opts.queueSheet || getPortalEmailQueueSheet_(ss);
    const now = nowIso_();
    const messageAtMs = parseIsoDateMs_(normalizedMessage.ts) || Date.now();
    const notBefore = new Date(messageAtMs + CHAT_MESSAGE_DIGEST_DELAY_MS).toISOString();
    const existingJob = findOpenChatMessageDigestEmailQueueJob_(queueSheet, token, direction);
    const existingRow = existingJob && existingJob.rowObjNormalized ? existingJob.rowObjNormalized : {};
    const existingMeta = safeJsonParse_(existingRow.portalstatejson, {}) || {};
    const messageIds = uniqueTrimmedStrings_(
      (Array.isArray(existingMeta.messageIds) ? existingMeta.messageIds : [])
        .concat([normalizedMessage.id])
    );
    const windowStartedAt = trimString_(existingMeta.windowStartedAt || normalizedMessage.ts || now);
    const firstMessageId = trimString_(existingMeta.firstMessageId || messageIds[0] || normalizedMessage.id);
    const meta = {
      jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.chat_message_digest_email,
      direction: direction,
      recipientClass: recipientClass,
      token: token,
      firstMessageId: firstMessageId,
      messageIds: messageIds,
      windowStartedAt: windowStartedAt,
      lastMessageAt: trimString_(normalizedMessage.ts || now),
      notBefore: notBefore,
      sourceEvent: 'appendChatMessage',
      queuedAt: trimString_(existingMeta.queuedAt || now),
      updatedAt: now
    };
    const idempotencyKey = buildChatMessageDigestEmailIdempotencyKey_({
      token: token,
      direction: direction,
      recipientClass: recipientClass,
      firstMessageId: firstMessageId,
      windowStartedAt: windowStartedAt,
      toList: recipients.toList,
      ccList: recipients.ccList
    });
    const jobValues = {
      jobId: trimString_(existingRow.jobid) || newPortalId_('eml'),
      jobType: PORTAL_EMAIL_QUEUE_JOB_TYPES.chat_message_digest_email,
      idempotencyKey: idempotencyKey,
      token: token,
      status: PORTAL_EMAIL_QUEUE_STATUSES.queued,
      recipientsJson: JSON.stringify({
        toList: recipients.toList,
        ccList: recipients.ccList,
        recipientClass: recipientClass,
        direction: direction
      }),
      portalStateJson: JSON.stringify(meta),
      orderDraftJson: '',
      invoicePdfUrl: '',
      invoiceFileName: '',
      attemptCount: existingJob
        ? Math.max(0, parseInt(String(existingRow.attemptcount || 0), 10) || 0)
        : 0,
      lastError: '',
      createdAt: trimString_(existingRow.createdat) || now,
      updatedAt: now,
      startedAt: '',
      completedAt: '',
      leaseUntil: ''
    };
    let jobInfo;
    if (existingJob) {
      setRowValuesByHeaderMap_(queueSheet, existingJob.row, existingJob.colMap, jobValues);
      jobInfo = buildRowInfoFromSheet_(queueSheet, existingJob.row);
    } else {
      jobInfo = appendPortalEmailQueueJob_(queueSheet, jobValues);
    }
    logChatMessageDigestQueueEvent_(existingJob ? 'updated' : 'queued', {
      ok: true,
      direction: direction,
      recipientClass: recipientClass,
      token: token,
      recipientCount: recipients.toList.length,
      ccCount: recipients.ccList.length,
      recipientDomains: summarizeEmailDomainsForLog_(recipients.toList.concat(recipients.ccList)),
      messageCount: messageIds.length,
      notBefore: notBefore,
      due: false,
      status: PORTAL_EMAIL_QUEUE_STATUSES.queued
    });
    schedulePortalEmailQueueProcessor_(Math.max(0, parseIsoDateMs_(notBefore) - Date.now()));
    return jobInfo;
  } catch (err) {
    logChatMessageDigestQueueEvent_('not_queued', {
      ok: false,
      reason: 'queue_error',
      error: String((err && err.message) || err)
    });
    return null;
  }
}

function selectChatMessageDigestMessages_(chatLog, meta, direction) {
  const normalizedLog = normalizeChatLog_(chatLog);
  const expectedSender = getChatMessageDigestExpectedSender_(direction);
  const source = (meta && typeof meta === 'object') ? meta : {};
  const messageIds = uniqueTrimmedStrings_(Array.isArray(source.messageIds) ? source.messageIds : []);
  if (messageIds.length) {
    const byId = {};
    normalizedLog.forEach(function(message) {
      byId[trimString_(message.id)] = message;
    });
    return messageIds
      .map(function(messageId) { return byId[messageId]; })
      .filter(function(message) {
        return message && (!expectedSender || trimString_(message.sender).toLowerCase() === expectedSender);
      });
  }
  const windowStartedMs = parseIsoDateMs_(source.windowStartedAt);
  const lastMessageMs = parseIsoDateMs_(source.lastMessageAt);
  if (!windowStartedMs || !lastMessageMs) return [];
  return normalizedLog.filter(function(message) {
    if (expectedSender && trimString_(message.sender).toLowerCase() !== expectedSender) return false;
    const messageMs = parseIsoDateMs_(message.ts);
    return messageMs >= windowStartedMs && messageMs <= lastMessageMs;
  });
}

function formatChatMessageDigestTimestamp_(value) {
  const ms = parseIsoDateMs_(value);
  if (!ms) return '';
  try {
    return Utilities.formatDate(new Date(ms), Session.getScriptTimeZone(), 'M/d/yyyy h:mm a');
  } catch (_) {
    return new Date(ms).toISOString();
  }
}

function getChatMessageDigestJobNumber_(message) {
  const idRaw = trimString_(message && (message.pjId || message.printJobId));
  if (idRaw) {
    const idMatch = idRaw.match(/(?:^|[^0-9])(\d+)\b/);
    if (idMatch && idMatch[1]) return trimString_(idMatch[1]);
  }
  const sources = [
    trimString_(message && message.pjLabel),
    trimString_(String((message && message.text) || '').split(/\r?\n/)[0])
  ];
  for (let i = 0; i < sources.length; i += 1) {
    const raw = sources[i];
    if (!raw) continue;
    const jobMatch = raw.match(/\bprint\s*job\s*(?:pj)?\s*(\d+)\b/i);
    if (jobMatch && jobMatch[1]) return trimString_(jobMatch[1]);
    const pjMatch = raw.match(/\bpj\s*(\d+)\b/i);
    if (pjMatch && pjMatch[1]) return trimString_(pjMatch[1]);
  }
  return '';
}

function getChatMessageDigestJobName_(message) {
  const direct = trimString_(message && (message.pjName || message.printJobName));
  if (direct) return direct;

  const label = trimString_(message && message.pjLabel);
  const firstLine = trimString_(String((message && message.text) || '').split(/\r?\n/)[0]);
  const sources = [label, firstLine];
  for (let i = 0; i < sources.length; i += 1) {
    const raw = sources[i];
    if (!raw) continue;
    const match = raw.match(/^\s*comment on print\s*job\s*(?:pj)?\s*\d+\s*(.*)$/i);
    if (match && match[1]) {
      return trimString_(String(match[1]).replace(/^[\s:;-]+/, ''));
    }
  }
  return '';
}

function buildChatMessageDigestJobLine_(message) {
  const number = getChatMessageDigestJobNumber_(message);
  const name = getChatMessageDigestJobName_(message);
  if (number && name) return 'PJ' + number + ': ' + name;
  if (number) return 'PJ' + number;
  if (name) return name;
  return '';
}

function stripChatMessageDigestEmbeddedJobLine_(message, value) {
  const raw = trimString_(value);
  if (!raw) return '';
  const lines = raw.split(/\r?\n/);
  const firstLine = trimString_(lines[0]);
  const explicitLabel = trimString_(message && message.pjLabel);
  const firstLower = firstLine.toLowerCase();
  const labelLower = explicitLabel.toLowerCase();
  const dropFirstLine = (labelLower && firstLower === labelLower) ||
    /^comment on print\s*job\b/i.test(firstLine);
  return dropFirstLine ? trimString_(lines.slice(1).join('\n')) : raw;
}

function getChatDigestProjectNumberLabel_(projectName, lifecycleSections) {
  const ctx = lifecycleSections && lifecycleSections.emailContext ? lifecycleSections.emailContext : null;
  const fromContext = getLifecycleEmailProjectNumberLabel_(ctx);
  if (fromContext) return fromContext;
  const match = trimString_(projectName).match(/\b([0-9]{3,})\b/);
  return match ? trimString_(match[1]) : '';
}

function buildChatDigestClientCtaLabel_(projectNumber) {
  return 'Reply to this message in your portal';
}

function buildChatDigestTeamCtaLabel_(projectNumber) {
  return buildLifecycleEmailTeamModeProjectCtaLabel_(projectNumber, 'to reply');
}

function buildChatMessageDigestEmailContent_(rowInfo, messages, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const row = rowInfo && rowInfo.rowObjNormalized ? rowInfo.rowObjNormalized : {};
  const direction = normalizeChatMessageDigestDirection_(opts.direction);
  const isTeamDigest = direction === CHAT_MESSAGE_DIGEST_DIRECTIONS.client_to_team;
  const safeMessages = normalizeChatLog_(messages);
  const token = trimString_(opts.token || row.token);
  const snapshot = safeJsonParse_(row.snapshotjson, null);
  const projectName = deriveProjectNameForNotification_(row, snapshot, opts);
  const messageCount = safeMessages.length;
  const clientEmail = normalizeEmail_(row[EXPORT_LOG_PERSON_EMAIL_HEADER]);
  const clientDisplayName = trimString_(
    row.personname ||
    row.clientname ||
    row.primarycontactname ||
    row.billingcontactname ||
    row.orgname
  );
  const clientName = clientDisplayName || 'there';
  const firstName = trimString_(clientName.split(/\s+/)[0]) || 'there';
  let resolvedClientSenderName = trimString_(
    clientDisplayName ||
    deriveSenderNameForNotification_(row, 'client', opts) ||
    row.orgname ||
    'Project contact'
  );
  if (/^client$/i.test(resolvedClientSenderName)) resolvedClientSenderName = 'Project contact';
  const portalUrl = isTeamDigest
    ? buildTeamSnapshotPortalUrl_(token)
    : buildExternalPortalUrl_(token);
  const lifecycleSections = buildDirectLifecycleEmailSectionBlocks_({ rowInfo: rowInfo }, null, {
    family: 'chat_message_digest',
    recipientClass: isTeamDigest ? 'team' : 'client',
    token: token,
    cfg: opts.cfg,
    ss: opts.ss,
    infra: opts.infra,
    projectDetailsCta: false
  });
  const communicationContract = buildPortalCommunicationContext_({
    emailContext: lifecycleSections.emailContext
  }, {
    family: 'chat_message_digest',
    trigger: 'chat_digest',
    recipientClass: isTeamDigest ? 'team' : 'client',
    cfg: opts.cfg,
    ss: opts.ss,
    infra: opts.infra
  });
  const projectNumber = getChatDigestProjectNumberLabel_(projectName, lifecycleSections);
  const subjectBase = isTeamDigest
    ? buildTeamSubject_('New client portal messages (' + messageCount + ')')
    : (messageCount === 1
      ? 'New portal message from Red Threads'
      : 'New portal messages from Red Threads (' + messageCount + ')');
  const subject = buildPortalEmailSubject_(subjectBase, {
    projectNumber: projectNumber,
    projectName: projectName
  });
  const projectNameDisplay = formatLifecycleEmailProjectNameValue_(projectName, projectNumber) || projectName;
  const ctaLabel = isTeamDigest ? buildChatDigestTeamCtaLabel_(projectNumber) : buildChatDigestClientCtaLabel_(projectNumber);
  const teamModePassword = isTeamDigest && opts.cfg ? trimString_(opts.cfg.teamModePassword) : '';
  const teamPasswordHintText = buildLifecycleEmailTeamPasswordHintText_(teamModePassword);
  const teamPasswordHintHtml = buildLifecycleEmailTeamPasswordHintHtml_(teamModePassword);
  const lifecycleText = lifecycleSections.blocks.map(function(block) {
    return trimString_(block && block.text);
  }).filter(Boolean).join('\n\n');
  const lifecycleHtml = lifecycleSections.blocks.map(function(block) {
    return trimString_(block && block.html);
  }).filter(Boolean).join('\n');
  const messageRows = safeMessages.map(function(message) {
    const senderName = trimString_(message.sender).toLowerCase() === 'team'
      ? trimString_(message.authorName || getVisibleTeamAuthorName_(row) || 'Red Threads Team')
      : (/^client$/i.test(trimString_(message.authorName))
        ? resolvedClientSenderName
        : trimString_(message.authorName || resolvedClientSenderName));
    return {
      senderName: senderName,
      isTeamMessage: trimString_(message.sender).toLowerCase() === 'team',
      timestamp: formatChatMessageDigestTimestamp_(message.ts),
      jobLine: buildChatMessageDigestJobLine_(message),
      text: stripChatMessageDigestEmbeddedJobLine_(message, message.text)
    };
  });
  const plainMessageLines = [];
  messageRows.forEach(function(messageRow) {
    plainMessageLines.push(messageRow.senderName + ' ' + (messageRow.timestamp || 'Time unavailable'));
    if (messageRow.jobLine) plainMessageLines.push(messageRow.jobLine);
    plainMessageLines.push(messageRow.text || '--');
    plainMessageLines.push('');
  });
  const body = isTeamDigest
    ? [
        resolvedClientSenderName + ' sent ' + messageCount + ' portal message' + (messageCount === 1 ? '' : 's') + '.',
        'Messages:',
        plainMessageLines.join('\n').trim(),
        '',
        portalUrl ? (ctaLabel + ': ' + portalUrl) : '',
        portalUrl ? teamPasswordHintText : '',
        '',
        lifecycleText
      ].filter(Boolean).join('\n')
    : [
        'Hi ' + firstName + ',',
        '',
        'You have ' + messageCount + ' new Red Threads portal message' + (messageCount === 1 ? '' : 's') + '.',
        plainMessageLines.join('\n').trim(),
        '',
        portalUrl ? (ctaLabel + ': ' + portalUrl) : '',
        lifecycleText || (projectName ? ('Project: ' + projectName) : ''),
        '',
        buildStandardNoReplyFooterCopy_(),
        '',
        '- Red Threads Team'
      ].filter(Boolean).join('\n');
  const theme = getPortalNativeEmailTheme_();
  const htmlMessages = messageRows.map(function(messageRow) {
    const metaColor = messageRow.isTeamMessage ? theme.brandRedMid : '#94a3b8';
    const textColor = isTeamDigest && !messageRow.isTeamMessage
      ? theme.successGreen
      : (messageRow.isTeamMessage ? theme.brandRedMid : '#cbd5e1');
    return [
      '      <tr>',
      '        <td style="padding:14px 16px;border-top:1px solid #1e293b;">',
      '          <div style="font-size:13px;line-height:1.5;color:' + metaColor + ';"><strong style="color:' + metaColor + ';">' + escapeHtml_(messageRow.senderName) + '</strong>' + (messageRow.timestamp ? (' <span style="color:' + metaColor + ';">' + escapeHtml_(messageRow.timestamp) + '</span>') : '') + '</div>',
      messageRow.jobLine ? ('          <div style="margin-top:6px;font-size:13px;line-height:1.45;color:#f8fafc;font-weight:800;">' + escapeHtml_(messageRow.jobLine) + '</div>') : '',
      '          <div style="margin-top:8px;font-size:15px;line-height:1.65;color:' + textColor + ';white-space:pre-wrap;">' + escapeHtml_(messageRow.text || '--') + '</div>',
      '        </td>',
      '      </tr>'
    ].join('\n');
  }).join('\n');
  const messagesHtmlBlock = [
    '    <table role="presentation" width="100%" cellspacing="0" cellpadding="0" style="border-collapse:collapse;margin:0 0 20px;border:1px solid #1e293b;border-radius:12px;overflow:hidden;">',
    '      <tr><td style="padding:12px 16px;background:#0f172a;font-size:12px;letter-spacing:0.14em;text-transform:uppercase;color:#94a3b8;font-weight:800;">' + escapeHtml_(resolvedClientSenderName + ' sent ' + messageCount + ' portal message' + (messageCount === 1 ? '' : 's')) + '</td></tr>',
    htmlMessages,
    '    </table>'
  ].join('\n');
  const ctaHtml = portalUrl
    ? ('    <div style="margin:14px 0 18px;' + (isTeamDigest ? 'text-align:center;' : '') + '"><a href="' + escapeHtml_(portalUrl) + '" style="display:inline-block;padding:10px 15px;border-radius:999px;background:' + theme.brandRed + ';color:#ffffff;text-decoration:none;font-size:12px;line-height:1.2;font-weight:900;border:1px solid ' + theme.brandRedMid + ';">' + escapeHtml_(ctaLabel) + '</a>' + (isTeamDigest ? teamPasswordHintHtml : '') + '</div>')
    : '';
  const clientHtmlMessagesBlock = messageRows.map(function(messageRow, index) {
    const metaColor = messageRow.isTeamMessage ? theme.brandRed : theme.textSoft;
    const jobLineColor = messageRow.isTeamMessage ? theme.brandRedMid : theme.text;
    const textColor = messageRow.isTeamMessage ? '#fb7185' : theme.textMuted;
    const textWeight = messageRow.isTeamMessage ? '800' : '400';
    const separator = index > 0 ? ('padding-top:12px;border-top:1px solid ' + theme.panelBorderSoft + ';') : '';
    return [
      '<div style="margin:0 0 14px;' + separator + '">',
      '  <div style="font-size:13px;line-height:1.5;color:' + metaColor + ';"><strong style="color:' + metaColor + ';">' + escapeHtml_(messageRow.senderName) + '</strong>' + (messageRow.timestamp ? (' <span style="color:' + metaColor + ';">' + escapeHtml_(messageRow.timestamp) + '</span>') : '') + '</div>',
      messageRow.jobLine ? ('  <div style="margin-top:6px;font-size:13px;line-height:1.45;color:' + jobLineColor + ';font-weight:800;">' + escapeHtml_(messageRow.jobLine) + '</div>') : '',
      '  <div style="margin-top:8px;font-size:15px;line-height:1.65;color:' + textColor + ';font-weight:' + textWeight + ';white-space:pre-wrap;">' + escapeHtml_(messageRow.text || '--') + '</div>',
      '</div>'
    ].join('\n');
  }).join('\n');
  const clientMessageAndReplyHtml = !isTeamDigest
    ? [clientHtmlMessagesBlock, ctaHtml].filter(Boolean).join('\n')
    : '';
  const showProjectSummaryCard = isTeamDigest
    ? false
    : !!(projectName && !lifecycleHtml);
  const clientHeaderLabel = projectNumber
    ? ('Project # ' + projectNumber + ' — New portal message' + (messageCount === 1 ? '' : 's'))
    : 'You have new portal messages';
  const clientMessagePanelHtml = [
    '<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="margin:0 0 18px;border:1px solid ' + theme.panelBorder + ';border-radius:14px;background:' + theme.panelBg + ';border-collapse:separate;">',
    '<tr><td style="padding:14px 16px;">',
    '<p style="margin:0 0 12px;color:' + theme.text + ';">Hi ' + escapeHtml_(firstName) + ', you have ' + messageCount + ' new Red Threads portal message' + (messageCount === 1 ? '' : 's') + '.</p>',
    clientMessageAndReplyHtml,
    '</td></tr>',
    '</table>'
  ].filter(Boolean).join('\n');
  const clientHtmlBody = buildPortalNativeEmailShellHtml_({
    heading: clientHeaderLabel,
    bodyHtml: [
      '<div style="font-family:' + theme.fontFamily + ';font-size:14px;line-height:1.7;color:' + theme.textMuted + ';">',
      clientMessagePanelHtml,
      lifecycleHtml,
      '<p style="margin:0;color:' + theme.textSoft + ';font-size:13px;line-height:1.6;">' + escapeHtml_(buildStandardNoReplyFooterCopy_()) + '</p>',
      '</div>'
    ].filter(Boolean).join('\n')
  });
  const teamHtmlBody = [
    '<div style="margin:0;padding:24px 0;background:#000000;">',
    '  <div style="max-width:680px;margin:0 auto;padding:32px 28px;background:#05060a;border:1px solid #1e293b;border-radius:18px;font-family:Arial,sans-serif;color:#f8fafc;">',
    '    <div style="font-size:12px;letter-spacing:0.18em;text-transform:uppercase;color:' + theme.brandRedMid + ';font-weight:700;margin-bottom:12px;">' + escapeHtml_(getPortalNativeEmailEyebrow_('team')) + '</div>',
    isTeamDigest
      ? ''
      : ('    <p style="margin:0 0 18px;font-size:16px;line-height:1.7;color:#cbd5e1;">Hi ' + escapeHtml_(firstName) + ', you have ' + messageCount + ' new Red Threads portal message' + (messageCount === 1 ? '' : 's') + '.</p>'),
    showProjectSummaryCard
      ? ('    <div style="margin:0 0 18px;padding:16px 18px;border-radius:12px;background:#0f172a;border:1px solid #1e293b;font-size:14px;line-height:1.8;color:#cbd5e1;">'
        + (projectNumber ? ('<div><strong>Project #:</strong> ' + escapeHtml_(projectNumber) + '</div>') : '')
        + (projectNameDisplay ? ('<div><strong>Project name:</strong> ' + escapeHtml_(projectNameDisplay) + '</div>') : '')
        + (isTeamDigest && clientDisplayName ? ('<div><strong>Client name:</strong> ' + escapeHtml_(clientDisplayName) + '</div>') : '')
        + (isTeamDigest && clientEmail ? ('<div><strong>Client email:</strong> ' + escapeHtml_(clientEmail) + '</div>') : '')
        + '</div>')
      : '',
    isTeamDigest ? messagesHtmlBlock : clientMessageAndReplyHtml,
    isTeamDigest ? ctaHtml : '',
    lifecycleHtml,
    '    <p style="margin:0;font-size:14px;line-height:1.6;color:#94a3b8;">' + escapeHtml_(buildStandardNoReplyFooterCopy_()) + '</p>',
    '  </div>',
    '</div>'
  ].filter(Boolean).join('\n');
  const htmlBody = isTeamDigest ? teamHtmlBody : clientHtmlBody;
  return {
    subject: subject,
    body: body,
    htmlBody: htmlBody,
    communicationContract: communicationContract
  };
}

function processChatMessageDigestEmailQueueJob_(jobInfo, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  const cfg = opts.cfg || getConfig_();
  const ss = opts.ss || SpreadsheetApp.openById(cfg.sheetId);
  const infra = opts.infra || ensurePortalInfrastructure_(ss, cfg);
  const row = jobInfo && jobInfo.rowObjNormalized ? jobInfo.rowObjNormalized : {};
  const meta = safeJsonParse_(row.portalstatejson, {}) || {};
  const token = trimString_(row.token || meta.token);
  const direction = normalizeChatMessageDigestDirection_(meta.direction);
  const recipientClass = trimString_(meta.recipientClass) || getChatMessageDigestRecipientClass_(direction);
  const recipients = parseChatMessageDigestRecipients_(row.recipientsjson);
  if (!token) return { skipped: true, skipReason: 'missing_token' };
  if (!direction) return { skipped: true, skipReason: 'missing_direction' };
  if (!recipients.toList.length) return { skipped: true, skipReason: 'missing_recipients' };
  const rowInfo = findRowByToken_(infra.exportSheet, token);
  if (!rowInfo) return { skipped: true, skipReason: 'missing_project_row' };
  const messages = selectChatMessageDigestMessages_(readChatLogForRow_(infra.exportSheet, rowInfo), meta, direction);
  if (!messages.length) return { skipped: true, skipReason: 'no_digest_messages' };
  const content = buildChatMessageDigestEmailContent_(rowInfo, messages, {
    direction: direction,
    token: token,
    cfg: cfg,
    ss: ss,
    infra: infra
  });
  sendNotificationEmail_({
    toList: recipients.toList,
    ccList: recipients.ccList,
    subject: content.subject,
    body: content.body,
    htmlBody: content.htmlBody,
    fromAlias: NOTIFICATION_FROM_ALIAS,
    replyTo: NOTIFICATION_FROM_ALIAS
  });
  logChatMessageDigestQueueEvent_('sent', {
    ok: true,
    direction: direction,
    recipientClass: recipientClass,
    token: token,
    recipientCount: recipients.toList.length,
    ccCount: recipients.ccList.length,
    recipientDomains: summarizeEmailDomainsForLog_(recipients.toList.concat(recipients.ccList)),
    messageCount: messages.length,
    notBefore: trimString_(meta.notBefore),
    due: true,
    status: PORTAL_EMAIL_QUEUE_STATUSES.sent
  });
  return {
    messageCount: messages.length
  };
}

function normalizeEmail_(value) {
  return String(value || '').trim().toLowerCase();
}

function buildCacheDigestSegment_(value) {
  const digest = Utilities.computeDigest(
    Utilities.DigestAlgorithm.SHA_256,
    String(value || '')
  );
  return Utilities.base64EncodeWebSafe(digest).replace(/=+$/g, '').slice(0, 32);
}

function getDashboardProjectsCacheEpoch_() {
  try {
    return trimString_(CacheService.getScriptCache().get(DASHBOARD_PROJECT_CACHE_EPOCH_KEY)) || '0';
  } catch (_) {
    return '0';
  }
}

function bumpDashboardProjectsCacheEpoch_() {
  try {
    CacheService.getScriptCache().put(
      DASHBOARD_PROJECT_CACHE_EPOCH_KEY,
      String(Date.now()),
      AUTH_POLICY.PROJECT_CACHE_TTL_SEC
    );
  } catch (_) {}
}

function buildDashboardProjectsCacheProfileSegment_(profile) {
  return normalizeDashboardHomeProfile_(profile) === 'summary' ? 'summary' : 'full';
}

function buildProjectsCacheKey_(email, profile) {
  return 'rt:projects:v15:' + buildDashboardProjectsCacheProfileSegment_(profile) + ':' + getDashboardProjectsCacheEpoch_() + ':' + buildCacheDigestSegment_(normalizeEmail_(email));
}

function buildAccountProjectsCacheKey_(accountSummary, profile) {
  const account = (accountSummary && typeof accountSummary === 'object') ? accountSummary : {};
  const identity = {
    accountId: trimString_(account.accountId),
    orgId: trimString_(account.orgId),
    orgName: trimString_(account.orgName).toLowerCase(),
    primaryEmail: normalizeEmail_(account.primaryEmail),
    billingContactEmail: normalizeEmail_(account.billingContactEmail),
    updatedAt: trimString_(account.updatedAt),
    termsStatus: trimString_(account.documentWorkflows && account.documentWorkflows.creditTerms && account.documentWorkflows.creditTerms.status),
    taxExemptStatus: trimString_(account.documentWorkflows && account.documentWorkflows.taxExempt && account.documentWorkflows.taxExempt.status)
  };
  return DASHBOARD_ACCOUNT_PROJECT_CACHE_PREFIX + 'v15:' + buildDashboardProjectsCacheProfileSegment_(profile) + ':' + getDashboardProjectsCacheEpoch_() + ':' + buildCacheDigestSegment_(JSON.stringify(identity));
}

function parseIsoDateMs_(value) {
  if (!value) return 0;
  const ms = Date.parse(String(value));
  return isNaN(ms) ? 0 : ms;
}

function generateResetCode_() {
  return String(Math.floor(Math.random() * 900000) + 100000);
}

function hashPasswordV2_(password) {
  const salt = Utilities.getUuid();
  const iterations = AUTH_POLICY.HASH_ITERATIONS_V2;
  const hash = hashPasswordWithSalt_(salt, password, iterations);
  return 'v2:' + String(iterations) + ':' + salt + ':' + hash;
}

function hashPasswordWithSalt_(salt, password, iterations) {
  const rounds = Math.max(1, parseInt(String(iterations || 0), 10) || 0);
  let value = String(salt || '') + String(password || '');
  for (let i = 0; i < rounds; i++) {
    const bytes = Utilities.computeDigest(
      Utilities.DigestAlgorithm.SHA_256,
      value,
      Utilities.Charset.UTF_8
    );
    value = Utilities.base64Encode(bytes);
  }
  return value;
}

function verifyPasswordDetailed_(password, storedValue) {
  const stored = String(storedValue || '').trim();
  if (!stored) {
    return {
      ok: false,
      version: '',
      needsReset: true,
      reason: 'missing_hash'
    };
  }
  const parts = stored.split(':');
  if (!parts.length) return { ok: false, version: '' };

  // New format: v2:<iterations>:<salt>:<hash>
  if (parts[0] === 'v2' && parts.length === 4) {
    const iterations = parseInt(String(parts[1] || ''), 10);
    if (!Number.isFinite(iterations) || iterations < 1) return { ok: false, version: '' };
    if (iterations > AUTH_POLICY.MAX_VERIFY_ITERATIONS) {
      return {
        ok: false,
        version: 'v2',
        needsReset: true,
        reason: 'hash_too_slow'
      };
    }
    const salt = parts[2];
    const hash = parts[3];
    const computed = hashPasswordWithSalt_(salt, password, iterations);
    return { ok: timingSafeEquals_(computed, hash), version: 'v2', iterations: iterations };
  }

  // Legacy format: v1:<salt>:<hash>
  if (parts[0] === 'v1' && parts.length === 3) {
    return {
      ok: false,
      version: 'v1',
      needsReset: true,
      reason: 'legacy_hash'
    };
  }

  // Transitional fallback: support historical/plain-text rows long enough to upgrade on success.
  if (parts.length === 1) {
    const ok = timingSafeEquals_(String(password || ''), stored);
    return { ok: ok, version: 'plain', reason: ok ? 'plain_match' : 'plain_mismatch' };
  }

  return {
    ok: false,
    version: 'unknown',
    needsReset: true,
    reason: 'unknown_hash_format'
  };
}

function timingSafeEquals_(a, b) {
  const left = String(a || '');
  const right = String(b || '');
  const len = Math.max(left.length, right.length);
  let diff = left.length ^ right.length;
  for (let i = 0; i < len; i++) {
    const ca = i < left.length ? left.charCodeAt(i) : 0;
    const cb = i < right.length ? right.charCodeAt(i) : 0;
    diff |= (ca ^ cb);
  }
  return diff === 0;
}

function ensureRequiredCols_(colMap, required) {
  (required || []).forEach((key) => {
    if (!colMap[key]) {
      throw new Error('Missing required column: ' + key);
    }
  });
}

function findUserByEmail_(usersSheet, email) {
  const normalizedEmail = normalizeEmail_(email);
  if (!normalizedEmail) return null;

  const header = usersSheet.getRange(1, 1, 1, usersSheet.getLastColumn()).getValues()[0];
  const colMap = buildColumnMap_(header);
  const emailCol = colMap[AUTH_COLUMNS.USERS.email];
  if (!emailCol) throw new Error('USERS missing email column.');

  const lastRow = usersSheet.getLastRow();
  if (lastRow < 2) return null;

  const emailRange = usersSheet.getRange(2, emailCol, lastRow - 1, 1);
  const finder = emailRange.createTextFinder(normalizedEmail).matchEntireCell(true).matchCase(false);
  const cell = finder.findNext();
  if (!cell) {
    // Fallback for rows that may contain trailing/leading whitespace.
    const emailVals = emailRange.getValues();
    for (let i = 0; i < emailVals.length; i++) {
      const rowEmail = normalizeEmail_(emailVals[i][0]);
      if (rowEmail === normalizedEmail) {
        const row = i + 2;
        const rowVals = usersSheet.getRange(row, 1, 1, usersSheet.getLastColumn()).getValues()[0];
        const rowObj = {};
        const rowObjNormalized = {};
        header.forEach((h, idx) => {
          const rawKey = String(h || '').trim();
          rowObj[rawKey] = rowVals[idx];
          rowObjNormalized[normalizeHeaderKey_(rawKey)] = rowVals[idx];
        });
        return { row: row, colMap: colMap, rowObj: rowObj, rowObjNormalized: rowObjNormalized };
      }
    }
    return null;
  }

  const row = cell.getRow();
  const rowVals = usersSheet.getRange(row, 1, 1, usersSheet.getLastColumn()).getValues()[0];
  const rowObj = {};
  const rowObjNormalized = {};
  header.forEach((h, idx) => {
    const rawKey = String(h || '').trim();
    rowObj[rawKey] = rowVals[idx];
    rowObjNormalized[normalizeHeaderKey_(rawKey)] = rowVals[idx];
  });
  return { row: row, colMap: colMap, rowObj: rowObj, rowObjNormalized: rowObjNormalized };
}

function createUser_(usersSheet, email, password) {
  const header = usersSheet.getRange(1, 1, 1, usersSheet.getLastColumn()).getValues()[0];
  const colMap = buildColumnMap_(header);
  ensureRequiredCols_(colMap, [
    AUTH_COLUMNS.USERS.userId,
    AUTH_COLUMNS.USERS.email,
    AUTH_COLUMNS.USERS.passwordHash,
    AUTH_COLUMNS.USERS.emailVerified,
    AUTH_COLUMNS.USERS.createdAt,
    AUTH_COLUMNS.USERS.resetCode,
    AUTH_COLUMNS.USERS.resetCodeExpiresAt
  ]);

  const userId = Utilities.getUuid();
  const createdAt = nowIso_();
  const rowVals = new Array(usersSheet.getLastColumn()).fill('');
  rowVals[colMap[AUTH_COLUMNS.USERS.userId] - 1] = userId;
  rowVals[colMap[AUTH_COLUMNS.USERS.email] - 1] = normalizeEmail_(email);
  rowVals[colMap[AUTH_COLUMNS.USERS.passwordHash] - 1] = password ? hashPasswordV2_(password) : '';
  rowVals[colMap[AUTH_COLUMNS.USERS.emailVerified] - 1] = true;
  rowVals[colMap[AUTH_COLUMNS.USERS.createdAt] - 1] = createdAt;
  rowVals[colMap[AUTH_COLUMNS.USERS.resetCode] - 1] = '';
  rowVals[colMap[AUTH_COLUMNS.USERS.resetCodeExpiresAt] - 1] = '';
  if (colMap[AUTH_COLUMNS.USERS.displayName]) rowVals[colMap[AUTH_COLUMNS.USERS.displayName] - 1] = '';
  if (colMap[AUTH_COLUMNS.USERS.defaultOrgId]) rowVals[colMap[AUTH_COLUMNS.USERS.defaultOrgId] - 1] = '';
  if (colMap[AUTH_COLUMNS.USERS.defaultOrgName]) rowVals[colMap[AUTH_COLUMNS.USERS.defaultOrgName] - 1] = '';
  if (colMap[AUTH_COLUMNS.USERS.role]) rowVals[colMap[AUTH_COLUMNS.USERS.role] - 1] = 'client';
  if (colMap[AUTH_COLUMNS.USERS.status]) rowVals[colMap[AUTH_COLUMNS.USERS.status] - 1] = 'active';
  if (colMap[AUTH_COLUMNS.USERS.lastLoginAt]) rowVals[colMap[AUTH_COLUMNS.USERS.lastLoginAt] - 1] = '';
  if (colMap[AUTH_COLUMNS.USERS.notes]) rowVals[colMap[AUTH_COLUMNS.USERS.notes] - 1] = '';

  const row = usersSheet.getLastRow() + 1;
  usersSheet.getRange(row, 1, 1, rowVals.length).setValues([rowVals]);
  return findUserByEmail_(usersSheet, email);
}

function updateUserColumns_(usersSheet, userInfo, updates) {
  const colMap = userInfo.colMap || {};
  const row = userInfo.row;
  Object.keys(updates || {}).forEach((key) => {
    const col = colMap[key];
    if (!col) return;
    usersSheet.getRange(row, col).setValue(updates[key]);
  });
}

function updateUserResetCode_(usersSheet, userInfo, code, expiresAt) {
  const updates = {};
  updates[AUTH_COLUMNS.USERS.resetCode] = String(code || '');
  updates[AUTH_COLUMNS.USERS.resetCodeExpiresAt] = String(expiresAt || '');
  updateUserColumns_(usersSheet, userInfo, updates);
}

function createSession_(sessionsSheet, email) {
  const header = sessionsSheet.getRange(1, 1, 1, sessionsSheet.getLastColumn()).getValues()[0];
  const colMap = buildColumnMap_(header);
  ensureRequiredCols_(colMap, [
    AUTH_COLUMNS.USER_SESSIONS.sessionId,
    AUTH_COLUMNS.USER_SESSIONS.email,
    AUTH_COLUMNS.USER_SESSIONS.expiresAt,
    AUTH_COLUMNS.USER_SESSIONS.createdAt
  ]);

  const createdAt = new Date().toISOString();
  const expiresAt = new Date(Date.now() + AUTH_POLICY.SESSION_TTL_MS).toISOString();
  const sessionId = Utilities.getUuid();

  const rowVals = new Array(sessionsSheet.getLastColumn()).fill('');
  rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.sessionId] - 1] = sessionId;
  rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.email] - 1] = normalizeEmail_(email);
  rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.expiresAt] - 1] = expiresAt;
  rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.createdAt] - 1] = createdAt;
  if (colMap[AUTH_COLUMNS.USER_SESSIONS.userId]) rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.userId] - 1] = '';
  if (colMap[AUTH_COLUMNS.USER_SESSIONS.lastSeenAt]) rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.lastSeenAt] - 1] = createdAt;
  if (colMap[AUTH_COLUMNS.USER_SESSIONS.revokedAt]) rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.revokedAt] - 1] = '';
  if (colMap[AUTH_COLUMNS.USER_SESSIONS.mode]) rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.mode] - 1] = 'portal';
  if (colMap[AUTH_COLUMNS.USER_SESSIONS.notes]) rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.notes] - 1] = '';

  const row = sessionsSheet.getLastRow() + 1;
  sessionsSheet.getRange(row, 1, 1, rowVals.length).setValues([rowVals]);

  return { sessionId: sessionId, email: normalizeEmail_(email), expiresAt: expiresAt };
}

/* ---------------- Low-Level Auth + Workbook Row Utilities ---------------- */

function validateSession_(sessionsSheet, sessionId) {
  const id = String(sessionId || '').trim();
  if (!id) return { ok: false, error: 'Missing session.' };

  const header = sessionsSheet.getRange(1, 1, 1, sessionsSheet.getLastColumn()).getValues()[0];
  const colMap = buildColumnMap_(header);
  ensureRequiredCols_(colMap, [
    AUTH_COLUMNS.USER_SESSIONS.sessionId,
    AUTH_COLUMNS.USER_SESSIONS.email,
    AUTH_COLUMNS.USER_SESSIONS.expiresAt
  ]);

  const idCol = colMap[AUTH_COLUMNS.USER_SESSIONS.sessionId];
  const lastRow = sessionsSheet.getLastRow();
  if (lastRow < 2) return { ok: false, error: 'Session expired. Please log in again.' };

  const idRange = sessionsSheet.getRange(2, idCol, lastRow - 1, 1);
  const finder = idRange.createTextFinder(id).matchEntireCell(true).matchCase(true);
  const cell = finder.findNext();
  if (!cell) return { ok: false, error: 'Session expired. Please log in again.' };

  const row = cell.getRow();
  const rowVals = sessionsSheet.getRange(row, 1, 1, sessionsSheet.getLastColumn()).getValues()[0];
  const email = normalizeEmail_(rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.email] - 1]);
  const expiresAtMs = parseIsoDateMs_(rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.expiresAt] - 1]);
  const revokedAtMs = colMap[AUTH_COLUMNS.USER_SESSIONS.revokedAt]
    ? parseIsoDateMs_(rowVals[colMap[AUTH_COLUMNS.USER_SESSIONS.revokedAt] - 1])
    : 0;
  if (revokedAtMs && revokedAtMs <= Date.now()) {
    return { ok: false, error: 'Session expired. Please log in again.' };
  }
  if (!expiresAtMs || expiresAtMs <= Date.now()) {
    sessionsSheet.deleteRow(row);
    return { ok: false, error: 'Session expired. Please log in again.' };
  }
  if (colMap[AUTH_COLUMNS.USER_SESSIONS.lastSeenAt]) {
    sessionsSheet.getRange(row, colMap[AUTH_COLUMNS.USER_SESSIONS.lastSeenAt]).setValue(nowIso_());
  }
  return { ok: true, email: email, row: row, colMap: colMap };
}

function deleteSessionById_(sessionsSheet, sessionId) {
  const id = String(sessionId || '').trim();
  if (!id) return;

  const header = sessionsSheet.getRange(1, 1, 1, sessionsSheet.getLastColumn()).getValues()[0];
  const colMap = buildColumnMap_(header);
  const idCol = colMap[AUTH_COLUMNS.USER_SESSIONS.sessionId];
  if (!idCol) return;

  const lastRow = sessionsSheet.getLastRow();
  if (lastRow < 2) return;
  const vals = sessionsSheet.getRange(2, idCol, lastRow - 1, 1).getValues();
  for (let i = vals.length - 1; i >= 0; i--) {
    const v = String(vals[i][0] || '').trim();
    if (v === id) sessionsSheet.deleteRow(i + 2);
  }
}

function emailExistsInExportLog_(exportSheet, email) {
  const normalizedEmail = normalizeEmail_(email);
  if (!normalizedEmail) return false;

  const header = exportSheet.getRange(1, 1, 1, exportSheet.getLastColumn()).getValues()[0];
  const colMap = buildColumnMap_(header);
  const personEmailCol = colMap[EXPORT_LOG_PERSON_EMAIL_HEADER];
  if (!personEmailCol) return false;

  const lastRow = exportSheet.getLastRow();
  if (lastRow < 2) return false;

  const vals = exportSheet.getRange(2, personEmailCol, lastRow - 1, 1).getValues();
  for (let i = 0; i < vals.length; i++) {
    const rowEmail = normalizeEmail_(vals[i][0]);
    if (rowEmail && rowEmail === normalizedEmail) return true;
  }
  return false;
}

function findRowByToken_(sheet, token) {
  const header = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  const colMap = buildColumnMap_(header);

  const tokenCol = colMap.token;
  if (!tokenCol) {
    throw new Error('EXPORT_LOG must have a "token" column in row 1.');
  }

  const lastRow = sheet.getLastRow();
  if (lastRow < 2) return null;

  const tokenRange = sheet.getRange(2, tokenCol, lastRow - 1, 1);
  const finder = tokenRange.createTextFinder(String(token)).matchEntireCell(true);
  const cell = finder.findNext();
  if (!cell) return null;

  const row = cell.getRow();
  const rowVals = sheet.getRange(row, 1, 1, sheet.getLastColumn()).getValues()[0];

  const rowObj = {};
  const rowObjNormalized = {};
  header.forEach((h, idx) => {
    const rawKey = String(h || '').trim();
    rowObj[rawKey] = rowVals[idx];
    rowObjNormalized[normalizeHeaderKey_(rawKey)] = rowVals[idx];
  });

  return {
    row: row,
    rowObj: rowObj,
    rowObjNormalized: rowObjNormalized,
    colMap: colMap
  };
}

function buildColumnMap_(headerRow) {
  const out = {};
  (headerRow || []).forEach((h, idx) => {
    const key = normalizeHeaderKey_(h);
    if (!key) return;
    if (!out[key]) out[key] = idx + 1;
  });
  return out;
}

function normalizeHeaderKey_(h) {
  return String(h || '')
    .trim()
    .toLowerCase();
}

function majorVersion_(version) {
  const m = String(version || '').trim().match(/^(\d+)/);
  return m ? Number(m[1]) : 0;
}

function safeJsonParse_(input, fallback) {
  try {
    if (input == null) return fallback;
    if (typeof input === 'object') return input;
    const s = String(input).trim();
    if (!s) return fallback;
    return JSON.parse(s);
  } catch (err) {
    return fallback;
  }
}

function makeClientSafe_(value, depth) {
  const level = Number(depth || 0);
  if (level > 30) return null;
  if (value == null) return value;

  if (Object.prototype.toString.call(value) === '[object Date]') {
    const ms = value.getTime();
    return isNaN(ms) ? '' : value.toISOString();
  }

  const valueType = typeof value;
  if (valueType === 'string' || valueType === 'number' || valueType === 'boolean') {
    return value;
  }

  if (Array.isArray(value)) {
    return value.map((item) => makeClientSafe_(item, level + 1));
  }

  if (valueType === 'object') {
    const out = {};
    Object.keys(value).forEach((key) => {
      const nextValue = makeClientSafe_(value[key], level + 1);
      if (typeof nextValue !== 'undefined') out[key] = nextValue;
    });
    return out;
  }

  return String(value);
}

function normalizeChatLog_(input) {
  if (!Array.isArray(input)) return [];
  return input
    .map((m) => {
      if (!m || typeof m !== 'object') return null;
      const text = String(m.text || '').trim();
      const senderRaw = String(m.sender || '').trim().toLowerCase();
      const sender = senderRaw === 'team'
        ? 'team'
        : (senderRaw === 'system' ? 'system' : 'client');
      const authorName = String(m.authorName || m.senderName || '').trim();
      if (!text) return null;
      const tsRaw = String(m.ts || m.tsIso || '').trim();
      const ts = tsRaw && !isNaN(new Date(tsRaw).getTime()) ? tsRaw : new Date().toISOString();
      const pjId = String(m.pjId || m.printJobId || '').trim();
      const pjName = String(m.pjName || m.printJobName || m.projectName || '').trim();
      const pjLabel = String(m.pjLabel || m.printJobLabel || '').trim();
      return {
        id: String(m.id || ('msg_' + Utilities.getUuid())),
        ts: ts,
        sender: sender,
        authorName: authorName,
        text: text,
        pjId: pjId,
        pjName: pjName,
        pjLabel: pjLabel
      };
    })
    .filter(Boolean);
}

function hasNonBlankJsonSignal_(value) {
  if (value == null) return false;
  if (typeof value === 'object') {
    if (Array.isArray(value)) return value.length > 0;
    return Object.keys(value).length > 0;
  }
  const raw = String(value || '').trim();
  if (!raw || raw === 'null' || raw === 'undefined') return false;
  if (raw === '{}' || raw === '[]') return false;
  const parsed = safeJsonParse_(raw, null);
  if (parsed == null) return raw !== '';
  if (Array.isArray(parsed)) return parsed.length > 0;
  if (typeof parsed === 'object') return Object.keys(parsed).length > 0;
  return String(parsed || '').trim() !== '';
}

function isFinalPortalStatus_(status) {
  return FINAL_LOCK_STATUSES[String(status || '').trim().toLowerCase()] === true;
}

function derivePortalDisplayOrderStatus_(stateInput, fallbackStatus) {
  /* Legacy compatibility layer — keep until Tranche 4E deletion pass.
     Raw order/payment/lock fields are interpreted here as a display-status bridge.
     Do not use this helper for new lifecycle decisions when workflowContext is available. */
  const state = (stateInput && typeof stateInput === 'object') ? stateInput : {};
  const teamWorkflowMode = normalizeTeamWorkflowMode_(state.teamWorkflowMode);
  const portalLockState = trimString_(
    state.portalLockState ||
    state.portallockstate ||
    state.currentPortalLockState ||
    state.currentportallockstate
  ).toLowerCase();
  const orderState = trimString_(
    state.orderState ||
    state.orderstate ||
    state.currentOrderState ||
    state.currentorderstate
  ).toLowerCase();
  const paymentState = trimString_(
    state.paymentState ||
    state.paymentstate ||
    state.currentPaymentState ||
    state.currentpaymentstate
  ).toLowerCase();
  const productionAuthorizationState = trimString_(
    state.productionAuthorizationState ||
    state.productionauthorizationstate ||
    state.currentProductionAuthorizationState ||
    state.currentproductionauthorizationstate
  ).toLowerCase();
  const paidAt = trimString_(state.paidAt || state.paidat);
  const poSubmittedAt = trimString_(state.poSubmittedAt || state.posubmittedat);
  const poNumber = trimString_(state.poNumber || state.ponumber);
  const fallback = trimString_(fallbackStatus || state.status).toLowerCase();

  const isOperationallyAccepted =
    !!paidAt ||
    paymentState === PAYMENT_STATES.paid ||
    paymentState === PAYMENT_STATES.manual_received ||
    !!poSubmittedAt ||
    !!poNumber ||
    orderState === ORDER_STATES.in_production ||
    orderState === ORDER_STATES.closed;

  const isPendingLockedOrder =
    orderState === ORDER_STATES.awaiting_manual_payment ||
    orderState === ORDER_STATES.awaiting_po_submission ||
    orderState === ORDER_STATES.awaiting_payment_confirmation ||
    paymentState === PAYMENT_STATES.checkout_created ||
    paymentState === PAYMENT_STATES.submitted ||
    paymentState === PAYMENT_STATES.pending ||
    paymentState === PAYMENT_STATES.manual_pending ||
    productionAuthorizationState === PRODUCTION_AUTHORIZATION_STATES.po_pending;

  if (teamWorkflowMode === TEAM_WORKFLOW_MODES.team_hold || teamWorkflowMode === TEAM_WORKFLOW_MODES.checkout_reset) {
    return PORTAL_DISPLAY_ORDER_STATUSES.editable;
  }

  if (portalLockState === PORTAL_LOCK_STATES.editable) {
    return PORTAL_DISPLAY_ORDER_STATUSES.editable;
  }
  if (portalLockState === PORTAL_LOCK_STATES.locked) {
    return isOperationallyAccepted
      ? PORTAL_DISPLAY_ORDER_STATUSES.processing
      : PORTAL_DISPLAY_ORDER_STATUSES.locked;
  }
  if (isOperationallyAccepted) {
    return PORTAL_DISPLAY_ORDER_STATUSES.processing;
  }
  if (fallback === PORTAL_DISPLAY_ORDER_STATUSES.processing.toLowerCase()) {
    return PORTAL_DISPLAY_ORDER_STATUSES.processing;
  }
  if (isPendingLockedOrder || isFinalPortalStatus_(fallback)) {
    return PORTAL_DISPLAY_ORDER_STATUSES.locked;
  }
  if (!fallback || fallback === 'sent' || fallback === 'estimate' || fallback === 'editable' || fallback === 'saved') {
    return PORTAL_DISPLAY_ORDER_STATUSES.editable;
  }
  return PORTAL_DISPLAY_ORDER_STATUSES.editable;
}

function getFinalStatusForRow_(row) {
  return derivePortalDisplayOrderStatus_(row, row && row.status);
}

function isLockedPortalRow_(row, portalState) {
  /* Legacy compatibility layer — keep until Tranche 4E deletion pass.
     Raw export-row fallback — do not use for new lifecycle decisions. Canonical
     lock/editability should flow from derivePortalLifecycle_() and hydrated workflowContext. */
  const status = String((row && row.status) || '').trim().toLowerCase();
  const portalLockState = trimString_(
    row && (row.portallockstate || row.portalLockState || row.currentportallockstate || row.currentPortalLockState)
  ).toLowerCase();
  if (portalLockState === PORTAL_LOCK_STATES.editable) return false;
  if (portalLockState === PORTAL_LOCK_STATES.locked) return true;
  if (status === 'saved' || status === 'editable' || status === 'editable / estimate') return false;
  if (hasNonBlankJsonSignal_(row && row.submittedstatejson)) return true;
  if (isFinalPortalStatus_(status)) return true;
  return Boolean(portalState && portalState.isReadOnly === true);
}

function parsePortalStateInput_(portalStateInput) {
  const portalState = safeJsonParse_(portalStateInput, null);
  if (!portalState || typeof portalState !== 'object' || Array.isArray(portalState)) {
    throw new Error('portalState must be an object.');
  }
  if (!portalState.printJobs || typeof portalState.printJobs !== 'object' || Array.isArray(portalState.printJobs)) {
    throw new Error('portalState.printJobs must be an object.');
  }
  return portalState;
}

function detectMessageLogKey_(stateObj) {
  if (!stateObj || typeof stateObj !== 'object') return 'messageLog';
  if (Array.isArray(stateObj.messageLog)) return 'messageLog';
  if (Array.isArray(stateObj.chatLog)) return 'chatLog';
  if (Array.isArray(stateObj.messages)) return 'messages';
  return 'messageLog';
}

function writeChatLogIntoPortalState_(stateObj, chatLog) {
  if (!stateObj || typeof stateObj !== 'object') return;
  const key = detectMessageLogKey_(stateObj);
  delete stateObj.messageLog;
  delete stateObj.chatLog;
  delete stateObj.messages;
  stateObj[key] = normalizeChatLog_(chatLog);
}

function readChatLogForRow_(sheet, rowInfo) {
  const colMap = rowInfo.colMap || {};
  const chatCol = colMap.chatlogjson || EXPORT_LOG_COLUMNS.chatLogJson;
  if (!chatCol) return [];
  const existingRaw = sheet.getRange(rowInfo.row, chatCol).getValue();
  return normalizeChatLog_(safeJsonParse_(existingRaw, []));
}

function createChatMessage_(sender, text, tsOverride, options) {
  const opts = (options && typeof options === 'object') ? options : {};
  return {
    id: 'msg_' + Utilities.getUuid(),
    ts: String(tsOverride || new Date().toISOString()),
    sender: String(sender || '').trim().toLowerCase() || 'client',
    authorName: String(opts.authorName || '').trim(),
    text: String(text || '').trim(),
    pjId: String(opts.pjId || opts.printJobId || '').trim(),
    pjName: String(opts.pjName || opts.printJobName || opts.projectName || '').trim(),
    pjLabel: String(opts.pjLabel || opts.printJobLabel || '').trim()
  };
}

function getChatMessageSemanticKey_(message) {
  if (!message || typeof message !== 'object') return '';
  const sender = String(message.sender || '').trim().toLowerCase();
  const text = String(message.text || '').trim();
  if (sender === 'system' && /^Order placed successfully on .+\.$/.test(text)) {
    return 'system:order_placed_successfully';
  }
  if (sender === 'system' && /^ACH payment cleared on .+\. Order authorized for production\.$/.test(text)) {
    return 'system:ach_payment_cleared';
  }
  return '';
}

function dedupeChatLogBySemanticKey_(chatLog, semanticKey) {
  if (!semanticKey) return normalizeChatLog_(chatLog);
  let seen = false;
  return normalizeChatLog_(chatLog).filter((item) => {
    if (getChatMessageSemanticKey_(item) !== semanticKey) return true;
    if (seen) return false;
    seen = true;
    return true;
  });
}

function appendUniqueChatMessage_(chatLog, message) {
  let nextLog = normalizeChatLog_(chatLog);
  const normalized = normalizeChatLog_([message])[0];
  if (!normalized) return nextLog;
  const semanticKey = getChatMessageSemanticKey_(normalized);
  if (semanticKey) {
    nextLog = dedupeChatLogBySemanticKey_(nextLog, semanticKey);
    const hasSemanticMatch = nextLog.some((item) => (
      getChatMessageSemanticKey_(item) === semanticKey
    ));
    if (hasSemanticMatch) return nextLog;
  }
  const alreadyPresent = nextLog.some((item) => (
    String(item.sender || '') === String(normalized.sender || '') &&
    String(item.text || '') === String(normalized.text || '') &&
    String(item.ts || '') === String(normalized.ts || '')
  ));
  if (alreadyPresent) return nextLog;
  nextLog.push(normalized);
  return normalizeChatLog_(nextLog);
}

function jsonOutput_(obj) {
  return ContentService
    .createTextOutput(JSON.stringify(obj || {}))
    .setMimeType(ContentService.MimeType.JSON);
}

function escapeHtml_(s) {
  return String(s || '')
    .replace(/&/g, '&amp;').replace(/</g, '&lt;')
    .replace(/>/g, '&gt;').replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function renderTeamContractMessage_(diag) {
  const html = `
  <html>
    <head>
      <meta name="viewport" content="width=device-width,initial-scale=1" />
      <title>Contract Mismatch (Team)</title>
      <style>
        body{font-family:Arial,sans-serif;margin:0;background:#f6f7f9}
        .wrap{max-width:900px;margin:24px auto;padding:0 16px}
        .card{background:#fff;border-radius:14px;box-shadow:0 6px 18px rgba(0,0,0,.08);padding:22px}
        h1{margin:0 0 10px;font-size:20px}
        p{margin:0 0 10px;color:#333;line-height:1.4}
        .kv{display:grid;grid-template-columns:190px 1fr;gap:6px 12px;margin-top:12px;font-size:13px}
        .k{font-weight:700;color:#111}
        pre{margin-top:12px;background:#f3f4f6;border:1px solid #d1d5db;border-radius:8px;padding:10px;white-space:pre-wrap;word-break:break-word;font-size:12px}
      </style>
    </head>
    <body><div class="wrap"><div class="card">
      <h1>Unsupported Contract Version</h1>
      <p>This link is not on contract v2 and cannot be rendered by this build in client mode.</p>
      <div class="kv">
        <div class="k">token</div><div>${escapeHtml_(diag.token || '')}</div>
        <div class="k">status</div><div>${escapeHtml_(diag.status || '')}</div>
        <div class="k">contractVersion</div><div>${escapeHtml_(diag.contractVersion || '')}</div>
        <div class="k">snapshotId</div><div>${escapeHtml_(diag.snapshotId || '')}</div>
        <div class="k">exportedAt</div><div>${escapeHtml_(diag.exportedAt || '')}</div>
      </div>
      <pre>${escapeHtml_(diag.snapshotSnippet || '')}</pre>
    </div></div></body>
  </html>`;

  return HtmlService.createHtmlOutput(html)
    .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL);
}

function renderMessage_(title, message) {
  const html = `
  <html>
    <head>
      <meta name="viewport" content="width=device-width,initial-scale=1" />
      <title>${escapeHtml_(title)}</title>
      <style>
        body{font-family:Arial,sans-serif;margin:0;background:#f6f7f9}
        .wrap{max-width:760px;margin:40px auto;padding:0 16px}
        .card{background:#fff;border-radius:14px;box-shadow:0 6px 18px rgba(0,0,0,.08);padding:22px}
        h1{margin:0 0 10px;font-size:20px}
        p{margin:0;color:#333;line-height:1.4}
      </style>
    </head>
    <body><div class="wrap"><div class="card">
      <h1>${escapeHtml_(title)}</h1><p>${escapeHtml_(message)}</p>
    </div></div></body>
  </html>`;

  return HtmlService.createHtmlOutput(html)
    .setXFrameOptionsMode(HtmlService.XFrameOptionsMode.ALLOWALL);
}
